def _referral_percent_to_bp(value, default_bp: int) -> int:
    """Convert percent-like config values to basis points: 5 -> 500, 2.5 -> 250."""
    try:
        from decimal import Decimal, ROUND_HALF_UP
        raw = Decimal(str(value))
        if raw < 0:
            return 0
        return int((raw * Decimal(100)).quantize(Decimal("1"), rounding=ROUND_HALF_UP))
    except Exception:
        return int(default_bp)


