def _connect_sqlite_with_timeout(database, *args, **kwargs):
    kwargs.setdefault("timeout", SQLITE_BUSY_TIMEOUT_SECONDS)
    return _orig_aiosqlite_connect(database, *args, **kwargs)

aiosqlite.connect = _connect_sqlite_with_timeout


async def telegram_send_throttle(*, bulk: bool = False) -> None:
    """Small global Telegram send throttle for broadcasts/reminders/admin bursts.

    Normal single-user screens remain responsive, while background tasks that
    send many messages are paced and TelegramRetryAfter is respected.
    """
    global telegram_last_send_at
    interval = TELEGRAM_BULK_SEND_MIN_INTERVAL_SECONDS if bulk else TELEGRAM_SEND_MIN_INTERVAL_SECONDS
    if interval <= 0:
        return
    async with telegram_send_lock:
        now = time.monotonic()
        wait_for = interval - (now - telegram_last_send_at)
        if wait_for > 0:
            await asyncio.sleep(wait_for)
        telegram_last_send_at = time.monotonic()


async def send_message_limited(
    bot: Bot,
    chat_id: int,
    text: str,
    *,
    reply_markup=None,
    parse_mode=None,
    disable_web_page_preview: bool | None = None,
    bulk: bool = False,
    attempts: int = 3,
):
    for attempt in range(max(1, attempts)):
        await telegram_send_throttle(bulk=bulk)
        try:
            kwargs = {"reply_markup": reply_markup}
            if parse_mode is not None:
                kwargs["parse_mode"] = parse_mode
            if disable_web_page_preview is not None:
                kwargs["disable_web_page_preview"] = disable_web_page_preview
            return await bot.send_message(int(chat_id), text, **kwargs)
        except TelegramRetryAfter as exc:
            retry_after = float(getattr(exc, "retry_after", 1) or 1)
            retry_after = min(retry_after, TELEGRAM_MAX_RETRY_AFTER_SECONDS)
            logging.warning("Telegram flood limit chat=%s retry_after=%.2fs attempt=%s", chat_id, retry_after, attempt + 1)
            await asyncio.sleep(retry_after + TELEGRAM_RETRY_AFTER_EXTRA_SECONDS)
        except Exception as exc:
            logging.warning("Telegram send_message failed chat=%s attempt=%s: %s", chat_id, attempt + 1, exc)
            if attempt + 1 >= max(1, attempts):
                return None
            await asyncio.sleep(0.5)
    return None


async def send_photo_limited(
    bot: Bot,
    chat_id: int,
    photo: str,
    *,
    caption: str | None = None,
    reply_markup=None,
    parse_mode=None,
    bulk: bool = False,
    attempts: int = 3,
):
    for attempt in range(max(1, attempts)):
        await telegram_send_throttle(bulk=bulk)
        try:
            kwargs = {"caption": caption, "reply_markup": reply_markup}
            if parse_mode is not None:
                kwargs["parse_mode"] = parse_mode
            return await bot.send_photo(int(chat_id), photo=photo, **kwargs)
        except TelegramRetryAfter as exc:
            retry_after = float(getattr(exc, "retry_after", 1) or 1)
            retry_after = min(retry_after, TELEGRAM_MAX_RETRY_AFTER_SECONDS)
            logging.warning("Telegram flood limit photo chat=%s retry_after=%.2fs attempt=%s", chat_id, retry_after, attempt + 1)
            await asyncio.sleep(retry_after + TELEGRAM_RETRY_AFTER_EXTRA_SECONDS)
        except Exception as exc:
            logging.warning("Telegram send_photo failed chat=%s attempt=%s: %s", chat_id, attempt + 1, exc)
            if attempt + 1 >= max(1, attempts):
                return None
            await asyncio.sleep(0.5)
    return None


@contextlib.asynccontextmanager
async def db_connect(database=DATABASE_DB):
    """
    Open a short-lived SQLite connection with production-safe pragmas.
    WAL is configured once at startup, while busy_timeout/foreign_keys are per-connection.
    """
    async with aiosqlite.connect(database) as conn:
        await conn.execute("PRAGMA foreign_keys=ON;")
        yield conn



