TRIAL_AUTO_DELETE_GRACE_SECONDS = (TRIAL_AUTO_DELETE_GRACE_MINUTES * 60) if TRIAL_AUTO_DELETE_GRACE_MINUTES is not None else (TRIAL_AUTO_DELETE_GRACE_HOURS * 3600)
