# =========================
# DATA
# =========================

@dataclass(frozen=True)
class Tariff:
    key: str
    title: str
    days: int
    traffic_gb: int | None
    stars_price: int
    code: str
    is_public: bool = True
    is_admin_only: bool = False
    connection_limit: int = 10
    stars_purchase_url: str | None = None
    rub_payment_enabled: bool = False
    rub_price: int = 0
    stars_payment_enabled: bool = True
    show_stars_official: bool = True
    show_stars_alt: bool = True
    sui_group: str = "user"
    sui_inbounds: str = ""
    double_vpn_enabled: bool = True
    double_vpn_reset_days: int = 0
    remote_node_scope: str = "all"
    preview_extra_text: str = ""
    buy_short_text: str = ""
    is_custom: bool = False


PUBLIC_TARIFFS: dict[str, Tariff] = {}

ADMIN_TARIFFS: dict[str, Tariff] = {}


@dataclass(frozen=True)
class TariffPeriod:
    tariff_key: str
    period_key: str
    title: str
    days: int
    stars_price: int = 0
    rub_price: int = 0
    enabled: bool = True
    is_default: bool = False
    sort_order: int = 0
    is_base: bool = False


TARIFF_PERIODS_CACHE: dict[str, list[dict]] = {}

TARIFF_PERIOD_KEY_RE = re.compile(r"^[a-zA-Z0-9_-]{1,24}$")


def normalize_tariff_period_key(value: str) -> str:
    key = str(value or "").strip().lower()
    if not key:
        raise ValueError("Ключ срока не может быть пустым.")
    if key in {"base", "default"}:
        raise ValueError("Ключи base/default зарезервированы.")
    if not TARIFF_PERIOD_KEY_RE.fullmatch(key):
        raise ValueError("Ключ срока: 1–24 символа, латиница, цифры, _ или -.")
    return key


def tariff_base_period(tariff: Tariff) -> TariffPeriod:
    return TariffPeriod(
        tariff_key=str(tariff.key),
        period_key="base",
        title=f"{int(tariff.days)} дн.",
        days=max(1, int(tariff.days or 30)),
        stars_price=max(0, int(tariff.stars_price or 0)),
        rub_price=max(0, int(tariff.rub_price or 0)),
        enabled=True,
        is_default=True,
        sort_order=0,
        is_base=True,
    )


def tariff_explicit_periods(tariff_key: str) -> list[TariffPeriod]:
    result: list[TariffPeriod] = []
    for row in TARIFF_PERIODS_CACHE.get(str(tariff_key), []) or []:
        try:
            result.append(TariffPeriod(
                tariff_key=str(row.get("tariff_key") or tariff_key),
                period_key=str(row.get("period_key") or ""),
                title=str(row.get("title") or ""),
                days=max(1, int(row.get("days") or 0)),
                stars_price=max(0, int(row.get("stars_price") or 0)),
                rub_price=max(0, int(row.get("rub_price") or 0)),
                enabled=bool(int(row.get("enabled") if row.get("enabled") is not None else 1)),
                is_default=bool(int(row.get("is_default") or 0)),
                sort_order=int(row.get("sort_order") or 1000),
                is_base=False,
            ))
        except Exception:
            continue
    return sorted(result, key=lambda x: (int(x.sort_order or 0), str(x.period_key)))


def tariff_periods_for_tariff(tariff: Tariff) -> list[TariffPeriod]:
    # The base period keeps backward compatibility. A tariff remains monthly-only
    # until the admin adds extra enabled periods with prices.
    return [tariff_base_period(tariff)] + tariff_explicit_periods(tariff.key)


def tariff_period_has_price(tariff: Tariff, period: TariffPeriod) -> bool:
    return (
        (bool(tariff.rub_payment_enabled) and int(period.rub_price or 0) > 0)
        or (bool(tariff.stars_payment_enabled) and int(period.stars_price or 0) > 0)
    )


def tariff_available_periods(tariff: Tariff) -> list[TariffPeriod]:
    result: list[TariffPeriod] = []
    for period in tariff_periods_for_tariff(tariff):
        if not period.enabled or int(period.days or 0) <= 0:
            continue
        if tariff_period_has_price(tariff, period):
            result.append(period)
    return result


def tariff_period_by_key(tariff: Tariff, period_key: str | None) -> TariffPeriod | None:
    key = str(period_key or "base").strip()
    for period in tariff_periods_for_tariff(tariff):
        if period.period_key == key:
            return period
    return None


def tariff_choose_period(tariff: Tariff, period_key: str | None = None) -> TariffPeriod | None:
    if period_key:
        period = tariff_period_by_key(tariff, period_key)
        if period and period.enabled:
            return period
    periods = tariff_available_periods(tariff)
    return periods[0] if periods else None


def tariff_period_label(period: TariffPeriod | None) -> str:
    if not period:
        return "—"
    title = str(period.title or "").strip()
    return title or f"{int(period.days)} дн."


def tariff_period_price(tariff: Tariff, period: TariffPeriod | None, currency: str) -> int:
    if not period:
        period = tariff_base_period(tariff)
    cur = str(currency or "XTR").upper()
    return max(0, int(period.rub_price if cur == "RUB" else period.stars_price or 0))


def payment_period_from_row(payment, tariff: Tariff) -> TariffPeriod:
    try:
        days = int(payment["period_days"] or 0) if "period_days" in payment.keys() else 0
    except Exception:
        days = 0
    if days > 0:
        try:
            pkey = str(payment["period_key"] or "base") if "period_key" in payment.keys() else "base"
        except Exception:
            pkey = "base"
        try:
            ptitle = str(payment["period_title"] or "") if "period_title" in payment.keys() else ""
        except Exception:
            ptitle = ""
        return TariffPeriod(
            tariff_key=tariff.key,
            period_key=pkey or "base",
            title=ptitle or f"{days} дн.",
            days=days,
            stars_price=max(0, int(tariff.stars_price or 0)),
            rub_price=max(0, int(tariff.rub_price or 0)),
            enabled=True,
            is_default=(pkey in {"", "base"}),
            sort_order=0,
            is_base=(pkey in {"", "base"}),
        )
    return tariff_choose_period(tariff, str(payment["period_key"] or "base") if "period_key" in payment.keys() else "base") or tariff_base_period(tariff)


def period_payload_fields(period: TariffPeriod | None) -> dict:
    if not period:
        return {}
    return {
        "period_key": period.period_key,
        "period_title": tariff_period_label(period),
        "period_days": int(period.days),
    }


def is_admin(user_id: int) -> bool:
    return int(user_id) in ADMIN_IDS


def get_tariff_base(key: str) -> Optional[Tariff]:
    if str(key) == "test":
        return get_trial_tariff()
    base = PUBLIC_TARIFFS.get(key) or ADMIN_TARIFFS.get(key)
    if base:
        return base
    row = TARIFF_OVERRIDES_CACHE.get(key)
    if row and int(row.get("is_custom") or 0) == 1:
        traffic = row.get("traffic_gb")
        if traffic == -1:
            traffic = None
        return Tariff(
            key=str(key),
            title=str(row.get("title") or key),
            days=int(row.get("days") or 30),
            traffic_gb=traffic,
            stars_price=int(row["stars_price"]) if row.get("stars_price") is not None else 1,
            code=str(row.get("code") or "c1"),
            is_public=not bool(int(row.get("is_admin_only") or 0)),
            is_admin_only=bool(int(row.get("is_admin_only") or 0)),
            connection_limit=max(1, int(row.get("connection_limit") or 10)),
            stars_purchase_url=normalize_stars_purchase_url(row.get("stars_purchase_url")),
            rub_payment_enabled=bool(int(row.get("rub_payment_enabled") if row.get("rub_payment_enabled") is not None else 0)),
            rub_price=max(0, int(row.get("rub_price") or 0)),
            stars_payment_enabled=bool(int(row.get("stars_payment_enabled") if row.get("stars_payment_enabled") is not None else 1)),
            show_stars_official=bool(int(row.get("show_stars_official") if row.get("show_stars_official") is not None else 1)),
            show_stars_alt=bool(int(row.get("show_stars_alt") if row.get("show_stars_alt") is not None else 1)),
            sui_group=normalize_sui_group_input(row.get("sui_group") or "user"),
            sui_inbounds=normalize_sui_inbounds_input(row.get("sui_inbounds") or ""),
            double_vpn_enabled=bool(int(row.get("double_vpn_enabled") if row.get("double_vpn_enabled") is not None else 1)),
            double_vpn_reset_days=max(0, int(row.get("double_vpn_reset_days") or 0)),
            remote_node_scope=normalize_remote_node_scope_value(row.get("remote_node_scope") or "all"),
            preview_extra_text=normalize_tariff_multiline_text(row.get("preview_extra_text") or "", limit=1000),
            buy_short_text=normalize_tariff_short_text(row.get("buy_short_text") or "", limit=240),
            is_custom=True,
        )
    return None


TARIFF_OVERRIDES_CACHE: dict[str, dict] = {}


def normalize_stars_purchase_url(value: str | None) -> str | None:
    raw = str(value or "").strip()
    lowered = raw.lower()
    if not raw or lowered in {"-", "none", "null", "нет", "skip"}:
        return None

    # Явный мусор вроде "1" / "0" / просто цифр не должен попадать в URL-кнопку
    if raw.isdigit():
        return None

    if raw.startswith("t.me/"):
        raw = "https://" + raw
    if raw.startswith("telegram.me/"):
        raw = "https://" + raw
    if raw.startswith("www.t.me/"):
        raw = "https://" + raw
    if raw.startswith("@"):
        raw = "https://t.me/" + raw[1:]
    if raw.startswith("http://"):
        raw = "https://" + raw[len("http://"):]

    if not raw.startswith("https://"):
        return None

    try:
        parsed = urlparse(raw)
        if parsed.scheme != "https" or not parsed.netloc:
            return None
    except Exception:
        return None

    return raw


def is_resettable_stars_url_input(value: str | None) -> bool:
    lowered = str(value or "").strip().lower()
    return lowered in {"", "-", "none", "null", "нет", "skip"}


def normalize_tariff_multiline_text(value: str | None, *, limit: int = 1000) -> str:
    """Normalize admin-entered tariff text for clean Telegram output."""
    raw = str(value or "").replace("\r\n", "\n").replace("\r", "\n").strip()
    if not raw:
        return ""
    lines: list[str] = []
    for line in raw.split("\n"):
        clean = re.sub(r"\s+", " ", line.strip())
        if not clean:
            continue
        if clean.startswith("•") and not clean.startswith("• "):
            clean = "• " + clean[1:].lstrip()
        lines.append(clean)
    return "\n".join(lines)[:limit].strip()


def normalize_tariff_short_text(value: str | None, *, limit: int = 240) -> str:
    raw = normalize_tariff_multiline_text(value, limit=limit * 2)
    raw = re.sub(r"\s+", " ", raw.replace("\n", " ")).strip()
    if raw.startswith("•"):
        raw = raw[1:].strip()
    return raw[:limit].strip()


def parse_admin_bool_input(value: str) -> bool:
    norm = str(value or "").strip().lower()
    if norm in {"yes", "y", "да", "д", "1", "+", "on", "true", "вкл", "включить"}:
        return True
    if norm in {"no", "n", "нет", "н", "0", "-", "off", "false", "выкл", "выключить"}:
        return False
    raise ValueError("Введите yes/no или да/нет.")


TARIFF_KEY_PATTERN = re.compile(r"^[a-z0-9][a-z0-9_-]{1,23}$")


def normalize_tariff_key_input(value: str) -> str:
    key = str(value or "").strip().lower()
    if not key:
        raise ValueError("Ключ тарифа не может быть пустым.")
    if not TARIFF_KEY_PATTERN.fullmatch(key):
        raise ValueError("Ключ тарифа: 2–24 символа, только латиница a-z, цифры 0-9, _ и -. Первый символ — буква или цифра.")
    return key


def tariff_key_for_client_name(value: str) -> str:
    # Безопасный кусок имени клиента в S-UI. Для новых тарифов это ровно key.
    # Для старых/базовых тарифов оставляем defensive-normalization, чтобы не сломать создание клиента.
    key = str(value or "").strip().lower()
    key = re.sub(r"[^a-z0-9_-]+", "_", key).strip("_-")
    if not key:
        return "plan"
    return key[:24]


SUI_GROUP_PATTERN = re.compile(r"^[A-Za-z0-9][A-Za-z0-9_-]{0,31}$")


def normalize_sui_group_input(value: str | None) -> str:
    group = str(value or "").strip()
    if not group or group in {"-", "none", "null", "нет", "skip"}:
        return "user"
    if not SUI_GROUP_PATTERN.fullmatch(group):
        raise ValueError("Группа S-UI: 1–32 символа, только латиница A-Z/a-z, цифры 0-9, _ и -. Первый символ — буква или цифра.")
    return group


def normalize_sui_inbounds_input(value: str | None) -> str:
    raw = str(value or "").strip()
    if not raw or raw.lower() in {"-", "default", "none", "null", "нет", "skip", "по умолчанию"}:
        return ""
    parts = re.split(r"[,\s]+", raw)
    result: list[int] = []
    for part in parts:
        if not part:
            continue
        if not part.isdigit():
            raise ValueError("Inbounds S-UI: укажите ID через запятую, например 1,2,3, или '-' для значения из config.json.")
        value_int = int(part)
        if value_int <= 0:
            raise ValueError("Inbounds S-UI: ID должен быть положительным числом.")
        if value_int not in result:
            result.append(value_int)
    if not result:
        return ""
    return ",".join(str(x) for x in result)


REMOTE_NODE_ID_PATTERN = re.compile(r"^[A-Za-z0-9_-]{1,64}$")


def normalize_remote_node_scope_value(value) -> str:
    """Tariff location scope stored as 'all', 'none' or comma-separated node ids."""
    if value is None:
        return "all"
    if isinstance(value, (list, tuple, set)):
        parts = [str(x).strip() for x in value]
        if not parts:
            return "none"
    else:
        raw = str(value or "").strip()
        low = raw.lower()
        if not raw or low in {"all", "*", "все", "default"}:
            return "all"
        if low in {"none", "нет", "empty", "off", "no", "no_nodes", "без"}:
            return "none"
        if raw.startswith("["):
            parts = []
            with contextlib.suppress(Exception):
                parsed = json.loads(raw)
                if isinstance(parsed, list):
                    parts = [str(x).strip() for x in parsed]
        else:
            parts = [x.strip() for x in re.split(r"[,\s]+", raw) if x.strip()]
    clean: list[str] = []
    for part in parts:
        if not part:
            continue
        if not REMOTE_NODE_ID_PATTERN.fullmatch(part):
            raise ValueError("Локации тарифа: node id может содержать только A-Z/a-z, цифры, _ и -.")
        if part not in clean:
            clean.append(part)
    return "none" if not clean else ",".join(clean)


def tariff_remote_node_scope_ids(tariff: Tariff | None) -> set[str] | None:
    if tariff is None:
        return None
    raw = normalize_remote_node_scope_value(getattr(tariff, "remote_node_scope", "all") or "all")
    if raw == "all":
        return None
    if raw == "none":
        return set()
    return {x.strip() for x in raw.split(",") if x.strip()}


def tariff_allows_remote_node(tariff: Tariff | None, node: dict) -> bool:
    allowed = tariff_remote_node_scope_ids(tariff)
    if allowed is None:
        return True
    return str((node or {}).get("id") or "").strip() in allowed


def tariff_remote_node_scope_label(tariff: Tariff | None) -> str:
    allowed = tariff_remote_node_scope_ids(tariff)
    if allowed is None:
        return "все доступные локации"
    if not allowed:
        return "локации не выбраны"
    return ", ".join(sorted(allowed))


def tariff_double_vpn_enabled(tariff: Tariff | None) -> bool:
    if tariff is None:
        return True
    return bool(getattr(tariff, "double_vpn_enabled", True))


def tariff_double_vpn_display(tariff: Tariff | None) -> str:
    return "доступен" if tariff_double_vpn_enabled(tariff) else "недоступен"


def tariff_double_vpn_reset_days(tariff: Tariff | None) -> int:
    # This is an admin tariff setting and must be persisted/displayed independently
    # from available purchase periods. Whether it is applied to S-UI for a specific
    # client is decided later by tariff_period_uses_auto_reset(tariff, period).
    try:
        return max(0, int(getattr(tariff, "double_vpn_reset_days", 0) or 0))
    except Exception:
        return 0


def tariff_double_vpn_reset_display(tariff: Tariff | None) -> str:
    days = tariff_double_vpn_reset_days(tariff)
    if days > 0:
        return f"auto reset каждые {days} дн."
    return "save / весь срок подписки"


def tariff_period_days(tariff: Tariff | None, period: TariffPeriod | None = None) -> int:
    try:
        if period is not None:
            return max(1, int(getattr(period, "days", 0) or 0))
        if tariff is not None:
            return max(1, int(getattr(tariff, "days", 0) or 30))
    except Exception:
        pass
    return 30


def tariff_period_uses_auto_reset(tariff: Tariff | None, period: TariffPeriod | None = None) -> bool:
    """Use S-UI auto-reset only for periods longer than the configured reset cycle.

    Monthly renewals keep the historical behavior: add another tariff traffic
    bucket to the existing one, so unused traffic is not lost. Long periods
    like 365 days use a fixed monthly Double VPN limit with S-UI auto-reset.
    """
    if not tariff or not tariff_double_vpn_enabled(tariff):
        return False
    reset_days = tariff_double_vpn_reset_days(tariff)
    if reset_days <= 0:
        return False
    return tariff_period_days(tariff, period) > int(reset_days)


def tariff_sui_traffic_reset_fields(tariff: Tariff | None, period: TariffPeriod | None = None) -> dict:
    if tariff_period_uses_auto_reset(tariff, period):
        days = tariff_double_vpn_reset_days(tariff)
        return {"autoReset": True, "resetDays": int(days), "nextReset": 0}
    return {"autoReset": False, "resetDays": 0, "nextReset": 0}


def tariff_main_traffic_limit_text(tariff: Tariff | None, period: TariffPeriod | None = None) -> str:
    """Human, user-facing Double VPN traffic text."""
    if tariff is None:
        return "—"
    traffic = human_traffic(getattr(tariff, "traffic_gb", None))
    reset_days = tariff_double_vpn_reset_days(tariff)
    if tariff_period_uses_auto_reset(tariff, period):
        if int(reset_days) == 30:
            return f"{traffic} / Ежемесячно"
        return f"{traffic} / каждые {int(reset_days)} дней"
    return traffic


def tariff_renewal_volume_bytes(current_volume: int, tariff: Tariff, period: TariffPeriod | None = None) -> int:
    if tariff.traffic_gb is None:
        return 0
    limit_bytes = bytes_from_gb(tariff.traffic_gb)
    if tariff_period_uses_auto_reset(tariff, period):
        return int(limit_bytes)
    return int(limit_bytes if int(current_volume or 0) == 0 else int(current_volume or 0) + limit_bytes)


def tariff_renewal_traffic_line(tariff: Tariff, period: TariffPeriod | None = None) -> str | None:
    if not tariff_double_vpn_enabled(tariff):
        return None
    if tariff_period_uses_auto_reset(tariff, period):
        return f"• Лимит трафика Double VPN: {tariff_main_traffic_limit_text(tariff, period)}"
    if tariff.traffic_gb is None:
        return "• Трафик Double VPN: ∞"
    return f"• Трафик Double VPN: +{human_traffic(tariff.traffic_gb)}"


def tariff_sui_inbound_ids(tariff: Tariff) -> list[int]:
    if not tariff_double_vpn_enabled(tariff):
        return []
    custom = normalize_sui_inbounds_input(getattr(tariff, "sui_inbounds", "") or "")
    if not custom:
        return get_default_inbound_ids()
    result: list[int] = []
    for part in custom.split(","):
        part = part.strip()
        if not part:
            continue
        try:
            value = int(part)
        except Exception:
            continue
        if value > 0 and value not in result:
            result.append(value)
    return result or get_default_inbound_ids()


def tariff_sui_inbounds_display(tariff: Tariff) -> str:
    if not tariff_double_vpn_enabled(tariff):
        return "Double VPN отключён"
    custom = normalize_sui_inbounds_input(getattr(tariff, "sui_inbounds", "") or "")
    if custom:
        return custom
    return f"по умолчанию ({SUI_DEFAULT_INBOUNDS})"


async def init_tariffs_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    async with db_connect(TARIFFS_DB) as conn:
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS tariff_overrides (
                key TEXT PRIMARY KEY,
                title TEXT,
                days INTEGER,
                traffic_gb INTEGER,
                stars_price INTEGER,
                enabled INTEGER,
                is_admin_only INTEGER,
                sort_order INTEGER,
                connection_limit INTEGER,
                stars_purchase_url TEXT,
                rub_payment_enabled INTEGER NOT NULL DEFAULT 0,
                rub_price INTEGER NOT NULL DEFAULT 0,
                stars_payment_enabled INTEGER NOT NULL DEFAULT 1,
                show_stars_official INTEGER NOT NULL DEFAULT 1,
                show_stars_alt INTEGER NOT NULL DEFAULT 1,
                sui_group TEXT NOT NULL DEFAULT 'user',
                sui_inbounds TEXT NOT NULL DEFAULT '',
                double_vpn_enabled INTEGER NOT NULL DEFAULT 1,
                double_vpn_reset_days INTEGER NOT NULL DEFAULT 0,
                remote_node_scope TEXT NOT NULL DEFAULT 'all',
                preview_extra_text TEXT NOT NULL DEFAULT '',
                buy_short_text TEXT NOT NULL DEFAULT '',
                code TEXT,
                is_custom INTEGER NOT NULL DEFAULT 0,
                updated_at REAL NOT NULL
            );
            """
        )
        async with conn.execute("PRAGMA table_info(tariff_overrides)") as cur:
            cols = {row[1] for row in await cur.fetchall()}
        if "connection_limit" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN connection_limit INTEGER")
        if "sort_order" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN sort_order INTEGER")
        await conn.execute("UPDATE tariff_overrides SET sort_order=COALESCE(sort_order, rowid)")
        await conn.execute("CREATE INDEX IF NOT EXISTS idx_tariff_overrides_sort ON tariff_overrides(sort_order, key)")
        if "code" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN code TEXT")
        if "stars_purchase_url" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN stars_purchase_url TEXT")
        if "rub_payment_enabled" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN rub_payment_enabled INTEGER NOT NULL DEFAULT 0")
        if "rub_price" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN rub_price INTEGER NOT NULL DEFAULT 0")
        if "stars_payment_enabled" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN stars_payment_enabled INTEGER NOT NULL DEFAULT 1")
        if "show_stars_official" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN show_stars_official INTEGER NOT NULL DEFAULT 1")
        if "show_stars_alt" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN show_stars_alt INTEGER NOT NULL DEFAULT 1")
        if "sui_group" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN sui_group TEXT NOT NULL DEFAULT 'user'")
        if "sui_inbounds" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN sui_inbounds TEXT NOT NULL DEFAULT ''")
        if "double_vpn_enabled" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN double_vpn_enabled INTEGER NOT NULL DEFAULT 1")
        if "double_vpn_reset_days" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN double_vpn_reset_days INTEGER NOT NULL DEFAULT 0")
        if "remote_node_scope" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN remote_node_scope TEXT NOT NULL DEFAULT 'all'")
        if "preview_extra_text" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN preview_extra_text TEXT NOT NULL DEFAULT ''")
        if "buy_short_text" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN buy_short_text TEXT NOT NULL DEFAULT ''")
        if "is_custom" not in cols:
            await conn.execute("ALTER TABLE tariff_overrides ADD COLUMN is_custom INTEGER NOT NULL DEFAULT 0")
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT * FROM tariff_overrides") as cur:
            rows = await cur.fetchall()
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS tariff_periods (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                tariff_key TEXT NOT NULL,
                period_key TEXT NOT NULL,
                title TEXT NOT NULL,
                days INTEGER NOT NULL,
                stars_price INTEGER NOT NULL DEFAULT 0,
                rub_price INTEGER NOT NULL DEFAULT 0,
                enabled INTEGER NOT NULL DEFAULT 1,
                is_default INTEGER NOT NULL DEFAULT 0,
                sort_order INTEGER,
                created_at REAL NOT NULL,
                updated_at REAL NOT NULL,
                UNIQUE(tariff_key, period_key)
            );
            CREATE INDEX IF NOT EXISTS idx_tariff_periods_tariff_sort
            ON tariff_periods(tariff_key, sort_order, period_key);
            """
        )
        async with conn.execute("PRAGMA table_info(tariff_periods)") as cur:
            period_cols = {row[1] for row in await cur.fetchall()}
        for col, ddl in {
            "stars_price": "INTEGER NOT NULL DEFAULT 0",
            "rub_price": "INTEGER NOT NULL DEFAULT 0",
            "enabled": "INTEGER NOT NULL DEFAULT 1",
            "is_default": "INTEGER NOT NULL DEFAULT 0",
            "sort_order": "INTEGER",
            "created_at": "REAL NOT NULL DEFAULT 0",
            "updated_at": "REAL NOT NULL DEFAULT 0",
        }.items():
            if col not in period_cols:
                await conn.execute(f"ALTER TABLE tariff_periods ADD COLUMN {col} {ddl}")
        async with conn.execute("SELECT * FROM tariff_periods ORDER BY tariff_key, COALESCE(sort_order, id), id") as cur:
            period_rows = await cur.fetchall()
        global TARIFF_OVERRIDES_CACHE, TARIFF_PERIODS_CACHE
        TARIFF_OVERRIDES_CACHE = {str(row["key"]): dict(row) for row in rows}
        tmp_periods: dict[str, list[dict]] = {}
        for row in period_rows:
            item = dict(row)
            tmp_periods.setdefault(str(item.get("tariff_key") or ""), []).append(item)
        TARIFF_PERIODS_CACHE = tmp_periods
        await conn.commit()


def get_tariff_override(key: str):
    return TARIFF_OVERRIDES_CACHE.get(key)


def merge_tariff(base: Tariff, override_row) -> Tariff:
    if not override_row:
        return base
    traffic = override_row["traffic_gb"]
    if traffic == -1:
        traffic = None
    elif traffic is None:
        traffic = base.traffic_gb
    return Tariff(
        key=base.key,
        title=override_row["title"] if override_row["title"] is not None else base.title,
        days=int(override_row["days"]) if override_row["days"] is not None else base.days,
        traffic_gb=traffic,
        stars_price=int(override_row["stars_price"]) if override_row["stars_price"] is not None else base.stars_price,
        code=str(override_row["code"]) if override_row.get("code") is not None else base.code,
        is_public=not (bool(int(override_row["is_admin_only"])) if override_row["is_admin_only"] is not None else base.is_admin_only),
        is_admin_only=bool(int(override_row["is_admin_only"])) if override_row["is_admin_only"] is not None else base.is_admin_only,
        connection_limit=int(override_row["connection_limit"]) if override_row.get("connection_limit") is not None else base.connection_limit,
        stars_purchase_url=normalize_stars_purchase_url(override_row.get("stars_purchase_url")) if override_row.get("stars_purchase_url") is not None else base.stars_purchase_url,
        rub_payment_enabled=bool(int(override_row.get("rub_payment_enabled"))) if override_row.get("rub_payment_enabled") is not None else base.rub_payment_enabled,
        rub_price=max(0, int(override_row.get("rub_price"))) if override_row.get("rub_price") is not None else base.rub_price,
        stars_payment_enabled=bool(int(override_row.get("stars_payment_enabled"))) if override_row.get("stars_payment_enabled") is not None else base.stars_payment_enabled,
        show_stars_official=bool(int(override_row.get("show_stars_official"))) if override_row.get("show_stars_official") is not None else base.show_stars_official,
        show_stars_alt=bool(int(override_row.get("show_stars_alt"))) if override_row.get("show_stars_alt") is not None else base.show_stars_alt,
        sui_group=normalize_sui_group_input(override_row.get("sui_group") or base.sui_group),
        sui_inbounds=normalize_sui_inbounds_input(override_row.get("sui_inbounds") or base.sui_inbounds or ""),
        double_vpn_enabled=bool(int(override_row.get("double_vpn_enabled"))) if override_row.get("double_vpn_enabled") is not None else base.double_vpn_enabled,
        double_vpn_reset_days=max(0, int(override_row.get("double_vpn_reset_days") or getattr(base, "double_vpn_reset_days", 0) or 0)),
        remote_node_scope=normalize_remote_node_scope_value(override_row.get("remote_node_scope") or getattr(base, "remote_node_scope", "all") or "all"),
        preview_extra_text=normalize_tariff_multiline_text((override_row.get("preview_extra_text") if override_row.get("preview_extra_text") is not None else getattr(base, "preview_extra_text", "")) or "", limit=1000),
        buy_short_text=normalize_tariff_short_text((override_row.get("buy_short_text") if override_row.get("buy_short_text") is not None else getattr(base, "buy_short_text", "")) or "", limit=240),
        is_custom=base.is_custom or bool(int(override_row.get("is_custom") or 0)),
    )


def tariff_enabled(key: str) -> bool:
    override_row = get_tariff_override(key)
    if override_row and override_row.get("enabled") is not None:
        return bool(int(override_row["enabled"]))
    return True


def get_tariff(key: str) -> Optional[Tariff]:
    base = get_tariff_base(key)
    if not base:
        return None
    return merge_tariff(base, get_tariff_override(key))


def tariff_sort_order(key: str) -> int:
    row = TARIFF_OVERRIDES_CACHE.get(str(key))
    if row and row.get("sort_order") is not None:
        try:
            return int(row.get("sort_order") or 0)
        except Exception:
            pass
    # Базовые тарифы без override уходят после явно упорядоченных.
    return 100000


def all_tariff_keys() -> list[str]:
    keys = list(PUBLIC_TARIFFS.keys()) + list(ADMIN_TARIFFS.keys())
    for key, row in TARIFF_OVERRIDES_CACHE.items():
        if int(row.get("is_custom") or 0) == 1 and key not in keys:
            keys.append(str(key))
    return sorted(keys, key=lambda k: (tariff_sort_order(str(k)), str(k)))


async def next_tariff_sort_order() -> int:
    async with db_connect(TARIFFS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT COALESCE(MAX(COALESCE(sort_order, rowid)), 0) AS max_order FROM tariff_overrides") as cur:
            row = await cur.fetchone()
            return int(row["max_order"] or 0) + 10


async def rewrite_tariff_sort_orders(keys: list[str]) -> None:
    now_ts = time.time()
    async with db_connect(TARIFFS_DB) as conn:
        for idx, key in enumerate(keys, start=1):
            sort_order = idx * 10
            await conn.execute(
                """
                INSERT INTO tariff_overrides(key, sort_order, updated_at)
                VALUES (?, ?, ?)
                ON CONFLICT(key) DO UPDATE SET
                    sort_order=excluded.sort_order,
                    updated_at=excluded.updated_at
                """,
                (str(key), int(sort_order), now_ts),
            )
        await conn.commit()
    for idx, key in enumerate(keys, start=1):
        current = dict(TARIFF_OVERRIDES_CACHE.get(str(key)) or {
            "key": str(key), "title": None, "days": None, "traffic_gb": None,
            "stars_price": None, "enabled": None, "is_admin_only": None,
            "connection_limit": None, "sort_order": None, "stars_purchase_url": None,
            "rub_payment_enabled": 0, "rub_price": 0, "stars_payment_enabled": 1,
            "show_stars_official": 1, "show_stars_alt": 1, "sui_group": "user", "sui_inbounds": "", "double_vpn_enabled": 1, "double_vpn_reset_days": 0, "remote_node_scope": "all", "preview_extra_text": "", "buy_short_text": "", "code": None,
            "is_custom": 0, "updated_at": now_ts,
        })
        current["sort_order"] = idx * 10
        current["updated_at"] = now_ts
        TARIFF_OVERRIDES_CACHE[str(key)] = current


async def move_tariff_order(key: str, direction: str) -> bool:
    keys = all_tariff_keys()
    raw_key = str(key)
    if raw_key not in keys:
        return False
    idx = keys.index(raw_key)
    if str(direction) == "up":
        new_idx = idx - 1
    elif str(direction) == "down":
        new_idx = idx + 1
    else:
        return False
    if new_idx < 0 or new_idx >= len(keys):
        return False
    keys[idx], keys[new_idx] = keys[new_idx], keys[idx]
    await rewrite_tariff_sort_orders(keys)
    return True


def list_tariffs(user_id: int) -> list[Tariff]:
    items = []
    for key in all_tariff_keys():
        tariff = get_tariff(key)
        if not tariff or not tariff_enabled(key):
            continue
        if tariff.is_admin_only and not is_admin(user_id):
            continue
        items.append(tariff)
    return items


def list_all_tariffs_for_admin() -> list[Tariff]:
    result = []
    for key in all_tariff_keys():
        tariff = get_tariff(key)
        if tariff:
            result.append(tariff)
    return result


async def upsert_tariff_override(key: str, **fields) -> None:
    allowed = {"title", "days", "traffic_gb", "stars_price", "rub_payment_enabled", "rub_price", "enabled", "is_admin_only", "sort_order", "connection_limit", "stars_purchase_url", "stars_payment_enabled", "show_stars_official", "show_stars_alt", "sui_group", "sui_inbounds", "double_vpn_enabled", "double_vpn_reset_days", "remote_node_scope", "preview_extra_text", "buy_short_text", "code", "is_custom"}
    patch = {k: v for k, v in fields.items() if k in allowed}
    if "stars_purchase_url" in patch:
        patch["stars_purchase_url"] = normalize_stars_purchase_url(patch.get("stars_purchase_url"))
    if "sui_group" in patch:
        patch["sui_group"] = normalize_sui_group_input(patch.get("sui_group"))
    if "sui_inbounds" in patch:
        patch["sui_inbounds"] = normalize_sui_inbounds_input(patch.get("sui_inbounds"))
    if "remote_node_scope" in patch:
        patch["remote_node_scope"] = normalize_remote_node_scope_value(patch.get("remote_node_scope"))
    if "preview_extra_text" in patch:
        patch["preview_extra_text"] = normalize_tariff_multiline_text(patch.get("preview_extra_text"), limit=1000)
    if "buy_short_text" in patch:
        patch["buy_short_text"] = normalize_tariff_short_text(patch.get("buy_short_text"), limit=240)
    if not patch:
        return
    existing = get_tariff_override(key)
    now_ts = time.time()
    if existing:
        sets = ", ".join([f"{k}=?" for k in patch.keys()]) + ", updated_at=?"
        values = list(patch.values()) + [now_ts, key]
        async with db_connect(TARIFFS_DB) as conn:
            await conn.execute(f"UPDATE tariff_overrides SET {sets} WHERE key=?", values)
            await conn.commit()
    else:
        columns = ["key"] + list(patch.keys()) + ["updated_at"]
        placeholders = ",".join(["?"] * len(columns))
        values = [key] + list(patch.values()) + [now_ts]
        async with db_connect(TARIFFS_DB) as conn:
            await conn.execute(
                f"INSERT INTO tariff_overrides ({','.join(columns)}) VALUES ({placeholders})",
                values,
            )
            await conn.commit()
    current = dict(existing) if existing else {"key": key, "title": None, "days": None, "traffic_gb": None, "stars_price": None, "enabled": None, "is_admin_only": None, "connection_limit": None, "sort_order": None, "stars_purchase_url": None, "rub_payment_enabled": 0, "rub_price": 0, "stars_payment_enabled": 1, "show_stars_official": 1, "show_stars_alt": 1, "sui_group": "user", "sui_inbounds": "", "double_vpn_enabled": 1, "double_vpn_reset_days": 0, "remote_node_scope": "all", "preview_extra_text": "", "buy_short_text": "", "code": None, "is_custom": 0, "updated_at": now_ts}
    current.update(patch)
    current["updated_at"] = now_ts
    TARIFF_OVERRIDES_CACHE[key] = current



async def upsert_tariff_period(
    *,
    tariff_key: str,
    period_key: str,
    title: str,
    days: int,
    stars_price: int = 0,
    rub_price: int = 0,
    enabled: bool = True,
    is_default: bool = False,
    sort_order: int | None = None,
) -> None:
    key = normalize_tariff_key_input(tariff_key)
    pkey = normalize_tariff_period_key(period_key)
    clean_title = str(title or "").strip()[:64] or f"{int(days)} дн."
    days = max(1, int(days))
    stars_price = max(0, int(stars_price or 0))
    rub_price = max(0, int(rub_price or 0))
    now_ts = time.time()
    if sort_order is None:
        explicit = tariff_explicit_periods(key)
        sort_order = (max([int(x.sort_order or 0) for x in explicit], default=0) + 10) or 10
    async with db_connect(TARIFFS_DB) as conn:
        if is_default:
            await conn.execute("UPDATE tariff_periods SET is_default=0 WHERE tariff_key=?", (key,))
        await conn.execute(
            """
            INSERT INTO tariff_periods(tariff_key, period_key, title, days, stars_price, rub_price, enabled, is_default, sort_order, created_at, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(tariff_key, period_key) DO UPDATE SET
                title=excluded.title,
                days=excluded.days,
                stars_price=excluded.stars_price,
                rub_price=excluded.rub_price,
                enabled=excluded.enabled,
                is_default=excluded.is_default,
                sort_order=excluded.sort_order,
                updated_at=excluded.updated_at
            """,
            (key, pkey, clean_title, days, stars_price, rub_price, 1 if enabled else 0, 1 if is_default else 0, int(sort_order or 10), now_ts, now_ts),
        )
        await conn.commit()
    await reload_tariff_periods_cache()


async def delete_tariff_period(tariff_key: str, period_key: str) -> None:
    key = normalize_tariff_key_input(tariff_key)
    pkey = normalize_tariff_period_key(period_key)
    async with db_connect(TARIFFS_DB) as conn:
        await conn.execute("DELETE FROM tariff_periods WHERE tariff_key=? AND period_key=?", (key, pkey))
        await conn.commit()
    await reload_tariff_periods_cache()


async def toggle_tariff_period(tariff_key: str, period_key: str) -> None:
    key = normalize_tariff_key_input(tariff_key)
    pkey = normalize_tariff_period_key(period_key)
    async with db_connect(TARIFFS_DB) as conn:
        await conn.execute("UPDATE tariff_periods SET enabled=CASE WHEN COALESCE(enabled,1)=1 THEN 0 ELSE 1 END, updated_at=? WHERE tariff_key=? AND period_key=?", (time.time(), key, pkey))
        await conn.commit()
    await reload_tariff_periods_cache()


async def reload_tariff_periods_cache() -> None:
    global TARIFF_PERIODS_CACHE
    async with db_connect(TARIFFS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT * FROM tariff_periods ORDER BY tariff_key, COALESCE(sort_order, id), id") as cur:
            rows = await cur.fetchall()
    tmp: dict[str, list[dict]] = {}
    for row in rows:
        item = dict(row)
        tmp.setdefault(str(item.get("tariff_key") or ""), []).append(item)
    TARIFF_PERIODS_CACHE = tmp


def parse_tariff_period_admin_line(raw: str) -> dict:
    text = str(raw or "").strip()
    if not text:
        raise ValueError("Введите срок в формате: 365d; 365 дней; 365; 2990; 10; yes")
    # Формат: key; title; days; rub; stars; enabled(optional)
    parts = [x.strip() for x in re.split(r"[;|]", text)]
    if len(parts) < 5:
        raise ValueError("Формат: ключ; название; дней; цена RUB; цена Stars; enabled(optional yes/no)")
    pkey = normalize_tariff_period_key(parts[0])
    title = parts[1][:64] or f"{int(parts[2])} дн."
    days = int(parts[2])
    if days <= 0:
        raise ValueError("Дней должно быть больше 0.")
    rub_price = int(parts[3])
    stars_price = int(parts[4])
    if rub_price < 0 or stars_price < 0:
        raise ValueError("Цены должны быть 0 или больше.")
    enabled = True
    if len(parts) >= 6 and parts[5]:
        enabled = parse_admin_bool_input(parts[5])
    return {"period_key": pkey, "title": title, "days": days, "rub_price": rub_price, "stars_price": stars_price, "enabled": enabled}

async def delete_custom_tariff(key: str) -> None:
    existing = get_tariff_override(key)
    if not existing or int(existing.get("is_custom") or 0) != 1:
        raise ValueError("Можно удалить только пользовательский тариф.")
    async with db_connect(TARIFFS_DB) as conn:
        await conn.execute("DELETE FROM tariff_periods WHERE tariff_key=?", (key,))
        await conn.execute("DELETE FROM tariff_overrides WHERE key=?", (key,))
        await conn.commit()
    TARIFF_OVERRIDES_CACHE.pop(key, None)
    TARIFF_PERIODS_CACHE.pop(str(key), None)


async def create_custom_tariff(*, key: str, title: str, days: int, traffic_gb: int | None, stars_price: int, is_admin_only: bool, connection_limit: int, stars_purchase_url: str | None = None, rub_payment_enabled: bool = False, rub_price: int = 0, stars_payment_enabled: bool = True, show_stars_official: bool = True, show_stars_alt: bool = True, sui_group: str = "user", sui_inbounds: str = "", double_vpn_enabled: bool = True, double_vpn_reset_days: int = 0, remote_node_scope: str = "all", preview_extra_text: str = "", buy_short_text: str = "", sort_order: int | None = None) -> None:
    if get_tariff_base(key) or get_tariff_override(key):
        raise ValueError("Тариф с таким ключом уже существует.")
    code = tariff_key_for_client_name(key)
    if sort_order is None:
        sort_order = await next_tariff_sort_order()
    await upsert_tariff_override(
        key,
        title=title,
        days=int(days),
        traffic_gb=-1 if traffic_gb is None else int(traffic_gb),
        stars_price=int(stars_price),
        enabled=1,
        is_admin_only=1 if is_admin_only else 0,
        connection_limit=max(1, int(connection_limit)),
        sort_order=int(sort_order),
        stars_purchase_url=normalize_stars_purchase_url(stars_purchase_url),
        rub_payment_enabled=1 if rub_payment_enabled else 0,
        rub_price=max(0, int(rub_price or 0)),
        stars_payment_enabled=1 if stars_payment_enabled else 0,
        show_stars_official=1 if show_stars_official else 0,
        show_stars_alt=1 if show_stars_alt else 0,
        sui_group=normalize_sui_group_input(sui_group),
        sui_inbounds=normalize_sui_inbounds_input(sui_inbounds),
        double_vpn_enabled=1 if double_vpn_enabled else 0,
        double_vpn_reset_days=max(0, int(double_vpn_reset_days or 0)),
        remote_node_scope=normalize_remote_node_scope_value(remote_node_scope),
        preview_extra_text=normalize_tariff_multiline_text(preview_extra_text, limit=1000),
        buy_short_text=normalize_tariff_short_text(buy_short_text, limit=240),
        code=code,
        is_custom=1,
    )

def human_traffic(traffic_gb: int | None) -> str:
    return "∞" if traffic_gb is None else f"{traffic_gb} ГБ"



def setup_logging() -> None:
    LOG_DIR.mkdir(parents=True, exist_ok=True)
    formatter = logging.Formatter("%(asctime)s | %(levelname)s | %(name)s | %(message)s")

    root = logging.getLogger()
    root.setLevel(logging.INFO)

    for handler in list(root.handlers):
        root.removeHandler(handler)

    stream_handler = logging.StreamHandler()
    stream_handler.setFormatter(formatter)

    file_handler = RotatingFileHandler(LOG_FILE, maxBytes=2_000_000, backupCount=5, encoding="utf-8")
    file_handler.setFormatter(formatter)

    root.addHandler(stream_handler)
    root.addHandler(file_handler)


def write_health_snapshot(*, status: str, extra: dict | None = None) -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    payload = {
        "status": status,
        "timestamp": datetime.now().isoformat(),
        "build": APP_BUILD,
    }
    if extra:
        payload.update(extra)
    HEALTH_FILE.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")


async def write_health_snapshot_async(*, status: str, extra: dict | None = None) -> None:
    await asyncio.to_thread(write_health_snapshot, status=status, extra=extra)


def runtime_cache_get(key: str, ttl_seconds: int) -> object | None:
    if ttl_seconds <= 0:
        return None
    item = admin_runtime_cache.get(str(key))
    if not item:
        return None
    ts, value = item
    if (time.time() - float(ts or 0)) > ttl_seconds:
        admin_runtime_cache.pop(str(key), None)
        return None
    return value


def runtime_cache_set(key: str, value: object) -> object:
    admin_runtime_cache[str(key)] = (time.time(), value)
    return value


def runtime_cache_clear(prefix: str | None = None) -> None:
    if prefix is None:
        admin_runtime_cache.clear()
        return
    raw_prefix = str(prefix)
    for key in list(admin_runtime_cache.keys()):
        if key.startswith(raw_prefix):
            admin_runtime_cache.pop(key, None)


async def health_loop() -> None:
    while True:
        try:
            await write_health_snapshot_async(status="ok")
        except Exception as exc:
            logging.exception("health_loop failed: %s", exc)
        await asyncio.sleep(30)


async def sleep_with_jitter(seconds: float, jitter_seconds: float = 5.0) -> None:
    """Small randomized delay to avoid all background workers waking at the same instant."""
    base = max(0.0, float(seconds or 0))
    jitter = max(0.0, float(jitter_seconds or 0))
    extra = (secrets.randbelow(1000) / 1000.0) * jitter if jitter > 0 else 0.0
    await asyncio.sleep(base + extra)


async def antiabuse_unique_ip_count_for_name(name: str) -> int:
    if not ANTIABUSE_ENABLED or not name:
        return 0
    sets = await antiabuse_unified_active_ip_sets_for_names([name])
    return len(sets.get(str(name).strip(), set()))


async def antiabuse_unique_ip_counts_for_names(names: list[str]) -> dict[str, int]:
    if not ANTIABUSE_ENABLED:
        return {}
    sets = await antiabuse_unified_active_ip_sets_for_names(names)
    return {str(name).strip(): len(sets.get(str(name).strip(), set())) for name in names if str(name or '').strip()}


async def antiabuse_unique_ip_sets_for_names(names: list[str]) -> dict[str, set[str]]:
    return await antiabuse_unified_active_ip_sets_for_names(names)


async def antiabuse_limit_overrides_for_names(names: list[str]) -> dict[str, int]:
    clean_names = [str(name).strip() for name in names if str(name or "").strip()]
    if not clean_names:
        return {}
    placeholders = ",".join(["?"] * len(clean_names))
    query = f"""
        SELECT name, ip_limit_override
        FROM antiabuse_cases
        WHERE name IN ({placeholders}) AND ip_limit_override IS NOT NULL
    """
    result: dict[str, int] = {}
    async with db_connect(ANTIABUSE_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(query, tuple(clean_names)) as cur:
            rows = await cur.fetchall()
    for row in rows:
        try:
            result[str(row["name"])] = max(1, int(row["ip_limit_override"]))
        except Exception:
            continue
    return result

async def get_http_session() -> aiohttp.ClientSession:
    global http_session
    if http_session is None or http_session.closed:
        timeout = aiohttp.ClientTimeout(total=30)
        connector = aiohttp.TCPConnector(ssl=False)
        headers = {"User-Agent": SUI_USER_AGENT}
        http_session = aiohttp.ClientSession(timeout=timeout, connector=connector, headers=headers)
    return http_session


async def close_http_session() -> None:
    global http_session
    if http_session is not None and not http_session.closed:
        await http_session.close()
    http_session = None


def normalize_support_waiting_for(status: str, waiting_for: str | None) -> str:
    raw_status = str(status or "")
    raw_waiting = str(waiting_for or "").strip()

    if raw_waiting in {"admin", "user", "closed"}:
        return raw_waiting
    if raw_status == "closed":
        return "closed"
    if raw_status == "answered":
        return "user"
    return "admin"


def support_waiting_label(waiting_for: str) -> str:
    normalized = normalize_support_waiting_for("", waiting_for)
    return {
        "admin": "🟢 ждёт администратора",
        "user": "🟡 ждёт пользователя",
        "closed": "⚫ закрыт",
    }.get(normalized, normalized)


def support_status_label(status: str) -> str:
    raw_status = str(status or "")
    return {
        "open": "🟢 открыт",
        "answered": "🟡 отвечён",
        "closed": "⚫ закрыт",
    }.get(raw_status, raw_status)


async def configure_database_pragmas() -> None:
    DATABASE_DB.parent.mkdir(parents=True, exist_ok=True)
    async with aiosqlite.connect(DATABASE_DB) as conn:
        await conn.execute("PRAGMA journal_mode=WAL;")
        await conn.execute("PRAGMA foreign_keys=ON;")
        await conn.commit()


async def log_runtime_audit() -> None:
    logging.info("BUILD=%s", APP_BUILD)
    logging.info("DB backend: aiosqlite")
    logging.info("HTTP session mode: shared aiohttp ClientSession")
    logging.info("sqlite3 sync connect usage in runtime path: disabled")
    logging.info("Log file: %s", LOG_FILE)
    logging.info("Health file: %s", HEALTH_FILE)


