async def init_payments_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    payments_create_sql = """
            CREATE TABLE IF NOT EXISTS payments (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                payment_uid TEXT NOT NULL UNIQUE,
                user_id INTEGER NOT NULL,
                username TEXT,
                kind TEXT NOT NULL DEFAULT 'buy',
                tarif_key TEXT NOT NULL,
                client_id INTEGER,
                period_key TEXT,
                period_title TEXT,
                period_days INTEGER,
                amount INTEGER NOT NULL,
                original_amount INTEGER,
                discount_pct INTEGER NOT NULL DEFAULT 0,
                discount_amount INTEGER NOT NULL DEFAULT 0,
                currency TEXT NOT NULL DEFAULT 'XTR',
                status TEXT NOT NULL DEFAULT 'pending',
                application_status TEXT NOT NULL DEFAULT 'not_applied',
                provider TEXT NOT NULL DEFAULT 'stars',
                provider_charge_id TEXT,
                payment_url TEXT,
                provider_status TEXT,
                provider_payload TEXT,
                provider_last_check_at REAL,
                provider_confirmed_at REAL,
                provider_callback_at REAL,
                created_at REAL NOT NULL,
                paid_at REAL,
                apply_started_at REAL,
                applied_at REAL,
                notified_at REAL,
                failed_at REAL,
                result_payload TEXT,
                notes TEXT
            )
    """
    payment_events_create_sql = """
            CREATE TABLE IF NOT EXISTS payment_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                payment_id INTEGER NOT NULL,
                event_type TEXT NOT NULL,
                actor_type TEXT NOT NULL DEFAULT 'system',
                actor_id INTEGER,
                payment_method TEXT,
                details_json TEXT,
                created_at REAL NOT NULL,
                FOREIGN KEY(payment_id) REFERENCES payments(id)
            )
    """
    payment_columns = {
        "kind": "TEXT NOT NULL DEFAULT 'buy'",
        "client_id": "INTEGER",
        "period_key": "TEXT",
        "period_title": "TEXT",
        "period_days": "INTEGER",
        "amount": "INTEGER NOT NULL DEFAULT 0",
        "original_amount": "INTEGER",
        "discount_pct": "INTEGER NOT NULL DEFAULT 0",
        "discount_amount": "INTEGER NOT NULL DEFAULT 0",
        "currency": "TEXT NOT NULL DEFAULT 'XTR'",
        "status": "TEXT NOT NULL DEFAULT 'pending'",
        "application_status": "TEXT NOT NULL DEFAULT 'not_applied'",
        "provider": "TEXT NOT NULL DEFAULT 'stars'",
        "provider_charge_id": "TEXT",
        "payment_url": "TEXT",
        "provider_status": "TEXT",
        "provider_payload": "TEXT",
        "provider_last_check_at": "REAL",
        "provider_confirmed_at": "REAL",
        "provider_callback_at": "REAL",
        "paid_at": "REAL",
        "apply_started_at": "REAL",
        "applied_at": "REAL",
        "notified_at": "REAL",
        "failed_at": "REAL",
        "result_payload": "TEXT",
        "notes": "TEXT",
    }
    base_columns = {"id", "payment_uid", "user_id", "username", "tarif_key", "created_at"}
    required_columns = base_columns | set(payment_columns.keys())
    ordered_columns = [
        "id", "payment_uid", "user_id", "username", "kind", "tarif_key", "client_id", "period_key", "period_title", "period_days", "amount",
        "original_amount", "discount_pct", "discount_amount", "currency", "status", "application_status",
        "provider", "provider_charge_id", "payment_url", "provider_status", "provider_payload",
        "provider_last_check_at", "provider_confirmed_at", "provider_callback_at", "created_at", "paid_at",
        "apply_started_at", "applied_at", "notified_at", "failed_at", "result_payload", "notes",
    ]

    async def read_payment_columns(conn) -> set[str]:
        async with conn.execute("PRAGMA table_info(payments)") as cur:
            return {row[1] for row in await cur.fetchall()}

    async with db_connect(PAYMENTS_DB) as conn:
        await conn.execute(payments_create_sql)
        await conn.execute(payment_events_create_sql)
        await conn.commit()

        cols = await read_payment_columns(conn)
        for col, ddl in payment_columns.items():
            if col not in cols:
                await conn.execute(f"ALTER TABLE payments ADD COLUMN {col} {ddl}")
        await conn.commit()

        cols_after = await read_payment_columns(conn)
        missing_after = required_columns - cols_after
        if missing_after:
            logging.warning("payments schema incomplete after migration, rebuilding; missing=%s", sorted(missing_after))
            legacy_table = f"payments_legacy_schema_{int(time.time())}"
            await conn.execute(f"ALTER TABLE payments RENAME TO {legacy_table}")
            await conn.execute(payments_create_sql)
            legacy_cols = cols_after
            copy_cols = [col for col in ordered_columns if col in legacy_cols]
            if copy_cols:
                cols_sql = ", ".join(copy_cols)
                await conn.execute(f"INSERT INTO payments ({cols_sql}) SELECT {cols_sql} FROM {legacy_table}")
            await conn.execute(f"DROP TABLE {legacy_table}")
            await conn.commit()
            cols_after = await read_payment_columns(conn)
            missing_after = required_columns - cols_after
            if missing_after:
                raise RuntimeError(f"payments schema migration failed, missing columns: {sorted(missing_after)}")

        await conn.executescript(
            """
            CREATE INDEX IF NOT EXISTS idx_payments_user_created
            ON payments(user_id, created_at DESC);

            CREATE INDEX IF NOT EXISTS idx_payments_status_created
            ON payments(status, created_at DESC);

            CREATE UNIQUE INDEX IF NOT EXISTS idx_payments_provider_charge_unique
            ON payments(provider_charge_id)
            WHERE provider_charge_id IS NOT NULL
              AND provider_charge_id != ''
              AND provider_charge_id NOT LIKE 'admin_manual:%';

            CREATE INDEX IF NOT EXISTS idx_payment_events_payment_created
            ON payment_events(payment_id, created_at ASC);

            CREATE INDEX IF NOT EXISTS idx_payment_events_type_created
            ON payment_events(event_type, created_at DESC);

            CREATE INDEX IF NOT EXISTS idx_payments_provider_status_check
            ON payments(provider, status, provider_last_check_at);

            CREATE INDEX IF NOT EXISTS idx_payments_provider_created
            ON payments(provider, created_at DESC);

            CREATE INDEX IF NOT EXISTS idx_payments_application_status
            ON payments(application_status, apply_started_at);

            CREATE INDEX IF NOT EXISTS idx_payments_currency_paid
            ON payments(currency, paid_at DESC);

            CREATE INDEX IF NOT EXISTS idx_payments_discount_created
            ON payments(discount_pct, created_at DESC);
            """
        )
        await conn.commit()

def new_payment_uid() -> str:
    return uuid.uuid4().hex[:16]


async def create_payment(
    *,
    user_id: int,
    username: str | None,
    tarif_key: str,
    amount: int,
    kind: str = "buy",
    client_id: int | None = None,
    period_key: str | None = None,
    period_title: str | None = None,
    period_days: int | None = None,
    notes: str = "",
    provider: str = "stars",
    currency: str = "XTR",
    original_amount: int | None = None,
    discount_pct: int = 0,
    discount_amount: int = 0,
) -> int:
    now_ts = time.time()
    payment_uid = new_payment_uid()
    provider = str(provider or "stars").strip().lower()
    currency = str(currency or ("RUB" if provider == "platega" else "XTR")).strip().upper()
    final_amount = int(amount)
    orig_amount = int(original_amount if original_amount is not None else final_amount)
    discount_pct = normalize_referral_discount_bp(discount_pct)
    discount_amount = max(0, int(discount_amount or 0))
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        cur = await conn.execute(
            """
            INSERT INTO payments (
                payment_uid, user_id, username, kind, tarif_key, client_id, period_key, period_title, period_days, amount,
                currency, status, provider, created_at, notes, original_amount, discount_pct, discount_amount
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 'pending', ?, ?, ?, ?, ?, ?)
            """,
            (
                payment_uid,
                int(user_id),
                username or "",
                kind,
                tarif_key,
                client_id,
                str(period_key or ""),
                str(period_title or ""),
                int(period_days or 0) if period_days else None,
                final_amount,
                currency,
                provider,
                now_ts,
                notes,
                orig_amount,
                discount_pct,
                discount_amount,
            ),
        )
        await conn.commit()
        payment_id = int(cur.lastrowid)
    await log_payment_event(
        payment_id,
        "created",
        actor_type="user",
        actor_id=int(user_id),
        payment_method=provider,
        details={"kind": kind, "tarif_key": tarif_key, "period_key": str(period_key or ""), "period_title": str(period_title or ""), "period_days": int(period_days or 0) if period_days else 0, "amount": final_amount, "currency": currency, "original_amount": orig_amount, "discount_pct": discount_pct, "discount_amount": discount_amount, "notes": notes},
    )
    return payment_id


async def log_payment_event(
    payment_id: int,
    event_type: str,
    *,
    actor_type: str = "system",
    actor_id: int | None = None,
    payment_method: str | None = None,
    details: dict | None = None,
) -> None:
    """Append-only event log for future payment methods: stars, crypto, bank cards, SBP, manual."""
    try:
        details_json = json.dumps(details or {}, ensure_ascii=False, separators=(",", ":"))
    except Exception:
        details_json = "{}"
    async with db_connect(PAYMENTS_DB) as conn:
        await conn.execute(
            """
            INSERT INTO payment_events (
                payment_id, event_type, actor_type, actor_id, payment_method, details_json, created_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (
                int(payment_id),
                str(event_type),
                str(actor_type or "system"),
                int(actor_id) if actor_id is not None else None,
                str(payment_method) if payment_method else None,
                details_json,
                time.time(),
            ),
        )
        await conn.commit()


async def list_payment_events(payment_id: int, limit: int = 30):
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT *
            FROM payment_events
            WHERE payment_id=?
            ORDER BY id DESC
            LIMIT ?
            """,
            (int(payment_id), int(limit)),
        ) as cur:
            return await cur.fetchall()


async def cleanup_payment_events_for_autonomy() -> dict:
    """Keep useful audit trail but remove noisy old status-check events."""
    now_ts = time.time()
    status_cutoff = now_ts - AUTONOMY_PAYMENT_STATUS_EVENT_RETENTION_DAYS * 86400
    watchdog_cutoff = now_ts - AUTONOMY_WATCHDOG_EVENT_RETENTION_DAYS * 86400
    noisy_status_events = (
        "provider_status",
        "provider_security_status",
        "provider_status_error",
        "provider_security_status_error",
    )
    async with db_connect(PAYMENTS_DB) as conn:
        placeholders = ",".join(["?"] * len(noisy_status_events))
        cur1 = await conn.execute(
            f"DELETE FROM payment_events WHERE event_type IN ({placeholders}) AND created_at < ?",
            (*noisy_status_events, float(status_cutoff)),
        )
        cur2 = await conn.execute(
            "DELETE FROM payment_events WHERE event_type LIKE 'watchdog_%' AND created_at < ?",
            (float(watchdog_cutoff),),
        )
        await conn.commit()
        return {
            "status_events_deleted": int(cur1.rowcount or 0),
            "watchdog_events_deleted": int(cur2.rowcount or 0),
        }


def payment_event_details_short(raw: str | None, max_len: int = 180) -> str:
    if not raw:
        return "—"
    try:
        data = json.loads(str(raw))
        if isinstance(data, dict):
            safe = {}
            for key in (
                "source", "status", "provider_status", "transaction_id", "charge_id",
                "provider_charge_id", "note", "kind", "tarif_key", "amount",
                "currency", "error", "result", "payment_url", "callback_status",
            ):
                if key in data and data[key] not in (None, ""):
                    value = data[key]
                    if key in {"payment_url"}:
                        value = "есть"
                    safe[key] = value
            text = json.dumps(safe or data, ensure_ascii=False, separators=(",", ":"))
        else:
            text = str(data)
    except Exception:
        text = str(raw)
    text = text.replace("\n", " ").strip()
    if len(text) > max_len:
        return text[:max_len - 1] + "…"
    return text or "—"


