async def update_payment_provider_data(
    payment_id: int,
    *,
    provider_charge_id: str | None = None,
    payment_url: str | None = None,
    provider_status: str | None = None,
    provider_payload: dict | str | None = None,
    provider_confirmed: bool = False,
) -> None:
    now_ts = time.time()
    payload_raw = None
    if provider_payload is not None:
        if isinstance(provider_payload, str):
            payload_raw = provider_payload
        else:
            try:
                payload_raw = json.dumps(provider_payload, ensure_ascii=False, separators=(",", ":"))
            except Exception:
                payload_raw = "{}"
    async with db_connect(PAYMENTS_DB) as conn:
        await conn.execute(
            """
            UPDATE payments
            SET provider_charge_id=COALESCE(NULLIF(?, ''), provider_charge_id),
                payment_url=COALESCE(NULLIF(?, ''), payment_url),
                provider_status=COALESCE(NULLIF(?, ''), provider_status),
                provider_payload=COALESCE(?, provider_payload),
                provider_last_check_at=?,
                provider_confirmed_at=CASE WHEN ? THEN COALESCE(provider_confirmed_at, ?) ELSE provider_confirmed_at END
            WHERE id=?
            """,
            (
                str(provider_charge_id or ""),
                str(payment_url or ""),
                str(provider_status or ""),
                payload_raw,
                now_ts,
                1 if provider_confirmed else 0,
                now_ts,
                int(payment_id),
            ),
        )
        await conn.commit()


async def mark_payment_provider_failed(payment_id: int, provider_status: str = "", note: str = "") -> None:
    now_ts = time.time()
    suffix = f" provider_failed:{provider_status}"
    if note:
        suffix += f" {note.strip()}"
    async with db_connect(PAYMENTS_DB) as conn:
        await conn.execute(
            """
            UPDATE payments
            SET status='failed',
                failed_at=COALESCE(failed_at, ?),
                provider_status=COALESCE(NULLIF(?, ''), provider_status),
                notes=TRIM(COALESCE(notes,'') || ?)
            WHERE id=? AND status='pending'
            """,
            (now_ts, str(provider_status or ""), suffix, int(payment_id)),
        )
        await conn.commit()
