    cutoff_created = time.time() - max(1, int(days)) * 86400
    cutoff_check = time.time() - max(3600, int(stale_seconds))
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT *
            FROM payments
            WHERE provider='platega'
              AND status='success'
              AND COALESCE(provider_charge_id, '') != ''
              AND provider_charge_id NOT LIKE 'admin_manual:%'
              AND created_at >= ?
              AND COALESCE(provider_last_check_at, 0) < ?
            ORDER BY COALESCE(provider_last_check_at, 0) ASC, id ASC
            LIMIT ?
            """,
            (float(cutoff_created), float(cutoff_check), int(limit)),
        ) as cur:
            return await cur.fetchall()


