async def cancel_expired_pending_payments(user_id: int | None = None) -> int:
    """Mark old unpaid invoices as failed so they do not block new purchases forever."""
    ttl_hours = max(1, int(PENDING_PAYMENT_TTL_HOURS or 24))
    cutoff_ts = time.time() - ttl_hours * 3600
    suffix = f" auto_cancel_pending_older_than_{ttl_hours}h"
    async with db_connect(PAYMENTS_DB) as conn:
        if user_id is None:
            cur = await conn.execute(
                """
                UPDATE payments
                SET status='failed',
                    failed_at=COALESCE(failed_at, ?),
                    notes=TRIM(COALESCE(notes,'') || ?)
                WHERE status='pending' AND created_at < ?
                """,
                (time.time(), suffix, cutoff_ts),
            )
        else:
            cur = await conn.execute(
                """
                UPDATE payments
                SET status='failed',
                    failed_at=COALESCE(failed_at, ?),
                    notes=TRIM(COALESCE(notes,'') || ?)
                WHERE status='pending' AND created_at < ? AND user_id=?
                """,
                (time.time(), suffix, cutoff_ts, int(user_id)),
            )
        await conn.commit()
        return int(cur.rowcount or 0)


