def payment_result_payload_dumps(payload: dict | None) -> str | None:
    if not payload:
        return None
    try:
        return json.dumps(payload, ensure_ascii=False, separators=(",", ":"))
    except Exception:
        return None


def payment_result_payload_loads(raw: str | None) -> dict:
    if not raw:
        return {}
    try:
        data = json.loads(raw)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}


def payment_success_text_from_payload(kind: str, tariff: Tariff, payload: dict) -> str:
    raw_kind = str(kind or payload.get("kind") or "buy")
    period = TariffPeriod(
        tariff_key=tariff.key,
        period_key=str(payload.get("period_key") or "base"),
        title=str(payload.get("period_title") or "") or (f"{int(payload.get('period_days') or tariff.days)} дн."),
        days=max(1, int(payload.get("period_days") or tariff.days)),
        stars_price=max(0, int(tariff.stars_price or 0)),
        rub_price=max(0, int(tariff.rub_price or 0)),
        enabled=True,
        is_default=str(payload.get("period_key") or "base") == "base",
        is_base=str(payload.get("period_key") or "base") == "base",
    )
    if raw_kind == "buy":
        return created_key_text(
            tariff,
            str(payload.get("sub_link") or "—"),
            str(payload.get("clash_link") or "—"),
            period,
        )
    item = {
        "name": str(payload.get("name") or payload.get("client_name") or "unknown"),
        "sub_link": str(payload.get("sub_link") or "—"),
        "clash_link": str(payload.get("clash_link") or "—"),
        "tariff_title": str(payload.get("tariff_title") or getattr(tariff, "title", "") or ""),
        "period_title": tariff_period_label(period),
    }
    return renew_success_text(item, tariff)


async def mark_payment_processing(payment_id: int, provider_charge_id: str = "", payment_method: str = "stars") -> bool:
    now_ts = time.time()
    note = " payment_processing"
    try:
        async with db_connect(PAYMENTS_DB) as conn:
            cur = await conn.execute(
                """
                UPDATE payments
                SET status='processing',
                    paid_at=COALESCE(paid_at, ?),
                    apply_started_at=COALESCE(apply_started_at, ?),
                    provider_charge_id=COALESCE(NULLIF(?, ''), provider_charge_id),
                    notes=TRIM(COALESCE(notes,'') || ?)
                WHERE id=? AND status='pending'
                """,
                (now_ts, now_ts, provider_charge_id, note, int(payment_id)),
            )
            await conn.commit()
            changed = int(cur.rowcount or 0) > 0
    except sqlite3.IntegrityError:
        logging.warning("Duplicate provider_charge_id ignored while claiming payment id=%s charge_id=%s", payment_id, provider_charge_id)
        changed = False
    if changed:
        await log_payment_event(
            payment_id,
            "processing",
            payment_method=payment_method,
            details={"provider_charge_id": provider_charge_id},
        )
    return changed




