def payment_amount_text(amount: int, currency: str = "XTR") -> str:
    cur = str(currency or "XTR").upper()
    if cur == "RUB":
        return f"{int(amount)} ₽"
    return f"{int(amount)} ⭐"


def payment_amount_text_from_row(row) -> str:
    try:
        return payment_amount_text(int(row["amount"] or 0), str(row["currency"] or "XTR"))
    except Exception:
        return payment_amount_text(int(row["amount"] or 0), "XTR")


def payment_discount_text_from_row(row) -> str:
    try:
        bp = normalize_referral_discount_bp(row["discount_pct"] if "discount_pct" in row.keys() else 0)
        original = int(row["original_amount"] or 0) if "original_amount" in row.keys() else 0
        amount = int(row["amount"] or 0)
        currency = str(row["currency"] or "XTR") if "currency" in row.keys() else "XTR"
    except Exception:
        return ""
    if bp <= 0 or original <= 0 or original <= amount:
        return ""
    return f"Скидка: {format_referral_discount_bp(bp)} · было {payment_amount_text(original, currency)}"


def payment_dt_text(value) -> str:
    try:
        ts = float(value or 0)
    except Exception:
        ts = 0
    return "—" if ts <= 0 else datetime.fromtimestamp(ts).strftime("%d.%m.%Y %H:%M")


