def get_app_setting_bool(key: str, default: bool = True) -> bool:
    raw = APP_SETTINGS_CACHE.get(str(key))
    if raw is None:
        return bool(default)
    return str(raw).strip().lower() in {"1", "true", "yes", "on", "вкл", "да"}


async def set_app_setting(key: str, value: str) -> None:
    raw_key = str(key)
    raw_value = str(value)
    now_ts = time.time()
    async with db_connect(SETTINGS_DB) as conn:
        await conn.execute(
            """
            INSERT INTO app_settings(key, value, updated_at)
            VALUES (?, ?, ?)
            ON CONFLICT(key) DO UPDATE SET
                value=excluded.value,
                updated_at=excluded.updated_at
            """,
            (raw_key, raw_value, now_ts),
        )
        await conn.commit()
    APP_SETTINGS_CACHE[raw_key] = raw_value


def referral_program_enabled() -> bool:
    return get_app_setting_bool("referral_program_enabled", True)


async def set_referral_program_enabled(enabled: bool) -> None:
    await set_app_setting("referral_program_enabled", "1" if enabled else "0")


def normalize_referral_discount_bp(value) -> int:
    """Normalize legacy integer percent values and new basis-point values."""
    try:
        raw = int(value or 0)
    except Exception:
        raw = 0
    if raw <= 0:
        return 0
    # Compatibility with 39.2.0 test data where discount_pct stored integer percent.
    if raw <= 100:
        raw *= 100
    return max(0, min(REFERRAL_MAX_DISCOUNT_BP, raw))


def format_referral_discount_bp(bp: int) -> str:
    value = max(0, int(bp or 0))
    whole = value // 100
    frac = value % 100
    if frac == 0:
        return f"{whole}%"
    if frac % 10 == 0:
        return f"{whole}.{frac // 10}%"
    return f"{whole}.{frac:02d}%"


def referral_discount_bp_for_qualified_count(qualified_total: int) -> int:
    count = max(0, int(qualified_total or 0))
    if count <= 0 or not referral_program_enabled():
        return 0
    value = REFERRAL_FIRST_FRIEND_DISCOUNT_BP + max(0, count - 1) * REFERRAL_NEXT_FRIEND_DISCOUNT_BP
    return max(0, min(REFERRAL_MAX_DISCOUNT_BP, value))


def referral_discount_cap_text() -> str:
    return (
        f"{format_referral_discount_bp(REFERRAL_FIRST_FRIEND_DISCOUNT_BP)} за первого оплатившего друга, "
        f"+{format_referral_discount_bp(REFERRAL_NEXT_FRIEND_DISCOUNT_BP)} за каждого следующего, "
        f"максимум {format_referral_discount_bp(REFERRAL_MAX_DISCOUNT_BP)}"
    )


def apply_referral_discount_amount(original_amount: int, discount_pct: int) -> tuple[int, int]:
    original = max(0, int(original_amount or 0))
    bp = normalize_referral_discount_bp(discount_pct)
    if original <= 1 or bp <= 0:
        return original, 0

    # Prices are integer units: Telegram Stars and whole RUB amounts.
    # Use ceiling for the discount amount so a real referral discount is visible
    # even on small test prices, while never reducing the payable amount below 1.
    discount_amount = max(1, (original * bp + 9999) // 10000)
    discount_amount = min(discount_amount, original - 1)
    final = original - discount_amount
    return final, discount_amount


def price_line_with_discount(label: str, original_amount: int, currency: str, discount_pct: int) -> str:
    bp = normalize_referral_discount_bp(discount_pct)
    final, saved = apply_referral_discount_amount(original_amount, bp)
    if bp > 0 and saved > 0:
        return f"{label}: {payment_amount_text(original_amount, currency)} → {payment_amount_text(final, currency)} (скидка {format_referral_discount_bp(bp)})"
    return f"{label}: {payment_amount_text(original_amount, currency)}"

def price_bullet_with_discount(label: str, original_amount: int, currency: str, discount_pct: int) -> str:
    bp = normalize_referral_discount_bp(discount_pct)
    final, saved = apply_referral_discount_amount(original_amount, bp)
    if bp > 0 and saved > 0:
        return f"• {label} — {payment_amount_text(original_amount, currency)} → {payment_amount_text(final, currency)} (скидка {format_referral_discount_bp(bp)})"
    return f"• {label} — {payment_amount_text(original_amount, currency)}"


