async def referral_register_from_payload(user_id: int, username: str | None, payload: str | None) -> tuple[bool, str]:
    if not referral_program_enabled():
        return False, "disabled"
    raw = str(payload or "").strip()
    if not raw.startswith("ref_"):
        return False, "no_ref"
    ref_raw = raw[4:].strip()
    if not ref_raw.isdigit():
        return False, "bad_ref"
    referrer_id = int(ref_raw)
    referred_id = int(user_id)
    if referrer_id <= 0 or referrer_id == referred_id:
        return False, "self_ref"
    now_ts = time.time()
    async with db_connect(REFERRALS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT 1 FROM referrals WHERE referred_user_id=? LIMIT 1", (referred_id,)) as cur:
            existing = await cur.fetchone()
        if existing:
            return False, "already_bound"
        await conn.execute(
            """
            INSERT INTO referrals (referrer_user_id, referred_user_id, referred_username, source_payload, status, created_at)
            VALUES (?, ?, ?, ?, 'registered', ?)
            """,
            (referrer_id, referred_id, username or "", raw, now_ts),
        )
        await conn.commit()
    return True, "registered"


async def referral_stats_for_user(user_id: int) -> dict:
    uid = int(user_id)
    async with db_connect(REFERRALS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT
                COUNT(*) AS invited_total,
                SUM(CASE WHEN status='qualified' THEN 1 ELSE 0 END) AS qualified_total
            FROM referrals
            WHERE referrer_user_id=?
            """,
            (uid,),
        ) as cur:
            row = await cur.fetchone()
        async with conn.execute(
            "SELECT referrer_user_id, status, created_at, qualified_at FROM referrals WHERE referred_user_id=? LIMIT 1",
            (uid,),
        ) as cur:
            invited_by = await cur.fetchone()
    invited_total = int(row["invited_total"] or 0) if row else 0
    qualified_total = int(row["qualified_total"] or 0) if row else 0
    discount_pct = referral_discount_bp_for_qualified_count(qualified_total)
    return {
        "enabled": referral_program_enabled(),
        "invited_total": invited_total,
        "qualified_total": qualified_total,
        "discount_pct": discount_pct,
        "invited_by": dict(invited_by) if invited_by else None,
    }


async def referral_discount_pct_for_user(user_id: int) -> int:
    stats = await referral_stats_for_user(int(user_id))
    return int(stats.get("discount_pct") or 0)


async def referral_maybe_qualify_after_payment(bot: Bot, referred_user_id: int, payment_id: int) -> None:
    if not referral_program_enabled():
        return
    uid = int(referred_user_id)
    async with db_connect(REFERRALS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            "SELECT * FROM referrals WHERE referred_user_id=? AND status='registered' LIMIT 1",
            (uid,),
        ) as cur:
            row = await cur.fetchone()
        if not row:
            return
        now_ts = time.time()
        await conn.execute(
            """
            UPDATE referrals
            SET status='qualified', qualified_at=?, qualifying_payment_id=?, notes=TRIM(COALESCE(notes,'') || ' qualified_by_payment')
            WHERE id=? AND status='registered'
            """,
            (now_ts, int(payment_id), int(row["id"])),
        )
        await conn.commit()
    referrer_id = int(row["referrer_user_id"] or 0)
    if referrer_id <= 0:
        return
    stats = await referral_stats_for_user(referrer_id)
    try:
        await send_message_limited(
            bot,
            referrer_id,
            "🎉 Ваш друг оплатил подписку.\n\n"
            f"Ваша постоянная скидка теперь: {format_referral_discount_bp(int(stats['discount_pct'] or 0))}.\n"
            f"Условия: {referral_discount_cap_text()}."
        )
    except Exception as exc:
        logging.warning("referral notify failed referrer=%s payment=%s: %s", referrer_id, payment_id, exc)


