async def init_user_blocks_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    async with db_connect(USER_BLOCKS_DB) as conn:
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS bot_user_blocks (
                user_id INTEGER PRIMARY KEY,
                username TEXT,
                reason TEXT,
                is_active INTEGER NOT NULL DEFAULT 1,
                blocked_by INTEGER,
                blocked_at REAL,
                unblocked_by INTEGER,
                unblocked_at REAL,
                updated_at REAL NOT NULL
            );

            CREATE TABLE IF NOT EXISTS bot_user_block_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                user_id INTEGER NOT NULL,
                event_type TEXT NOT NULL,
                actor_id INTEGER,
                reason TEXT,
                created_at REAL NOT NULL
            );

            CREATE INDEX IF NOT EXISTS idx_bot_user_blocks_active
            ON bot_user_blocks(is_active, updated_at DESC);

            CREATE INDEX IF NOT EXISTS idx_bot_user_blocks_user_active
            ON bot_user_blocks(user_id, is_active);

            CREATE INDEX IF NOT EXISTS idx_bot_user_block_events_user_created
            ON bot_user_block_events(user_id, created_at DESC);
            """
        )
        await conn.commit()


def invalidate_user_block_cache(user_id: int | None = None) -> None:
    if user_id is None:
        user_block_cache.clear()
        return
    user_block_cache.pop(int(user_id), None)


async def get_user_block(user_id: int):
    async with db_connect(USER_BLOCKS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT * FROM bot_user_blocks WHERE user_id=? LIMIT 1", (int(user_id),)) as cur:
            return await cur.fetchone()


async def is_user_blocked(user_id: int) -> bool:
    uid = int(user_id)
    if is_admin(uid):
        return False
    now_ts = time.time()
    cached = user_block_cache.get(uid)
    if cached and (now_ts - float(cached[0])) < USER_BLOCK_CACHE_SECONDS:
        return bool(cached[1])
    row = await get_user_block(uid)
    blocked = bool(row and int(row["is_active"] or 0) == 1)
    user_block_cache[uid] = (now_ts, blocked)
    return blocked


async def list_blocked_users(limit: int = 50):
    async with db_connect(USER_BLOCKS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT *
            FROM bot_user_blocks
            WHERE is_active=1
            ORDER BY updated_at DESC
            LIMIT ?
            """,
            (int(limit),),
        ) as cur:
            return await cur.fetchall()


async def add_user_block_event(user_id: int, event_type: str, actor_id: int | None = None, reason: str = "") -> None:
    async with db_connect(USER_BLOCKS_DB) as conn:
        await conn.execute(
            """
            INSERT INTO bot_user_block_events(user_id, event_type, actor_id, reason, created_at)
            VALUES (?, ?, ?, ?, ?)
            """,
            (int(user_id), str(event_type), int(actor_id) if actor_id is not None else None, str(reason or ""), time.time()),
        )
        await conn.commit()


async def block_bot_user(user_id: int, username: str | None, admin_id: int, reason: str = "") -> None:
    uid = int(user_id)
    if is_admin(uid):
        raise ValueError("Админа нельзя заблокировать через этот раздел.")
    reason = str(reason or "").strip()[:1000]
    username = str(username or "").strip().lstrip("@")[:64]
    now_ts = time.time()
    async with db_connect(USER_BLOCKS_DB) as conn:
        await conn.execute(
            """
            INSERT INTO bot_user_blocks(user_id, username, reason, is_active, blocked_by, blocked_at, unblocked_by, unblocked_at, updated_at)
            VALUES (?, ?, ?, 1, ?, ?, NULL, NULL, ?)
            ON CONFLICT(user_id) DO UPDATE SET
                username=excluded.username,
                reason=excluded.reason,
                is_active=1,
                blocked_by=excluded.blocked_by,
                blocked_at=excluded.blocked_at,
                unblocked_by=NULL,
                unblocked_at=NULL,
                updated_at=excluded.updated_at
            """,
            (uid, username, reason, int(admin_id), now_ts, now_ts),
        )
        await conn.commit()
    invalidate_user_block_cache(uid)
    await add_user_block_event(uid, "blocked", actor_id=int(admin_id), reason=reason)


async def unblock_bot_user(user_id: int, admin_id: int, reason: str = "admin unblock") -> None:
    uid = int(user_id)
    now_ts = time.time()
    async with db_connect(USER_BLOCKS_DB) as conn:
        await conn.execute(
            """
            UPDATE bot_user_blocks
            SET is_active=0,
                unblocked_by=?,
                unblocked_at=?,
                updated_at=?
            WHERE user_id=?
            """,
            (int(admin_id), now_ts, now_ts, uid),
        )
        await conn.commit()
    invalidate_user_block_cache(uid)
    await add_user_block_event(uid, "unblocked", actor_id=int(admin_id), reason=reason)


def user_blocked_text() -> str:
    return "⛔ Доступ к боту ограничен."


class UserBlockMiddleware:
    async def __call__(self, handler, event, data):
        user = getattr(event, "from_user", None)
        if user is None:
            return await handler(event, data)
        try:
            uid = int(user.id)
        except Exception:
            return await handler(event, data)
        if not await is_user_blocked(uid):
            return await handler(event, data)

        if isinstance(event, types.CallbackQuery):
            with contextlib.suppress(Exception):
                await event.answer(user_blocked_text(), show_alert=True)
            return None

        if isinstance(event, types.Message):
            with contextlib.suppress(Exception):
                await event.answer(user_blocked_text())
            return None

        return None


