def get_app_setting_int(key: str, default: int, *, min_value: int = 0, max_value: int = 100000) -> int:
    raw = APP_SETTINGS_CACHE.get(str(key))
    try:
        value = int(str(raw if raw is not None else default).strip())
    except Exception:
        value = int(default)
    return max(int(min_value), min(int(max_value), value))


