async def init_trials_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    async with db_connect(TRIALS_DB) as conn:
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS trials (
                user_id INTEGER PRIMARY KEY,
                username TEXT,
                client_name TEXT,
                granted_at REAL NOT NULL,
                last_trial_at REAL,
                notes TEXT
            );
            """
        )
        async with conn.execute("PRAGMA table_info(trials)") as cur:
            cols = {row[1] for row in await cur.fetchall()}
        if "last_trial_at" not in cols:
            await conn.execute("ALTER TABLE trials ADD COLUMN last_trial_at REAL")
        if "sui_deleted_at" not in cols:
            await conn.execute("ALTER TABLE trials ADD COLUMN sui_deleted_at REAL")
        if "sui_deleted_client_id" not in cols:
            await conn.execute("ALTER TABLE trials ADD COLUMN sui_deleted_client_id INTEGER")
        if "sui_delete_note" not in cols:
            await conn.execute("ALTER TABLE trials ADD COLUMN sui_delete_note TEXT")
        await conn.execute("UPDATE trials SET last_trial_at=COALESCE(last_trial_at, granted_at)")
        await conn.commit()




async def init_tgproxy_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    async with db_connect(TGPROXY_DB) as conn:
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS telegram_proxies (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                title TEXT NOT NULL,
                url TEXT NOT NULL,
                enabled INTEGER NOT NULL DEFAULT 1,
                sort_order INTEGER NOT NULL DEFAULT 0,
                created_at REAL NOT NULL,
                updated_at REAL NOT NULL
            );

            CREATE INDEX IF NOT EXISTS idx_telegram_proxies_sort
            ON telegram_proxies(sort_order, id);
            """
        )
        async with conn.execute("PRAGMA table_info(telegram_proxies)") as cur:
            cols = {row[1] for row in await cur.fetchall()}
        for col, ddl in {
            "managed_by": "TEXT",
            "node_id": "TEXT",
            "node_code": "TEXT",
            "domain": "TEXT",
            "port": "INTEGER",
            "secret_hash": "TEXT",
            "installed_at": "REAL",
            "last_check_at": "REAL",
            "last_error": "TEXT",
            "mtg_version": "TEXT",
        }.items():
            if col not in cols:
                await conn.execute(f"ALTER TABLE telegram_proxies ADD COLUMN {col} {ddl}")
        await conn.execute(
            """
            CREATE UNIQUE INDEX IF NOT EXISTS idx_telegram_proxies_managed_node
            ON telegram_proxies(managed_by, node_id)
            WHERE managed_by IS NOT NULL AND node_id IS NOT NULL
            """
        )
        await conn.commit()


def normalize_tgproxy_url(value: str | None) -> str | None:
    raw = str(value or "").strip()
    return raw if raw.startswith("tg://") else None


async def list_telegram_proxies(include_disabled: bool = False):
    async with db_connect(TGPROXY_DB) as conn:
        conn.row_factory = aiosqlite.Row
        query = "SELECT * FROM telegram_proxies"
        params = []
        if not include_disabled:
            query += " WHERE enabled=1"
        query += " ORDER BY sort_order ASC, id ASC"
        async with conn.execute(query, tuple(params)) as cur:
            return await cur.fetchall()


