async def get_managed_telegram_proxy_by_node(node_id: str, *, include_disabled: bool = True):
    nid = str(node_id or "").strip()
    if not nid:
        return None
    async with db_connect(TGPROXY_DB) as conn:
        conn.row_factory = aiosqlite.Row
        query = "SELECT * FROM telegram_proxies WHERE managed_by=? AND node_id=?"
        params = [TELEGRAM_PROXY_MANAGED_BY, nid]
        if not include_disabled:
            query += " AND enabled=1"
        query += " ORDER BY id DESC LIMIT 1"
        async with conn.execute(query, tuple(params)) as cur:
            return await cur.fetchone()


def tgproxy_row_value(row, key: str, default=None):
    if row is None:
        return default
    try:
        if isinstance(row, dict):
            return row.get(key, default)
        return row[key]
    except Exception:
        return default


def get_managed_telegram_proxy_by_node_sync(node_id: str, *, include_disabled: bool = True):
    """Read-only helper for admin node card rendering.

    The main DB path remains aiosqlite; this tiny sync read is used only to
    show TG PROXY status in a synchronous text builder.
    """
    nid = str(node_id or "").strip()
    if not nid:
        return None
    try:
        conn = sqlite3.connect(DATABASE_DB, timeout=SQLITE_BUSY_TIMEOUT_SECONDS)
        conn.row_factory = sqlite3.Row
        try:
            query = "SELECT * FROM telegram_proxies WHERE managed_by=? AND node_id=?"
            params = [TELEGRAM_PROXY_MANAGED_BY, nid]
            if not include_disabled:
                query += " AND enabled=1"
            query += " ORDER BY id DESC LIMIT 1"
            row = conn.execute(query, tuple(params)).fetchone()
            return row
        finally:
            conn.close()
    except Exception:
        return None


def remote_tgproxy_status_for_node_card(node_id: str) -> str:
    row = get_managed_telegram_proxy_by_node_sync(node_id, include_disabled=True)
    if not row:
        return "не установлен"
    enabled = bool(int(tgproxy_row_value(row, "enabled", 0) or 0))
    domain = str(tgproxy_row_value(row, "domain", "") or "").strip() or "—"
    port = tgproxy_row_value(row, "port", None)
    port_text = f"{int(port)}/tcp" if port else "—"
    if enabled:
        return f"установлен · {domain}:{port_text}"
    return "не установлен (запись выключена)"


async def upsert_managed_telegram_proxy(*, node_id: str, node_code: str, title: str, url: str, domain: str, port: int, secret_hash: str, mtg_version: str | None = None) -> int:
    normalized_url = normalize_tgproxy_url(url)
    if not normalized_url:
        raise ValueError("Ссылка должна начинаться с tg://")
    nid = str(node_id or "").strip()
    if not nid:
        raise ValueError("node_id не может быть пустым")
    now_ts = time.time()
    title = str(title or f"Telegram proxy {nid.upper()}").strip()[:128]
    async with db_connect(TGPROXY_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT id FROM telegram_proxies WHERE managed_by=? AND node_id=? LIMIT 1", (TELEGRAM_PROXY_MANAGED_BY, nid)) as cur:
            existing = await cur.fetchone()
        if existing:
            proxy_id = int(existing["id"])
            await conn.execute(
                """
                UPDATE telegram_proxies
                SET title=?, url=?, enabled=1, node_code=?, domain=?, port=?, secret_hash=?, mtg_version=?,
                    installed_at=?, last_check_at=NULL, last_error=NULL, updated_at=?
                WHERE id=?
                """,
                (title, normalized_url, str(node_code or "")[:16], str(domain or ""), int(port), str(secret_hash or ""), str(mtg_version or TELEGRAM_PROXY_MTG_VERSION_LABEL), now_ts, now_ts, proxy_id),
            )
        else:
            async with conn.execute("SELECT COALESCE(MAX(sort_order), 0) AS max_order FROM telegram_proxies") as cur:
                row = await cur.fetchone()
                next_order = int(row["max_order"] or 0) + 1 if row else 1
            cur = await conn.execute(
                """
                INSERT INTO telegram_proxies (
                    title, url, enabled, sort_order, created_at, updated_at,
                    managed_by, node_id, node_code, domain, port, secret_hash, mtg_version, installed_at
                ) VALUES (?, ?, 1, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (title, normalized_url, next_order, now_ts, now_ts, TELEGRAM_PROXY_MANAGED_BY, nid, str(node_code or "")[:16], str(domain or ""), int(port), str(secret_hash or ""), str(mtg_version or TELEGRAM_PROXY_MTG_VERSION_LABEL), now_ts),
            )
            proxy_id = int(cur.lastrowid)
        await conn.commit()
        return proxy_id


