async def trial_cooldown_remaining_seconds(user_id: int) -> int:
    row = await get_trial_record(int(user_id))
    if not row:
        return 0
    if not trial_repeat_enabled():
        return 10**9
    try:
        last_ts = float(row["last_trial_at"] or row["granted_at"] or 0)
    except Exception:
        last_ts = 0
    cooldown = trial_cooldown_days_setting() * 86400
    if cooldown <= 0 or last_ts <= 0:
        return 0
    return max(0, int((last_ts + cooldown) - time.time()))


def format_seconds_as_days_hours(seconds: int) -> str:
    seconds = max(0, int(seconds))
    days = seconds // 86400
    hours = (seconds % 86400) // 3600
    if days > 0:
        return f"{days} дн. {hours} ч."
    minutes = max(1, (seconds + 59) // 60)
    return f"{minutes} мин."


async def trial_button_visible(user_id: int) -> bool:
    if not trial_menu_enabled():
        return False
    flags = await get_user_subscription_flags(int(user_id))
    if flags.get("has_paid_active") or flags.get("has_trial_active"):
        return False
    if await trial_cooldown_remaining_seconds(int(user_id)) > 0:
        return False
    return True


async def check_trial_availability(user_id: int) -> tuple[bool, str]:
    if not trial_menu_enabled():
        return False, "🎁 Тестовый доступ\n\nТестовый доступ временно отключён."
    flags = await get_user_subscription_flags(int(user_id), force_refresh=True)
    if flags.get("has_paid_active"):
        return False, "🎁 Тестовый доступ\n\nУ вас уже есть активная обычная подписка. Тестовый доступ предназначен для новых пользователей."
    if flags.get("has_trial_active"):
        return False, "🎁 Тестовый доступ\n\nУ вас уже есть активный тестовый доступ."
    row = await get_trial_record(int(user_id))
    if row and not trial_repeat_enabled():
        return False, "🎁 Тестовый доступ\n\nПовторная выдача тестового доступа сейчас отключена."
    remaining = await trial_cooldown_remaining_seconds(int(user_id))
    if remaining > 0:
        return False, "🎁 Тестовый доступ\n\nПовторный тестовый доступ будет доступен позже.\n\nОсталось: " + format_seconds_as_days_hours(remaining)
    return True, ""


async def user_has_trial_access(user_id: int) -> bool:
    ok, _ = await check_trial_availability(int(user_id))
    return not ok


