async def count_reminder_marks() -> dict:
    async with db_connect(REMINDERS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT
                SUM(CASE WHEN reminder_type='expiring_3' THEN 1 ELSE 0 END) AS c3,
                SUM(CASE WHEN reminder_type='expiring_1' THEN 1 ELSE 0 END) AS c1,
                SUM(CASE WHEN reminder_type='expired' THEN 1 ELSE 0 END) AS ce
            FROM reminder_marks
            """
        ) as cur:
            row = await cur.fetchone()
            return {
                "expiring_3": int(row["c3"] or 0),
                "expiring_1": int(row["c1"] or 0),
                "expired": int(row["ce"] or 0),
            }



async def init_antiabuse_db() -> None:
    BASE_DIR.mkdir(parents=True, exist_ok=True)
    async with db_connect(ANTIABUSE_DB) as conn:
        await conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS antiabuse_cases (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT UNIQUE,
                admin_status TEXT NOT NULL DEFAULT 'new',
                admin_note TEXT,
                ip_limit_override INTEGER,
                updated_at REAL NOT NULL
            );

            CREATE TABLE IF NOT EXISTS raw_events (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                ts_text TEXT NOT NULL,
                ts_epoch REAL NOT NULL,
                protocol TEXT NOT NULL,
                connection_id TEXT,
                event_type TEXT NOT NULL,
                ip TEXT,
                port INTEGER,
                name TEXT,
                destination TEXT,
                raw_line TEXT NOT NULL,
                matched INTEGER NOT NULL DEFAULT 0,
                created_at REAL NOT NULL
            );

            CREATE TABLE IF NOT EXISTS matches (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                ts_epoch REAL NOT NULL,
                protocol TEXT NOT NULL,
                connection_id TEXT,
                name TEXT NOT NULL,
                ip TEXT NOT NULL,
                port INTEGER,
                event_from_id INTEGER NOT NULL,
                event_name_id INTEGER NOT NULL,
                confidence TEXT NOT NULL,
                created_at REAL NOT NULL
            );

            CREATE TABLE IF NOT EXISTS ip_state (
                name TEXT NOT NULL,
                ip TEXT NOT NULL,
                first_seen REAL NOT NULL,
                last_seen REAL NOT NULL,
                hits INTEGER NOT NULL DEFAULT 1,
                protocols TEXT NOT NULL DEFAULT '',
                PRIMARY KEY(name, ip)
            );

            CREATE TABLE IF NOT EXISTS alerts (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                unique_ip_count INTEGER NOT NULL,
                window_minutes INTEGER NOT NULL,
                first_seen REAL NOT NULL,
                last_seen REAL NOT NULL,
                sent_at REAL NOT NULL,
                user_notified INTEGER NOT NULL DEFAULT 0,
                admin_notified INTEGER NOT NULL DEFAULT 0,
                details TEXT
            );

            CREATE UNIQUE INDEX IF NOT EXISTS idx_matches_unique_pair
            ON matches(event_from_id, event_name_id);

            CREATE INDEX IF NOT EXISTS idx_matches_name_ts
            ON matches(name, ts_epoch);

            CREATE INDEX IF NOT EXISTS idx_ip_state_name_last_seen
            ON ip_state(name, last_seen);

            CREATE INDEX IF NOT EXISTS idx_alerts_name_sent
            ON alerts(name, sent_at DESC);

            CREATE TABLE IF NOT EXISTS antiabuse_events (
                source_type TEXT NOT NULL,
                source_id TEXT NOT NULL,
                client_name TEXT NOT NULL,
                source_ip TEXT NOT NULL,
                protocol TEXT,
                first_seen REAL,
                last_seen REAL NOT NULL,
                event_count INTEGER NOT NULL DEFAULT 0,
                raw_ref TEXT,
                updated_at REAL NOT NULL,
                PRIMARY KEY(source_type, source_id, client_name, source_ip)
            );

            CREATE INDEX IF NOT EXISTS idx_antiabuse_events_client_last
            ON antiabuse_events(client_name, last_seen DESC);

            CREATE INDEX IF NOT EXISTS idx_antiabuse_events_last
            ON antiabuse_events(last_seen DESC);

            CREATE INDEX IF NOT EXISTS idx_antiabuse_events_ip_last
            ON antiabuse_events(source_ip, last_seen DESC);

            CREATE TABLE IF NOT EXISTS antiabuse_notifications (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                kind TEXT NOT NULL,
                sent_at REAL NOT NULL,
                user_notified INTEGER NOT NULL DEFAULT 0,
                admin_notified INTEGER NOT NULL DEFAULT 0,
                details TEXT
            );

            CREATE INDEX IF NOT EXISTS idx_antiabuse_notifications_name_kind_sent
            ON antiabuse_notifications(name, kind, sent_at DESC);

            CREATE TABLE IF NOT EXISTS antiabuse_warnings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                created_at REAL NOT NULL,
                case_key TEXT NOT NULL,
                client_name TEXT NOT NULL,
                tgid INTEGER,
                username TEXT,
                source TEXT,
                active_ip_count INTEGER NOT NULL DEFAULT 0,
                device_limit INTEGER NOT NULL DEFAULT 0,
                sent_to_admin INTEGER NOT NULL DEFAULT 0,
                sent_to_user INTEGER NOT NULL DEFAULT 0,
                mode TEXT,
                details TEXT
            );

            CREATE INDEX IF NOT EXISTS idx_antiabuse_warnings_client_created
            ON antiabuse_warnings(client_name, created_at DESC);

            CREATE INDEX IF NOT EXISTS idx_antiabuse_warnings_created
            ON antiabuse_warnings(created_at DESC);

            CREATE TABLE IF NOT EXISTS antiabuse_enforcement (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                is_active INTEGER NOT NULL DEFAULT 1,
                disabled_until REAL NOT NULL,
                disabled_at REAL NOT NULL,
                disabled_by INTEGER,
                enabled_at REAL,
                enabled_by INTEGER,
                reason TEXT,
                details TEXT
            );

            CREATE INDEX IF NOT EXISTS idx_antiabuse_enforcement_name_active
            ON antiabuse_enforcement(name, is_active, disabled_until);
            """
        )

        async with conn.execute("PRAGMA table_info(antiabuse_cases)") as cur:
            cols_rows = await cur.fetchall()

        cols = {row[1]: {"type": row[2], "notnull": row[3], "pk": row[5]} for row in cols_rows}

        needs_rebuild = False
        if "tgid" in cols and int(cols["tgid"]["notnull"] or 0) == 1:
            needs_rebuild = True
        if "name" not in cols:
            needs_rebuild = True
        if "updated_at" not in cols:
            needs_rebuild = True

        if needs_rebuild:
            now_ts = time.time()
            await conn.execute("ALTER TABLE antiabuse_cases RENAME TO antiabuse_cases_legacy")
            await conn.execute(
                """
                CREATE TABLE antiabuse_cases (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT UNIQUE,
                    admin_status TEXT NOT NULL DEFAULT 'new',
                    admin_note TEXT,
                    ip_limit_override INTEGER,
                    updated_at REAL NOT NULL
                )
                """
            )

            async with conn.execute("PRAGMA table_info(antiabuse_cases_legacy)") as cur:
                legacy_cols = {row[1] for row in await cur.fetchall()}

            if "name" in legacy_cols:
                await conn.execute(
                    """
                    INSERT OR IGNORE INTO antiabuse_cases (name, admin_status, admin_note, ip_limit_override, updated_at)
                    SELECT
                        TRIM(name),
                        COALESCE(admin_status, 'new'),
                        admin_note,
                        ip_limit_override,
                        COALESCE(updated_at, ?)
                    FROM antiabuse_cases_legacy
                    WHERE name IS NOT NULL AND TRIM(name) != ''
                    """,
                    (now_ts,),
                )

            await conn.execute("DROP TABLE antiabuse_cases_legacy")
        else:
            if "name" not in cols:
                await conn.execute("ALTER TABLE antiabuse_cases ADD COLUMN name TEXT")
            if "ip_limit_override" not in cols:
                await conn.execute("ALTER TABLE antiabuse_cases ADD COLUMN ip_limit_override INTEGER")
            if "updated_at" not in cols:
                await conn.execute("ALTER TABLE antiabuse_cases ADD COLUMN updated_at REAL")

        try:
            await conn.execute("CREATE UNIQUE INDEX IF NOT EXISTS idx_antiabuse_cases_name ON antiabuse_cases(name)")
        except Exception:
            pass

        # Stage45 audit cleanup: make main antiabuse CID-based when sing-box journal provides connection IDs.
        # Existing databases are migrated in place and old rows keep NULL/empty connection_id.
        for table_name in ("raw_events", "matches"):
            try:
                async with conn.execute(f"PRAGMA table_info({table_name})") as cur:
                    existing_cols = {row[1] for row in await cur.fetchall()}
                if "connection_id" not in existing_cols:
                    await conn.execute(f"ALTER TABLE {table_name} ADD COLUMN connection_id TEXT")
            except Exception:
                logging.exception("failed to ensure connection_id column on %s", table_name)

        await conn.commit()


def antiabuse_log(message: str) -> None:
    logging.info("[antiabuse] %s", message)


def antiabuse_parse_ts(ts_text: str) -> float:
    try:
        if "T" in ts_text:
            return datetime.fromisoformat(ts_text).timestamp()
        return datetime.strptime(ts_text, "%Y/%m/%d %H:%M:%S").timestamp()
    except Exception:
        antiabuse_log(f"bad timestamp in log: {ts_text!r}")
        return 0.0


ANTIABUSE_TS_RE = r"(?P<ts>\d{4}-\d{2}-\d{2}T[0-9:.+\-]+|\d{4}/\d{2}/\d{2}\s+\d{2}:\d{2}:\d{2})"
# Main antiabuse must handle both old S-UI style logs:
#   INFO - inbound/vless[...] inbound connection from ...
# and direct sing-box/journal style logs:
#   INFO [123 0ms] inbound/vless[...] inbound connection from ...
ANTIABUSE_LOG_PREFIX_RE = rf"^{ANTIABUSE_TS_RE} .*?INFO(?:\s+-)?(?:\s+\[(?P<cid>\d+)\s+[^\]]+\])?\s+"
ANTIABUSE_FROM_RE = re.compile(
    rf"{ANTIABUSE_LOG_PREFIX_RE}inbound/(?P<proto>vless|tuic|hysteria2)\[[^\]]+\]\s*inbound(?: packet)? connection from (?P<ip>[^: \]]+):(?P<port>\d+)",
    re.IGNORECASE,
)
ANTIABUSE_NAME_RE = re.compile(
    rf"{ANTIABUSE_LOG_PREFIX_RE}inbound/(?P<proto>vless|tuic|hysteria2)\[[^\]]+\]\s*\[(?P<name>[^\]]+)\]\s*inbound(?: packet)? connection to (?P<dst>.+)$",
    re.IGNORECASE,
)


def parse_antiabuse_event(line: str):
    m = ANTIABUSE_FROM_RE.search(line)
    if m:
        ts_text = m.group("ts")
        ts_epoch = antiabuse_parse_ts(ts_text)
        if ts_epoch <= 0:
            return None
        return {
            "ts_text": ts_text,
            "ts_epoch": ts_epoch,
            "protocol": m.group("proto").lower(),
            "connection_id": m.groupdict().get("cid"),
            "event_type": "from",
            "ip": m.group("ip"),
            "port": int(m.group("port")),
            "name": None,
            "destination": None,
            "raw_line": line.strip(),
        }

    m = ANTIABUSE_NAME_RE.search(line)
    if m:
        ts_text = m.group("ts")
        ts_epoch = antiabuse_parse_ts(ts_text)
        if ts_epoch <= 0:
            return None
        return {
            "ts_text": ts_text,
            "ts_epoch": ts_epoch,
            "protocol": m.group("proto").lower(),
            "connection_id": m.groupdict().get("cid"),
            "event_type": "name",
            "ip": None,
            "port": None,
            "name": m.group("name"),
            "destination": m.group("dst"),
            "raw_line": line.strip(),
        }
    return None


def prune_recent_events(protocol: str, now_ts: float) -> None:
    ttl = max(ANTIABUSE_MATCH_WINDOWS.values()) * 3
    for queue in (antiabuse_recent_from[protocol], antiabuse_recent_name[protocol]):
        while queue and (now_ts - queue[0]["ts_epoch"]) > ttl:
            queue.popleft()


async def antiabuse_insert_raw_event(event: dict) -> int:
    async with db_connect(ANTIABUSE_DB) as conn:
        cur = await conn.execute(
            """
            INSERT INTO raw_events (
                ts_text, ts_epoch, protocol, connection_id, event_type, ip, port, name, destination, raw_line, created_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                event["ts_text"], event["ts_epoch"], event["protocol"], event.get("connection_id"), event["event_type"],
                event.get("ip"), event.get("port"), event.get("name"), event.get("destination"),
                event["raw_line"], time.time(),
            ),
        )
        await conn.commit()
        return int(cur.lastrowid)


async def antiabuse_insert_raw_events(events: list[dict]) -> int:
    """Insert parsed journal events in one transaction and attach DB ids in-place."""
    if not events:
        return 0
    now_value = time.time()
    async with db_connect(ANTIABUSE_DB) as conn:
        inserted = 0
        for event in events:
            cur = await conn.execute(
                """
                INSERT INTO raw_events (
                    ts_text, ts_epoch, protocol, connection_id, event_type, ip, port, name, destination, raw_line, created_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    event["ts_text"], event["ts_epoch"], event["protocol"], event.get("connection_id"), event["event_type"],
                    event.get("ip"), event.get("port"), event.get("name"), event.get("destination"),
                    event["raw_line"], now_value,
                ),
            )
            event["id"] = int(cur.lastrowid)
            inserted += 1
        await conn.commit()
        return inserted


async def antiabuse_mark_matched(event_from_id: int, event_name_id: int) -> None:
    async with db_connect(ANTIABUSE_DB) as conn:
        await conn.execute("UPDATE raw_events SET matched=1 WHERE id IN (?, ?)", (int(event_from_id), int(event_name_id)))
        await conn.commit()


async def antiabuse_save_match(from_event: dict, name_event: dict) -> None:
    now_ts = time.time()
    async with db_connect(ANTIABUSE_DB) as conn:
        conn.row_factory = aiosqlite.Row
        await conn.execute(
            """
            INSERT OR IGNORE INTO matches (
                ts_epoch, protocol, connection_id, name, ip, port, event_from_id, event_name_id, confidence, created_at
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                max(float(from_event["ts_epoch"]), float(name_event["ts_epoch"])),
                str(from_event["protocol"]),
                str(from_event.get("connection_id") or name_event.get("connection_id") or ""),
                str(name_event["name"]),
                str(from_event["ip"]),
                int(from_event.get("port") or 0),
                int(from_event["id"]),
                int(name_event["id"]),
                "cid" if (from_event.get("connection_id") or name_event.get("connection_id")) else "unique_window",
                now_ts,
            ),
        )
        async with conn.execute("SELECT protocols FROM ip_state WHERE name=? AND ip=?", (str(name_event["name"]), str(from_event["ip"]))) as cur:
            existing = await cur.fetchone()
        proto_set = {str(from_event["protocol"])}
        if existing and existing["protocols"]:
            proto_set.update(x for x in str(existing["protocols"]).split(",") if x)
        if existing:
            await conn.execute(
                "UPDATE ip_state SET last_seen=?, hits=hits+1, protocols=? WHERE name=? AND ip=?",
                (now_ts, ",".join(sorted(proto_set)), str(name_event["name"]), str(from_event["ip"])),
            )
        else:
            await conn.execute(
                "INSERT INTO ip_state (name, ip, first_seen, last_seen, hits, protocols) VALUES (?, ?, ?, ?, ?, ?)",
                (str(name_event["name"]), str(from_event["ip"]), now_ts, now_ts, 1, ",".join(sorted(proto_set))),
            )
        await conn.commit()


async def antiabuse_save_matches_batch(pairs: list[tuple[dict, dict]]) -> None:
    """Persist antiabuse matches in one SQLite transaction."""
    if not pairs:
        return
    now_value = time.time()
    async with db_connect(ANTIABUSE_DB) as conn:
        conn.row_factory = aiosqlite.Row
        for from_event, name_event in pairs:
            await conn.execute(
                "UPDATE raw_events SET matched=1 WHERE id IN (?, ?)",
                (int(from_event["id"]), int(name_event["id"])),
            )
            await conn.execute(
                """
                INSERT OR IGNORE INTO matches (
                    ts_epoch, protocol, connection_id, name, ip, port, event_from_id, event_name_id, confidence, created_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
                """,
                (
                    max(float(from_event["ts_epoch"]), float(name_event["ts_epoch"])),
                    str(from_event["protocol"]),
                    str(from_event.get("connection_id") or name_event.get("connection_id") or ""),
                    str(name_event["name"]),
                    str(from_event["ip"]),
                    int(from_event.get("port") or 0),
                    int(from_event["id"]),
                    int(name_event["id"]),
                    "cid" if (from_event.get("connection_id") or name_event.get("connection_id")) else "unique_window",
                    now_value,
                ),
            )
            async with conn.execute("SELECT protocols FROM ip_state WHERE name=? AND ip=?", (str(name_event["name"]), str(from_event["ip"]))) as cur:
                existing = await cur.fetchone()
            proto_set = {str(from_event["protocol"])}
            if existing and existing["protocols"]:
                proto_set.update(x for x in str(existing["protocols"]).split(",") if x)
            if existing:
                await conn.execute(
                    "UPDATE ip_state SET last_seen=?, hits=hits+1, protocols=? WHERE name=? AND ip=?",
                    (now_value, ",".join(sorted(proto_set)), str(name_event["name"]), str(from_event["ip"])),
                )
            else:
                await conn.execute(
                    "INSERT INTO ip_state (name, ip, first_seen, last_seen, hits, protocols) VALUES (?, ?, ?, ?, ?, ?)",
                    (str(name_event["name"]), str(from_event["ip"]), now_value, now_value, 1, ",".join(sorted(proto_set))),
                )
        await conn.commit()


def antiabuse_try_match_in_memory(new_event: dict) -> tuple[dict, dict] | None:
    """
    Match main antiabuse raw events.

    Production rule:
    - If sing-box journal has a connection id (CID), match strictly by CID.
      This prevents false matches when many clients connect at the same time.
    - If CID is absent (legacy S-UI log format), fall back to the old short time-window matcher.
    """
    protocol = str(new_event["protocol"])
    now_ts = float(new_event["ts_epoch"])
    cid = str(new_event.get("connection_id") or "").strip()
    prune_recent_events(protocol, now_ts)
    window = float(ANTIABUSE_MATCH_WINDOWS.get(protocol, 1.0))

    def mark_pair(from_event: dict, name_event: dict) -> tuple[dict, dict]:
        from_event["matched"] = True
        name_event["matched"] = True
        if cid:
            from_event["match_strategy"] = "cid"
            name_event["match_strategy"] = "cid"
        return from_event, name_event

    if new_event["event_type"] == "from":
        if cid:
            candidates = [
                item for item in antiabuse_recent_name[protocol]
                if (not item.get("matched")) and str(item.get("connection_id") or "").strip() == cid
            ]
            if candidates:
                candidate = max(candidates, key=lambda item: float(item["ts_epoch"]))
                return mark_pair(new_event, candidate)
        antiabuse_recent_from[protocol].append(new_event)
        return None

    # name/client event
    if cid:
        candidates = [
            item for item in antiabuse_recent_from[protocol]
            if (not item.get("matched")) and str(item.get("connection_id") or "").strip() == cid
        ]
    else:
        candidates = [
            item for item in antiabuse_recent_from[protocol]
            if (not item.get("matched")) and not item.get("connection_id") and 0 <= (now_ts - float(item["ts_epoch"])) <= window
        ]
        if not candidates:
            candidates = [
                item for item in antiabuse_recent_from[protocol]
                if (not item.get("matched")) and not item.get("connection_id") and abs(now_ts - float(item["ts_epoch"])) <= window
            ]

    if not candidates:
        antiabuse_recent_name[protocol].append(new_event)
        return None

    candidate = max(candidates, key=lambda item: float(item["ts_epoch"]))
    return mark_pair(candidate, new_event)


async def antiabuse_cap_table_runtime(conn, table: str, target_rows: int, order_col: str = "ts_epoch") -> None:
    """Keep hot antiabuse tables below warning caps during runtime, not only in daily maintenance."""
    allowed = {"raw_events", "matches"}
    if table not in allowed or int(target_rows or 0) <= 0:
        return
    q_table = '"' + table.replace('"', '""') + '"'
    q_order = '"' + order_col.replace('"', '""') + '"'
    try:
        async with conn.execute(f"SELECT COUNT(*) AS c FROM {q_table}") as cur:
            row = await cur.fetchone()
        total = int((row[0] if row else 0) or 0)
        excess = total - int(target_rows)
        if excess <= 0:
            return
        await conn.execute(
            f"""
            DELETE FROM {q_table}
            WHERE rowid IN (
                SELECT rowid
                FROM {q_table}
                ORDER BY {q_order} ASC, rowid ASC
                LIMIT ?
            )
            """,
            (int(excess),),
        )
        logging.info("antiabuse runtime cap %s: deleted=%s total_before=%s target=%s", table, excess, total, target_rows)
    except Exception as exc:
        logging.warning("antiabuse runtime cap failed table=%s: %s", table, exc)


async def antiabuse_cleanup_db() -> None:
    threshold = time.time() - (ANTIABUSE_RETENTION_HOURS * 3600)
    async with db_connect(ANTIABUSE_DB) as conn:
        await conn.execute("DELETE FROM raw_events WHERE ts_epoch < ?", (threshold,))
        await conn.execute("DELETE FROM matches WHERE ts_epoch < ?", (threshold,))
        await conn.execute("DELETE FROM ip_state WHERE last_seen < ?", (threshold,))
        await conn.execute("DELETE FROM alerts WHERE sent_at < ?", (threshold,))
        await conn.execute("DELETE FROM antiabuse_notifications WHERE sent_at < ?", (threshold,))
        await antiabuse_cap_table_runtime(conn, "raw_events", ANTIABUSE_RAW_EVENTS_TARGET_ROWS, "ts_epoch")
        await antiabuse_cap_table_runtime(conn, "matches", ANTIABUSE_MATCHES_TARGET_ROWS, "ts_epoch")
        await conn.commit()


