async def antiabuse_disable_for_minutes(name: str, minutes: int, admin_id: int | None, reason: str) -> dict:
    minutes = max(1, min(int(minutes), ANTIABUSE_DISABLE_MAX_MINUTES))
    action_result = await antiabuse_set_client_enabled(name, False)
    now_ts = time.time()
    disabled_until = now_ts + minutes * 60
    details = {
        "minutes": minutes,
        "disabled_via": "editbulk",
        "remote_sync": action_result.get("remote_sync") if isinstance(action_result, dict) else None,
    }
    async with db_connect(ANTIABUSE_DB) as conn:
        await conn.execute(
            "UPDATE antiabuse_enforcement SET is_active=0, enabled_at=?, enabled_by=?, details=? WHERE name=? AND is_active=1",
            (now_ts, int(admin_id or 0), json.dumps({"closed_by": "new_disable"}, ensure_ascii=False), str(name)),
        )
        await conn.execute(
            "INSERT INTO antiabuse_enforcement (name, is_active, disabled_until, disabled_at, disabled_by, reason, details) VALUES (?, 1, ?, ?, ?, ?, ?)",
            (
                str(name),
                float(disabled_until),
                float(now_ts),
                int(admin_id or 0),
                str(reason or "antiabuse manual disable"),
                json.dumps(details, ensure_ascii=False),
            ),
        )
        await conn.commit()
    return {"sui_ok": True, "remote_sync": action_result.get("remote_sync") if isinstance(action_result, dict) else None, "disabled_until": disabled_until, "minutes": minutes}


async def antiabuse_enable_now(name: str, admin_id: int | None, reason: str) -> dict:
    action_result = await antiabuse_set_client_enabled(name, True)
