def remote_node_safe_id(value: str) -> str:
    raw = str(value or "").strip()
    if not re.fullmatch(r"[A-Za-z0-9_-]{2,32}", raw):
        raise ValueError("ID node: 2–32 символа, латиница/цифры/_/-. Например nl1")
    return raw


def remote_admin_nodes_all(nodes_cfg: dict | None) -> list[dict]:
    if not nodes_cfg:
        return []
    return [n for n in nodes_cfg.get("nodes", []) if isinstance(n, dict)]


def remote_admin_get_node(nodes_cfg: dict, node_id: str) -> dict | None:
    raw_id = str(node_id or "")
    for node in remote_admin_nodes_all(nodes_cfg):
        if str(node.get("id") or "") == raw_id:
            return node
    return None


def remote_admin_default_node_template(node_id: str) -> dict:
    nid = remote_node_safe_id(node_id)
    domain = f"{nid}.astramind.dpdns.org"
    return {
        "id": nid,
        "enabled": False,
        "bootstrap": True,
        "maintenance": True,
        "drain": False,
        "include_in_paid": True,
        "include_in_trial": False,
        "host": domain,
        "domain": domain,
        "display_name": nid.upper(),
        "legacy_domains": [],
        "ssh": {},
        "protocols": {
            "vless": {"enabled": True, "port": 443, "sni": domain},
            "hysteria2": {"enabled": True, "port": 443, "sni": domain, "alpn": "h3", "obfs_type": "salamander"},
            "tuic": {"enabled": True, "port": 8443, "sni": domain, "alpn": "h3", "congestion_control": "bbr"},
        },
    }



def remote_admin_clean_json_input(raw: str) -> str:
    text = str(raw or "").strip()
    if text.startswith("```"):
        lines = text.splitlines()
        if lines and lines[0].strip().startswith("```"):
            lines = lines[1:]
        if lines and lines[-1].strip() == "```":
            lines = lines[:-1]
        text = "\n".join(lines).strip()
    return text

def remote_admin_validate_node_json(data: dict, *, allow_existing_id: str | None = None) -> dict:
    if not isinstance(data, dict):
        raise ValueError("Node JSON должен быть объектом")
    node = dict(data)
    node["id"] = remote_node_safe_id(str(node.get("id") or allow_existing_id or ""))
    if allow_existing_id and node["id"] != str(allow_existing_id):
        raise ValueError("ID node нельзя менять через JSON-редактор. Создайте новую node и удалите старую.")
    if not str(node.get("host") or "").strip():
        raise ValueError("Поле host обязательно")
    node["host"] = str(node.get("host") or "").strip()
    node["domain"] = str(node.get("domain") or node.get("host") or "").strip()
    node["display_name"] = str(node.get("display_name") or node["id"].upper()).strip()[:64]
    node["enabled"] = bool(node.get("enabled", False))
    node["bootstrap"] = bool(node.get("bootstrap", False))
    node["maintenance"] = bool(node.get("maintenance", False))
    node["include_in_paid"] = bool(node.get("include_in_paid", True))
    node["include_in_trial"] = bool(node.get("include_in_trial", False))
    node["drain"] = bool(node.get("drain", False))
    if not isinstance(node.get("legacy_domains"), list):
        node["legacy_domains"] = []
    if not isinstance(node.get("ssh"), dict):
        node["ssh"] = {}
    if not isinstance(node.get("protocols"), dict):
        node["protocols"] = {}
    return node


def remote_admin_save_nodes_config(nodes_cfg: dict) -> None:
    remote_save_json_atomic(REMOTE_NODES_FILE, nodes_cfg)


async def remote_admin_remove_node_state(node_id: str) -> None:
    nid = str(node_id or "").strip()
    if not nid:
        return
    async with db_connect(DATABASE_DB) as conn:
        await conn.execute("DELETE FROM remote_node_state WHERE node_id=?", (nid,))
        await conn.execute("DELETE FROM remote_client_sync WHERE node_id=?", (nid,))
        await conn.commit()


async def remote_admin_mark_node_state_after_full_cleanup(node_id: str, node: dict | None = None) -> None:
    nid = str(node_id or "").strip()
    if not nid:
        return
    node = node or {}
    state = await remote_load_node_state()
    row = state.setdefault(nid, {"node_id": nid})
    now_ts = remote_now()
    row.update({
        "node_id": nid,
        "status": "cleaned",
        "host": node.get("host"),
        "domain": node.get("domain"),
        "deployed_client_count": 0,
        "last_deployed_hash": "",
        "last_render_hash": "",
        "last_error": "node full cleanup completed; bootstrap required",
        "last_error_at": None,
        "last_warning": "",
        "updated_at": now_ts,
        "last_ok_at": None,
        "bootstrap_in_progress": 0,
        "bootstrap_started_at": None,
        "bootstrap_finished_at": None,
        "retry_count": 0,
        "next_retry_at": None,
    })
    await remote_save_node_state(state)


async def remote_admin_update_node_field(node_id: str, field: str, value) -> dict:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    node = remote_admin_get_node(nodes_cfg, node_id)
    if not node:
        raise RuntimeError("Node не найдена")
    if field not in {"enabled", "maintenance", "include_in_paid", "include_in_trial", "drain", "display_name", "remote_antiabuse_enabled"}:
        raise RuntimeError("Поле нельзя изменить через этот action")
    node[field] = bool(value) if field != "display_name" else str(value or "").strip()[:64]
    remote_admin_save_nodes_config(nodes_cfg)
    remote_request_sync(reason=f"admin_node_{field}:{node_id}")
    return node


async def remote_admin_replace_node_json(node_id: str, raw_json: str) -> dict:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    nodes = nodes_cfg.setdefault("nodes", [])
    data = json.loads(remote_admin_clean_json_input(raw_json))
    existing_node = None
    for item in nodes:
        if isinstance(item, dict) and str(item.get("id") or "") == str(node_id):
            existing_node = item
            break
    if existing_node is None:
        raise RuntimeError("Node не найдена")
    if isinstance(data, dict) and isinstance(data.get("ssh"), dict):
        if str(data["ssh"].get("password") or "") == "***hidden***":
            old_password = ((existing_node.get("ssh") or {}).get("password"))
            if old_password:
                data["ssh"]["password"] = old_password
            else:
                data["ssh"].pop("password", None)
    new_node = remote_admin_validate_node_json(data, allow_existing_id=node_id)
    for idx, item in enumerate(nodes):
        if isinstance(item, dict) and str(item.get("id") or "") == str(node_id):
            nodes[idx] = new_node
            remote_admin_save_nodes_config(nodes_cfg)
            remote_request_sync(reason=f"admin_node_json:{node_id}")
            return new_node
    raise RuntimeError("Node не найдена")


async def remote_admin_add_node_json(raw_json: str) -> dict:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    nodes = nodes_cfg.setdefault("nodes", [])
    data = json.loads(remote_admin_clean_json_input(raw_json))
    new_node = remote_admin_validate_node_json(data)
    if any(isinstance(n, dict) and str(n.get("id") or "") == new_node["id"] for n in nodes):
        raise RuntimeError("Node с таким id уже существует")
    nodes.append(new_node)
    remote_admin_save_nodes_config(nodes_cfg)
    remote_request_sync(reason=f"admin_node_add:{new_node['id']}")
    return new_node


async def remote_admin_delete_node(node_id: str) -> None:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    nodes = nodes_cfg.setdefault("nodes", [])
    before = len(nodes)
    nodes_cfg["nodes"] = [n for n in nodes if not (isinstance(n, dict) and str(n.get("id") or "") == str(node_id))]
    if len(nodes_cfg["nodes"]) == before:
        raise RuntimeError("Node не найдена")
    remote_admin_save_nodes_config(nodes_cfg)
    await remote_admin_remove_node_state(node_id)
    remote_request_sync(reason=f"admin_node_delete:{node_id}")




def remote_admin_redacted_nodes_json(nodes_cfg: dict | None) -> str:
    data = json.loads(json.dumps(nodes_cfg or {}, ensure_ascii=False))
    for node in data.get("nodes", []) if isinstance(data, dict) else []:
        if isinstance(node, dict) and isinstance(node.get("ssh"), dict) and node["ssh"].get("password"):
            node["ssh"]["password"] = "***hidden***"
    return json.dumps(data, ensure_ascii=False, indent=2)


async def remote_admin_set_node_drain_and_sync(node_id: str, drain: bool = True) -> dict:
    # remote_admin_update_node_field already saves nodes.json and queues one full sync.
    # Do not queue a second event here; debounce will still batch nearby admin actions.
    node = await remote_admin_update_node_field(node_id, "drain", bool(drain))
    return node


def remote_rotate_node_keys_blocking(nodes_cfg: dict, node: dict) -> dict:
    nid = str(node.get("id") or "")
    protos = node.setdefault("protocols", {})
    changed: list[str] = []
    vless = protos.setdefault("vless", {"enabled": True})
    if vless.get("enabled", True):
        p = remote_ssh_run(nodes_cfg, node, "/usr/local/bin/sing-box generate reality-keypair", timeout=30)
        private_key, public_key = remote_parse_reality_keypair(p.stdout)
        vless["private_key"] = private_key
        vless["public_key"] = public_key
        vless["short_id"] = secrets.token_hex(4)
        changed.append("vless reality keypair + short_id")
    hy2 = protos.setdefault("hysteria2", {"enabled": True})
    if hy2.get("enabled", True) and str(hy2.get("obfs_type") or "") == "salamander":
        hy2["obfs_password"] = secrets.token_urlsafe(18)
        changed.append("hysteria2 obfs_password")
    remote_ensure_node_generated(node)
    if not changed:
        changed.append("no enabled key-based protocols")
    return {"node_id": nid, "changed": changed}


async def remote_admin_rotate_node_keys(node_id: str) -> dict:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    node = remote_admin_get_node(nodes_cfg, node_id)
    if not node:
        raise RuntimeError("Node не найдена")
    result = await asyncio.to_thread(remote_rotate_node_keys_blocking, nodes_cfg, node)
    remote_admin_save_nodes_config(nodes_cfg)
    state = await remote_load_node_state()
    row = state.setdefault(str(node_id), {"node_id": str(node_id)})
    row["status"] = "keys_rotated"
    row["last_deployed_hash"] = ""
    row["last_render_hash"] = ""
    row["last_error"] = ""
    row["updated_at"] = remote_now()
    await remote_save_node_state(state)
    remote_request_node_sync(str(node_id), reason=f"admin_rotate_node_keys:{node_id}")
    return result




def remote_admin_mark_node_after_full_cleanup(nodes_cfg: dict, node: dict) -> None:
    """Mark a node as intentionally wiped so deploy/sync skips it until bootstrap runs again."""
    if not isinstance(nodes_cfg, dict) or not isinstance(node, dict):
        raise RuntimeError("nodes config/node invalid")
    nid = str(node.get("id") or "").strip()
    if not nid:
        raise RuntimeError("node id пустой")
    node["enabled"] = False
    node["maintenance"] = True
    node["drain"] = True
    node["bootstrap"] = True
    node["last_full_cleanup_at"] = remote_now()
    # Keep include_in_paid/include_in_trial unchanged as admin intent for after re-bootstrap.
    remote_admin_save_nodes_config(nodes_cfg)


