def remote_resolve_summary(domain: str, expected_host: str = "") -> str:
    raw_domain = str(domain or "").strip()
    if not raw_domain:
        return "—"
    try:
        import socket
        ips = sorted({item[4][0] for item in socket.getaddrinfo(raw_domain, None, type=socket.SOCK_STREAM)})
        expected = str(expected_host or "").strip()
        mark = "✅" if (not expected or expected in ips) else "⚠️"
        return f"{', '.join(ips[:4]) or '—'} {mark}"
    except Exception as exc:
        return f"ошибка DNS: {str(exc)[:80]}"


