def tgproxy_flag_for_code(code: str) -> str:
    return {
        "NL": "🇳🇱", "PL": "🇵🇱", "DE": "🇩🇪", "FI": "🇫🇮", "FL": "🇫🇮",
        "SE": "🇸🇪", "FR": "🇫🇷", "GB": "🇬🇧", "UK": "🇬🇧", "US": "🇺🇸",
    }.get(str(code or "").upper()[:2], "🌍")


def tgproxy_code_from_node(node: dict) -> str:
    nid = str((node or {}).get("id") or "").strip().upper()
    display = str((node or {}).get("display_name") or "").strip().upper()
    tokens = re.findall(r"[A-Z]{2,3}", display)
    for token in tokens + [nid[:2], nid[:3]]:
        if token in CODE_COUNTRY_RU or token in {"FL"}:
            return token[:2]
    return (nid[:2] or "TG").upper()


def tgproxy_title_for_node(node: dict) -> str:
    code = tgproxy_code_from_node(node)
    display = str((node or {}).get("display_name") or "")
    m_flag = re.search(r"[🇦-🇿]{2}", display)
    flag = m_flag.group(0) if m_flag else tgproxy_flag_for_code(code)
    return f"{flag} Telegram proxy {code}".strip()


def tgproxy_default_domain_for_node(node: dict) -> str:
    return str((node or {}).get("domain") or "").strip()


def validate_tgproxy_domain(value: str) -> str:
    raw = str(value or "").strip().lower()
    if not raw:
        raise ValueError("Домен/SNI не может быть пустым.")
    if len(raw) > 253 or any(ch.isspace() for ch in raw) or ":" in raw or "/" in raw:
        raise ValueError("Введите только домен/SNI без схемы, порта и пробелов.")
    if re.fullmatch(r"\d{1,3}(?:\.\d{1,3}){3}", raw):
        raise ValueError("IP не используется как основной SNI. Укажите домен.")
    if not re.fullmatch(r"[a-z0-9.-]+", raw) or "." not in raw:
        raise ValueError("Введите корректный домен, например proxy.example.com.")
    return raw


def validate_tgproxy_port(value) -> int:
    try:
        port = int(value if value not in (None, "") else TELEGRAM_PROXY_DEFAULT_PORT)
    except Exception:
        raise ValueError("Порт должен быть числом.")
    if port < 1 or port > 65535:
        raise ValueError("Порт должен быть в диапазоне 1–65535.")
    return port


def tgproxy_link(domain: str, port: int, secret: str) -> str:
    return "tg://proxy?" + urlencode({"server": str(domain), "port": int(port), "secret": str(secret)})


def remote_tgproxy_install_script() -> str:
    firewall_block = """
if [ "${AUTO_FIREWALL}" = "1" ]; then
  if command -v ufw >/dev/null 2>&1; then
    ufw allow "${PORT}/tcp" >/dev/null 2>&1 || true
  fi
  if command -v firewall-cmd >/dev/null 2>&1; then
    firewall-cmd --add-port="${PORT}/tcp" --permanent >/dev/null 2>&1 || true
    firewall-cmd --reload >/dev/null 2>&1 || true
  fi
fi
""" if TELEGRAM_PROXY_AUTO_OPEN_FIREWALL else ""
    return f"""set -euo pipefail
VERSION="$1"
DOMAIN="$2"
PORT="$3"
AUTO_FIREWALL="$4"
export DEBIAN_FRONTEND=noninteractive
if command -v apt-get >/dev/null 2>&1; then
  apt-get update -y >/dev/null
  apt-get install -y ca-certificates curl git make golang-go >/dev/null
elif command -v dnf >/dev/null 2>&1; then
  dnf install -y ca-certificates curl git make golang >/dev/null
elif command -v yum >/dev/null 2>&1; then
  yum install -y ca-certificates curl git make golang >/dev/null
else
  echo "unsupported package manager: install Go/git manually" >&2
  exit 20
fi
export GOPATH="${{GOPATH:-/root/go}}"
export PATH="/usr/local/go/bin:${{GOPATH}}/bin:/usr/local/bin:/usr/bin:/bin:$PATH"
GOBIN=/usr/local/bin go install "github.com/9seconds/mtg/v2@${{VERSION}}"
test -x /usr/local/bin/mtg
SECRET="$(/usr/local/bin/mtg generate-secret --hex "$DOMAIN" | tail -n 1 | tr -d '[:space:]')"
if ! echo "$SECRET" | grep -Eq '^ee[0-9a-fA-F]+$'; then
  echo "bad secret generated: $SECRET" >&2
  exit 22
fi
umask 077
cat > /etc/mtg.env <<EOF_MTG
MTG_SECRET=$SECRET
MTG_PORT=$PORT
MTG_DOMAIN=$DOMAIN
EOF_MTG
cat > /etc/systemd/system/mtg.service <<'EOF_SERVICE'
[Unit]
Description=mtg - MTProto proxy server
Documentation=https://github.com/9seconds/mtg
After=network.target

[Service]
EnvironmentFile=/etc/mtg.env
ExecStart=/usr/local/bin/mtg simple-run 0.0.0.0:${{MTG_PORT}} ${{MTG_SECRET}}
Restart=always
RestartSec=3
LimitNOFILE=65536
AmbientCapabilities=CAP_NET_BIND_SERVICE

[Install]
WantedBy=multi-user.target
EOF_SERVICE
systemctl daemon-reload
systemctl enable mtg >/dev/null
systemctl restart mtg >/dev/null
{firewall_block}
sleep 1
systemctl is-active --quiet mtg
echo "TGPROXY_SECRET=$SECRET"
echo "TGPROXY_DOMAIN=$DOMAIN"
echo "TGPROXY_PORT=$PORT"
echo "TGPROXY_VERSION=$(/usr/local/bin/mtg --version 2>&1 | head -n 1 || true)"
"""


def remote_tgproxy_uninstall_script() -> str:
    return """set -euo pipefail
systemctl disable --now mtg >/dev/null 2>&1 || true
rm -f /etc/systemd/system/mtg.service /etc/mtg.env
systemctl daemon-reload >/dev/null 2>&1 || true
echo "TGPROXY_REMOVED=1"
"""


def remote_tgproxy_check_script(port: int | None = None) -> str:
    port_line = f"PORT={int(port)}" if port else "PORT=0"
    return f"""set -euo pipefail
{port_line}
echo "active=$(systemctl is-active mtg 2>/dev/null || true)"
echo "enabled=$(systemctl is-enabled mtg 2>/dev/null || true)"
echo "version=$(/usr/local/bin/mtg --version 2>&1 | head -n 1 || true)"
if [ -f /etc/mtg.env ]; then
  echo "config=present"
else
  echo "config=missing"
fi
if command -v ss >/dev/null 2>&1 && [ "$PORT" -gt 0 ]; then
  LISTEN="$(ss -ltn | grep -E ":${{PORT}}( |$)" | head -n 1 || true)"
  echo "listen=$LISTEN"
fi
"""


def remote_tgproxy_install_blocking(nodes_cfg: dict, node: dict, *, domain: str, port: int, mtg_version: str | None = None) -> dict:
    clean_domain = validate_tgproxy_domain(domain)
    clean_port = validate_tgproxy_port(port)
    install_version, install_label = normalize_mtg_version(mtg_version or TELEGRAM_PROXY_MTG_VERSION)
    p = remote_ssh_run(
        nodes_cfg,
        node,
        "bash -s -- " + " ".join([
            shlex.quote(install_version),
            shlex.quote(clean_domain),
            shlex.quote(str(clean_port)),
            shlex.quote("1" if TELEGRAM_PROXY_AUTO_OPEN_FIREWALL else "0"),
        ]),
        input_text=remote_tgproxy_install_script(),
        timeout=900,
    )
    stdout = str(p.stdout or "")
    m = re.search(r"TGPROXY_SECRET=(\S+)", stdout)
    if not m:
        raise RuntimeError("mtg installed, but secret was not returned. STDOUT:\n" + stdout[-1200:])
    secret = m.group(1).strip()
    return {
        "title": tgproxy_title_for_node(node),
        "url": tgproxy_link(clean_domain, clean_port, secret),
        "domain": clean_domain,
        "port": clean_port,
        "secret_hash": hashlib.sha256(secret.encode("utf-8")).hexdigest(),
        "stdout": stdout,
        "mtg_version": install_version,
        "mtg_version_label": install_label,
    }


async def remote_tgproxy_install_for_node(node_id: str, *, domain: str, port: int, mtg_version: str | None = None) -> dict:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    node = remote_admin_get_node(nodes_cfg, node_id)
    if not node:
        raise RuntimeError("Node не найдена")
    result = await asyncio.to_thread(remote_tgproxy_install_blocking, nodes_cfg, node, domain=domain, port=port, mtg_version=mtg_version)
    if TELEGRAM_PROXY_AUTO_ADD_TO_USER_MENU:
        await upsert_managed_telegram_proxy(
            node_id=node_id,
            node_code=tgproxy_code_from_node(node),
            title=result["title"],
            url=result["url"],
            domain=result["domain"],
            port=int(result["port"]),
            secret_hash=result["secret_hash"],
            mtg_version=result.get("mtg_version_label") or mtg_version_label(mtg_version),
        )
    return result


async def remote_tgproxy_check_for_node(node_id: str) -> tuple[bool, str]:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    node = remote_admin_get_node(nodes_cfg, node_id)
    if not node:
        raise RuntimeError("Node не найдена")
    row = await get_managed_telegram_proxy_by_node(node_id, include_disabled=True)
    port = int(row["port"] or 0) if row and row["port"] is not None else None
    p = await asyncio.to_thread(remote_ssh_run, nodes_cfg, node, "bash -s", input_text=remote_tgproxy_check_script(port), timeout=60, check=False)
    ok = p.returncode == 0 and "active=active" in str(p.stdout or "")
    output = (str(p.stdout or "") + str(p.stderr or "")).strip()
    await mark_managed_telegram_proxy_check(node_id, ok=ok, error="" if ok else output[-1000:])
    return ok, output or "нет вывода"


async def remote_tgproxy_uninstall_for_node(node_id: str) -> str:
    nodes_cfg = remote_load_nodes_config()
    if not nodes_cfg:
        raise RuntimeError("nodes.json недоступен")
    node = remote_admin_get_node(nodes_cfg, node_id)
    if not node:
        raise RuntimeError("Node не найдена")
    p = await asyncio.to_thread(remote_ssh_run, nodes_cfg, node, "bash -s", input_text=remote_tgproxy_uninstall_script(), timeout=120, check=False)
    await disable_managed_telegram_proxy(node_id, error="removed by admin")
    return (str(p.stdout or "") + str(p.stderr or "")).strip()


