    if not row:
        return remote_tgproxy_setup_text(node)
    enabled = "включена" if int(row["enabled"] or 0) else "выключена"
    last_error = str(row["last_error"] or "") if "last_error" in row.keys() else ""
    try:
        configured_version = str(row["mtg_version"] or TELEGRAM_PROXY_MTG_VERSION_LABEL)
    except Exception:
        configured_version = TELEGRAM_PROXY_MTG_VERSION_LABEL
    return (
        "💎 TG PROXY на node\n"
        "━━━━━━━━━━━━━━\n"
        f"Node: {nid}\n"
        f"Статус записи: {enabled}\n"
        f"Название: {row['title']}\n"
        f"Домен/SNI: {row['domain'] or '—'}\n"
        f"Порт: {row['port'] or '—'}\n"
        f"Версия mtg: {configured_version}\n"
        f"Установлен: {payment_dt_text(row['installed_at'] or 0)}\n"
        f"Последняя проверка: {payment_dt_text(row['last_check_at'] or 0)}\n"
        + (f"Ошибка: {last_error[:700]}\n" if last_error else "")
        + "━━━━━━━━━━━━━━\n"
        "Переустановка создаёт новый secret, перезапускает mtg и обновляет ссылку в 💎 Telegram proxy. "
        "Если проверка binary reports `dev`, смотри configured version выше."
    )


