def remote_admin_node_add_help_text(example: str) -> str:
    return (
        "➕ Добавить новую VPS / node\n\n"
        "Это мастер добавления новой VPS в nodes.json. Сначала бот только сохранит запись, "
        "а потом подготовит сервер кнопкой 🚀 Подготовить VPS (bootstrap).\n\n"
        "Что нужно сделать перед добавлением:\n"
        "1. Создать VPS и получить IP + временный root-пароль.\n"
        "2. В Cloudflare/DNS создать запись, например se1 → IP новой VPS.\n"
        "3. Скопировать JSON ниже, заменить свои значения и отправить его одним сообщением.\n"
        "4. Открыть созданную VPS-локацию и нажать 🚀 Подготовить VPS (bootstrap).\n"
        "5. После старта не нажимать bootstrap повторно. Для контроля использовать 🔍 Проверить эту VPS.\n\n"
        "Что реально заполняет админ:\n"
        "• id — короткий уникальный ID node, например se1, fr1, uk1. После запуска лучше не менять.\n"
        "• display_name — название в VPN-ссылках, например 🇸🇪 SE.\n"
        "• host — IP новой VPS для SSH.\n"
        "• domain — домен для VPN-ссылок, например se1.astramind.dpdns.org. DNS уже должен вести на host.\n"
        "• ssh.password — временный root-пароль от новой VPS. После bootstrap бот удалит его из nodes.json.\n\n"
        "Что обычно НЕ менять:\n"
        "• enabled: false — правильно. Бот сам включит node только после успешного bootstrap/deploy.\n"
        "• bootstrap: true — правильно. Это команда подготовить VPS через временный root-пароль.\n"
        "• maintenance: true — правильно. Пока VPS не готова, она не выдаётся пользователям.\n"
        "• include_in_paid: true — node будет участвовать в платных подписках после successful deploy.\n"
        "• локации теста настраиваются в 🎁 Тестовый доступ → 🌍 Локации теста.\n"
        "• ssh.user / ssh.port — обычно root и 22.\n"
        "• ssh.key_path — оставь /opt/bot-sui/keys/nodes_ed25519.\n"
        "• vless.sni — Reality-маскировка, например www.microsoft.com, www.apple.com или www.cloudflare.com. Это не обязан быть домен node.\n"
        "• hysteria2.sni и tuic.sni — лучше ставить domain этой node.\n"
        "• порты — VLESS 443/TCP, HY2 443/UDP, TUIC 8443/UDP. VLESS и HY2 могут оба быть 443, потому что TCP и UDP разные.\n\n"
        "Что бот сам добавит после bootstrap:\n"
        "• Reality private_key/public_key и short_id.\n"
        "• HY2 obfs_password, если obfs_type=salamander.\n"
        "• placeholder credentials для пустого sing-box config.\n"
        "• Удалит ssh.password из nodes.json.\n"
        "• Поставит enabled=true и maintenance=false только если VPS реально готова.\n\n"
        "Главное правило: ссылки этой VPS появятся в подписках только после successful deploy и active sing-box.\n"
        "Для отмены отправьте '-'.\n\n"
        f"Готовый оптимальный шаблон для копирования:\n```json\n{example}\n```"
    )

def remote_admin_status_text(snapshot: dict) -> str:
    nodes_cfg = snapshot.get("nodes_cfg")
    enabled_nodes = snapshot.get("enabled_nodes") or []
    state = snapshot.get("state") or {}
    all_nodes = [n for n in (nodes_cfg or {}).get("nodes", []) if isinstance(n, dict)] if nodes_cfg else []
    lines = [
        "🌍 Локации / VPS-node",
        "",
        f"Remote-модуль: {'включён' if REMOTE_NODES_ENABLED else 'выключен'}",
        f"Файл nodes.json: {REMOTE_NODES_FILE}",
        f"Параллельный деплой: до {REMOTE_NODES_DEPLOY_PARALLELISM} локаций одновременно",
        f"Задержка batching перед sync: {REMOTE_NODES_SYNC_DEBOUNCE_SECONDS:g} сек.",
        f"Авто-sync локаций: каждые {REMOTE_NODES_SYNC_INTERVAL_SECONDS} сек.",
        "",
        "Защитные блокировки в generated config:",
        f"• {remote_policy_short_text()}",
        "",
        f"Активных paid-подписок: {len(snapshot.get('active_paid') or [])}",
        f"Учётных данных клиентов для node в SQLite: {snapshot.get('credentials_count', 0)}",
        f"Записей истории sync по клиентам: {snapshot.get('sync_rows', 0)}",
        f"Тестовых node-credentials: {snapshot.get('test_credentials_count', 0)}",
        f"Последнее состояние nodes: {payment_dt_text(snapshot.get('last_state_ts') or 0)}",
    ]
    last_audit = snapshot.get("last_audit") or {}
    if last_audit:
        lines += [
            f"Последний sync: {remote_admin_status_label(str(last_audit.get('status') or '—'))} · {payment_dt_text(last_audit.get('created_at') or 0)} · {float(last_audit.get('elapsed_seconds') or 0):.2f} сек.",
            f"Причина: {str(last_audit.get('reason') or '—')[:120]}",
        ]
    lines += [
        "",
        f"Локаций всего: {len(all_nodes)} · активных для deploy: {len(enabled_nodes)}",
    ]
    if not nodes_cfg:
        lines.append("• nodes.json недоступен")
    elif not all_nodes:
        lines.append("• локаций в nodes.json нет")
    else:
        for node in all_nodes:
            nid = str(node.get("id") or "?")
            st = state.get(nid) or {}
            status = remote_admin_node_status_label(node, st)
            deployed = int(st.get("deployed_client_count") or 0)
            err = str(st.get("last_error") or "").strip()
            ok_at = payment_dt_text(st.get("last_ok_at") or 0)
            display = str(node.get("display_name") or nid.upper())
            domain = str(node.get("domain") or node.get("host") or "—")
            line = f"• {nid} · {display} · {status} · {domain} · клиентов {deployed} · последний OK {ok_at}"
            if err:
                line += f" · ошибка: {err[:80]}"
            lines.append(line)
    return "\n".join(lines)


def remote_admin_audit_rows_text(rows: list[dict], *, page: int = 0, total: int = 0) -> str:
    total_pages = max(1, (max(0, total) + REMOTE_ADMIN_AUDIT_PAGE_SIZE - 1) // REMOTE_ADMIN_AUDIT_PAGE_SIZE)
    current_page = min(max(0, int(page)), total_pages - 1)
    lines = [
        "🧾 Журнал синхронизации локаций",
        f"За последние {REMOTE_ADMIN_AUDIT_HOURS} часа · страница {current_page + 1}/{total_pages} · всего: {total}",
        "",
    ]
    if not rows:
        lines.append("За последние 24 часа sync-событий нет.")
        return "\n".join(lines)
    for row in rows:
        status = str(row.get("status") or "unknown")
        reason = str(row.get("reason") or "—")[:80]
        ts_text = payment_dt_text(row.get("created_at") or 0)
        elapsed = float(row.get("elapsed_seconds") or 0)
        ok_nodes = remote_json_maybe_loads(row.get("ok_nodes_json"), [])
        failed_nodes = remote_json_maybe_loads(row.get("failed_nodes_json"), [])
        error = str(row.get("error") or "").strip()
        lines.append(
            f"#{int(row.get('id') or 0)} · {status} · {ts_text} · {elapsed:.2f}s\n"
            f"Причина: {reason}\n"
            f"Клиенты: {int(row.get('active_clients') or 0)} · OK nodes: {','.join(ok_nodes) or '—'} · Ошибки: {','.join(failed_nodes) or '—'}\n"
            f"Ссылки: обновлено {int(row.get('links_updated') or 0)} / очищено {int(row.get('links_cleaned') or 0)} / ошибок {int(row.get('links_failed') or 0)}"
        )
        if error:
            lines.append(f"Ошибка: {error[:160]}")
        lines.append("")
    return "\n".join(lines).strip()


async def remote_admin_audit_text(page: int = 0) -> tuple[str, int, int]:
    safe_page = max(0, int(page))
    rows, total = await remote_list_sync_audit(
        limit=REMOTE_ADMIN_AUDIT_PAGE_SIZE,
        offset=safe_page * REMOTE_ADMIN_AUDIT_PAGE_SIZE,
        hours=REMOTE_ADMIN_AUDIT_HOURS,
    )
    total_pages = max(1, (max(0, total) + REMOTE_ADMIN_AUDIT_PAGE_SIZE - 1) // REMOTE_ADMIN_AUDIT_PAGE_SIZE)
    if safe_page >= total_pages:
        safe_page = total_pages - 1
        rows, total = await remote_list_sync_audit(
            limit=REMOTE_ADMIN_AUDIT_PAGE_SIZE,
            offset=safe_page * REMOTE_ADMIN_AUDIT_PAGE_SIZE,
            hours=REMOTE_ADMIN_AUDIT_HOURS,
        )
    return remote_admin_audit_rows_text(rows, page=safe_page, total=total), safe_page, total_pages


def remote_admin_audit_keyboard(page: int = 0, total_pages: int = 1) -> InlineKeyboardMarkup:
    page = max(0, int(page))
    total_pages = max(1, int(total_pages))
    rows = []
    nav = []
    if page > 0:
        nav.append(InlineKeyboardButton(text="← Назад", callback_data=f"admin:remote:audit:{page - 1}"))
    if page + 1 < total_pages:
        nav.append(InlineKeyboardButton(text="Вперёд →", callback_data=f"admin:remote:audit:{page + 1}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton(text="🔄 Обновить", callback_data=f"admin:remote:audit:{page}")])
    rows.append([InlineKeyboardButton(text="← К локациям", callback_data="admin:remote")])
    return InlineKeyboardMarkup(inline_keyboard=rows)



def remote_admin_faq_text(page: int = 1) -> str:
    """Paged FAQ for remote nodes. Keep every page under Telegram message limit."""
    line = "━━━━━━━━━━━━━━"
    page = max(1, min(3, int(page or 1)))
    if page == 1:
        return (
            "❓ FAQ по локациям · 1/3\n"
            f"{line}\n"
            "Локации — это отдельные VPS, на которые бот ставит sing-box и добавляет пользователю прямые VPN-ссылки. S-UI на MAIN остаётся источником подписки: срок, enable, тариф и трафик MAIN/Double VPN.\n\n"
            "Главная логика\n"
            "• Пользователь покупает тариф → клиент создаётся в S-UI → бот создаёт credentials для node → deploy на выбранные локации тарифа → ссылки попадают в подписку.\n"
            "• Если тариф не включает локацию, клиента не будет в config этой VPS и ссылки этой VPS не будет в подписке.\n"
            "• Тестовые подписки сейчас main-only, если отдельно не включить trial remote в config.\n\n"
            "Главные кнопки\n"
            "• 🔄 Синхронизировать все локации — пересобрать config на всех активных VPS и обновить ссылки подписок.\n"
            "• 🧪 Обновить статус без deploy — перечитать состояние, ничего не меняя на VPS.\n"
            "• 🖥 Управление VPS-локациями — список VPS из nodes.json.\n"
            "• 🧹 Клиенты на локациях — remote credentials и sync-state по клиентам.\n"
            "• 🧾 Журнал синхронизации — история sync/deploy событий.\n\n"
            "💎 TG PROXY\n"
            "• Это отдельный Telegram-прокси на VPS. Он помогает Telegram подключаться, но не заменяет VPN-подписку.\n"
            "• Auto-managed proxy от node обновляется в существующей записи, а не создаёт дубли."
        )
    if page == 2:
        return (
            "❓ FAQ по локациям · 2/3\n"
            f"{line}\n"
            "Статусы VPS\n"
            "• Включена для deploy — бот может заливать config на эту VPS.\n"
            "• Обслуживание / maintenance — VPS временно исключена из deploy и подписок.\n"
            "• Drain — мягко убрать ссылки этой VPS из подписок, но продолжать держать config под контролем.\n"
            "• Доступна для платных тарифов — глобальный рубильник. Если он выключен, ни один тариф не выдаст эту VPS.\n"
            "• Локации тарифа — второй фильтр поверх глобального рубильника node.\n\n"
            "Сверка и восстановление\n"
            "• 🔁 Сверка локаций и ссылок — read-only: ничего не меняет, только сравнивает S-UI, SQLite, node config и реальные subscription links.\n"
            "• Нет node-credentials — активный клиент должен быть на node, но у бота нет UUID/password для deploy.\n"
            "• Клиент должен быть на VPS, но его нет в node config — обычно помогает sync/deploy, если VPS доступна по SSH.\n"
            "• Лишний клиент на VPS — user есть в config, но тариф/S-UI уже не требует его там. Обычно исправляет sync.\n"
            "• Проблемы со ссылками — config может быть правильный, но ссылки в подписке не совпадают. Тогда используй 🔗 Восстановить ссылки локаций.\n"
            "• Если VPS не читается по SSH, это отдельная ошибка. В таком случае missing/ghost по этой VPS не считается, пока SSH не восстановится."
        )
    return (
        "❓ FAQ по локациям · 3/3\n"
        f"{line}\n"
        "Опасные действия\n"
        "• 🚀 Подготовить VPS (bootstrap) — первичная установка sing-box, certs, firewall, collector и ключей. После успешного bootstrap VPS включается сама.\n"
        "• 🧨 Полная очистка VPS — удаляет sing-box/mtg/collector/config с VPS, но сохраняет SSH-доступ. После неё нужен новый bootstrap.\n"
        "• 🔐 Перегенерировать Reality/HY2 ключи — меняет параметры ссылок этой VPS. Использовать только при необходимости.\n"
        "• 🗑 Удалить VPS из nodes.json — удаляет запись в боте, но не удаляет сам сервер.\n\n"
        "Node antiabuse\n"
        "• Collector на VPS читает локальный journalctl sing-box и делает summary. MAIN забирает только маленькую сводку.\n"
        "• Один и тот же IP на разных локациях считается один раз. Нарушение — разные активные IP сверх лимита тарифа.\n"
        "• Диагностика логов Antiabuse отправляет TXT-файл, чтобы не упираться в лимит Telegram.\n\n"
        "Порядок добавления новой VPS\n"
        "1. Добавь VPS-локацию в nodes.json.\n"
        "2. Нажми 🚀 Подготовить VPS.\n"
        "3. Нажми 🔍 Проверить эту VPS.\n"
        "4. Запусти sync.\n"
        "5. Проверь 🔁 Сверка локаций и ссылок."
    )

