def remote_admin_is_paid_like_client(client: dict) -> bool:
    desc = str(client.get("desc") or "")
    name = str(client.get("name") or "")
    if not name:
        return False
    if re.search(r"\bTEST\b", desc, flags=re.IGNORECASE):
        return False
    m = re.search(r"\bPLAN=([^\s]+)", desc)
    plan_raw = str(m.group(1) if m else "").strip()
    plan_key = plan_raw.rsplit("_", 1)[0].lower() if "_" in plan_raw else plan_raw.lower()
    if plan_key == "test":
        return False
    # New client names are configurable and no longer have to start with OriginalVPN-.
    # Treat S-UI clients with bot metadata as paid-like, while keeping old names compatible.
    return bool(plan_raw or parse_tgid_from_desc(desc) or name.startswith("OriginalVPN-"))


def remote_admin_client_matches_query(client: dict, query: str) -> bool:
    raw = str(query or "").strip().lower()
    if not raw:
        return True
    haystack = " ".join([
        str(client.get("id") or ""),
        str(client.get("name") or ""),
        str(client.get("desc") or ""),
        str(extract_tgid_from_client(client) or ""),
        str(parse_username_from_desc(str(client.get("desc") or "")) or ""),
        str(parse_plan_key_from_desc(str(client.get("desc") or "")) or ""),
    ]).lower()
    return raw in haystack


def remote_admin_filter_clients(clients: list[dict], *, query: str = "", filter_mode: str = "all") -> list[dict]:
    paid_like = [c for c in clients if remote_admin_is_paid_like_client(c)]
    if filter_mode == "enabled":
        paid_like = [c for c in paid_like if bool(c.get("enable", True))]
    elif filter_mode == "disabled":
        paid_like = [c for c in paid_like if not bool(c.get("enable", True))]
    if query:
        paid_like = [c for c in paid_like if remote_admin_client_matches_query(c, query)]
    paid_like.sort(key=lambda c: (0 if bool(c.get("enable", True)) else 1, -int(c.get("id") or 0)))
    return paid_like


def remote_admin_clients_keyboard(clients: list[dict], *, page: int = 0, filter_mode: str = "all", query: str = "") -> InlineKeyboardMarkup:
    safe_page = max(0, int(page))
    total_pages = max(1, (len(clients) + REMOTE_ADMIN_CLIENTS_PAGE_SIZE - 1) // REMOTE_ADMIN_CLIENTS_PAGE_SIZE)
    if safe_page >= total_pages:
        safe_page = total_pages - 1
    start = safe_page * REMOTE_ADMIN_CLIENTS_PAGE_SIZE
    page_items = clients[start:start + REMOTE_ADMIN_CLIENTS_PAGE_SIZE]
    rows = [
        [
            InlineKeyboardButton(text=("✅ Все" if filter_mode == "all" else "Все"), callback_data="admin:remote:clients:0:all"),
            InlineKeyboardButton(text=("✅ Вкл" if filter_mode == "enabled" else "Вкл"), callback_data="admin:remote:clients:0:enabled"),
            InlineKeyboardButton(text=("✅ Выкл" if filter_mode == "disabled" else "Выкл"), callback_data="admin:remote:clients:0:disabled"),
        ],
        [InlineKeyboardButton(text="🔎 Поиск", callback_data="admin:remote:clients_search")],
    ]
    if query:
        rows.append([InlineKeyboardButton(text=f"✖️ Сбросить поиск: {query[:24]}", callback_data=f"admin:remote:clients_clear:{filter_mode}")])
    for client in page_items:
        cid = int(client.get("id") or 0)
        if cid <= 0:
            continue
        name = str(client.get("name") or "unknown")
        plan = parse_plan_key_from_desc(str(client.get("desc") or "")) or "—"
        username = parse_username_from_desc(str(client.get("desc") or "")) or ""
        enabled = "🟢" if client.get("enable", True) else "⚫"
        label_user = username if username else f"id {cid}"
        rows.append([InlineKeyboardButton(text=f"{enabled} {plan} · {label_user} · {name[-6:]}", callback_data=f"admin:remote:client:{cid}:{safe_page}:{filter_mode}")])
    nav = []
    if safe_page > 0:
        nav.append(InlineKeyboardButton(text="← Назад", callback_data=f"admin:remote:clients:{safe_page - 1}:{filter_mode}"))
    if safe_page + 1 < total_pages:
        nav.append(InlineKeyboardButton(text="Вперёд →", callback_data=f"admin:remote:clients:{safe_page + 1}:{filter_mode}"))
    if nav:
        rows.append(nav)
    rows.append([InlineKeyboardButton(text="🔄 Обновить", callback_data=f"admin:remote:clients:{safe_page}:{filter_mode}")])
    rows.append([InlineKeyboardButton(text="← К локациям", callback_data="admin:remote")])
    return InlineKeyboardMarkup(inline_keyboard=rows)


def remote_admin_clients_text(clients: list[dict], *, all_count: int, page: int = 0, filter_mode: str = "all", query: str = "") -> str:
    total_pages = max(1, (len(clients) + REMOTE_ADMIN_CLIENTS_PAGE_SIZE - 1) // REMOTE_ADMIN_CLIENTS_PAGE_SIZE)
    safe_page = min(max(0, int(page)), total_pages - 1)
    enabled_count = len([c for c in clients if c.get("enable", True)])
    disabled_count = len([c for c in clients if not c.get("enable", True)])
    filter_label = {"all": "все", "enabled": "включённые", "disabled": "выключенные"}.get(filter_mode, filter_mode)
    lines = [
        "🧹 Клиенты на локациях",
        "",
        f"Фильтр: {filter_label}",
        f"Поиск: {query or '—'}",
        f"Страница: {safe_page + 1}/{total_pages}",
        f"Найдено: {len(clients)} из {all_count}",
        f"В этой выборке: включены {enabled_count} / выключены {disabled_count}",
        "",
        "Кнопка внутри клиента очищает только node-данные: managed links, remote credentials/state и затем ставит sync в очередь. S-UI подписка и данные бота не отключаются.",
    ]
    if not clients:
        lines.append("\nКлиентов нет.")
    return "\n".join(lines)


