async def remote_delete_local_state(client_name: str) -> None:
    name = str(client_name or "").strip()
    if not name:
        return
    async with db_connect(DATABASE_DB) as conn:
        await conn.execute("DELETE FROM remote_client_credentials WHERE client_name=?", (name,))
        await conn.execute("DELETE FROM remote_client_sync WHERE client_name=?", (name,))
        await conn.commit()


async def remote_admin_clean_remote_state(client_id: int) -> dict:
    client = await get_client_by_id(int(client_id))
    if not client:
        raise RuntimeError("Клиент не найден в S-UI")
    name = str(client.get("name") or "").strip()
    if not name:
        raise RuntimeError("У клиента пустой name")
    if not remote_admin_is_paid_like_client(client):
        raise RuntimeError("Это не paid-клиент или это test-клиент")

    nodes_cfg = remote_load_nodes_config() or {}
    prepared = (await remote_prepare_clients([client]))[0]
    current_links = remote_client_links(prepared)
    preserved_links = [link for link in current_links if not remote_is_managed_link(link, nodes_cfg)]
    cleaned_links = max(0, len(current_links) - len(preserved_links))
    # Rewrite even when /clients reports zero links: S-UI may still keep external rows
    # visible in the panel/subscription. Full edit with preserved links is the canonical
    # way to wipe managed remote links before issuing fresh credentials.
    await remote_post_sui_client_links(prepared, preserved_links)
    invalidate_sui_clients_cache()

    await remote_delete_local_state(name)

    new_uuid = str(uuid.uuid4())
    new_password = generate_secret_password(16)
    new_config = remote_build_full_client_config_from_credentials(name, new_uuid, new_password, "xtls-rprx-vision")
    desc = str(client.get("desc") or "")
    await remote_save_client_credentials(
        client_name=name,
        client_id=int(client.get("id") or 0) or None,
        user_id=extract_tgid_from_client(client),
        username=parse_username_from_desc(desc).lstrip("@") or None,
        tariff_key=parse_plan_key_from_desc(desc) or None,
        uuid_value=new_uuid,
        password=new_password,
        flow="xtls-rprx-vision",
        config=new_config,
        is_test=False,
        source="admin_remote_clean",
    )
    remote_request_sync(reason=f"admin_clean_remote_client:{name}", client_name=name)
    return {"name": name, "cleaned_links": cleaned_links, "new_uuid": new_uuid}



