def random_suffix(length: int = 4) -> str:
    alphabet = string.ascii_lowercase + string.digits
    return "".join(secrets.choice(alphabet) for _ in range(length))


def generate_secret_password(length: int = 10) -> str:
    alphabet = string.ascii_letters + string.digits
    return "".join(secrets.choice(alphabet) for _ in range(length))


def build_desc(user_id: int, username: str | None, tarif_key: str, server_code: str, is_test: bool = False) -> str:
    desc = f"TGID={int(user_id)}"
    if username:
        desc += f" @{username}"
    desc += f" PLAN={tarif_key}_{server_code}"
    if is_test:
        desc += " TEST"
    return desc




def apply_period_marker_to_desc(desc: str, period: TariffPeriod | None) -> str:
    raw = str(desc or "").strip()
    raw = re.sub(r"\s+PERIOD=[A-Za-z0-9_-]+\b", "", raw).strip()
    raw = re.sub(r"\s+PERIOD_DAYS=\d+\b", "", raw).strip()
    raw = re.sub(r"\s{2,}", " ", raw).strip()
    if period is None:
        return raw
    key = re.sub(r"[^A-Za-z0-9_-]+", "", str(period.period_key or "base"))[:24] or "base"
    try:
        days = max(1, int(period.days))
    except Exception:
        days = 30
    suffix = f"PERIOD={key} PERIOD_DAYS={days}"
    return (raw + " " + suffix).strip() if raw else suffix


def parse_period_days_from_desc(desc: str) -> int | None:
    m = re.search(r"\bPERIOD_DAYS=(\d+)\b", str(desc or ""))
    if not m:
        return None
    try:
        days = int(m.group(1))
        return days if days > 0 else None
    except Exception:
        return None


def parse_period_key_from_desc(desc: str) -> str:
    m = re.search(r"\bPERIOD=([A-Za-z0-9_-]+)\b", str(desc or ""))
    return str(m.group(1)) if m else ""


def tariff_period_from_desc(desc: str, tariff: Tariff | None) -> TariffPeriod | None:
    if not tariff:
        return None
    key = parse_period_key_from_desc(desc)
    if key:
        period = tariff_period_by_key(tariff, key)
        if period:
            return period
    days = parse_period_days_from_desc(desc)
    if days:
        return TariffPeriod(
            tariff_key=str(tariff.key),
            period_key=key or f"{days}d",
            title=f"{days} дн.",
            days=int(days),
            stars_price=max(0, int(tariff.stars_price or 0)),
            rub_price=max(0, int(tariff.rub_price or 0)),
            enabled=True,
            is_default=False,
            sort_order=0,
            is_base=False,
        )
    return None

def parse_tgid_from_desc(desc: str) -> int | None:
    marker = "TGID="
    if marker not in (desc or ""):
        return None
    try:
        raw = (desc.split(marker, 1)[1]).split()[0]
        return int(raw)
    except Exception:
        return None


def extract_tgid_from_client(client: dict | None) -> int | None:
    if not client:
        return None
    desc_tgid = parse_tgid_from_desc(str(client.get("desc") or ""))
    if desc_tgid:
        return int(desc_tgid)
    tg_id_raw = str(client.get("tgId") or "").strip()
    if tg_id_raw.isdigit():
        return int(tg_id_raw)
    return None


def parse_username_from_desc(desc: str) -> str:
    m = re.search(r"TGID=\d+\s+(@[A-Za-z0-9_]+)", desc or "")
    return str(m.group(1) if m else "")


def parse_plan_key_from_desc(desc: str) -> str:
    marker = "PLAN="
    if marker not in (desc or ""):
        return ""
    raw = (desc.split(marker, 1)[1]).split()[0].strip()
    if not raw:
        return ""

    # Новый формат: PLAN=<tariff_key>_<server_code>
    # Но для старых/переходных подписок нужно не терять исходный ключ,
    # если обрезанный вариант не соответствует реальному тарифу.
    suffix = f"_{SUI_SERVER_CODE}"
    if raw.endswith(suffix):
        candidate = raw[: -len(suffix)]
        if candidate:
            try:
                if get_tariff_base(candidate) is not None or get_tariff_override(candidate) is not None:
                    return candidate
            except Exception:
                return candidate

    try:
        if get_tariff_base(raw) is not None or get_tariff_override(raw) is not None:
            return raw
    except Exception:
        pass

    # Fallback для старых подписок, где серверный код был последним сегментом
    if "_" in raw:
        return raw.rsplit("_", 1)[0]
    return raw


def tariff_title_by_key(plan_key: str | None) -> str:
    raw = str(plan_key or "").strip()
    if not raw:
        return "без плана"
    tariff = get_tariff(raw)
    if tariff:
        return str(tariff.title or raw)
    return raw


def subscription_display_title(item: dict) -> str:
    title = str(item.get("plan_title") or "").strip()
    if title:
        return title
    return tariff_title_by_key(str(item.get("plan_key") or ""))


def subscription_display_name(item: dict, *, with_expiry: bool = False) -> str:
    title = subscription_display_title(item)
    if with_expiry:
        expiry_text = str(item.get("expiry_text") or "").strip()
        if expiry_text and expiry_text != "—":
            return f"{title} · до {expiry_text}"
    return title


def subscription_double_vpn_enabled(item: dict) -> bool:
    plan_key = str((item or {}).get("plan_key") or "").strip()
    tariff = get_tariff(plan_key) if plan_key else None
    if tariff is None:
        return True
    return tariff_double_vpn_enabled(tariff)

def tariff_double_vpn_lines(tariff: Tariff, *, include_traffic: bool = True, period: TariffPeriod | None = None) -> list[str]:
    if tariff_double_vpn_enabled(tariff):
        lines = ["Double VPN: доступен"]
        if include_traffic:
            lines.insert(0, f"Лимит трафика Double VPN: {tariff_main_traffic_limit_text(tariff, period)}")
        return lines
    return ["Double VPN: недоступен"]


CLIENT_NAME_PART_RE = re.compile(r"[^A-Za-z0-9_-]+")


def client_name_part(value: str | None, fallback: str = "srv") -> str:
    """Safe technical part for S-UI client names and subscription links.

    server_code is admin-configurable, so it must not contain spaces/emoji in
    the actual S-UI client name. server_name remains the human display name.
    """
    raw = str(value or "").strip()
    raw = CLIENT_NAME_PART_RE.sub("-", raw).strip("-_")
    return (raw or str(fallback or "srv"))[:40]


def make_client_name(server_code: str, tariff_key: str) -> str:
    # New format: <server_code>-<tariff>-<random>.
    # Example: MAIN-vip-a1b2 or OriginalVPN-test-ru4k.
    # Existing clients with old names like OriginalVPN-MAIN-vip-xxxx remain valid.
    return f"{client_name_part(server_code)}-{tariff_key_for_client_name(tariff_key)}-{random_suffix()}"


FLAG_COUNTRY_RU = {
    "🇳🇱": "Нидерланды", "🇵🇱": "Польша", "🇩🇪": "Германия", "🇫🇮": "Финляндия",
    "🇸🇪": "Швеция", "🇫🇷": "Франция", "🇬🇧": "Великобритания", "🇺🇸": "США",
    "🇨🇦": "Канада", "🇪🇸": "Испания", "🇮🇹": "Италия", "🇦🇹": "Австрия",
    "🇨🇭": "Швейцария", "🇳🇴": "Норвегия", "🇩🇰": "Дания",
}
CODE_COUNTRY_RU = {
    "NL": "Нидерланды", "PL": "Польша", "DE": "Германия", "FI": "Финляндия", "FL": "Финляндия",
    "SE": "Швеция", "FR": "Франция", "UK": "Великобритания", "GB": "Великобритания", "US": "США",
    "CA": "Канада", "ES": "Испания", "IT": "Италия", "AT": "Австрия", "CH": "Швейцария",
    "NO": "Норвегия", "DK": "Дания",
}


def public_location_name_from_node(node: dict) -> str:
    display = str((node or {}).get("display_name") or (node or {}).get("id") or "").strip()
    node_id = str((node or {}).get("id") or "").strip().upper()
    flag = ""
    m_flag = re.search(r"[🇦-🇿]{2}", display)
    if m_flag:
        flag = m_flag.group(0)
    country = FLAG_COUNTRY_RU.get(flag, "") if flag else ""
    if not country:
        tokens = re.findall(r"[A-Za-z]{2,3}", display.upper())
        for token in tokens + [node_id[:2], node_id[:3]]:
            if token in CODE_COUNTRY_RU:
                country = CODE_COUNTRY_RU[token]
                break
    if country and flag:
        return f"{flag} {country}"
    if country:
        return country
    if display:
        parts = display.split()
        if len(parts) >= 2 and re.fullmatch(r"[A-Za-z]{2,3}", parts[1]):
            return " ".join(parts[:2])
        return display
    return str((node or {}).get("id") or "Локация")


def public_location_names_for_paid(tariff: Tariff | None = None) -> list[str]:
    result: list[str] = []
    try:
        nodes_cfg = remote_load_nodes_config()
        if nodes_cfg:
            for node in remote_link_enabled_nodes(nodes_cfg):
                if not bool(node.get("include_in_paid", True)):
                    continue
                if not tariff_allows_remote_node(tariff, node):
                    continue
                name = public_location_name_from_node(node)
                if name and name not in result:
                    result.append(name)
    except Exception:
        logging.warning("failed to build public location list", exc_info=True)
    if not result and tariff is None:
        result = ["🇳🇱 Нидерланды", "🇵🇱 Польша", "🇩🇪 Германия"]
    return result


def public_locations_text(max_items: int = 8, tariff: Tariff | None = None) -> str:
    names = public_location_names_for_paid(tariff)
    lines = [f"• {name}" for name in names[:max_items]]
    if len(names) > max_items:
        lines.append(f"• ещё {len(names) - max_items} локац.")
    return "\n".join(lines) if lines else "• локации не выбраны"


def tariff_locations_text(tariff: Tariff, max_items: int = 8) -> str:
    return public_locations_text(max_items=max_items, tariff=tariff)


def subscription_links(client_name: str) -> tuple[str, str]:
    main_link = f"{SUI_SUB_URL}{quote(client_name, safe='')}"
    clash_link = f"{main_link}?format=clash"
    return main_link, clash_link


def bytes_from_gb(gb: int | None) -> int:
    return 0 if gb is None else int(gb) * 1024 * 1024 * 1024


def extract_clients(data: dict) -> list[dict]:
    if not isinstance(data, dict):
        return []
    obj = data.get("obj")
    if isinstance(obj, dict):
        clients = obj.get("clients")
        return clients if isinstance(clients, list) else []
    if isinstance(obj, list):
        return obj
    clients = data.get("clients")
    return clients if isinstance(clients, list) else []


def compute_subscription_stats(client: dict) -> tuple[int, str]:
    volume = int(client.get("volume") or 0)
    up = int(client.get("up") or 0)
    down = int(client.get("down") or 0)
    used = up + down
    expiry = int(client.get("expiry") or 0)
    now_ts = int(time.time())
    days_left = max(0, int((expiry - now_ts) / 86400)) if expiry > 0 else 0

    if volume == 0:
        traffic_text = f"{round(used / (1024**3), 2)} ГБ / ∞"
    else:
        used_gb = round(used / (1024**3), 2)
        volume_gb = round(volume / (1024**3), 2)
        traffic_text = f"{used_gb} / {volume_gb} ГБ"
    return days_left, traffic_text


def format_expiry(client: dict) -> str:
    expiry = int(client.get("expiry") or 0)
    if expiry <= 0:
        return "—"
    return datetime.fromtimestamp(expiry).strftime("%d.%m.%Y")


async def create_client(*, user_id: int, username: str | None, tariff: Tariff, is_test: bool = False, period: TariffPeriod | None = None) -> tuple[str, str, str]:
    period = period or tariff_base_period(tariff)
    expiry_sec = int(time.time()) + int(period.days) * 86400
    volume_bytes = bytes_from_gb(tariff.traffic_gb)

    client_name = make_client_name(SUI_SERVER_CODE, tariff.key)
    client_uuid = str(uuid.uuid4())
    secret_password = generate_secret_password(10)
    desc = build_desc(user_id=user_id, username=username, tarif_key=tariff.key, server_code=SUI_SERVER_CODE, is_test=is_test)
    desc = apply_period_marker_to_desc(desc, period)

    data_obj = {
        "enable": True,
        "name": client_name,
        "tgId": str(user_id),
        "config": {
            "mixed": {"username": client_name, "password": secret_password},
            "socks": {"username": client_name, "password": secret_password},
            "http": {"username": client_name, "password": secret_password},
            "shadowsocks": {"name": client_name, "password": secret_password},
            "shadowsocks16": {"name": client_name, "password": secret_password},
            "shadowtls": {"name": client_name, "password": secret_password},
            "vmess": {"name": client_name, "uuid": client_uuid, "alterId": 0},
            "vless": {"name": client_name, "uuid": client_uuid, "flow": "xtls-rprx-vision"},
            "anytls": {"name": client_name, "password": secret_password},
            "trojan": {"name": client_name, "password": secret_password},
            "naive": {"username": client_name, "password": secret_password},
            "hysteria": {"name": client_name, "auth_str": secret_password},
            "tuic": {"name": client_name, "uuid": client_uuid, "password": secret_password},
            "hysteria2": {"name": client_name, "password": secret_password},
        },
        "inbounds": tariff_sui_inbound_ids(tariff),
        "links": [],
        "volume": volume_bytes,
        "expiry": expiry_sec,
        "up": 0,
        "down": 0,
        "desc": desc,
        "group": normalize_sui_group_input(tariff.sui_group),
        "delayStart": False,
        **tariff_sui_traffic_reset_fields(tariff, period),
        "totalUp": 0,
        "totalDown": 0,
    }

    payload = {
        "object": "clients",
        "action": "new",
        "data": json.dumps(data_obj, ensure_ascii=False),
    }
    headers = {"Token": SUI_TOKEN, "Content-Type": "application/x-www-form-urlencoded"}

    session = await get_http_session()
    async with session.post(f"{SUI_API_URL}/save", data=urlencode(payload), headers=headers) as resp:
            raw_text = await resp.text()
            if resp.status != 200:
                raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
            result = json.loads(raw_text)
            if not result.get("success"):
                raise RuntimeError(f"S-UI error: {raw_text[:700]}")

    try:
        reset_result = await ensure_sui_client_traffic_reset(client_name, tariff, period=period)
        if not reset_result.get("verified") and tariff_double_vpn_reset_days(tariff) > 0:
            logging.warning("S-UI traffic reset not verified after create client=%s result=%s", client_name, reset_result)
    except Exception as exc:
        logging.warning("S-UI traffic reset ensure after create failed client=%s: %s", client_name, exc)

    if (not is_test) or trial_remote_locations_enabled():
        try:
            await remote_save_client_credentials(
                client_name=client_name,
                user_id=int(user_id),
                username=username,
                tariff_key=tariff.key,
                uuid_value=client_uuid,
                password=secret_password,
                flow="xtls-rprx-vision",
                config=data_obj["config"],
                is_test=bool(is_test),
                source="bot_create",
            )
        except Exception as exc:
            logging.warning("remote credentials save failed for %s: %s", client_name, exc)

    sub_link, clash_link = subscription_links(client_name)
    invalidate_sui_clients_cache()
    invalidate_user_subscription_flags_cache(user_id)
    return sub_link, clash_link, client_name


def invalidate_sui_clients_cache() -> None:
    global sui_cache_data, sui_cache_ts
    sui_cache_data = None
    sui_cache_ts = 0.0


async def get_all_clients(force_refresh: bool = False) -> list[dict]:
    global sui_cache_data, sui_cache_ts

    now_ts = time.time()

    # Fast path: fresh in-memory cache.
    async with sui_cache_lock:
        if not force_refresh and sui_cache_data is not None and (now_ts - sui_cache_ts) < SUI_CLIENTS_CACHE_SECONDS:
            return list(sui_cache_data)

    # Single-flight refresh: when many users open menus after cache expiry,
    # only one coroutine should hit S-UI /clients; the rest wait and reuse it.
    try:
        async with sui_refresh_lock:
            now_ts = time.time()
            async with sui_cache_lock:
                if not force_refresh and sui_cache_data is not None and (now_ts - sui_cache_ts) < SUI_CLIENTS_CACHE_SECONDS:
                    return list(sui_cache_data)

            headers = {"Token": SUI_TOKEN}
            session = await get_http_session()
            async with session.get(f"{SUI_API_URL}/clients", headers=headers) as resp:
                raw_text = await resp.text()
                if resp.status != 200:
                    raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
                data = json.loads(raw_text)

            fresh_data = list(extract_clients(data))
            fresh_ts = time.time()

            async with sui_cache_lock:
                sui_cache_data = fresh_data
                sui_cache_ts = fresh_ts
                return list(sui_cache_data)
    except Exception:
        # Stale cache fallback: keep the bot usable during short S-UI outages and
        # avoid hammering a degraded panel. Force-refresh callers still receive
        # stale data only while it is inside the explicit stale TTL.
        now_ts = time.time()
        async with sui_cache_lock:
            if sui_cache_data is not None and (now_ts - sui_cache_ts) < SUI_CLIENTS_STALE_CACHE_SECONDS:
                logging.warning(
                    "S-UI /clients refresh failed; using stale cache age=%.1fs",
                    now_ts - float(sui_cache_ts or 0),
                )
                return list(sui_cache_data)
        raise


async def get_client_by_id(client_id: int) -> dict | None:
    clients = await get_all_clients()
    for client in clients:
        try:
            if int(client.get("id") or 0) == int(client_id):
                return client
        except Exception:
            continue

    clients = await get_all_clients(force_refresh=True)
    for client in clients:
        try:
            if int(client.get("id") or 0) == int(client_id):
                return client
        except Exception:
            continue
    return None


def invalidate_user_subscription_flags_cache(user_id: int | None = None) -> None:
    if user_id is None:
        user_subscription_flags_cache.clear()
        return
    user_subscription_flags_cache.pop(int(user_id), None)


def prune_user_subscription_flags_cache(now_ts: float | None = None) -> None:
    now_value = time.time() if now_ts is None else float(now_ts)
    cutoff = now_value - USER_SUBSCRIPTION_FLAGS_CACHE_SECONDS
    stale = [uid for uid, (ts, _) in user_subscription_flags_cache.items() if float(ts or 0) < cutoff]
    for uid in stale:
        user_subscription_flags_cache.pop(uid, None)


async def get_user_subscription_flags(user_id: int, *, force_refresh: bool = False) -> dict[str, bool]:
    """Быстрая проверка активных подписок без antiabuse-подсчётов.

    Используется для меню и тестового доступа, чтобы не запускать тяжёлый
    get_user_subscriptions() там, где нужны только флаги. Результат коротко
    кэшируется, чтобы главное меню не ждало S-UI при каждом построении.
    """
    uid = int(user_id)
    now_ts_float = time.time()
    prune_user_subscription_flags_cache(now_ts_float)
    if not force_refresh:
        cached = user_subscription_flags_cache.get(uid)
        if cached and (now_ts_float - float(cached[0])) < USER_SUBSCRIPTION_FLAGS_CACHE_SECONDS:
            return dict(cached[1])

    flags = {"has_paid_active": False, "has_trial_active": False}
    try:
        clients = await get_all_clients(force_refresh=force_refresh)
    except Exception:
        return flags

    now_ts = int(time.time())
    for client in clients:
        desc = str(client.get("desc") or "")
        tgid = parse_tgid_from_desc(desc)
        tg_id_raw = str(client.get("tgId") or "")
        desc_tgid_matches = tgid is not None and int(tgid) == int(user_id)
        raw_tgid_matches = tg_id_raw.isdigit() and int(tg_id_raw) == int(user_id)
        if not (desc_tgid_matches or raw_tgid_matches):
            continue

        expiry = int(client.get("expiry") or 0)
        days_left = max(0, int((expiry - now_ts) / 86400)) if expiry > 0 else 0
        if days_left <= 0:
            continue

        plan_key = parse_plan_key_from_desc(desc)
        if str(plan_key or "") == "test" or " TEST" in desc:
            flags["has_trial_active"] = True
        else:
            flags["has_paid_active"] = True

        if flags["has_paid_active"] and flags["has_trial_active"]:
            break

    user_subscription_flags_cache[uid] = (time.time(), dict(flags))
    return flags


async def get_user_subscriptions(user_id: int) -> list[dict]:
    clients = await get_all_clients()
    matched_clients: list[dict] = []

    for client in clients:
        tgid = extract_tgid_from_client(client)
        if tgid is not None and int(tgid) == int(user_id):
            matched_clients.append(client)

    names = [str(client.get("name") or "unknown") for client in matched_clients]
    main_ip_sets = await antiabuse_unique_ip_sets_for_names(names)
    remote_ip_sets = await remote_antiabuse_active_ip_sets_for_names(names) if REMOTE_ANTIABUSE_ENABLED else {}
    limit_overrides = await antiabuse_limit_overrides_for_names(names)

    result: list[dict] = []
    for client in matched_clients:
        desc = str(client.get("desc") or "")
        name = str(client.get("name") or "unknown")
        sub_link, clash_link = subscription_links(name)
        plan_key = parse_plan_key_from_desc(desc)
        days_left, traffic_text = compute_subscription_stats(client)

        unique_connections = len(set(main_ip_sets.get(name, set())) | set(remote_ip_sets.get(name, set())))
        tariff = get_tariff(plan_key) if plan_key else None
        plan_title = str(tariff.title) if tariff else tariff_title_by_key(plan_key)
        if name in limit_overrides:
            connection_limit = int(limit_overrides[name])
        else:
            connection_limit = max(1, int(tariff.connection_limit)) if tariff else ANTIABUSE_IP_LIMIT

        result.append(
            {
                "id": int(client.get("id") or 0),
                "name": name,  # technical S-UI client name, keep hidden from normal user UI
                "desc": desc,
                "plan_key": plan_key,
                "is_trial": (str(plan_key or "") == "test" or " TEST" in desc),
                "plan_title": plan_title,
                "sub_link": sub_link,
                "clash_link": clash_link,
                "days_left": days_left,
                "traffic_text": traffic_text,
                "expiry_text": format_expiry(client),
                "expiry_ts": int(client.get("expiry") or 0),
                "unique_connections": unique_connections,
                "connection_limit": connection_limit,
            }
        )

    result.sort(key=lambda x: (x["days_left"], x["id"]), reverse=True)
    return result


def format_subscription_card(item: dict) -> str:
    plan_label = subscription_display_title(item)
    days_left = int(item.get("days_left") or 0)
    expiry_text = item.get("expiry_text", "—")
    is_trial = bool(item.get("is_trial"))
    if days_left <= 0:
        status = "⌛ Истекла"
    elif days_left <= 3:
        status = "⚠️ Скоро закончится"
    else:
        status = "✅ Активна"
    access_type = "Тестовый доступ" if is_trial else "Обычная подписка"
    double_vpn_enabled = subscription_double_vpn_enabled(item)
    double_vpn_lines = ["Double VPN: доступен" if double_vpn_enabled else "Double VPN: недоступен"]
    if double_vpn_enabled:
        double_vpn_lines.insert(0, f"Трафик Double VPN: {item.get('traffic_text', '—')}")

    return (
        "________________\n"
        f"{SUI_SERVER_NAME} · {plan_label}\n"
        f"Статус: {status}\n"
        f"Тип: {access_type}\n"
        f"Осталось дней: {days_left}\n"
        f"Истекает: {expiry_text}\n"
        + "\n".join(double_vpn_lines) + "\n"
        f"Устройств/IP: {int(item.get('unique_connections') or 0)}/{item.get('connection_limit', 10)}\n\n"
        "Подписка:\n"
        f"{item.get('sub_link', '—')}\n\n"
        "Clash:\n"
        f"{item.get('clash_link', '—')}"
    )

def get_default_inbound_ids() -> list[int]:
    raw = str(SUI_DEFAULT_INBOUNDS or "1,2,3").strip()
    result: list[int] = []
    for part in raw.split(","):
        part = part.strip()
        if not part:
            continue
        try:
            value = int(part)
        except Exception:
            continue
        if value > 0 and value not in result:
            result.append(value)
    return result or [1, 2, 3]


def normalize_inbound_ids(raw_value) -> list[int]:
    result: list[int] = []
    if isinstance(raw_value, list):
        for item in raw_value:
            try:
                value = int(item)
            except Exception:
                continue
            if value > 0 and value not in result:
                result.append(value)
    return result or [1, 2, 3]


def build_editbulk_client_payload(client: dict, new_expiry: int, new_volume: int) -> dict:
    client_id = client.get("id")
    name = str(client.get("name") or "")
    if not client_id:
        raise RuntimeError("У клиента нет id для editbulk")
    if not name:
        raise RuntimeError("У клиента пустой name для editbulk")

    payload = {
        "id": int(client_id),
        "enable": bool(client.get("enable", True)),
        "name": name,
        "inbounds": normalize_inbound_ids(client.get("inbounds")),
        "volume": int(new_volume),
        "expiry": int(new_expiry),
        "down": int(client.get("down") or 0),
        "up": int(client.get("up") or 0),
        "desc": str(client.get("desc") or ""),
        "group": str(client.get("group") or "User"),
        "delayStart": bool(client.get("delayStart", False)),
        "autoReset": bool(client.get("autoReset", False)),
        "resetDays": int(client.get("resetDays") or 0),
        "nextReset": int(client.get("nextReset") or 0),
        "totalUp": int(client.get("totalUp") or 0),
        "totalDown": int(client.get("totalDown") or 0),
    }
    tgid_raw = client.get("tgId")
    if tgid_raw not in (None, ""):
        payload["tgId"] = str(tgid_raw)
    return payload


async def sui_delete_clients_bulk(client_ids: list[int]) -> dict:
    ids: list[int] = []
    for value in client_ids:
        try:
            cid = int(value)
        except Exception:
            continue
        if cid > 0 and cid not in ids:
            ids.append(cid)
    if not ids:
        return {"success": True, "deleted": 0, "ids": []}
    payload = {
        "object": "clients",
        "action": "delbulk",
        "data": json.dumps(ids, ensure_ascii=False, separators=(",", ":")),
    }
    headers = {"Token": SUI_TOKEN, "Content-Type": "application/x-www-form-urlencoded"}
    session = await get_http_session()
    async with session.post(f"{SUI_API_URL}/save", data=urlencode(payload), headers=headers) as resp:
        raw_text = await resp.text()
        if resp.status != 200:
            raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
        result = json.loads(raw_text)
        if not result.get("success"):
            raise RuntimeError(f"S-UI delbulk error: {raw_text[:1200]}")
    invalidate_sui_clients_cache()
    invalidate_user_subscription_flags_cache(None)
    return {"success": True, "deleted": len(ids), "ids": ids}


def normalize_old_expiry_desc(desc: str, *, expired_old: bool) -> tuple[str, bool]:
    raw = str(desc or "").strip()
    without_marker = SUI_OLD_EXPIRY_MARKER_RE.sub("", raw).strip()
    without_marker = re.sub(r"\s{2,}", " ", without_marker).strip()
    if expired_old:
        new_desc = without_marker
        if SUI_OLD_EXPIRY_MARKER not in new_desc:
            new_desc = (new_desc + " " + SUI_OLD_EXPIRY_MARKER).strip() if new_desc else SUI_OLD_EXPIRY_MARKER
    else:
        new_desc = without_marker
    return new_desc, (new_desc != raw)


async def post_sui_editbulk_clients(updated_clients: list[dict]) -> None:
    if not updated_clients:
        return
    payload = {
        "object": "clients",
        "action": "editbulk",
        "data": json.dumps(updated_clients, ensure_ascii=False, separators=(",", ":")),
    }
    headers = {"Token": SUI_TOKEN, "Content-Type": "application/x-www-form-urlencoded"}
    session = await get_http_session()
    async with session.post(f"{SUI_API_URL}/save", data=urlencode(payload), headers=headers) as resp:
        raw_text = await resp.text()
        if resp.status != 200:
            raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
        result = json.loads(raw_text)
        if not result.get("success"):
            raise RuntimeError(f"S-UI editbulk error: {raw_text[:1200]}")
    invalidate_sui_clients_cache()
    invalidate_user_subscription_flags_cache(None)


async def post_sui_edit_client_full(client_payload: dict) -> None:
    """Persist full S-UI client payload through action=edit.

    S-UI can ignore autoReset/resetDays on action=new/editbulk in some builds.
    Full action=edit is the stable path for links and traffic reset fields.
    """
    if not client_payload.get("id") or not client_payload.get("name"):
        raise RuntimeError("S-UI full edit requires client id/name")
    payload = {
        "object": "clients",
        "action": "edit",
        "data": json.dumps(client_payload, ensure_ascii=False, separators=(",", ":")),
    }
    headers = {"Token": SUI_TOKEN, "Content-Type": "application/x-www-form-urlencoded"}
    session = await get_http_session()
    async with session.post(f"{SUI_API_URL}/save", data=urlencode(payload), headers=headers) as resp:
        raw_text = await resp.text()
        if resp.status != 200:
            raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
        result = json.loads(raw_text)
        if not result.get("success"):
            raise RuntimeError(f"S-UI full edit error: {raw_text[:1200]}")
    invalidate_sui_clients_cache()
    invalidate_user_subscription_flags_cache(None)


def tariff_for_sui_client(client: dict) -> Tariff | None:
    plan_key = parse_plan_key_from_desc(str(client.get("desc") or ""))
    if plan_key:
        tariff = get_tariff(plan_key)
        if tariff:
            return tariff
    group = str(client.get("group") or "").strip()
    if group:
        tariff = get_tariff(group)
        if tariff:
            return tariff
    return None


def desired_sui_traffic_reset_fields_for_client(client: dict) -> dict | None:
    tariff = tariff_for_sui_client(client)
    if not tariff:
        return None
    period = tariff_period_from_desc(str(client.get("desc") or ""), tariff)
    if period is None:
        return None
    return tariff_sui_traffic_reset_fields(tariff, period)


async def verify_sui_client_traffic_reset(client_name: str, desired: dict, *, attempts: int = 4, delay_seconds: float = 0.7) -> dict:
    """Verify S-UI autoReset/resetDays with small retry.

    Some S-UI builds apply editbulk immediately in the panel but /clients may return
    old values for a short time. Treat verification as a separate signal from the
    write result so the admin report does not show a false hard error.
    """
    desired_auto = bool(desired.get("autoReset", False))
    desired_days = int(desired.get("resetDays") or 0)
    last = {"verified": False, "actual_auto": None, "actual_days": None}
    total = max(1, int(attempts or 1))
    for attempt in range(total):
        invalidate_sui_clients_cache()
        fresh_clients = await get_all_clients(force_refresh=True)
        fresh = next((c for c in fresh_clients if str(c.get("name") or "").strip() == str(client_name)), None)
        if not fresh:
            last = {"verified": False, "actual_auto": None, "actual_days": None, "error": "client_not_found_after_write"}
        else:
            actual_auto = bool(fresh.get("autoReset", False))
            actual_days = int(fresh.get("resetDays") or 0)
            last = {
                "verified": (actual_auto == desired_auto and actual_days == desired_days),
                "actual_auto": actual_auto,
                "actual_days": actual_days,
                "attempts": attempt + 1,
            }
            if last["verified"]:
                return last
        if attempt < total - 1:
            await asyncio.sleep(float(delay_seconds or 0.0))
    return last



async def persist_sui_client_traffic_reset_with_fallback(client: dict, desired: dict) -> dict:
    """Persist autoReset/resetDays through slim editbulk and verify best-effort.

    Full action=edit is deliberately NOT used for this field: on some S-UI builds it
    can fail inside users/inbounds processing with json_extract(config.$.vless)
    scan errors even though we only want to change autoReset/resetDays.
    """
    name = str(client.get("name") or "").strip()
    errors: list[str] = []
    warnings: list[str] = []
    write_ok = False

    try:
        payload = build_editbulk_client_payload(
            client=client,
            new_expiry=int(client.get("expiry") or 0),
            new_volume=int(client.get("volume") or 0),
        )
        payload.update(desired)
        payload["nextReset"] = int(desired.get("nextReset") or 0)
        await post_sui_editbulk_clients([payload])
        write_ok = True
    except Exception as exc:
        errors.append(f"editbulk returned: {str(exc)[:220]}")

    try:
        verify = await verify_sui_client_traffic_reset(name, desired)
        if verify.get("verified"):
            verify["method"] = "editbulk"
            verify["write_ok"] = write_ok
            if warnings:
                verify["warnings"] = warnings[:2]
            if errors:
                verify["warnings"] = (verify.get("warnings") or []) + errors[:1]
            return verify
        if write_ok:
            warnings.append(f"write accepted; /clients not yet verified: actual auto={verify.get('actual_auto')} days={verify.get('actual_days')}")
            return {
                "verified": False,
                "write_ok": True,
                "pending_verify": True,
                "actual_auto": verify.get("actual_auto"),
                "actual_days": verify.get("actual_days"),
                "method": "editbulk",
                "warnings": warnings[:2],
            }
        errors.append(f"not verified after editbulk: actual auto={verify.get('actual_auto')} days={verify.get('actual_days')}")
    except Exception as exc:
        if write_ok:
            warnings.append(f"write accepted; verify failed: {str(exc)[:160]}")
            return {"verified": False, "write_ok": True, "pending_verify": True, "method": "editbulk", "warnings": warnings[:2]}
        errors.append(f"verify after editbulk: {str(exc)[:160]}")

    return {"verified": False, "write_ok": False, "errors": errors[:4]}



async def ensure_sui_client_traffic_reset(client_name: str, tariff: Tariff | None, period: TariffPeriod | None = None) -> dict:
    """Force S-UI traffic reset mode for a client and verify best-effort."""
    if not tariff:
        return {"changed": 0, "verified": False, "error": "tariff_not_found"}
    desired = tariff_sui_traffic_reset_fields(tariff, period)
    clients = await get_all_clients(force_refresh=True)
    client = next((c for c in clients if str(c.get("name") or "").strip() == str(client_name)), None)
    if not client:
        return {"changed": 0, "verified": False, "error": "client_not_found"}
    current_auto = bool(client.get("autoReset", False))
    current_days = int(client.get("resetDays") or 0)
    desired_auto = bool(desired.get("autoReset", False))
    desired_days = int(desired.get("resetDays") or 0)
    changed = int(current_auto != desired_auto or current_days != desired_days)
    result = {"verified": False, "actual_auto": current_auto, "actual_days": current_days}
    if desired_days > 0 or changed:
        result = await persist_sui_client_traffic_reset_with_fallback(client, desired)
    else:
        with contextlib.suppress(Exception):
            result = await verify_sui_client_traffic_reset(client_name, desired)
    return {
        "changed": changed,
        "verified": bool(result.get("verified")),
        "actual_auto": result.get("actual_auto", current_auto),
        "actual_days": result.get("actual_days", current_days),
        "desired_auto": desired_auto,
        "desired_days": desired_days,
        "method": result.get("method"),
        "warnings": result.get("warnings") or [],
        "errors": result.get("errors") or [],
    }


async def apply_tariff_sui_traffic_reset_to_existing(tariff_key: str) -> dict:
    """Apply tariff traffic reset mode to existing active S-UI clients of this tariff.

    Uses only slim editbulk. Verification is best-effort because some S-UI builds
    apply editbulk in the panel while /clients can lag or return old reset fields.
    """
    tariff = get_tariff(tariff_key)
    if not tariff:
        return {"checked": 0, "changed": 0, "skipped": 0, "verified": 0, "pending_verify": 0, "failed": 0, "error": "tariff_not_found"}
    # reset mode is stored on the tariff, but the actual S-UI mode depends on
    # the client's selected period: 30d keeps additive traffic, long periods use
    # auto-reset if the tariff setting is enabled.
    default_reset_fields = tariff_sui_traffic_reset_fields(tariff, tariff_base_period(tariff))
    clients = await get_all_clients(force_refresh=True)
    now_ts = int(time.time())
    checked = changed = skipped = verified = pending_verify = failed = 0
    errors: list[str] = []
    warnings: list[str] = []
    for client in clients:
        name = str(client.get("name") or "").strip()
        if not name:
            continue
        desc = str(client.get("desc") or "")
        plan_key = parse_plan_key_from_desc(desc)
        if plan_key != tariff_key:
            continue
        client_period = tariff_period_from_desc(desc, tariff) or tariff_base_period(tariff)
        reset_fields = tariff_sui_traffic_reset_fields(tariff, client_period)
        checked += 1
        try:
            expiry = int(client.get("expiry") or 0)
        except Exception:
            expiry = 0
        if not bool(client.get("enable", True)) or (expiry > 0 and expiry <= now_ts):
            skipped += 1
            continue
        current_auto = bool(client.get("autoReset", False))
        current_days = int(client.get("resetDays") or 0)
        desired_auto = bool(reset_fields.get("autoReset", False))
        desired_days = int(reset_fields.get("resetDays") or 0)
        already_matches = (current_auto == desired_auto and current_days == desired_days)
        if already_matches and desired_days <= 0:
            skipped += 1
            continue
        try:
            result = await persist_sui_client_traffic_reset_with_fallback(client, reset_fields)
            if result.get("verified"):
                changed += 0 if already_matches else 1
                verified += 1
                for w in (result.get("warnings") or [])[:1]:
                    warnings.append(f"{name}: {w}")
            elif result.get("write_ok"):
                changed += 0 if already_matches else 1
                pending_verify += 1
                for w in (result.get("warnings") or [])[:1]:
                    warnings.append(f"{name}: {w}")
            else:
                failed += 1
                err = "; ".join(result.get("errors") or ["not verified"])
                errors.append(f"{name}: {err[:240]}")
        except Exception as exc:
            failed += 1
            errors.append(f"{name}: {str(exc)[:240]}")
    return {
        "checked": checked,
        "changed": changed,
        "skipped": skipped,
        "verified": verified,
        "pending_verify": pending_verify,
        "failed": failed,
        "errors": errors[:5],
        "warnings": warnings[:5],
        "desired_days": int(default_reset_fields.get("resetDays") or 0),
        "tariff_reset_days": tariff_double_vpn_reset_days(tariff),
    }



def tariff_reset_apply_result_text(result: dict) -> str:
    if not result:
        return ""
    if result.get("error"):
        return f"\nПрименение к существующим подпискам: ошибка {result.get('error')}"
    text = (
        "\nПрименение к существующим активным подпискам тарифа: "
        f"изменено {int(result.get('changed') or 0)}, "
        f"проверено {int(result.get('checked') or 0)}, "
        f"подтверждено S-UI {int(result.get('verified') or 0)}"
    )
    pending = int(result.get("pending_verify") or 0)
    if pending:
        text += f", ожидает подтверждения {pending}"
    if int(result.get("failed") or 0):
        text += f", ошибок {int(result.get('failed') or 0)}"
    text += "."
    warnings = result.get("warnings") or []
    if warnings:
        text += "\nПредупреждение: S-UI принял editbulk, но /clients ещё вернул старые значения для части клиентов. Проверьте страницу S-UI или повторите проверку позже."
    errors = result.get("errors") or []
    if errors:
        text += "\nОшибки: " + "; ".join(str(x) for x in errors[:3])
    return text



async def sui_old_expiry_mark_once() -> dict:
    if not SUI_OLD_EXPIRY_ENABLED:
        return {"changed": 0, "checked": 0, "enabled": False}
    clients = await get_all_clients(force_refresh=True)
    now_ts = int(time.time())
    cutoff = now_ts - int(SUI_OLD_EXPIRY_GRACE_DAYS) * 86400
    updated: list[dict] = []
    checked = 0
    for client in clients:
        checked += 1
        try:
            client_id = int(client.get("id") or 0)
            name = str(client.get("name") or "").strip()
            expiry = int(client.get("expiry") or 0)
        except Exception:
            continue
        if client_id <= 0 or not name or expiry <= 0:
            continue
        expired_old = expiry < cutoff
        desc = str(client.get("desc") or "")
        new_desc, changed = normalize_old_expiry_desc(desc, expired_old=expired_old)
        if not changed:
            continue
        payload = build_editbulk_client_payload(client=client, new_expiry=expiry, new_volume=int(client.get("volume") or 0))
        payload["desc"] = new_desc
        updated.append(payload)
    for i in range(0, len(updated), 50):
        await post_sui_editbulk_clients(updated[i:i + 50])
    if updated:
        logging.info("S-UI old_expiry marker updated clients=%s checked=%s", len(updated), checked)
    return {"changed": len(updated), "checked": checked, "enabled": True}


async def sui_old_expiry_worker() -> None:
    if not SUI_OLD_EXPIRY_ENABLED:
        logging.info("S-UI old_expiry worker disabled")
        return
    logging.info("S-UI old_expiry worker started poll=%ss grace=%sd", SUI_OLD_EXPIRY_POLL_SECONDS, SUI_OLD_EXPIRY_GRACE_DAYS)
    await sleep_with_jitter(60, 30)
    while True:
        try:
            await sui_old_expiry_mark_once()
        except Exception as exc:
            logging.exception("S-UI old_expiry worker failed: %s", exc)
        await sleep_with_jitter(SUI_OLD_EXPIRY_POLL_SECONDS, 300)


async def renew_client_in_sui(client: dict, tariff: Tariff, period: TariffPeriod | None = None) -> dict:
    period = period or tariff_base_period(tariff)
    current_expiry = int(client.get("expiry") or 0)
    now_ts = int(time.time())
    base_expiry = current_expiry if current_expiry > now_ts else now_ts
    new_expiry = base_expiry + int(period.days) * 86400

    current_volume = int(client.get("volume") or 0)
    new_volume = tariff_renewal_volume_bytes(current_volume, tariff, period)

    updated = build_editbulk_client_payload(client=client, new_expiry=new_expiry, new_volume=new_volume)
    new_desc, _old_expiry_changed = normalize_old_expiry_desc(str(updated.get("desc") or ""), expired_old=False)
    updated["desc"] = apply_period_marker_to_desc(new_desc, period)
    updated.update(tariff_sui_traffic_reset_fields(tariff, period))

    payload = {
        "object": "clients",
        "action": "editbulk",
        "data": json.dumps([updated], ensure_ascii=False, separators=(",", ":")),
    }
    headers = {"Token": SUI_TOKEN, "Content-Type": "application/x-www-form-urlencoded"}

    session = await get_http_session()
    async with session.post(f"{SUI_API_URL}/save", data=urlencode(payload), headers=headers) as resp:
            raw_text = await resp.text()
            if resp.status != 200:
                raise RuntimeError(f"S-UI HTTP {resp.status}: {raw_text[:500]}")
            result = json.loads(raw_text)
            if not result.get("success"):
                raise RuntimeError(f"S-UI editbulk error: {raw_text[:1200]}")
    try:
        reset_result = await ensure_sui_client_traffic_reset(str(client.get("name") or ""), tariff, period=period)
        if not reset_result.get("verified") and tariff_double_vpn_reset_days(tariff) > 0:
            logging.warning("S-UI traffic reset not verified after renew client=%s result=%s", client.get("name"), reset_result)
    except Exception as exc:
        logging.warning("S-UI traffic reset ensure after renew failed client=%s: %s", client.get("name"), exc)
    invalidate_sui_clients_cache()
    tgid = parse_tgid_from_desc(str(client.get("desc") or ""))
    if tgid:
        invalidate_user_subscription_flags_cache(int(tgid))
    return updated


