def trial_node_scope_menu_text() -> str:
    nodes_cfg = remote_load_nodes_config()
    nodes = remote_admin_nodes_all(nodes_cfg or {})
    selected = trial_remote_node_scope_ids()
    mode = "все доступные локации" if selected is None else ("ни одной локации" if not selected else "выбранные локации")
    lines = [
        "🌍 Локации тестового доступа",
        "━━━━━━━━━━━━━━",
        f"Remote-локации для теста: {'включены' if trial_remote_locations_enabled() else 'выключены'}",
        f"Режим: {mode}",
        "",
        "Что делает этот раздел:",
        "• выбирает, какие VPS-локации попадут в тестовую подписку;",
        "• если remote-локации выключены, тест остаётся только через основной сервер;",
        "• глобально выключенные, maintenance или drain node всё равно не выдаются.",
        "",
        "Доступные локации:",
    ]
    if not nodes:
        lines.append("• nodes.json пуст или недоступен")
    for node in nodes:
        nid = str(node.get("id") or "").strip()
        if not nid:
            continue
        display = str(node.get("display_name") or nid.upper())
        globally_available = bool(node.get("enabled", True)) and not bool(node.get("maintenance")) and not bool(node.get("drain"))
        if selected is None:
            mark = "✅" if globally_available else "⚪"
        else:
            mark = "✅" if nid in selected else "⬜"
        note = "доступна" if globally_available else "не выдаётся глобально"
        lines.append(f"{mark} {display} ({nid}) · {note}")
    return "\n".join(lines)


def trial_node_scope_keyboard() -> InlineKeyboardMarkup:
    rows: list[list[InlineKeyboardButton]] = []
    selected = trial_remote_node_scope_ids()
    all_mode = selected is None
    rows.append([InlineKeyboardButton(text=("✅ Все доступные локации" if all_mode else "🌍 Использовать все доступные локации"), callback_data="admin:trial:nodes_all")])
    try:
        nodes_cfg = remote_load_nodes_config()
        nodes = [n for n in remote_admin_nodes_all(nodes_cfg or {}) if n.get("id")]
    except Exception:
        nodes = []
    for node in nodes:
        nid = str(node.get("id") or "").strip()
        if not nid:
            continue
        globally_available = bool(node.get("enabled", True)) and not bool(node.get("maintenance")) and not bool(node.get("drain"))
        checked = all_mode or (selected is not None and nid in selected)
        prefix = "✅" if checked else "⬜"
        if not globally_available:
            prefix = "⚫" if checked else "▫️"
        label = public_location_name_from_node(node)
        suffix = "" if globally_available else " · глобально недоступна"
        rows.append([InlineKeyboardButton(text=f"{prefix} {label}{suffix}", callback_data=f"admin:trial:nodes_toggle:{nid}")])
    rows.append([InlineKeyboardButton(text="🔄 Запустить sync после изменения", callback_data="admin:trial:nodes_sync")])
    rows.append([InlineKeyboardButton(text="← К тестовому доступу", callback_data="admin:trial")])
    return InlineKeyboardMarkup(inline_keyboard=rows)


