async def production_doctor_text() -> str:
    """Compact production readiness report.

    Read-only checks only: config, SQLite, S-UI, node config, timers, storage, dependencies,
    payment queue and unified antiabuse sanity.
    """
    checks: list[tuple[str, bool, str]] = []

    def fmt_mb(value: float) -> str:
        return f"{value:.1f} MB"

    def file_mb(path: Path) -> float:
        try:
            return path.stat().st_size / (1024 * 1024) if path.exists() else 0.0
        except Exception:
            return 0.0

    def read_stamp(path: Path) -> str:
        try:
            if not path.exists():
                return "—"
            raw = path.read_text(encoding="utf-8", errors="ignore").strip()
            if raw.isdigit():
                return payment_dt_text(float(raw))
            return raw[:40] or "—"
        except Exception:
            return "—"

    def systemctl_state(unit: str) -> tuple[bool, str]:
        if not shutil.which("systemctl"):
            return False, "systemctl not found"
        enabled = subprocess.run(["systemctl", "is-enabled", unit], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=5)
        active = subprocess.run(["systemctl", "is-active", unit], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=5)
        en = (enabled.stdout or enabled.stderr or "").strip()
        ac = (active.stdout or active.stderr or "").strip()
        ok = en in {"enabled", "static", "generated"} and ac in {"active", "activating", "inactive"}
        # Timers are often active; services can be inactive oneshot. The detail is more useful than strict failure.
        return ok, f"enabled={en or 'unknown'} · active={ac or 'unknown'}"

    try:
        cfg_ok = isinstance(CONFIG, dict) and bool(CONFIG)
        checks.append(("config.json", cfg_ok, "loaded" if cfg_ok else "empty/not loaded"))
    except Exception as exc:
        checks.append(("config.json", False, str(exc)[:120]))

    try:
        db_path = Path(DATABASE_DB)
        wal = Path(str(db_path) + "-wal")
        shm = Path(str(db_path) + "-shm")
        detail = f"{db_path} · db {fmt_mb(file_mb(db_path))} · wal {fmt_mb(file_mb(wal))} · shm {fmt_mb(file_mb(shm))}"
        checks.append(("SQLite", db_path.exists(), detail))
    except Exception as exc:
        checks.append(("SQLite", False, str(exc)[:120]))

    try:
        clients = await get_all_clients(force_refresh=True)
        active = 0
        now_ms = int(time.time() * 1000)
        for c in clients:
            expiry = int(c.get("expiryTime") or c.get("expiry") or 0)
            if bool(c.get("enable", True)) and (expiry <= 0 or expiry > now_ms):
                active += 1
        checks.append(("S-UI clients", True, f"total {len(clients)} · active {active}"))
    except Exception as exc:
        checks.append(("S-UI clients", False, str(exc)[:160]))

    try:
        nodes_cfg = remote_load_nodes_config()
        nodes = remote_admin_nodes_all(nodes_cfg)
        enabled = sum(1 for n in nodes if n.get("enabled", True) and not n.get("maintenance"))
        checks.append(("nodes.json", True, f"nodes {len(nodes)} · enabled {enabled}"))
    except Exception as exc:
        checks.append(("nodes.json", False, str(exc)[:120]))

    try:
        async with db_connect(ANTIABUSE_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async def _count_table(name: str) -> int:
                try:
                    async with conn.execute(f"SELECT COUNT(*) AS c FROM {name}") as cur:
                        row = await cur.fetchone()
                        return int(row["c"] or 0) if row else 0
                except Exception:
                    return 0
            ev_count = await _count_table("antiabuse_events")
            cases_count = await _count_table("antiabuse_cases")
            raw_count = await _count_table("raw_events")
            matches_count = await _count_table("matches")
            warnings_count = await _count_table("antiabuse_warnings")
            remote_count = await _count_table("remote_antiabuse_events")
            too_big = []
            if raw_count > ANTIABUSE_RAW_EVENTS_MAX_ROWS:
                too_big.append(f"raw>{ANTIABUSE_RAW_EVENTS_MAX_ROWS}")
            if matches_count > ANTIABUSE_MATCHES_MAX_ROWS:
                too_big.append(f"matches>{ANTIABUSE_MATCHES_MAX_ROWS}")
            if warnings_count > ANTIABUSE_WARNINGS_MAX_ROWS:
                too_big.append(f"warnings>{ANTIABUSE_WARNINGS_MAX_ROWS}")
            if remote_count > ANTIABUSE_REMOTE_EVENTS_MAX_ROWS:
                too_big.append(f"remote>{ANTIABUSE_REMOTE_EVENTS_MAX_ROWS}")
            detail = (
                f"events {ev_count} · cases {cases_count} · raw {raw_count}/{ANTIABUSE_RAW_EVENTS_MAX_ROWS} · "
                f"matches {matches_count}/{ANTIABUSE_MATCHES_MAX_ROWS} · warnings {warnings_count}/{ANTIABUSE_WARNINGS_MAX_ROWS} · "
                f"remote {remote_count}/{ANTIABUSE_REMOTE_EVENTS_MAX_ROWS}"
            )
            if too_big:
                detail += " · over cap: " + ", ".join(too_big)
            checks.append(("Antiabuse DB", not too_big, detail))
    except Exception as exc:
        checks.append(("Antiabuse DB", False, str(exc)[:120]))

    try:
        cases = await antiabuse_build_cases(force_refresh=True)
        suspicious = sum(1 for c in cases if c.get("suspicious"))
        wrong_limits = []
        for c in cases:
            if c.get("exists_in_sui") and not c.get("has_override"):
                plan = str(c.get("plan_key") or "")
                tariff = get_tariff(plan) if plan else None
                if tariff and int(c.get("limit_value") or 0) != int(tariff.connection_limit):
                    wrong_limits.append(str(c.get("name") or "")[:40])
        checks.append(("Unified Antiabuse", not wrong_limits, f"cases {len(cases)} · suspicious {suspicious}" + (" · wrong limits: " + ", ".join(wrong_limits[:3]) if wrong_limits else "")))
    except Exception as exc:
        checks.append(("Unified Antiabuse", False, str(exc)[:160]))

    try:
        async with db_connect(PAYMENTS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status IN ('pending','processing')") as cur:
                row = await cur.fetchone()
            pending = int(row["c"] or 0)
        checks.append(("Payments queue", pending == 0, f"pending/processing {pending}"))
    except Exception as exc:
        checks.append(("Payments queue", False, str(exc)[:120]))

    try:
        needed = ["python3", "sqlite3", "rsync", "jq", "curl", "ssh", "sshpass", "tar", "gzip"]
        missing = [x for x in needed if not shutil.which(x)]
        checks.append(("System deps", not missing, "OK" if not missing else "missing: " + ", ".join(missing)))
    except Exception as exc:
        checks.append(("System deps", False, str(exc)[:120]))

    try:
        timer_units = ["bot-sui-backup.timer", "bot-sui-maintenance.timer", "bot-sui-monitor.timer"]
        details = []
        ok_all = True
        for unit in timer_units:
            ok_unit, detail = systemctl_state(unit)
            ok_all = ok_all and ok_unit
            details.append(f"{unit.replace('bot-sui-', '').replace('.timer','')}: {detail}")
        checks.append(("Systemd timers", ok_all, " · ".join(details)))
    except Exception as exc:
        checks.append(("Systemd timers", False, str(exc)[:160]))

    try:
        backups_size = 0.0
        backups_dir = BASE_DIR / "backups"
        if backups_dir.exists():
            proc = subprocess.run(["du", "-sm", str(backups_dir)], stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, text=True, timeout=10)
            if proc.returncode == 0 and proc.stdout.strip():
                backups_size = float(proc.stdout.split()[0])
        last_backup = read_stamp(BASE_DIR / ".last_backup")
        last_maintenance = read_stamp(BASE_DIR / ".last_maintenance")
        last_vacuum = read_stamp(BASE_DIR / ".last_vacuum")
        checks.append(("Storage hygiene", True, f"backups {backups_size:.0f} MB · last backup {last_backup} · maintenance {last_maintenance} · vacuum {last_vacuum}"))
    except Exception as exc:
        checks.append(("Storage hygiene", False, str(exc)[:160]))

    try:
        def _du_mb(path: str) -> float:
            proc = subprocess.run(["du", "-sm", path], stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, text=True, timeout=8)
            if proc.returncode == 0 and proc.stdout.strip():
                return float(proc.stdout.split()[0])
            return 0.0

        journal_mb = 0.0
        proc = subprocess.run(["journalctl", "--disk-usage"], stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, text=True, timeout=8)
        if proc.returncode == 0 and proc.stdout:
            m = re.search(r"([0-9]+(?:\.[0-9]+)?)\s*([KMGT])", proc.stdout, re.IGNORECASE)
            if m:
                value = float(m.group(1))
                unit = m.group(2).upper()
                mult = {"K": 1/1024, "M": 1, "G": 1024, "T": 1024*1024}.get(unit, 1)
                journal_mb = value * mult
        var_journal_mb = _du_mb("/var/log/journal") if Path("/var/log/journal").exists() else 0.0
        run_journal_mb = _du_mb("/run/log/journal") if Path("/run/log/journal").exists() else 0.0
        warn_mb = 1024.0
        checks.append(("System journal", journal_mb <= warn_mb, f"journalctl {journal_mb:.0f} MB · /var/log/journal {var_journal_mb:.0f} MB · /run/log/journal {run_journal_mb:.0f} MB · warn>{warn_mb:.0f} MB"))
    except Exception as exc:
        checks.append(("System journal", False, str(exc)[:160]))

    try:
        free_mb = 0
        proc = subprocess.run(["df", "-Pm", str(BASE_DIR)], stdout=subprocess.PIPE, stderr=subprocess.DEVNULL, text=True, timeout=5)
        if proc.returncode == 0:
            parts = proc.stdout.splitlines()[-1].split()
            free_mb = int(parts[3])
        checks.append(("Disk free", free_mb >= 2048, f"{free_mb} MB free"))
    except Exception as exc:
        checks.append(("Disk free", False, str(exc)[:120]))

    ok = all(ok for _, ok, _ in checks)
    lines = [
        "🩺 Проверка production",
        "━━━━━━━━━━━━━━",
        "Read-only: этот экран ничего не меняет, только проверяет здоровье бота и инфраструктуры.",
        f"Build: {APP_BUILD}",
        f"Итог: {'✅ OK' if ok else '⚠️ есть предупреждения'}",
        "",
    ]
    for name, passed, detail in checks:
        lines.append(f"{'✅' if passed else '❌'} {name}: {detail}")
    lines += [
        "",
        "Doctor ничего не меняет: это только безопасная проверка готовности.",
        "Для production: backup/restore drill желателен; если временно дорого — используй скрипт переезда VPS и аудит зависших оплат.",
    ]
    text = "\n".join(lines).strip()
    if len(text) > 3900:
        text = text[:3800].rstrip() + "\n\n… сообщение сокращено."
    return text


async def payment_retry_audit_text() -> str:
    """Read-only payment retry readiness report for RC checks."""
    now_ts = time.time()
    try:
        async with db_connect(PAYMENTS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT provider, status, COALESCE(application_status,'') AS app, COUNT(*) AS c FROM payments GROUP BY provider, status, app ORDER BY provider, status, app") as cur:
                groups = await cur.fetchall()
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status IN ('pending','processing')") as cur:
                pending_processing = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE COALESCE(application_status,'')='apply_failed'") as cur:
                apply_failed = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status='processing' AND COALESCE(application_status,'')!='applied' AND COALESCE(apply_started_at, created_at) < ?", (now_ts - 15*60,)) as cur:
                stuck_processing = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE provider='platega' AND status='pending' AND created_at < ?", (now_ts - 24*3600,)) as cur:
                old_platega_pending = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status='success' AND COALESCE(application_status,'')!='applied'") as cur:
                success_not_applied = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM (SELECT provider_charge_id FROM payments WHERE COALESCE(provider_charge_id,'')!='' GROUP BY provider_charge_id HAVING COUNT(*)>1)") as cur:
                duplicate_charges = int((await cur.fetchone())["c"] or 0)
            async with conn.execute("""
                SELECT id, payment_uid, user_id, username, provider, status, COALESCE(application_status,'') AS app,
                       tarif_key, kind, amount, currency, created_at, paid_at, apply_started_at, failed_at, notes
                FROM payments
                WHERE COALESCE(application_status,'')='apply_failed'
                   OR (status='processing' AND COALESCE(application_status,'')!='applied' AND COALESCE(apply_started_at, created_at) < ?)
                   OR (provider='platega' AND status='pending' AND created_at < ?)
                   OR (status='success' AND COALESCE(application_status,'')!='applied')
                ORDER BY COALESCE(failed_at, apply_started_at, created_at) DESC
                LIMIT 10
            """, (now_ts - 15*60, now_ts - 24*3600)) as cur:
                rows = await cur.fetchall()
    except Exception as exc:
        return "💳 Аудит зависших оплат\n━━━━━━━━━━━━━━\n❌ Ошибка: " + str(exc)[:1500]

    blockers = apply_failed + stuck_processing + old_platega_pending + success_not_applied + duplicate_charges
    lines = [
        "💳 Аудит зависших оплат",
        "━━━━━━━━━━━━━━",
        f"Итог: {'✅ OK' if blockers == 0 else '⚠️ есть что проверить'}",
        "",
        f"Ожидают/обрабатываются: {pending_processing}",
        f"Не применились после оплаты: {apply_failed}",
        f"Зависли в processing >15 мин: {stuck_processing}",
        f"Platega pending >24 ч: {old_platega_pending}",
        f"Оплата success, но подписка не applied: {success_not_applied}",
        f"Дубли provider_charge_id: {duplicate_charges}",
        "",
        "По статусам:",
    ]
    if groups:
        for r in groups[:20]:
            lines.append(f"• {r['provider']} · {r['status']} · {r['app'] or '—'}: {int(r['c'] or 0)}")
    else:
        lines.append("• платежей нет")
    if rows:
        lines += ["", "Требуют внимания:"]
        for r in rows:
            uname = ("@" + str(r['username']).lstrip('@')) if str(r['username'] or '').strip() else f"tgid {int(r['user_id'] or 0)}"
            lines.append(f"• #{int(r['id'])} {r['provider']} {r['status']}/{r['app'] or '—'} · {r['kind']} {r['tarif_key']} · {uname} · {payment_dt_text(r['created_at'])}")
    lines += ["", "Аудит ничего не меняет. Apply failed разбирай через админский раздел платежей или повторную обработку."]
    text = "\n".join(lines).strip()
    if len(text) > 3900:
        text = text[:3800].rstrip() + "\n\n… сообщение сокращено."
    return text




