def client_is_active_for_remote_report(client: dict) -> bool:
    try:
        if not bool(client.get("enable", True)):
            return False
        expiry = int(client.get("expiry") or client.get("expiryTime") or 0)
        now_s = int(time.time())
        now_ms = int(time.time() * 1000)
        if expiry > 10_000_000_000:
            return expiry > now_ms
        if expiry > 0:
            return expiry > now_s
        return True
    except Exception:
        return bool(client.get("enable", True))


async def remote_reconciliation_collect_node_users(nodes_cfg: dict, node: dict) -> dict:
    nid = str(node.get("id") or "")
    script = """
python3 - <<'PYREMOTE'
import json
from pathlib import Path
p=Path('/etc/sing-box/config.json')
if not p.exists():
    print(json.dumps({'ok': False, 'error': 'config-missing', 'users': []}))
    raise SystemExit(0)
try:
    cfg=json.loads(p.read_text())
    users=[]
    for ib in cfg.get('inbounds', []) or []:
        proto=str(ib.get('type') or '')
        tag=str(ib.get('tag') or '')
        for u in (ib.get('users') or []):
            name=str(u.get('name') or u.get('username') or '')
            if name and name != '__placeholder__':
                users.append({'name': name, 'protocol': proto, 'tag': tag})
    print(json.dumps({'ok': True, 'users': users}, ensure_ascii=False, separators=(',', ':')))
except Exception as e:
    print(json.dumps({'ok': False, 'error': str(e)[:500], 'users': []}, ensure_ascii=False))
PYREMOTE
"""
    try:
        proc = await asyncio.to_thread(remote_ssh_run, nodes_cfg, node, "bash -s", input_text=script, timeout=35, check=False)
        stdout = str(getattr(proc, "stdout", "") or "").strip()
        out = stdout.splitlines()[-1] if stdout else "{}"
        data = json.loads(out)
        return {"node_id": nid, "ok": bool(data.get("ok")), "users": data.get("users") or [], "error": str(data.get("error") or getattr(proc, "stderr", "") or "")[:500]}
    except Exception as exc:
        return {"node_id": nid, "ok": False, "users": [], "error": str(exc)[:500]}


async def remote_subscription_managed_count(client_name: str, nodes_cfg: dict) -> dict:
    """Read the real subscription endpoint and count managed remote links.

    S-UI /clients may return client.links=[] even when the subscription endpoint
    already contains external rows. Reconciliation must verify what the user
    actually receives, not only what the API echoes back.
    """
    name = str(client_name or "").strip()
    if not name:
        return {"ok": False, "count": 0, "error": "empty client name", "node_counts": {}}
    sub_url, _ = subscription_links(name)
    try:
        session = await get_http_session()
        async with session.get(sub_url, headers={"Cache-Control": "no-cache", "Pragma": "no-cache"}) as resp:
            raw = await resp.read()
            if resp.status != 200:
                return {"ok": False, "count": 0, "error": f"HTTP {resp.status}", "node_counts": {}, "url": sub_url}
        text = raw.decode("utf-8", "ignore")
        # S-UI subscriptions may be plain text or base64-encoded.
        if "://" not in text:
            try:
                import base64
                compact = re.sub(r"\s+", "", text)
                decoded = base64.b64decode(compact + "=" * (-len(compact) % 4)).decode("utf-8", "ignore")
                if "://" in decoded:
                    text = decoded
            except Exception:
                pass
        count = int(text.count(REMOTE_MANAGED_MARKER))
        node_counts = {}
        for node in remote_admin_nodes_all(nodes_cfg):
            nid = str(node.get("id") or "").strip()
            if nid:
                node_counts[nid] = int(text.count(f"x-node={nid}"))
        return {"ok": True, "count": count, "node_counts": node_counts, "error": "", "url": sub_url}
    except Exception as exc:
        return {"ok": False, "count": 0, "error": str(exc)[:300], "node_counts": {}, "url": sub_url}


async def remote_reconciliation_report_data() -> dict:
    await init_remote_nodes_db()
    nodes_cfg = remote_load_nodes_config()
    nodes = [n for n in remote_admin_nodes_all(nodes_cfg) if n.get("enabled", True) and not n.get("maintenance")]
    clients = await get_all_clients(force_refresh=True)
    active_clients = [c for c in clients if client_is_active_for_remote_report(c)]
    active_names = {str(c.get("name") or "").strip() for c in active_clients if str(c.get("name") or "").strip()}
    prepared_active = await remote_prepare_clients(active_clients)
    remote_eligible_names = {str(c.get("name") or "").strip() for c in prepared_active if str(c.get("name") or "").strip() and remote_is_paid_active_client(c)}
    async with db_connect(DATABASE_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT client_name, user_id, tariff_key, updated_at FROM remote_client_credentials") as cur:
            cred_rows = [dict(r) for r in await cur.fetchall()]
    cred_names = {str(r.get("client_name") or "").strip() for r in cred_rows if str(r.get("client_name") or "").strip()}
    stale_creds = sorted(cred_names - active_names)
    missing_creds = sorted(remote_eligible_names - cred_names)

    node_results = await asyncio.gather(*[remote_reconciliation_collect_node_users(nodes_cfg, n) for n in nodes], return_exceptions=False) if nodes else []
    node_user_map: dict[str, set[str]] = {}
    node_errors: list[str] = []
    unreadable_node_ids: set[str] = set()
    for res in node_results:
        nid = str(res.get("node_id") or "")
        if not res.get("ok"):
            unreadable_node_ids.add(nid)
            node_errors.append(f"{nid}: {res.get('error') or 'unknown'}")
            continue
        names = {str(u.get("name") or "").strip() for u in (res.get("users") or []) if str(u.get("name") or "").strip()}
        node_user_map[nid] = names

    expected_node_names: dict[str, set[str]] = {}
    for node in nodes:
        nid = str(node.get("id") or "")
        expected = set()
        for c in prepared_active:
            name = str(c.get("name") or "").strip()
            if not name:
                continue
            try:
                if remote_is_paid_active_client(c) and remote_node_allows_client(node, c):
                    expected.add(name)
            except Exception:
                pass
        expected_node_names[nid] = expected

    missing_on_nodes: list[str] = []
    ghost_on_nodes: list[str] = []
    for nid, expected in expected_node_names.items():
        if nid in unreadable_node_ids:
            continue
        actual = node_user_map.get(nid, set())
        for name in sorted(expected - actual):
            missing_on_nodes.append(f"{name} · {nid}")
        for name in sorted(actual - expected):
            ghost_on_nodes.append(f"{name} · {nid}")

    link_issues: list[str] = []
    subscription_ok_api_lag_count = 0
    checked_subscription_links = 0
    try:
        state = await remote_load_node_state()
        for c in prepared_active:
            name = str(c.get("name") or "").strip()
            if not name or not remote_is_paid_active_client(c):
                continue
            desired = remote_desired_links_for_client(nodes_cfg, state, c)
            current = remote_client_links(c)
            managed_current = [x for x in current if remote_is_managed_link(x, nodes_cfg)]
            api_count = len(managed_current)
            desired_count = len(desired)
            api_matches = remote_link_uri_set(managed_current) == remote_link_uri_set(desired)
            sub_info = await remote_subscription_managed_count(name, nodes_cfg)
            if sub_info.get("ok"):
                checked_subscription_links += 1
            sub_matches = remote_subscription_matches_desired_nodes(sub_info, desired, nodes_cfg)

            if api_matches or sub_matches:
                # S-UI API may return client.links=[] while the real subscription URL is already correct.
                # This is normal for this S-UI build, so do not show every client as a warning.
                if (not api_matches) and sub_matches:
                    subscription_ok_api_lag_count += 1
                continue

            sub_count = int(sub_info.get("count") or 0) if sub_info.get("ok") else -1
            sub_text = f"реальная подписка: {sub_count}/{desired_count}" if sub_info.get("ok") else f"реальную подписку не удалось проверить: {sub_info.get('error') or 'unknown'}"
            if sub_info.get("ok"):
                sub_text += f" · по локациям: {sub_info.get('node_counts') or {}}"
            link_issues.append(f"{name}: links в S-UI API {api_count}/{desired_count}; {sub_text}")
    except Exception as exc:
        link_issues.append(f"Проверка ссылок не удалась: {str(exc)[:300]}")

    problems = len(missing_creds) + len(stale_creds) + len(missing_on_nodes) + len(ghost_on_nodes) + len(link_issues) + len(node_errors)
    lines = [
        "🔁 Сверка локаций и ссылок",
        "━━━━━━━━━━━━━━",
        f"Итог: {'✅ всё хорошо' if problems == 0 else '⚠️ есть что проверить'}",
        "",
        f"S-UI клиенты: всего {len(clients)} · активных {len(active_clients)} · должны быть на локациях {len(remote_eligible_names)}",
        f"Учётные данные node в SQLite: {len(cred_names)}",
        f"Локаций проверялось: {len(nodes)}",
        "",
        f"Нет учётных данных node у активных клиентов: {len(missing_creds)}",
        f"Старые учётные данные node: {len(stale_creds)}",
        f"Клиент должен быть на VPS, но его нет в config: {len(missing_on_nodes)}",
        f"Лишний клиент есть на VPS, но не должен быть: {len(ghost_on_nodes)}",
        f"Реальные проблемы со ссылками в подписке: {len(link_issues)}",
        f"Локации не прочитались по SSH/config: {len(node_errors)}",
    ]
    if subscription_ok_api_lag_count:
        lines.append(f"Подписок уже OK по фактической ссылке подписки: {subscription_ok_api_lag_count}")
    if checked_subscription_links:
        lines.append(f"Фактических ссылок подписки проверено: {checked_subscription_links}")
    if node_errors:
        lines += ["", "Важно: если VPS не прочиталась по SSH, она не участвует в проверке missing/ghost. Сначала восстанови SSH/VPS, потом запусти сверку снова."]
    if problems == 0:
        lines += ["", "Сверка ничего не меняет. Если итог зелёный, нажимать восстановление ссылок не нужно."]
    else:
        lines += ["", "Сверка ничего не меняет. Детали открой кнопкой ниже, а исправление делай через sync / восстановление ссылок / очистку хвостов."]

    sections = [
        ("❌ Нет учётных данных node для активных S-UI клиентов", missing_creds),
        ("🧹 Старые учётные данные node", stale_creds),
        ("❌ Клиент должен быть на VPS, но его нет в node config", missing_on_nodes),
        ("👻 Лишний клиент есть в node config, но не должен быть", ghost_on_nodes),
        ("🔗 Реальные проблемы со ссылками подписки", link_issues),
        ("⚠️ Локации не прочитались по SSH/config", node_errors),
    ]
    summary = "\n".join(lines).strip()
    if len(summary) > 3900:
        summary = summary[:3800].rstrip() + "\n\n… summary сокращён. Детали открой отдельной страницей."
    return {"summary": summary, "sections": sections, "problems": problems}


async def remote_reconciliation_report_text() -> str:
    # Backward-compatible wrapper for places that still expect plain text.
    return (await remote_reconciliation_report_data()).get("summary", "")


def _sql_placeholders(values: list[str]) -> str:
    return ",".join("?" for _ in values)


async def _sqlite_table_exists(conn: aiosqlite.Connection, table: str) -> bool:
    try:
        async with conn.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table,)) as cur:
            return await cur.fetchone() is not None
    except Exception:
        return False


async def _sqlite_names_from_table(db_path: str, table: str, col: str) -> set[str]:
    names: set[str] = set()
    async with db_connect(db_path) as conn:
        if not await _sqlite_table_exists(conn, table):
            return names
        try:
            async with conn.execute(f"SELECT DISTINCT {col} AS name FROM {table} WHERE {col} IS NOT NULL AND TRIM({col})!=''") as cur:
                rows = await cur.fetchall()
            for row in rows:
                val = str(row[0] if not isinstance(row, aiosqlite.Row) else row["name"] or "").strip()
                if val:
                    names.add(val)
        except Exception:
            return set()
    return names


async def _sqlite_count_names(db_path: str, table: str, col: str, names: set[str], extra_where: str = "") -> int:
    if not names:
        return 0
    vals = sorted(str(x) for x in names if str(x).strip())
    total = 0
    async with db_connect(db_path) as conn:
        if not await _sqlite_table_exists(conn, table):
            return 0
        for i in range(0, len(vals), 400):
            chunk = vals[i:i+400]
            where = f"{col} IN ({_sql_placeholders(chunk)})"
            if extra_where:
                where += " " + extra_where
            try:
                async with conn.execute(f"SELECT COUNT(*) FROM {table} WHERE {where}", tuple(chunk)) as cur:
                    row = await cur.fetchone()
                total += int((row[0] if row else 0) or 0)
            except Exception:
                pass
    return total


async def _sqlite_delete_names(db_path: str, table: str, col: str, names: set[str], extra_where: str = "") -> int:
    if not names:
        return 0
    vals = sorted(str(x) for x in names if str(x).strip())
    deleted = 0
    async with db_connect(db_path) as conn:
        if not await _sqlite_table_exists(conn, table):
            return 0
        for i in range(0, len(vals), 300):
            chunk = vals[i:i+300]
            where = f"{col} IN ({_sql_placeholders(chunk)})"
            if extra_where:
                where += " " + extra_where
            try:
                cur = await conn.execute(f"DELETE FROM {table} WHERE {where}", tuple(chunk))
                deleted += int(cur.rowcount or 0)
            except Exception:
                pass
        await conn.commit()
    return deleted



async def production_cleanup_stale_remote_credentials_once() -> dict:
    """Remove leftover remote credential/sync rows for clients that are absent from S-UI and node configs.
    This is intentionally narrower than full cleanup: it only targets remote credential tails."""
    await init_remote_nodes_db()
    clients = await get_all_clients(force_refresh=True)
    sui_names = {str(c.get("name") or "").strip() for c in clients if str(c.get("name") or "").strip()}

    nodes_cfg = remote_load_nodes_config()
    nodes = [n for n in remote_admin_nodes_all(nodes_cfg) if n.get("enabled", True) and not n.get("maintenance")]
    node_names: set[str] = set()
    node_errors: list[str] = []
    if nodes:
        results = await asyncio.gather(*[remote_reconciliation_collect_node_users(nodes_cfg, n) for n in nodes], return_exceptions=False)
        for res in results:
            if not res.get("ok"):
                node_errors.append(f"{res.get('node_id')}: {res.get('error') or 'unknown'}")
            for u in (res.get("users") or []):
                name = str(u.get("name") or "").strip()
                if name:
                    node_names.add(name)

    active_enforcement_names: set[str] = set()
    with contextlib.suppress(Exception):
        async with db_connect(ANTIABUSE_DB) as conn:
            if await _sqlite_table_exists(conn, "antiabuse_enforcement"):
                async with conn.execute("SELECT DISTINCT name FROM antiabuse_enforcement WHERE is_active=1 AND name IS NOT NULL AND TRIM(name)!=''") as cur:
                    rows = await cur.fetchall()
                active_enforcement_names = {str(r[0]).strip() for r in rows if str(r[0]).strip()}

    protected = sui_names | node_names | active_enforcement_names
    cred_names = await _sqlite_names_from_table(DATABASE_DB, "remote_client_credentials", "client_name")
    stale = set(cred_names) - protected
    tables = {
        "remote_client_credentials": "client_name",
        "remote_client_sync": "client_name",
        "remote_antiabuse_events": "client_name",
        "remote_antiabuse_notifications": "client_name",
    }
    counts = {table: await _sqlite_count_names(DATABASE_DB, table, col, stale) for table, col in tables.items()}
    deleted: dict[str, int] = {}
    for table, col in tables.items():
        deleted[table] = await _sqlite_delete_names(DATABASE_DB, table, col, stale)
    queued = remote_request_sync(reason="production_cleanup_leftover_stale_credentials") if stale else {"queued": False}
    return {
        "stale_names": sorted(stale),
        "counts": counts,
        "deleted": deleted,
        "protected_sui": len(sui_names),
        "protected_node": len(node_names),
        "protected_enforcement": len(active_enforcement_names),
        "node_errors": node_errors,
        "remote_sync": queued,
    }


def production_stale_credentials_result_text(result: dict) -> str:
    names = result.get("stale_names") or []
    counts = result.get("counts") or {}
    deleted = result.get("deleted") or {}
    lines = [
        "🧹 Очистка старых node-credentials",
        "━━━━━━━━━━━━━━",
        f"Найдено старых node-credentials: {len(names)}",
        f"Защищены, потому что есть в S-UI: {result.get('protected_sui', 0)}",
        f"Защищены, потому что есть на VPS-node: {result.get('protected_node', 0)}",
        f"Защищены активными Antiabuse-ограничениями: {result.get('protected_enforcement', 0)}",
    ]
    if result.get("node_errors"):
        lines += ["", "⚠️ VPS не прочитались по SSH/config:"]
        for x in (result.get("node_errors") or [])[:5]:
            lines.append(f"• {x}")
    if names:
        lines += ["", "Удалены старые имена:"]
        for x in names[:15]:
            lines.append(f"• {x}")
        if len(names) > 15:
            lines.append(f"… ещё {len(names)-15}")
    lines += ["", "Строк было до очистки:"]
    any_count = False
    for k, v in counts.items():
        if int(v or 0):
            any_count = True
            lines.append(f"• {k}: {v}")
    if not any_count:
        lines.append("• 0")
    lines += ["", "Удалено строк:"]
    any_deleted = False
    for k, v in deleted.items():
        if int(v or 0):
            any_deleted = True
            lines.append(f"• {k}: {v}")
    if not any_deleted:
        lines.append("• 0")
    if (result.get("remote_sync") or {}).get("queued"):
        lines.append("Sync локаций: поставлен в очередь")
    lines += ["", "Эта очистка не меняет S-UI и не трогает клиентов, которые есть в S-UI, на VPS-node или под активным ограничением."]
    text = "\n".join(lines).strip()
    if len(text) > 3900:
        text = text[:3800].rstrip() + "\n\n… сообщение сокращено."
    return text


async def remote_restore_managed_links_once() -> dict:
    """Force rebuild managed external links for active paid remote clients using current node state/credentials."""
    await init_remote_nodes_db()
    nodes_cfg = remote_load_nodes_config()
    state = await remote_load_node_state()
    clients = await get_all_clients(force_refresh=True)
    active_clients = [c for c in clients if client_is_active_for_remote_report(c)]
    prepared = await remote_prepare_clients(active_clients)
    rows: list[dict] = []
    updated = 0
    skipped = 0
    failed = 0
    for client in prepared:
        name = str(client.get("name") or "").strip()
        if not name or not remote_is_paid_active_client(client):
            continue
        try:
            current = remote_client_links(client)
            preserved = [link for link in current if not remote_is_managed_link(link, nodes_cfg)]
            managed_current = [link for link in current if remote_is_managed_link(link, nodes_cfg)]
            desired = remote_desired_links_for_client(nodes_cfg, state, client)
            before = len(managed_current)
            after = len(desired)
            if after <= 0:
                skipped += 1
                rows.append({"name": name, "status": "skipped", "before": before, "after": after, "error": "desired links empty"})
                continue
            sub_info = await remote_subscription_managed_count(name, nodes_cfg)
            if before != after and remote_subscription_matches_desired_nodes(sub_info, desired, nodes_cfg):
                skipped += 1
                rows.append({"name": name, "status": "subscription_ok", "before": before, "after": after, "actual": int(sub_info.get("count") or 0), "error": "реальная подписка уже содержит нужные ссылки; обновлять не нужно"})
                continue
            old_hash = remote_sha256_text(json.dumps(current, ensure_ascii=False, sort_keys=True))
            new_links = preserved + desired
            new_hash = remote_sha256_text(json.dumps(new_links, ensure_ascii=False, sort_keys=True))
            if old_hash == new_hash:
                skipped += 1
                rows.append({"name": name, "status": "ok", "before": before, "after": after, "error": "already synced"})
                continue
            await remote_post_sui_client_links(client, new_links)
            actual_after = after
            with contextlib.suppress(Exception):
                fresh_clients = await get_all_clients(force_refresh=True)
                fresh = next((fc for fc in fresh_clients if str(fc.get("name") or "").strip() == name), None)
                if fresh:
                    actual_after = len([x for x in remote_client_links(fresh) if remote_is_managed_link(x, nodes_cfg)])
            if actual_after < after:
                failed += 1
                rows.append({"name": name, "status": "verify_failed", "before": before, "after": after, "actual": actual_after, "error": f"S-UI still reports links {actual_after}/{after}"})
                continue
            updated += 1
            rows.append({"name": name, "status": "updated", "before": before, "after": after, "actual": actual_after, "error": ""})
            for node in remote_enabled_nodes(nodes_cfg):
                await remote_record_client_sync(name, str(node.get("id")), status="links_restored", links_hash=new_hash)
        except Exception as exc:
            failed += 1
            rows.append({"name": name, "status": "failed", "before": -1, "after": -1, "error": str(exc)[:500]})
            logging.warning("remote restore managed links failed client=%s: %s", name, exc)
    if updated:
        invalidate_sui_clients_cache()
    return {"updated": updated, "skipped": skipped, "failed": failed, "rows": rows}


def remote_restore_links_result_data(result: dict, cleanup_result: dict | None = None) -> dict:
    rows = result.get("rows") or []
    updated_rows = [r for r in rows if str(r.get("status") or "") == "updated"]
    ok_rows = [r for r in rows if str(r.get("status") or "") in {"ok", "subscription_ok"}]
    skipped_rows = [r for r in rows if str(r.get("status") or "") == "skipped"]
    problem_rows = [r for r in rows if str(r.get("status") or "") not in {"updated", "ok", "subscription_ok", "skipped"}]
    subscription_ok_count = sum(1 for r in rows if str(r.get("status") or "") == "subscription_ok")
    stale = (cleanup_result or {}).get("stale_names") or []
    lines = [
        "🔗 Восстановление ссылок локаций",
        "━━━━━━━━━━━━━━",
        f"Обновлено клиентов: {result.get('updated', 0)}",
        f"Уже было правильно / без изменений: {len(ok_rows)}",
        f"Пропущено: {len(skipped_rows)}",
        f"Ошибок: {result.get('failed', 0)}",
    ]
    if subscription_ok_count:
        lines.append(f"Подписок уже OK по фактической ссылке подписки: {subscription_ok_count}")
    if cleanup_result:
        lines += ["", f"Очистка старых учётных данных node: удалено имён {len(stale)}"]
    if problem_rows:
        lines += ["", "⚠️ Есть проблемы. Открой детали кнопкой ниже."]
    elif int(result.get('updated') or 0) > 0:
        lines += ["", "✅ Ссылки обновлены. Через минуту открой сверку ещё раз."]
    else:
        lines += ["", "✅ Восстановление не требовалось: реальные подписки уже содержат нужные ссылки."]
    lines += ["", "Этот инструмент пересобирает только ссылки локаций, которыми управляет бот. S-UI клиентов и тарифы он не меняет."]

    def fmt_row(r: dict) -> str:
        status = str(r.get("status") or "")
        name = str(r.get("name") or "—")
        before = int(r.get("before") or 0) if str(r.get("before") or "").lstrip("-").isdigit() else r.get("before")
        after = int(r.get("after") or 0) if str(r.get("after") or "").lstrip("-").isdigit() else r.get("after")
        actual = r.get("actual")
        if status == "subscription_ok":
            return f"{name}: OK в фактической подписке · нужно {after} ссылок"
        if status == "ok":
            return f"{name}: уже синхронизировано · ссылок {after}"
        if status == "updated":
            return f"{name}: обновлено · было {before}, стало {after}"
        if status == "skipped":
            return f"{name}: пропущено · {r.get('error') or 'нет ожидаемых ссылок'}"
        extra = f" · фактически {actual}" if actual is not None else ""
        return f"{name}: {status} · было {before}, нужно {after}{extra} · {r.get('error') or '—'}"

    sections = [
        ("❌ Ошибки восстановления", [fmt_row(r) for r in problem_rows]),
        ("✅ Обновлено", [fmt_row(r) for r in updated_rows]),
        ("ℹ️ Уже было правильно", [fmt_row(r) for r in ok_rows]),
        ("⏭ Пропущено", [fmt_row(r) for r in skipped_rows]),
        ("🧹 Удалённые старые имена", [str(x) for x in stale]),
    ]
    summary = "\n".join(lines).strip()
    if len(summary) > 3900:
        summary = summary[:3800].rstrip() + "\n\n… summary сокращён. Детали открой отдельной страницей."
    return {"summary": summary, "sections": sections}


def remote_restore_links_result_text(result: dict, cleanup_result: dict | None = None) -> str:
    return remote_restore_links_result_data(result, cleanup_result).get("summary", "")


async def production_cleanup_build_plan() -> dict:
    """Safe stale/orphan cleanup plan. S-UI remains the source of truth.
    The plan protects active S-UI clients, users still present on node configs, and active antiabuse restrictions."""
    await init_remote_nodes_db()
    await init_remote_antiabuse_db()
    await init_antiabuse_db()
    clients = await get_all_clients(force_refresh=True)
    sui_names = {str(c.get("name") or "").strip() for c in clients if str(c.get("name") or "").strip()}

    nodes_cfg = remote_load_nodes_config()
    nodes = [n for n in remote_admin_nodes_all(nodes_cfg) if n.get("enabled", True) and not n.get("maintenance")]
    node_names: set[str] = set()
    node_errors: list[str] = []
    if nodes:
        results = await asyncio.gather(*[remote_reconciliation_collect_node_users(nodes_cfg, n) for n in nodes], return_exceptions=False)
        for res in results:
            if not res.get("ok"):
                node_errors.append(f"{res.get('node_id')}: {res.get('error') or 'unknown'}")
            for u in (res.get("users") or []):
                name = str(u.get("name") or "").strip()
                if name:
                    node_names.add(name)

    active_enforcement_names: set[str] = set()
    with contextlib.suppress(Exception):
        async with db_connect(ANTIABUSE_DB) as conn:
            if await _sqlite_table_exists(conn, "antiabuse_enforcement"):
                async with conn.execute("SELECT DISTINCT name FROM antiabuse_enforcement WHERE is_active=1 AND name IS NOT NULL AND TRIM(name)!=''") as cur:
                    rows = await cur.fetchall()
                active_enforcement_names = {str(r[0]).strip() for r in rows if str(r[0]).strip()}

    protected = set(sui_names) | set(node_names) | set(active_enforcement_names)

    remote_tables = {
        "remote_client_credentials": "client_name",
        "remote_client_sync": "client_name",
        "remote_antiabuse_events": "client_name",
        "remote_antiabuse_notifications": "client_name",
    }
    anti_tables = {
        "antiabuse_events": ("client_name", ""),
        "antiabuse_cases": ("name", ""),
        "antiabuse_notifications": ("name", ""),
        "antiabuse_warnings": ("client_name", ""),
        "alerts": ("name", ""),
        "matches": ("name", ""),
        "ip_state": ("name", ""),
        "raw_events": ("name", ""),
        "antiabuse_enforcement": ("name", "AND COALESCE(is_active,0)=0"),
    }

    all_remote_names: set[str] = set()
    for table, col in remote_tables.items():
        all_remote_names |= await _sqlite_names_from_table(DATABASE_DB, table, col)
    all_anti_names: set[str] = set()
    for table, (col, _extra) in anti_tables.items():
        all_anti_names |= await _sqlite_names_from_table(ANTIABUSE_DB, table, col)

    stale_remote_names = all_remote_names - protected
    stale_antiabuse_names = all_anti_names - protected
    protected_node_or_enforced = (node_names | active_enforcement_names) - sui_names

    remote_counts: dict[str, int] = {}
    for table, col in remote_tables.items():
        remote_counts[table] = await _sqlite_count_names(DATABASE_DB, table, col, stale_remote_names)
    anti_counts: dict[str, int] = {}
    for table, (col, extra) in anti_tables.items():
        anti_counts[table] = await _sqlite_count_names(ANTIABUSE_DB, table, col, stale_antiabuse_names, extra)

    return {
        "created_at": time.time(),
        "sui_names_count": len(sui_names),
        "node_names_count": len(node_names),
        "active_enforcement_count": len(active_enforcement_names),
        "stale_remote_names": sorted(stale_remote_names),
        "stale_antiabuse_names": sorted(stale_antiabuse_names),
        "protected_stale_names": sorted(protected_node_or_enforced),
        "remote_counts": remote_counts,
        "anti_counts": anti_counts,
        "node_errors": node_errors,
    }


def production_cleanup_plan_data(plan: dict, *, applied: bool = False, result: dict | None = None) -> dict:
    stale_remote = plan.get("stale_remote_names") or []
    stale_abuse = plan.get("stale_antiabuse_names") or []
    protected = plan.get("protected_stale_names") or []
    remote_counts = plan.get("remote_counts") or {}
    anti_counts = plan.get("anti_counts") or {}
    total_rows = sum(int(v or 0) for v in remote_counts.values()) + sum(int(v or 0) for v in anti_counts.values())
    deleted_total = sum(int(v or 0) for v in ((result or {}).get("deleted") or {}).values())
    lines = [
        "🧹 Очистка хвостов",
        "━━━━━━━━━━━━━━",
        f"Статус: {'✅ применено' if applied else 'предпросмотр'}",
        "",
        f"Защищено клиентов из S-UI: {plan.get('sui_names_count', 0)}",
        f"Защищено клиентов, найденных на VPS: {plan.get('node_names_count', 0)}",
        f"Защищено активных ограничений Antiabuse: {plan.get('active_enforcement_count', 0)}",
        "",
        f"Старых remote-имён: {len(stale_remote)}",
        f"Старых antiabuse-имён: {len(stale_abuse)}",
        f"Строк к удалению: {total_rows}",
    ]
    if applied:
        lines.append(f"Строк удалено: {deleted_total}")
    if plan.get("node_errors"):
        lines += ["", f"⚠️ Не удалось прочитать VPS: {len(plan.get('node_errors') or [])}", "Очистка всё равно защищает S-UI клиентов, но ghost users на недоступной VPS не видны."]
    if total_rows > 0 and not applied:
        lines += ["", "Перед применением открой списки кнопкой ниже и проверь имена."]
    elif total_rows <= 0:
        lines += ["", "✅ Удалять нечего."]
    if result and (result.get("remote_sync") or {}).get("queued"):
        lines.append("Sync локаций: поставлен в очередь")
    lines += ["", "Очистка не меняет S-UI и не трогает клиентов, которые есть в S-UI, на VPS или под активным ограничением."]

    tables = []
    for k, v in remote_counts.items():
        if int(v or 0):
            tables.append(f"{k}: {v}")
    for k, v in anti_counts.items():
        if int(v or 0):
            tables.append(f"{k}: {v}")
    deleted_lines = []
    if result:
        for k, v in (result.get("deleted") or {}).items():
            if int(v or 0):
                deleted_lines.append(f"{k}: {v}")
    sections = [
        ("🧹 Remote-хвосты", [str(x) for x in stale_remote]),
        ("🛡 Antiabuse-хвосты", [str(x) for x in stale_abuse]),
        ("🟡 Не трогаем: есть на VPS или под активным ограничением", [str(x) for x in protected]),
        ("⚠️ VPS не прочитались", [str(x) for x in (plan.get("node_errors") or [])]),
        ("Таблицы с удаляемыми строками", tables),
        ("Удалено по таблицам", deleted_lines),
    ]
    summary = "\n".join(lines).strip()
    if len(summary) > 3900:
        summary = summary[:3800].rstrip() + "\n\n… summary сокращён. Детали открой отдельной страницей."
    return {"summary": summary, "sections": sections, "total_rows": total_rows}


def production_cleanup_plan_text(plan: dict, *, applied: bool = False, result: dict | None = None) -> str:
    return production_cleanup_plan_data(plan, applied=applied, result=result).get("summary", "")


async def production_cleanup_apply(plan: dict) -> dict:
    stale_remote = set(plan.get("stale_remote_names") or [])
    stale_abuse = set(plan.get("stale_antiabuse_names") or [])
    deleted: dict[str, int] = {}
    remote_tables = {
        "remote_client_credentials": "client_name",
        "remote_client_sync": "client_name",
        "remote_antiabuse_events": "client_name",
        "remote_antiabuse_notifications": "client_name",
    }
    anti_tables = {
        "antiabuse_events": ("client_name", ""),
        "antiabuse_cases": ("name", ""),
        "antiabuse_notifications": ("name", ""),
        "antiabuse_warnings": ("client_name", ""),
        "alerts": ("name", ""),
        "matches": ("name", ""),
        "ip_state": ("name", ""),
        "raw_events": ("name", ""),
        "antiabuse_enforcement": ("name", "AND COALESCE(is_active,0)=0"),
    }
    for table, col in remote_tables.items():
        deleted[table] = await _sqlite_delete_names(DATABASE_DB, table, col, stale_remote)
    for table, (col, extra) in anti_tables.items():
        deleted[table] = await _sqlite_delete_names(ANTIABUSE_DB, table, col, stale_abuse, extra)
    queued = remote_request_sync(reason="production_cleanup_stale_orphans") if stale_remote else {"queued": False}
    return {"deleted": deleted, "remote_sync": queued}


def server_code_migration_make_new_name(old_name: str, old_code: str, new_code: str) -> str:
    old_name = str(old_name or "").strip(); old_code = str(old_code or "").strip(); new_code = str(new_code or "").strip()
    if not old_name or not old_code or not new_code:
        return old_name
    if old_name == old_code:
        return new_code
    prefix = old_code + "-"
    if old_name.startswith(prefix):
        return new_code + "-" + old_name[len(prefix):]
    return old_name


def server_code_migration_rewrite_desc(desc: str, old_code: str, new_code: str) -> str:
    raw = str(desc or "")
    old_code_esc = re.escape(str(old_code or ""))
    new_code_s = str(new_code or "")
    if not old_code_esc:
        return raw
    return re.sub(rf"(\bPLAN=[^\s_/]+_)({old_code_esc})(\b)", lambda m: m.group(1) + new_code_s + m.group(3), raw)


async def server_code_migration_build_plan(old_code: str, new_code: str) -> dict:
    old_code = client_name_part(old_code)
    new_code = client_name_part(new_code)
    if not old_code or not new_code or old_code == new_code:
        raise RuntimeError("Укажи разные old_code и new_code, например: MAIN OriginalVPN")
    clients = await get_all_clients(force_refresh=True)
    existing_names = {str(c.get("name") or "").strip() for c in clients}
    renames: list[dict] = []
    desc_updates: list[dict] = []
    conflicts: list[str] = []
    for c in clients:
        name = str(c.get("name") or "").strip()
        if not name:
            continue
        new_name = server_code_migration_make_new_name(name, old_code, new_code)
        new_desc = server_code_migration_rewrite_desc(str(c.get("desc") or ""), old_code, new_code)
        if new_name != name:
            if new_name in existing_names:
                conflicts.append(f"{name} → {new_name}")
                continue
            renames.append({"old": name, "new": new_name, "client": c, "desc": new_desc})
        elif new_desc != str(c.get("desc") or ""):
            desc_updates.append({"old": name, "new": name, "client": c, "desc": new_desc})
    return {"old_code": old_code, "new_code": new_code, "renames": renames, "desc_updates": desc_updates, "conflicts": conflicts, "created_at": time.time()}


def server_code_migration_plan_text(plan: dict, *, applied: bool = False) -> str:
    renames = plan.get("renames") or []
    desc_updates = plan.get("desc_updates") or []
    conflicts = plan.get("conflicts") or []
    lines = ["🧬 Миграция server_code", "━━━━━━━━━━━━━━", f"Old: {plan.get('old_code')}", f"New: {plan.get('new_code')}", f"Статус: {'✅ применено' if applied else 'предпросмотр'}", "", f"Переименований S-UI: {len(renames)}", f"Только desc PLAN: {len(desc_updates)}", f"Конфликтов: {len(conflicts)}"]
    if renames:
        lines += ["", "Будут переименованы:"]
        for item in renames[:15]:
            lines.append(f"• {item['old']} → {item['new']}")
        if len(renames) > 15:
            lines.append(f"… ещё {len(renames)-15}")
    if desc_updates:
        lines += ["", "Будет обновлён desc PLAN без смены имени:"]
        for item in desc_updates[:10]:
            lines.append(f"• {item['old']}")
        if len(desc_updates) > 10:
            lines.append(f"… ещё {len(desc_updates)-10}")
    if conflicts:
        lines += ["", "⚠️ Конфликты имён, они НЕ будут изменены:"]
        for x in conflicts[:10]:
            lines.append(f"• {x}")
    lines += ["", "Применение обновит S-UI через editbulk, SQLite antiabuse/remote имена и поставит remote sync в очередь."]
    return "\n".join(lines).strip()[:3900]


async def server_code_migration_update_sqlite_name(old: str, new: str) -> None:
    targets = [(DATABASE_DB, {"remote_client_credentials": "client_name", "remote_client_sync": "client_name", "remote_antiabuse_events": "client_name"}), (ANTIABUSE_DB, {"antiabuse_events": "client_name", "antiabuse_cases": "name", "antiabuse_notifications": "name", "antiabuse_warnings": "client_name", "alerts": "name", "matches": "name", "ip_state": "name", "antiabuse_enforcement": "name"})]
    for db_path, table_cols in targets:
        async with db_connect(db_path) as conn:
            for table, col in table_cols.items():
                try:
                    await conn.execute(f"UPDATE {table} SET {col}=? WHERE {col}=?", (new, old))
                except Exception:
                    pass
            await conn.commit()


async def server_code_migration_apply(plan: dict) -> dict:
    renames = plan.get("renames") or []
    desc_updates = plan.get("desc_updates") or []
    updated_payloads = []
    for item in renames + desc_updates:
        c = dict(item.get("client") or {})
        payload = build_editbulk_client_payload(c, int(c.get("expiry") or 0), int(c.get("volume") or 0))
        payload["name"] = str(item.get("new") or payload.get("name"))
        payload["desc"] = str(item.get("desc") or payload.get("desc") or "")
        updated_payloads.append(payload)
    if updated_payloads:
        for i in range(0, len(updated_payloads), 40):
            await post_sui_editbulk_clients(updated_payloads[i:i+40])
    for item in renames:
        await server_code_migration_update_sqlite_name(str(item.get("old")), str(item.get("new")))
    invalidate_sui_clients_cache()
    queued = remote_request_sync(reason=f"server_code_migration:{plan.get('old_code')}->{plan.get('new_code')}")
    return {"sui_updated": len(updated_payloads), "renamed": len(renames), "desc_updated": len(desc_updates), "remote_sync": queued}

def antiabuse_status_label(status: str) -> str:
    raw = str(status or "new")
    if raw == "review":
        raw = "check"
    return {
        "new": "🆕 новый",
        "check": "🟡 на проверке",
        "ok": "✅ норма",
        "ignore": "🙈 игнор",
    }.get(raw, raw)


def antiabuse_case_list_text(cases: list[dict], status: str = "suspicious", page: int = 1, per_page: int = 10, remote_cases: list[dict] | None = None) -> str:
    """Compact unified Antiabuse report: case rows are buttons, not duplicated in message text."""
    title_map = {"suspicious": "🛡 Antiabuse отчёт", "all": "📋 Все кейсы", "check": "🟡 На проверке", "ignore": "🙈 Игнор", "ok": "✅ Норма"}
    title = title_map.get(status, "🛡 Antiabuse отчёт")
    pages = max(1, (len(cases) + per_page - 1) // per_page) if cases else 1
    page = max(1, min(int(page or 1), pages))
    suspicious = [x for x in cases if x.get("suspicious")]
    source_counts = {"main": 0, "node": 0, "mixed": 0}
    for item in cases:
        label = str(item.get("source_label") or "")
        if label.startswith("main"):
            source_counts["main"] += 1
        elif label.startswith("локации"):
            source_counts["node"] += 1
        elif label.startswith("mixed"):
            source_counts["mixed"] += 1
    parts = [
        title,
        "━━━━━━━━━━━━━━",
        f"Всего кейсов: {len(cases)}",
        f"Подозрительных по лимиту: {len(suspicious)}",
        f"Источники: main {source_counts['main']} · node {source_counts['node']} · mixed {source_counts['mixed']}",
        f"Страница: {page}/{pages}",
    ]
    if not cases:
        parts += ["", "Ничего не найдено."]
    else:
        parts += [
            "",
            "Кейсы открываются кнопками ниже. Список подписок больше не дублируется в тексте сообщения.",
            "Удалённые/старые кейсы без текущих данных скрываются из общего списка; S-UI остаётся источником истины.",
        ]
    parts += ["", "Main и node считаются одним Antiabuse: одинаковый IP между источниками считается один раз."]
    return "\n".join(parts).strip()


