def antiabuse_keyboard(cases: list[dict], mode: str = "suspicious", page: int = 1, per_page: int = 10, remote_cases: list[dict] | None = None) -> InlineKeyboardMarkup:
    rows = [
        [InlineKeyboardButton(text="⚠️ Только подозрительные", callback_data="antiabuse:report"), InlineKeyboardButton(text="📋 Все", callback_data="antiabuse:all")],
        [InlineKeyboardButton(text="🟡 На проверке", callback_data="antiabuse:check"), InlineKeyboardButton(text="🙈 Игнор", callback_data="antiabuse:ignore")],
        [InlineKeyboardButton(text="⚙️ Настройки node collector", callback_data="remoteabuse:panel")],
        [InlineKeyboardButton(text="🔄 Обновить", callback_data=f"antiabuse:refresh:{mode}:{page}")],
    ]
    total = len(cases)
    page = max(1, int(page or 1))
    pages = max(1, (total + per_page - 1) // per_page)
    if page > pages:
        page = pages
    for item in cases[(page - 1) * per_page:page * per_page]:
        badge = antiabuse_status_label(item["admin_status"]).split(" ", 1)[0]
        label = str(item.get("source_label") or "")
        source_icon = "🌍" if label.startswith("локации") else ("🔀" if label.startswith("mixed") else "🏠")
        rows.append([InlineKeyboardButton(text=f"{source_icon} {badge} {item['unique_window']}/{item['limit_value']} · {item['name'][:28]}", callback_data=f"antiabuse:view:{item['case_id']}:{mode}")])
    nav = []
    if page > 1:
        nav.append(InlineKeyboardButton(text="◀️", callback_data=f"antiabuse:page:{mode}:{page-1}"))
    nav.append(InlineKeyboardButton(text=f"{page}/{pages}", callback_data="noop"))
    if page < pages:
        nav.append(InlineKeyboardButton(text="▶️", callback_data=f"antiabuse:page:{mode}:{page+1}"))
    rows.append(nav)
    rows.append([InlineKeyboardButton(text="← К 🛠 Админ", callback_data="admin:panel")])
    return InlineKeyboardMarkup(inline_keyboard=rows)


