def remote_antiabuse_parse_diagnostics(log_text: str) -> tuple[str, str]:
    rx_from = re.compile(r"\[(?P<cid>\d+)\s+[^\]]+\]\s+inbound/(?P<proto>vless|hysteria2|tuic)\[[^\]]+\]: inbound(?: packet)? connection from (?P<addr>\S+)")
    rx_name = re.compile(r"\[(?P<cid>\d+)\s+[^\]]+\]\s+inbound/(?P<proto>vless|hysteria2|tuic)\[[^\]]+\]: \[(?P<name>[^\]]+)\] inbound(?: packet)? connection to")
    rx_out = re.compile(r"\[(?P<cid>\d+)\s+[^\]]+\]\s+outbound/[^\[]+\[(?P<tag>[^\]]+)\]: outbound")
    proto_counts = {"vless": 0, "hysteria2": 0, "tuic": 0}
    from_count = name_count = out_count = 0
    examples = []
    by_cid = {}
    for line in str(log_text or "").splitlines():
        m = rx_from.search(line)
        if m:
            from_count += 1
            proto_counts[m.group("proto")] = proto_counts.get(m.group("proto"), 0) + 1
            by_cid.setdefault(m.group("cid"), {})["from"] = line
            continue
        m = rx_name.search(line)
        if m:
            name_count += 1
            by_cid.setdefault(m.group("cid"), {})["name"] = line
            continue
        m = rx_out.search(line)
        if m:
            out_count += 1
            by_cid.setdefault(m.group("cid"), {})["out"] = line
    for cid, parts in by_cid.items():
        if len(examples) >= 20:
            break
        if parts.get("from") or parts.get("name") or parts.get("out"):
            examples.append(f"CID {cid}\nFROM: {parts.get('from','—')}\nNAME: {parts.get('name','—')}\nOUT : {parts.get('out','—')}")
    summary = [
        f"Строк проверено: {len(str(log_text or '').splitlines())}",
        f"source_ip строк: {from_count}",
        f"client_name строк: {name_count}",
        f"outbound tag строк: {out_count}",
        "Протоколы: " + ", ".join(f"{k}={v}" for k, v in proto_counts.items()),
    ]
    full = "REMOTE ANTIABUSE DIAGNOSTICS\n\nSUMMARY\n" + "\n".join(summary) + "\n\nEXAMPLES\n" + "\n\n".join(examples) + "\n\nRAW LOGS\n" + str(log_text or "")
    return "\n".join(summary), full


