def tariff_node_scope_menu_text(tariff: Tariff) -> str:
    nodes_cfg = remote_load_nodes_config()
    nodes = remote_admin_nodes_all(nodes_cfg or {})
    selected = tariff_remote_node_scope_ids(tariff)
    mode = "все доступные локации" if selected is None else ("ни одной локации" if not selected else "выбранные локации")
    lines = [
        "🌍 VPN-локации тарифа",
        "━━━━━━━━━━━━━━",
        f"Тариф: {tariff.title} ({tariff.key})",
        f"Режим: {mode}",
        "",
        "Что делает этот раздел:",
        "• выбирает, на какие VPS-node попадёт клиент этого тарифа;",
        "• управляет ссылками локаций в подписке пользователя;",
        "• если локация не выбрана — клиента не будет в config этой VPS.",
        "",
        "Важно: глобально выключенные, maintenance или drain node всё равно не выдаются, даже если тариф их выбрал.",
        "",
        "Доступные локации:",
    ]
    if not nodes:
        lines.append("• nodes.json пуст или недоступен")
    for node in nodes:
        nid = str(node.get("id") or "").strip()
        if not nid:
            continue
        display = str(node.get("display_name") or nid.upper())
        globally_available = bool(node.get("enabled", True)) and not bool(node.get("maintenance")) and not bool(node.get("drain")) and bool(node.get("include_in_paid", True))
        if selected is None:
            mark = "✅" if globally_available else "⚪"
        else:
            mark = "✅" if nid in selected else "⬜"
        note = "доступна" if globally_available else "не выдаётся глобально"
        lines.append(f"{mark} {display} ({nid}) · {note}")
    return "\n".join(lines)

def tariff_node_scope_keyboard(tariff: Tariff) -> InlineKeyboardMarkup:
    rows: list[list[InlineKeyboardButton]] = []
    selected = tariff_remote_node_scope_ids(tariff)
    all_mode = selected is None
    rows.append([InlineKeyboardButton(text=("✅ Все доступные локации" if all_mode else "🌍 Использовать все доступные локации"), callback_data=f"admin:tariff:nodes_all:{tariff.key}")])
    try:
        nodes_cfg = remote_load_nodes_config()
        nodes = [n for n in remote_admin_nodes_all(nodes_cfg or {}) if n.get("id")]
    except Exception:
        nodes = []
    for node in nodes:
        nid = str(node.get("id") or "").strip()
        if not nid:
            continue
        globally_available = bool(node.get("enabled", True)) and not bool(node.get("maintenance")) and not bool(node.get("drain")) and bool(node.get("include_in_paid", True))
        checked = all_mode or (selected is not None and nid in selected)
        prefix = "✅" if checked else "⬜"
        if not globally_available:
            prefix = "⚫" if checked else "▫️"
        label = public_location_name_from_node(node)
        suffix = "" if globally_available else " · глобально недоступна"
        rows.append([InlineKeyboardButton(text=f"{prefix} {label}{suffix}", callback_data=f"admin:tariff:nodes_toggle:{tariff.key}:{nid}")])
    rows.append([InlineKeyboardButton(text="🔄 Запустить sync после изменения", callback_data=f"admin:tariff:nodes_sync:{tariff.key}")])
    rows.append([InlineKeyboardButton(text="← К тарифу", callback_data=f"admin:tariff:view:{tariff.key}")])
    return InlineKeyboardMarkup(inline_keyboard=rows)


