def tariff_periods_admin_summary(tariff: Tariff) -> str:
    lines = []
    for period in tariff_periods_for_tariff(tariff):
        status = "🟢" if period.enabled else "⚫"
        base = " · базовый" if period.is_base else ""
        visible = " · доступен" if period in tariff_available_periods(tariff) else " · не показывается"
        price = []
        if tariff.rub_payment_enabled:
            price.append(f"{int(period.rub_price or 0)} ₽")
        if tariff.stars_payment_enabled:
            price.append(f"{int(period.stars_price or 0)} ⭐")
        price_text = " / ".join(price) if price else "нет активных способов оплаты"
        lines.append(f"{status} {tariff_period_label(period)} · {price_text}{visible}{base}")
    return "\n".join(lines) if lines else "—"


