    now_ts = time.time()
    day_ago = now_ts - 86400
    week_ago = now_ts - 86400 * 7
    month_ago = now_ts - 86400 * 30
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row

        async def one(query: str, params=()):
            async with conn.execute(query, params) as cur:
                return await cur.fetchone()

        row1 = await one("SELECT COUNT(*) AS c FROM payments WHERE status='success' AND created_at>=?", (day_ago,))
        row7 = await one("SELECT COUNT(*) AS c FROM payments WHERE status='success' AND created_at>=?", (week_ago,))
        row30 = await one("SELECT COUNT(*) AS c FROM payments WHERE status='success' AND created_at>=?", (month_ago,))
        stars1 = await one("SELECT COALESCE(SUM(amount),0) AS s FROM payments WHERE status='success' AND currency='XTR' AND created_at>=?", (day_ago,))
        stars7 = await one("SELECT COALESCE(SUM(amount),0) AS s FROM payments WHERE status='success' AND currency='XTR' AND created_at>=?", (week_ago,))
        stars30 = await one("SELECT COALESCE(SUM(amount),0) AS s FROM payments WHERE status='success' AND currency='XTR' AND created_at>=?", (month_ago,))
