def payment_watchdog_alert_text(row, kind: str, extra: str = "") -> str:
    parts = [
        "⚠️ Контроль платежей",
        "━━━━━━━━━━━━━━",
        f"Событие: {kind}",
        f"Payment ID: #{row['id']}",
        f"TGID: {row['user_id']}",
        f"Тип: {payment_kind_label(str(row['kind']))}",
        f"Тариф: {str(row['tarif_key'] or '—')}",
        f"Сумма: {payment_amount_text_from_row(row)}",
        f"Провайдер: {str(row['provider'] or '—')}",
        f"Статус: {str(row['status'] or '—')}",
        f"Применение: {str(row['application_status'] or '—')}",
        f"Статус провайдера: {str(row['provider_status'] or '—') if 'provider_status' in row.keys() else '—'}",
        f"Создан: {payment_dt_text(row['created_at'])}",
    ]
    if extra:
        parts.extend(["", str(extra)[:900]])
    return "\n".join(parts)


async def platega_monitor_success_payments_for_reversal(bot: Bot) -> None:
    if not (platega_enabled() and PLATEGA_CHARGEBACK_MONITOR_ENABLED):
        return
    rows = await list_recent_success_platega_payments_for_security(
        days=PLATEGA_CHARGEBACK_CHECK_DAYS,
        stale_seconds=PLATEGA_CHARGEBACK_POLL_SECONDS,
        limit=20,
    )
    for row in rows:
        payment_id = int(row["id"])
        transaction_id = str(row["provider_charge_id"] or "").strip()
        if not transaction_id or transaction_id.startswith("admin_manual:"):
            continue
        try:
            data = await platega_get_transaction_status(transaction_id)
            status = platega_extract_status(data) or "UNKNOWN"
            await update_payment_provider_data(
                payment_id,
                provider_status=status,
                provider_payload=data,
                provider_confirmed=platega_status_is_paid(status),
            )
            await log_payment_event(
                payment_id,
                "provider_security_status",
                payment_method="platega",
                details={"transaction_id": transaction_id, "status": status, "source": "security_watchdog"},
            )
            if platega_status_is_failed(status):
                event_type = f"provider_reversal_{status.lower()}"
                if await payment_event_type_exists(payment_id, event_type):
                    continue
                await log_payment_event(
                    payment_id,
                    event_type,
                    payment_method="platega",
                    details={"transaction_id": transaction_id, "status": status, "source": "security_watchdog"},
                )
                await append_payment_note(payment_id, event_type)
                fresh = await get_payment(payment_id) or row
                await notify_admins_payment_alert(
                    bot,
                    payment_watchdog_alert_text(
                        fresh,
                        f"Platega payment changed after success: {status}",
                        "Автоматически подписка не отключалась. Проверьте платёж и решите действие вручную.",
                    ),
                    payment_id,
                )
        except Exception as exc:
            logging.warning("Platega success monitor failed payment=%s transaction=%s: %s", payment_id, transaction_id, exc)
            await log_payment_event(
                payment_id,
                "provider_security_status_error",
                payment_method="platega",
                details={"transaction_id": transaction_id, "error": str(exc)[:500], "source": "security_watchdog"},
            )


async def payment_watchdog_check_problem_items(bot: Bot) -> None:
    if not PLATEGA_SECURITY_WATCHDOG_ENABLED:
        return
    rows = await list_payment_watchdog_items(
        pending_hours=PLATEGA_PENDING_ALERT_HOURS,
        processing_minutes=PLATEGA_PROCESSING_ALERT_MINUTES,
        limit=30,
    )
    for row in rows:
        payment_id = int(row["id"])
        status = str(row["status"] or "")
        app_status = str(row["application_status"] or "")
        provider = str(row["provider"] or "")
        if app_status == "apply_failed":
            event_type = "watchdog_apply_failed"
            title = "application_status=apply_failed"
        elif status == "processing":
            event_type = "watchdog_processing_old"
            title = f"processing дольше {PLATEGA_PROCESSING_ALERT_MINUTES} мин."
        elif provider == "platega" and status == "pending":
            event_type = "watchdog_platega_pending_old"
            title = f"Platega ожидают старше {PLATEGA_PENDING_ALERT_HOURS} ч."
        else:
            continue
        if await payment_event_type_exists(payment_id, event_type):
            continue
        await log_payment_event(
            payment_id,
            event_type,
            payment_method=provider or None,
            details={"status": status, "application_status": app_status, "provider": provider, "source": "security_watchdog"},
        )
        await notify_admins_payment_alert(bot, payment_watchdog_alert_text(row, title), payment_id)


async def payment_security_watchdog_loop(bot: Bot) -> None:
    if not PLATEGA_SECURITY_WATCHDOG_ENABLED:
        logging.info("Payment security watchdog disabled")
        return
    logging.info("Payment security watchdog started")
    while True:
        try:
            await payment_watchdog_check_problem_items(bot)
            await platega_monitor_success_payments_for_reversal(bot)
        except Exception as exc:
            logging.exception("Payment security watchdog failed: %s", exc)
        await sleep_with_jitter(PLATEGA_SECURITY_WATCHDOG_POLL_SECONDS, 10)



def platega_callback_server_enabled() -> bool:
    return bool(platega_enabled() and PLATEGA_CALLBACK_SERVER_ENABLED)


def platega_callback_headers_valid(request: web.Request) -> bool:
    merchant = str(request.headers.get("X-MerchantId") or "").strip()
    secret = str(request.headers.get("X-Secret") or "").strip()
    return secrets.compare_digest(merchant, PLATEGA_MERCHANT_ID) and secrets.compare_digest(secret, PLATEGA_SECRET)


def platega_callback_payload_summary(payload: dict) -> dict:
    return {
        "id": str(payload.get("id") or "")[:80],
        "status": str(payload.get("status") or "")[:80],
        "amount": payload.get("amount"),
        "currency": str(payload.get("currency") or "")[:16],
        "paymentMethod": payload.get("paymentMethod"),
    }


async def platega_callback_handler(request: web.Request) -> web.Response:
    """
    Platega callback endpoint.
    It is only a trigger: before applying a payment, the bot still verifies
    the transaction through GET /transaction/{id}, so callback body alone is not trusted.
    """
    if not platega_enabled():
        return web.Response(status=503, text="platega disabled")

    if not platega_callback_headers_valid(request):
        logging.warning("Platega callback rejected: invalid auth headers from %s", request.remote)
        return web.Response(status=401, text="unauthorized")

    try:
        payload = await request.json()
    except Exception:
        logging.warning("Platega callback rejected: invalid json from %s", request.remote)
        return web.Response(status=400, text="invalid json")

    if not isinstance(payload, dict):
        return web.Response(status=400, text="invalid payload")

    transaction_id = str(payload.get("id") or "").strip()
    callback_status = str(payload.get("status") or "").strip().upper()
    if not transaction_id:
        logging.warning("Platega callback rejected: missing transaction id payload=%s", str(payload)[:500])
        return web.Response(status=400, text="missing id")

    payment = await get_payment_by_provider_charge_id(transaction_id)
    if not payment:
        logging.warning("Platega callback for unknown transaction_id=%s status=%s", transaction_id, callback_status or "—")
        # Return 200 so Platega does not retry forever for an already unknown/expired local payment.
        return web.Response(status=200, text="unknown transaction")

    payment_id = int(payment["id"])
    await log_payment_event(
        payment_id,
        "provider_callback",
        payment_method="platega",
        details={"callback": platega_callback_payload_summary(payload), "remote": str(request.remote or "")},
    )
    await update_payment_provider_data(
        payment_id,
        provider_charge_id=transaction_id,
        provider_status=callback_status or None,
        provider_payload={"callback": platega_callback_payload_summary(payload)},
        provider_confirmed=platega_status_is_paid(callback_status),
    )

    # Always verify against Platega API before applying the subscription.
    fresh = await get_payment(payment_id)
    try:
        result, message = await platega_check_and_apply_payment(request.app["bot"], fresh, source="platega_callback")
        logging.info("Platega callback processed payment=%s transaction=%s callback_status=%s result=%s message=%s", payment_id, transaction_id, callback_status or "—", result, message)
    except Exception as exc:
        logging.exception("Platega callback processing failed payment=%s transaction=%s: %s", payment_id, transaction_id, exc)
        # Non-200 asks Platega to retry later; useful if our DB/S-UI/API was temporarily unavailable.
        return web.Response(status=500, text="processing failed")

    return web.Response(status=200, text="ok")


async def platega_callback_server_loop(bot: Bot) -> None:
    if not platega_callback_server_enabled():
        logging.info("Platega callback server disabled")
        return

    app = web.Application()
    app["bot"] = bot
    app.router.add_post(PLATEGA_CALLBACK_PATH, platega_callback_handler)

    runner = web.AppRunner(app)
    await runner.setup()
    site = web.TCPSite(runner, PLATEGA_CALLBACK_HOST, PLATEGA_CALLBACK_PORT)
    await site.start()
    logging.info("Platega callback server started on http://%s:%s%s", PLATEGA_CALLBACK_HOST, PLATEGA_CALLBACK_PORT, PLATEGA_CALLBACK_PATH)

    try:
        while True:
            await sleep_with_jitter(3600, 30)
    finally:
        await runner.cleanup()
        logging.info("Platega callback server stopped")


async def apply_payment_without_payment(bot: Bot, payment, admin_id: int) -> str:
    payment_id = int(payment["id"])
    tariff = get_tariff(str(payment["tarif_key"]))
    if not tariff:
        raise RuntimeError("Тариф не найден для применения.")
    period = payment_period_from_row(payment, tariff)

    current_status = str(payment["status"] or "")
    current_app_status = str(payment["application_status"] or "not_applied")
    result_payload = payment_result_payload_loads(payment["result_payload"] if "result_payload" in payment.keys() else None)
    kind = str(payment["kind"] or "buy")

    if current_status == "success" and current_app_status == "applied":
        return "ℹ️ Этот платёж уже применён."

    if current_status == "processing" and current_app_status != "apply_failed":
        return "ℹ️ Этот платёж уже находится в обработке."

    if current_status not in ("pending", "processing"):
        raise RuntimeError("Применить можно только платёж, ожидающий оплаты, или processing/apply_failed.")

    if current_status == "pending":
        claimed = await mark_payment_processing(payment_id, provider_charge_id=f"admin_manual:{int(admin_id)}")
    else:
        claimed = await mark_payment_reprocessing_if_failed(payment_id, provider_charge_id=f"admin_manual:{int(admin_id)}")
    if not claimed:
        raise RuntimeError("Платёж уже был взят в обработку, обработан или не находится в apply_failed.")

    user_id = int(payment["user_id"] or 0)
    username = str(payment["username"] or "") or None

    try:
        if kind == "buy":
            sub_link, clash_link, client_name = await create_client(user_id=user_id, username=username, tariff=tariff, period=period)
            result_payload = {
                "kind": "buy",
                "client_name": client_name,
                "sub_link": sub_link,
                "clash_link": clash_link,
            }
            await remote_sync_after_paid_change(bot, payment_id=payment_id, client_name=client_name, reason="manual_buy")
            await mark_payment_success_manual(payment_id, int(admin_id), note="without_payment buy", result_payload=result_payload)
            invalidate_user_subscription_flags_cache(user_id)
            try:
                await bot.send_message(user_id, payment_success_text_from_payload(kind, tariff, result_payload), reply_markup=connect_device_close_keyboard())
                await mark_payment_notified(payment_id, note="manual_buy_notified")
            except Exception as exc:
                logging.warning("Failed to notify user about manual buy payment apply: %s", exc)
            return "✅ Подписка выдана без оплаты."

        if kind == "renew":
            client_id = int(payment["client_id"] or 0)
            if client_id <= 0:
                raise RuntimeError("У платежа продления нет client_id")
            client = await get_client_by_id(client_id)
            if not client:
                raise RuntimeError("Подписка для продления не найдена в S-UI")

            owner_items = await get_user_subscriptions(user_id)
            owner_item = next((x for x in owner_items if int(x["id"]) == client_id), None)
            if not owner_item:
                raise RuntimeError("Эта подписка не принадлежит пользователю платежа")

            await renew_client_in_sui(client, tariff, period=period)
            await remote_sync_after_paid_change(bot, payment_id=payment_id, client_name=str(owner_item["name"]), reason="manual_renew")
            result_payload = {
                "kind": "renew",
                "client_id": client_id,
                "name": owner_item["name"],
                "tarif_key": tariff.key,
                "tariff_title": tariff.title,
                **period_payload_fields(period),
                "sub_link": owner_item["sub_link"],
                "clash_link": owner_item["clash_link"],
            }
            await mark_payment_success_manual(payment_id, int(admin_id), note="without_payment renew", result_payload=result_payload)
            invalidate_user_subscription_flags_cache(user_id)
            try:
                await bot.send_message(user_id, payment_success_text_from_payload(kind, tariff, result_payload), reply_markup=connect_device_close_keyboard())
                await mark_payment_notified(payment_id, note="manual_renew_notified")
            except Exception as exc:
                logging.warning("Failed to notify user about manual renew payment apply: %s", exc)
            return "✅ Продление применено без оплаты."

        raise RuntimeError(f"Неизвестный тип платежа: {kind}")
    except Exception as exc:
        await mark_payment_apply_failed(payment_id, note=f"manual_apply {str(exc)[:260]}")
        raise

