def build_broadcast_reply_markup(button_text: str | None, button_url: str | None):
    if button_text and button_url:
        return InlineKeyboardMarkup(
            inline_keyboard=[[InlineKeyboardButton(text=button_text, url=button_url)]]
        )
    return None


async def send_broadcast_preview(message: types.Message, data: dict) -> None:
    reply_markup = build_broadcast_reply_markup(data.get("button_text"), data.get("button_url"))
    kind = data.get("kind")
    if kind == "photo":
        await message.answer_photo(
            photo=data["photo_file_id"],
            caption=data.get("caption") or " ",
            reply_markup=reply_markup,
        )
    else:
        await message.answer(
            data.get("text") or "—",
            reply_markup=reply_markup,
        )

    await message.answer(
        broadcast_preview_text(
            has_media=(kind == "photo"),
            has_button=bool(data.get("button_text") and data.get("button_url")),
        ),
        reply_markup=broadcast_preview_keyboard(
            has_button=bool(data.get("button_text") and data.get("button_url"))
        ),
    )


async def execute_broadcast(bot: Bot, data: dict) -> tuple[int, int, int]:
    user_ids = await collect_broadcast_user_ids()
    sent = failed = skipped = 0
    reply_markup = build_broadcast_reply_markup(data.get("button_text"), data.get("button_url"))

    for uid in user_ids:
        if uid in ADMIN_IDS:
            skipped += 1
            continue
        if data.get("kind") == "photo":
            msg = await send_photo_limited(
                bot,
                uid,
                data["photo_file_id"],
                caption=data.get("caption") or " ",
                reply_markup=reply_markup,
                bulk=True,
            )
        else:
            msg = await send_message_limited(
                bot,
                uid,
                data.get("text") or "—",
                reply_markup=reply_markup,
                bulk=True,
            )
        if msg:
            sent += 1
        else:
            failed += 1

    return sent, failed, skipped


def is_subscription_renewable_item(item: dict) -> bool:
    plan_key = str(item.get("plan_key") or "")
    if not plan_key or plan_key == "test":
        return False
    if get_tariff(plan_key) is None:
        return False

    # Окно продления считаем по точному expiry timestamp, а не по округлённым дням.
    # Это исключает edge-case, когда до окончания меньше суток и days_left уже равен 0.
    try:
        expiry_ts = int(item.get("expiry_ts") or 0)
    except Exception:
        expiry_ts = 0
    if expiry_ts <= 0:
        return False

    window_seconds = max(0, int(renew_window_days_setting())) * 86400
    seconds_left = expiry_ts - int(time.time())
    return seconds_left <= window_seconds


def filter_renewable_subscriptions(items: list[dict]) -> list[dict]:
    return [item for item in items if is_subscription_renewable_item(item)]


async def run_reminder_check(bot: Bot) -> dict:
    stats = {
        "checked_count": 0,
        "sent_3d": 0,
        "sent_1d": 0,
        "sent_expired": 0,
        "failed_count": 0,
    }

    try:
        clients = await get_all_clients()
    except Exception:
        return stats

    now_ts = int(time.time())
    grouped: dict[int, list[dict]] = {}
    for client in clients:
        desc = str(client.get("desc") or "")
        tgid = extract_tgid_from_client(client)
        if tgid is None:
            continue
        grouped.setdefault(int(tgid), []).append(client)

    for user_id, items in grouped.items():
        for client in items:
            stats["checked_count"] += 1
            expiry = int(client.get("expiry") or 0)
            client_id = int(client.get("id") or 0)
            if client_id <= 0:
                continue
            days_left = max(0, int((expiry - now_ts) / 86400)) if expiry > 0 else 0

            name = str(client.get("name") or "unknown")
            desc = str(client.get("desc") or "")
            item = {
                "id": client_id,
                "name": name,
                "plan_key": parse_plan_key_from_desc(desc),
            }

            if days_left in (3, 1):
                reminder_type = f"expiring_{days_left}"
                if not await reminder_already_sent(user_id, client_id, reminder_type):
                    try:
                        msg = await send_message_limited(bot, int(user_id), reminder_expiring_text(item, days_left), bulk=True)
                        if not msg:
                            raise RuntimeError("telegram_send_failed")
                        await mark_reminder_sent(user_id, client_id, reminder_type)
                        if days_left == 3:
                            stats["sent_3d"] += 1
                        else:
                            stats["sent_1d"] += 1
                    except Exception:
                        stats["failed_count"] += 1

            if expiry > 0 and expiry <= now_ts:
                reminder_type = "expired"
                if not await reminder_already_sent(user_id, client_id, reminder_type):
                    try:
                        msg = await send_message_limited(bot, int(user_id), reminder_expired_text(item), bulk=True)
                        if not msg:
                            raise RuntimeError("telegram_send_failed")
                        await mark_reminder_sent(user_id, client_id, reminder_type)
                        stats["sent_expired"] += 1
                    except Exception:
                        stats["failed_count"] += 1

    await log_reminder_run(**stats)
    return stats


async def build_reminders_panel_text() -> str:
    expiring_3d = 0
    expiring_1d = 0
    expired_now = 0

    try:
        clients = await get_all_clients()
        now_ts = int(time.time())
        for client in clients:
            expiry = int(client.get("expiry") or 0)
            if expiry <= 0:
                continue
            if expiry <= now_ts:
                expired_now += 1
                continue
            days_left = max(0, int((expiry - now_ts) / 86400))
            if days_left <= 3:
                expiring_3d += 1
            if days_left <= 1:
                expiring_1d += 1
    except Exception:
        pass

    marks = await count_reminder_marks()
    last_run = await get_last_reminder_run()
    if last_run:
        last_run_text = payment_dt_text(last_run["run_at"])
        last_run_stats = (
            f"Проверено: {int(last_run['checked_count'] or 0)} | "
            f"3d: {int(last_run['sent_3d'] or 0)} | "
            f"1d: {int(last_run['sent_1d'] or 0)} | "
            f"expired: {int(last_run['sent_expired'] or 0)} | "
            f"errors: {int(last_run['failed_count'] or 0)}"
        )
    else:
        last_run_text = "—"
        last_run_stats = "Статистика запуска пока отсутствует."

    return reminders_panel_text(
        expiring_3d=expiring_3d,
        expiring_1d=expiring_1d,
        expired_now=expired_now,
        marks_3d=marks["expiring_3"],
        marks_1d=marks["expiring_1"],
        marks_expired=marks["expired"],
        last_run_text=last_run_text,
        last_run_stats=last_run_stats,
    )


async def reminder_loop(bot: Bot) -> None:
    while True:
        try:
            cancelled = await cancel_expired_pending_payments()
            if cancelled:
                logging.info("auto-cancelled expired pending payments: %s", cancelled)
            await run_reminder_check(bot)
        except Exception as exc:
            logging.exception("reminder_loop failed: %s", exc)
        await sleep_with_jitter(3600, 30)


