async def search_admin_payments(query: str, limit: int = 50):
    q = (query or "").strip()
    if not q:
        return []

    normalized = q.replace("№", "#").replace(" ", "")
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        if normalized.startswith("#"):
            raw_id = normalized[1:]
            if raw_id.isdigit():
                payment_id = int(raw_id)
                async with conn.execute("SELECT * FROM payments WHERE id=?", (payment_id,)) as cur:
                    row = await cur.fetchone()
                    return [row] if row else []

        if q.isdigit():
            user_id = int(q)
            async with conn.execute(
                """
                SELECT *
                FROM payments
                WHERE user_id=?
                ORDER BY id DESC
                LIMIT ?
                """,
                (user_id, int(limit)),
            ) as cur:
                return await cur.fetchall()

    return []

def admin_payments_where(status_filter: str) -> tuple[str, list]:
    where_clause = ""
    params: list = []
    if status_filter in ("success", "pending", "failed"):
        where_clause = "WHERE status=?"
        params.append(status_filter)
    elif status_filter in ("platega", "stars"):
        where_clause = "WHERE provider=?"
        params.append(status_filter)
    elif status_filter == "apply_failed":
        where_clause = "WHERE application_status='apply_failed'"
    elif status_filter == "platega_pending":
        where_clause = "WHERE provider='platega' AND status='pending'"
    return where_clause, params


async def list_admin_payments_filtered(status_filter: str = "all", limit: int = ADMIN_PAYMENTS_PAGE_SIZE, offset: int = 0):
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        where_clause, params = admin_payments_where(status_filter)
        sql = f"""
            SELECT *
            FROM payments
            {where_clause}
            ORDER BY id DESC
            LIMIT ? OFFSET ?
        """
        params.extend([int(limit), max(0, int(offset))])
        async with conn.execute(sql, tuple(params)) as cur:
            return await cur.fetchall()


async def count_admin_payments_filtered(status_filter: str = "all") -> int:
    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        where_clause, params = admin_payments_where(status_filter)
        async with conn.execute(f"SELECT COUNT(*) AS c FROM payments {where_clause}", tuple(params)) as cur:
            row = await cur.fetchone()
            return int(row["c"] or 0) if row else 0


