def admin_payment_events_text(row, events) -> str:
    line = "━━━━━━━━━━━━━━"
    parts = [
        "📜 События платежа",
        line,
        f"Payment ID: #{row['id']}",
        f"Провайдер: {str(row['provider'] or '—')}",
        f"Статус: {payment_status_label(str(row['status']))}",
        line,
    ]
    if not events:
        parts.append("Событий пока нет.")
        return "\n".join(parts)
    for event in events:
        parts.append(
            f"#{event['id']} · {payment_dt_text(event['created_at'])} · "
            f"{event['event_type']} · {event['payment_method'] or '—'}"
        )
        details = payment_event_details_short(event['details_json'])
        if details and details != "—":
            parts.append(details)
        parts.append("")
    return "\n".join(parts).strip()


def admin_payment_detail_keyboard(row=None) -> InlineKeyboardMarkup:
    rows = []
    if row is not None:
        payment_id = int(row["id"])
        status = str(row["status"] or "")
        app_status = str(row["application_status"] or "")
        provider = str(row["provider"] or "")
        payment_url = str(row["payment_url"] or "") if "payment_url" in row.keys() else ""
        provider_charge_id = str(row["provider_charge_id"] or "")

        if provider == "platega" and provider_charge_id:
            rows.append([InlineKeyboardButton(text="🔄 Проверить Platega", callback_data=f"admin:payments:platega_check:{payment_id}")])
        if provider == "platega" and payment_url:
            rows.append([InlineKeyboardButton(text="💳 Открыть ссылку оплаты", url=payment_url)])
        rows.append([InlineKeyboardButton(text="📜 События платежа", callback_data=f"admin:payments:events:{payment_id}")])

        can_apply = status == "pending" or (status == "processing" and app_status == "apply_failed")
        if can_apply:
            if status == "processing" and app_status == "apply_failed":
                action_text = "♻️ Повторить применение"
            else:
                action_text = "✅ Выдать без оплаты" if str(row["kind"] or "") == "buy" else "✅ Продлить без оплаты"
            rows.append([InlineKeyboardButton(text=action_text, callback_data=f"admin:payments:approve:{payment_id}")])
    rows.append([InlineKeyboardButton(text="← К платежам", callback_data="admin:payments")])
    return InlineKeyboardMarkup(inline_keyboard=rows)

