def _admin_monitoring_dt(ts) -> str:
    try:
        value = float(ts or 0)
    except Exception:
        value = 0
    return "—" if value <= 0 else datetime.fromtimestamp(value).strftime("%d.%m.%Y %H:%M")


def _admin_monitoring_age(ts) -> str:
    try:
        value = float(ts or 0)
    except Exception:
        value = 0
    if value <= 0:
        return "—"
    delta = max(0, int(time.time() - value))
    if delta < 60:
        return f"{delta} сек назад"
    if delta < 3600:
        return f"{delta // 60} мин назад"
    if delta < 86400:
        return f"{delta // 3600} ч назад"
    return f"{delta // 86400} дн назад"


def admin_monitoring_keyboard() -> InlineKeyboardMarkup:
    return InlineKeyboardMarkup(inline_keyboard=[
        [InlineKeyboardButton(text="🔄 Обновить", callback_data="admin:monitoring:refresh")],
        [InlineKeyboardButton(text="🌍 Локации / VPS-node", callback_data="admin:remote")],
        [InlineKeyboardButton(text="← К 🛠 Админ", callback_data="admin:panel")],
    ])


async def build_admin_monitoring_text(*, force_refresh: bool = False) -> str:
    cache_key = "admin:monitoring:text"
    cached = runtime_cache_get(cache_key, 20)
    if isinstance(cached, str) and not force_refresh:
        return cached

    now_ts = time.time()
    day_ago = now_ts - 86400
    week_ago = now_ts - 7 * 86400

    payments_today = payments_success_today = payments_pending = payments_processing = 0
    stars_today = rub_today = 0
    buys_today = renews_today = 0
    recent_payments_failed = 0
    auto_deleted_trials_24h = 0
    open_tickets = 0
    try:
        async with db_connect(PAYMENTS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute(
                """
                SELECT
                    COUNT(*) AS payments_today,
                    SUM(CASE WHEN status='success' THEN 1 ELSE 0 END) AS success_today,
                    SUM(CASE WHEN status='pending' THEN 1 ELSE 0 END) AS pending_total,
                    SUM(CASE WHEN status='processing' THEN 1 ELSE 0 END) AS processing_total,
                    SUM(CASE WHEN status='success' AND currency='XTR' THEN amount ELSE 0 END) AS stars_today,
                    SUM(CASE WHEN status='success' AND currency='RUB' THEN amount ELSE 0 END) AS rub_today,
                    SUM(CASE WHEN kind='buy' THEN 1 ELSE 0 END) AS buys_today,
                    SUM(CASE WHEN kind='renew' THEN 1 ELSE 0 END) AS renews_today
                FROM payments
                WHERE created_at >= ?
                """,
                (day_ago,),
            ) as cur:
                row = await cur.fetchone()
            if row:
                payments_today = int(row["payments_today"] or 0)
                payments_success_today = int(row["success_today"] or 0)
                payments_pending = int(row["pending_total"] or 0)
                payments_processing = int(row["processing_total"] or 0)
                stars_today = int(row["stars_today"] or 0)
                rub_today = int(row["rub_today"] or 0)
                buys_today = int(row["buys_today"] or 0)
                renews_today = int(row["renews_today"] or 0)
            async with conn.execute(
                "SELECT COUNT(*) AS c FROM payments WHERE status='failed' AND COALESCE(failed_at, created_at) >= ?",
                (day_ago,),
            ) as cur:
                row = await cur.fetchone()
                recent_payments_failed = int(row["c"] or 0) if row else 0
    except Exception as exc:
        logging.warning("admin monitoring payments failed: %s", exc)

    try:
        async with db_connect(TRIALS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT COUNT(*) AS c FROM trials WHERE COALESCE(sui_deleted_at, 0) >= ?", (day_ago,)) as cur:
                row = await cur.fetchone()
                auto_deleted_trials_24h = int(row["c"] or 0) if row else 0
    except Exception:
        auto_deleted_trials_24h = 0

    try:
        async with db_connect(SUPPORT_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT COUNT(*) AS c FROM support_tickets WHERE status IN ('open','answered')") as cur:
                row = await cur.fetchone()
                open_tickets = int(row["c"] or 0) if row else 0
    except Exception:
        open_tickets = 0

    sui_total = sui_active = sui_paid_active = sui_test_active = sui_expired = 0
    expiring_24h = expiring_3d = 0
    try:
        clients = await get_all_clients(force_refresh=force_refresh)
        sui_total = len(clients)
        for c in clients:
            expiry = int(c.get("expiry") or 0)
            enabled = bool(c.get("enable", True))
            active = enabled and (expiry <= 0 or expiry > now_ts)
            is_test = remote_is_test_client(c)
            if active:
                sui_active += 1
                if is_test:
                    sui_test_active += 1
                else:
                    sui_paid_active += 1
                if expiry > 0 and expiry <= now_ts + 86400:
                    expiring_24h += 1
                if expiry > 0 and expiry <= now_ts + 3 * 86400:
                    expiring_3d += 1
            elif expiry > 0 and expiry <= now_ts:
                sui_expired += 1
    except Exception as exc:
        logging.warning("admin monitoring clients failed: %s", exc)

    nodes_total = nodes_enabled = nodes_active = nodes_error = nodes_maintenance = nodes_drain = 0
    last_node_error = "—"
    try:
        nodes_cfg = remote_load_nodes_config() if REMOTE_NODES_ENABLED and REMOTE_NODES_FILE.exists() else {"nodes": []}
        nodes = remote_admin_nodes_all(nodes_cfg)
        state = await remote_load_node_state()
        nodes_total = len(nodes)
        nodes_enabled = sum(1 for n in nodes if bool(n.get("enabled", False)))
        nodes_maintenance = sum(1 for n in nodes if bool(n.get("maintenance", False)))
        nodes_drain = sum(1 for n in nodes if bool(n.get("drain", False)))
        for n in nodes:
            st = str((state.get(str(n.get("id") or "")) or {}).get("status") or "unknown")
            if st == "active":
                nodes_active += 1
            if st == "error":
                nodes_error += 1
        error_rows = []
        for nid, row in state.items():
            if row.get("last_error"):
                error_rows.append((float(row.get("last_error_at") or row.get("updated_at") or 0), str(nid), str(row.get("last_error") or "")))
        if error_rows:
            error_rows.sort(reverse=True)
            _, nid, err = error_rows[0]
            last_node_error = f"{nid}: {err[:140]}"
    except Exception as exc:
        logging.warning("admin monitoring nodes failed: %s", exc)

    sync_24h = sync_errors_24h = links_updated_24h = links_cleaned_24h = links_failed_24h = 0
    sync_avg = 0.0
    last_sync_text = "—"
    try:
        async with db_connect(DATABASE_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute(
                """
                SELECT
                    COUNT(*) AS c,
                    SUM(CASE WHEN COALESCE(error,'')!='' OR links_failed>0 OR failed_nodes_json NOT IN ('[]','') THEN 1 ELSE 0 END) AS errors,
                    AVG(elapsed_seconds) AS avg_elapsed,
                    SUM(links_updated) AS links_updated,
                    SUM(links_cleaned) AS links_cleaned,
                    SUM(links_failed) AS links_failed
                FROM remote_sync_audit
                WHERE created_at >= ?
                """,
                (day_ago,),
            ) as cur:
                row = await cur.fetchone()
            if row:
                sync_24h = int(row["c"] or 0)
                sync_errors_24h = int(row["errors"] or 0)
                sync_avg = float(row["avg_elapsed"] or 0.0)
                links_updated_24h = int(row["links_updated"] or 0)
                links_cleaned_24h = int(row["links_cleaned"] or 0)
                links_failed_24h = int(row["links_failed"] or 0)
            async with conn.execute("SELECT * FROM remote_sync_audit ORDER BY id DESC LIMIT 1") as cur:
                last = await cur.fetchone()
            if last:
                failed_nodes = []
                with contextlib.suppress(Exception):
                    failed_nodes = json.loads(str(last["failed_nodes_json"] or "[]"))
                status_icon = "✅" if not last["error"] and not failed_nodes and int(last["links_failed"] or 0) == 0 else "⚠️"
                last_sync_text = f"{status_icon} {_admin_monitoring_age(last['created_at'])} · {float(last['elapsed_seconds'] or 0):.1f} сек · {str(last['reason'] or '')[:60]}"
    except Exception as exc:
        logging.warning("admin monitoring sync failed: %s", exc)

    backup_text = "—"
    try:
        backups = sorted(Path(tempfile.gettempdir()).glob("bot-sui-migration-*.tar.gz"), key=lambda x: x.stat().st_mtime, reverse=True)
        if backups:
            b = backups[0]
            size_mb = b.stat().st_size / (1024 * 1024)
            backup_text = f"{_admin_monitoring_age(b.stat().st_mtime)} · {size_mb:.1f} МБ"
    except Exception:
        backup_text = "—"

    ok_icon = "✅" if nodes_error == 0 and sync_errors_24h == 0 and recent_payments_failed == 0 else "⚠️"
    parts = [
        "📈 Мониторинг",
        "━━━━━━━━━━━━━━",
        f"Статус: {ok_icon}",
        f"Build: {APP_BUILD}",
        f"Обновлено: {datetime.now().strftime('%d.%m.%Y %H:%M:%S')}",
        "",
        "💳 Платежи за 24 часа",
        f"• всего: {payments_today} · успешно: {payments_success_today} · failed: {recent_payments_failed}",
        f"• покупки: {buys_today} · продления: {renews_today}",
        f"• Stars: {stars_today} ⭐" + (f" · RUB: {rub_today} ₽" if rub_today else ""),
        f"• ожидают оплаты: {payments_pending} · processing: {payments_processing}",
        "",
        "🔑 Подписки S-UI",
        f"• всего: {sui_total} · активных: {sui_active}",
        f"• paid active: {sui_paid_active} · test active: {sui_test_active} · expired: {sui_expired}",
        f"• истекают за 24ч: {expiring_24h} · за 3д: {expiring_3d}",
        f"• auto-delete test за 24ч: {auto_deleted_trials_24h}",
        "",
        "🌍 Локации",
        f"• nodes: {nodes_active}/{nodes_enabled} active · всего: {nodes_total}",
        f"• maintenance: {nodes_maintenance} · drain: {nodes_drain} · errors: {nodes_error}",
        f"• последний sync: {last_sync_text}",
        f"• sync за 24ч: {sync_24h} · errors: {sync_errors_24h} · avg: {sync_avg:.1f} сек",
        f"• links updated/cleaned/failed: {links_updated_24h}/{links_cleaned_24h}/{links_failed_24h}",
        "",
        "🧰 Система",
        f"• открытые тикеты: {open_tickets}",
        f"• последний migration backup: {backup_text}",
    ]
    if last_node_error != "—":
        parts.extend(["", "Последняя ошибка node:", last_node_error])
    text = "\n".join(parts).strip()
    # Telegram message hard limit is 4096 chars. Monitoring should stay compact,
    # but node errors can contain long SSH stderr. Keep a hard safety cap.
    if len(text) > 3600:
        text = text[:3500].rstrip() + "\n\n… сообщение сокращено. Откройте подраздел ⚠️ Ошибки или логи сервера для деталей."
    runtime_cache_set(cache_key, text)
    return text


# =========================
# ADMIN MONITORING UNIFIED
