MONITORING_PERIODS = {
    "24h": (86400, "24 часа"),
    "7d": (7 * 86400, "7 дней"),
    "30d": (30 * 86400, "30 дней"),
}
MONITORING_SECTIONS = {
    "summary": "📌 Сводка",
    "payments": "💳 Оплаты",
    "subs": "👥 Подписки",
    "locations": "🌍 Локации",
    "trials": "🎁 Тесты",
    "antiabuse": "🛡 AntiAbuse",
    "support": "🎫 Поддержка",
    "backup": "💾 Backup",
    "errors": "⚠️ Ошибки",
}


def monitoring_period_info(period: str) -> tuple[str, int, str]:
    raw = str(period or "24h")
    if raw not in MONITORING_PERIODS:
        raw = "24h"
    seconds, label = MONITORING_PERIODS[raw]
    return raw, int(seconds), label


def normalize_monitoring_section(section: str | None) -> str:
    raw = str(section or "summary")
    return raw if raw in MONITORING_SECTIONS else "summary"


def admin_monitoring_keyboard(section: str = "summary", period: str = "24h") -> InlineKeyboardMarkup:
    section = normalize_monitoring_section(section)
    period, _, _ = monitoring_period_info(period)
    period_row = [
        InlineKeyboardButton(text=("✅ 24ч" if period == "24h" else "24ч"), callback_data=f"admin:monitoring:{section}:24h"),
        InlineKeyboardButton(text=("✅ 7д" if period == "7d" else "7д"), callback_data=f"admin:monitoring:{section}:7d"),
        InlineKeyboardButton(text=("✅ 30д" if period == "30d" else "30д"), callback_data=f"admin:monitoring:{section}:30d"),
    ]
    return InlineKeyboardMarkup(inline_keyboard=[
        period_row,
        [InlineKeyboardButton(text="📌 Сводка", callback_data=f"admin:monitoring:summary:{period}"), InlineKeyboardButton(text="💳 Оплаты", callback_data=f"admin:monitoring:payments:{period}")],
        [InlineKeyboardButton(text="👥 Подписки", callback_data=f"admin:monitoring:subs:{period}"), InlineKeyboardButton(text="🌍 Локации", callback_data=f"admin:monitoring:locations:{period}")],
        [InlineKeyboardButton(text="🎁 Тесты", callback_data=f"admin:monitoring:trials:{period}"), InlineKeyboardButton(text="🛡 AntiAbuse", callback_data=f"admin:monitoring:antiabuse:{period}")],
        [InlineKeyboardButton(text="🎫 Поддержка", callback_data=f"admin:monitoring:support:{period}"), InlineKeyboardButton(text="💾 Backup", callback_data=f"admin:monitoring:backup:{period}")],
        [InlineKeyboardButton(text="⚠️ Ошибки", callback_data=f"admin:monitoring:errors:{period}")],
        [InlineKeyboardButton(text="🔄 Обновить", callback_data=f"admin:monitoring:refresh:{section}:{period}")],
        [InlineKeyboardButton(text="← К 🛠 Админ", callback_data="admin:panel")],
    ])


async def _monitoring_payments_stats(since_ts: float) -> dict:
    result = {
        "total": 0, "success": 0, "pending_total": 0, "processing_total": 0, "failed": 0,
        "buys": 0, "renews": 0, "stars": 0, "rub": 0, "apply_failed": 0,
    }
    try:
        async with db_connect(PAYMENTS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute(
                """
                SELECT
                    COUNT(*) AS total,
                    SUM(CASE WHEN status='success' THEN 1 ELSE 0 END) AS success_count,
                    SUM(CASE WHEN kind='buy' THEN 1 ELSE 0 END) AS buys,
                    SUM(CASE WHEN kind='renew' THEN 1 ELSE 0 END) AS renews,
                    SUM(CASE WHEN status='success' AND currency='XTR' THEN amount ELSE 0 END) AS stars,
                    SUM(CASE WHEN status='success' AND currency='RUB' THEN amount ELSE 0 END) AS rub,
                    SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) AS failed,
                    SUM(CASE WHEN COALESCE(application_status,'')='apply_failed' THEN 1 ELSE 0 END) AS apply_failed
                FROM payments
                WHERE created_at >= ?
                """,
                (float(since_ts),),
            ) as cur:
                row = await cur.fetchone()
            if row:
                result.update({
                    "total": int(row["total"] or 0),
                    "success": int(row["success_count"] or 0),
                    "buys": int(row["buys"] or 0),
                    "renews": int(row["renews"] or 0),
                    "stars": int(row["stars"] or 0),
                    "rub": int(row["rub"] or 0),
                    "failed": int(row["failed"] or 0),
                    "apply_failed": int(row["apply_failed"] or 0),
                })
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status='pending'") as cur:
                row = await cur.fetchone()
                result["pending_total"] = int(row["c"] or 0) if row else 0
            async with conn.execute("SELECT COUNT(*) AS c FROM payments WHERE status='processing'") as cur:
                row = await cur.fetchone()
                result["processing_total"] = int(row["c"] or 0) if row else 0
    except Exception as exc:
        logging.warning("unified monitoring payments failed: %s", exc)
    return result


async def _monitoring_subscriptions_stats(*, force_refresh: bool = False) -> dict:
    result = {"total": 0, "active": 0, "paid_active": 0, "test_active": 0, "expired": 0, "expiring_24h": 0, "expiring_3d": 0, "double_vpn_on": 0, "double_vpn_off": 0}
    try:
        clients = await get_all_clients(force_refresh=force_refresh)
        now_ts = time.time()
        result["total"] = len(clients)
        for client in clients:
            expiry = int(client.get("expiry") or 0)
            enabled = bool(client.get("enable", True))
            active = enabled and (expiry <= 0 or expiry > now_ts)
            is_test = remote_is_test_client(client)
            if active:
                result["active"] += 1
                if is_test:
                    result["test_active"] += 1
                else:
                    result["paid_active"] += 1
                if expiry > 0 and expiry <= now_ts + 86400:
                    result["expiring_24h"] += 1
                if expiry > 0 and expiry <= now_ts + 3 * 86400:
                    result["expiring_3d"] += 1
            elif expiry > 0 and expiry <= now_ts:
                result["expired"] += 1
            plan_key = parse_plan_key_from_desc(str(client.get("desc") or ""))
            tariff = get_tariff(plan_key) if plan_key else None
            if tariff and tariff_double_vpn_enabled(tariff):
                result["double_vpn_on"] += 1
            elif tariff:
                result["double_vpn_off"] += 1
    except Exception as exc:
        logging.warning("unified monitoring subscriptions failed: %s", exc)
    return result


async def _monitoring_locations_stats(since_ts: float) -> dict:
    result = {"total": 0, "enabled": 0, "active": 0, "maintenance": 0, "drain": 0, "error": 0, "sync_count": 0, "sync_errors": 0, "sync_avg": 0.0, "links_updated": 0, "links_cleaned": 0, "links_failed": 0, "last_sync": "—", "last_error": "—"}
    try:
        nodes_cfg = remote_load_nodes_config() if REMOTE_NODES_ENABLED and REMOTE_NODES_FILE.exists() else {"nodes": []}
        nodes = remote_admin_nodes_all(nodes_cfg)
        state = await remote_load_node_state()
        result["total"] = len(nodes)
        result["enabled"] = sum(1 for n in nodes if bool(n.get("enabled", False)))
        result["maintenance"] = sum(1 for n in nodes if bool(n.get("maintenance", False)))
        result["drain"] = sum(1 for n in nodes if bool(n.get("drain", False)))
        for n in nodes:
            st = str((state.get(str(n.get("id") or "")) or {}).get("status") or "unknown")
            if st == "active":
                result["active"] += 1
            if st == "error":
                result["error"] += 1
        errors = []
        for nid, row in state.items():
            if row.get("last_error"):
                errors.append((float(row.get("last_error_at") or row.get("updated_at") or 0), str(nid), str(row.get("last_error") or "")))
        if errors:
            errors.sort(reverse=True)
            _, nid, err = errors[0]
            result["last_error"] = f"{nid}: {err[:180]}"
    except Exception as exc:
        logging.warning("unified monitoring locations state failed: %s", exc)
    try:
        async with db_connect(DATABASE_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute(
                """
                SELECT
                    COUNT(*) AS c,
                    SUM(CASE WHEN COALESCE(error,'')!='' OR links_failed>0 OR failed_nodes_json NOT IN ('[]','') THEN 1 ELSE 0 END) AS errors,
                    AVG(elapsed_seconds) AS avg_elapsed,
                    SUM(links_updated) AS links_updated,
                    SUM(links_cleaned) AS links_cleaned,
                    SUM(links_failed) AS links_failed
                FROM remote_sync_audit
                WHERE created_at >= ?
                """,
                (float(since_ts),),
            ) as cur:
                row = await cur.fetchone()
            if row:
                result["sync_count"] = int(row["c"] or 0)
                result["sync_errors"] = int(row["errors"] or 0)
                result["sync_avg"] = float(row["avg_elapsed"] or 0.0)
                result["links_updated"] = int(row["links_updated"] or 0)
                result["links_cleaned"] = int(row["links_cleaned"] or 0)
                result["links_failed"] = int(row["links_failed"] or 0)
            async with conn.execute("SELECT * FROM remote_sync_audit ORDER BY id DESC LIMIT 1") as cur:
                last = await cur.fetchone()
            if last:
                failed_nodes = []
                with contextlib.suppress(Exception):
                    failed_nodes = json.loads(str(last["failed_nodes_json"] or "[]"))
                icon = "✅" if not last["error"] and not failed_nodes and int(last["links_failed"] or 0) == 0 else "⚠️"
                result["last_sync"] = f"{icon} {_admin_monitoring_age(last['created_at'])} · {float(last['elapsed_seconds'] or 0):.1f} сек · {str(last['reason'] or '')[:60]}"
    except Exception as exc:
        logging.warning("unified monitoring sync failed: %s", exc)
    return result


async def _monitoring_trials_stats(since_ts: float) -> dict:
    result = {"issued": 0, "records_total": 0, "auto_deleted": 0, "active": 0}
    try:
        async with db_connect(TRIALS_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT COUNT(*) AS c FROM trials") as cur:
                row = await cur.fetchone()
                result["records_total"] = int(row["c"] or 0) if row else 0
            async with conn.execute("SELECT COUNT(*) AS c FROM trials WHERE granted_at >= ?", (float(since_ts),)) as cur:
                row = await cur.fetchone()
                result["issued"] = int(row["c"] or 0) if row else 0
            async with conn.execute("SELECT COUNT(*) AS c FROM trials WHERE COALESCE(sui_deleted_at, 0) >= ?", (float(since_ts),)) as cur:
                row = await cur.fetchone()
                result["auto_deleted"] = int(row["c"] or 0) if row else 0
        subs = await _monitoring_subscriptions_stats(force_refresh=False)
        result["active"] = int(subs.get("test_active") or 0)
    except Exception as exc:
        logging.warning("unified monitoring trials failed: %s", exc)
    return result


async def _monitoring_antiabuse_stats(since_ts: float) -> dict:
    result = {"cases": 0, "warn1": 0, "warn2": 0, "disabled_active": 0, "events": 0}
    try:
        async with db_connect(ANTIABUSE_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute("SELECT COUNT(*) AS c FROM antiabuse_cases") as cur:
                row = await cur.fetchone()
                result["cases"] = int(row["c"] or 0) if row else 0
            async with conn.execute("SELECT kind, COUNT(*) AS c FROM antiabuse_notifications WHERE sent_at >= ? GROUP BY kind", (float(since_ts),)) as cur:
                for row in await cur.fetchall():
                    kind = str(row["kind"] or "")
                    if kind == "warn1":
                        result["warn1"] = int(row["c"] or 0)
                    elif kind == "warn2":
                        result["warn2"] = int(row["c"] or 0)
                    result["events"] += int(row["c"] or 0)
            async with conn.execute("SELECT COUNT(*) AS c FROM antiabuse_enforcement WHERE is_active=1") as cur:
                row = await cur.fetchone()
                result["disabled_active"] = int(row["c"] or 0) if row else 0
    except Exception as exc:
        logging.warning("unified monitoring antiabuse failed: %s", exc)
    return result


async def _monitoring_support_stats(since_ts: float) -> dict:
    result = {"open": 0, "waiting_admin": 0, "waiting_user": 0, "closed": 0, "created": 0}
    try:
        async with db_connect(SUPPORT_DB) as conn:
            conn.row_factory = aiosqlite.Row
            async with conn.execute(
                """
                SELECT
                    SUM(CASE WHEN status IN ('open','answered') THEN 1 ELSE 0 END) AS open_count,
                    SUM(CASE WHEN waiting_for='admin' AND status IN ('open','answered') THEN 1 ELSE 0 END) AS waiting_admin,
                    SUM(CASE WHEN waiting_for='user' AND status IN ('open','answered') THEN 1 ELSE 0 END) AS waiting_user,
                    SUM(CASE WHEN status='closed' THEN 1 ELSE 0 END) AS closed_count,
                    SUM(CASE WHEN created_at >= ? THEN 1 ELSE 0 END) AS created_count
                FROM support_tickets
                """,
                (float(since_ts),),
            ) as cur:
                row = await cur.fetchone()
            if row:
                result["open"] = int(row["open_count"] or 0)
                result["waiting_admin"] = int(row["waiting_admin"] or 0)
                result["waiting_user"] = int(row["waiting_user"] or 0)
                result["closed"] = int(row["closed_count"] or 0)
                result["created"] = int(row["created_count"] or 0)
    except Exception as exc:
        logging.warning("unified monitoring support failed: %s", exc)
    return result


async def _monitoring_backup_stats() -> dict:
    result = {"last": "—", "integrity": "—", "root_helper": "—", "archive": "—"}
    try:
        backups = sorted(Path(tempfile.gettempdir()).glob("bot-sui-migration-*.tar.gz"), key=lambda x: x.stat().st_mtime, reverse=True)
        if backups:
            b = backups[0]
            result["last"] = f"{_admin_monitoring_age(b.stat().st_mtime)} · {b.stat().st_size / (1024 * 1024):.1f} МБ"
            result["archive"] = "есть"
            # Read report/manifest best-effort without extracting fully.
            import tarfile
            with tarfile.open(b, "r:gz") as tar:
                names = set(tar.getnames())
                report_name = next((n for n in names if n.endswith("MIGRATION_BACKUP_REPORT.txt")), "")
                if report_name:
                    f = tar.extractfile(report_name)
                    if f:
                        txt = f.read(4096).decode("utf-8", "ignore")
                        if "SQLite integrity:" in txt:
                            line = next((x for x in txt.splitlines() if "SQLite integrity:" in x), "")
                            result["integrity"] = line.split("SQLite integrity:",1)[1].strip() if line else "—"
                        if "archive readable:" in txt:
                            line = next((x for x in txt.splitlines() if "archive readable:" in x), "")
                            result["archive"] = line.split("archive readable:",1)[1].strip() if line else result["archive"]
                manifest_name = next((n for n in names if n.endswith("MANIFEST.json")), "")
                if manifest_name:
                    f = tar.extractfile(manifest_name)
                    if f:
                        data = json.loads(f.read().decode("utf-8", "ignore"))
                        notes = data.get("notes") or []
                        result["root_helper"] = "OK" if not any("root migration helper failed" in str(x) for x in notes) else "FAILED"
    except Exception as exc:
        logging.warning("unified monitoring backup failed: %s", exc)
    return result


async def build_admin_monitoring_text(*, force_refresh: bool = False, period: str = "24h", section: str = "summary") -> str:
    section = normalize_monitoring_section(section)
    period, seconds, label = monitoring_period_info(period)
    cache_key = f"admin:monitoring:v2:{section}:{period}"
    cached = runtime_cache_get(cache_key, 20)
    if isinstance(cached, str) and not force_refresh:
        return cached

    now_ts = time.time()
    since_ts = now_ts - seconds
    payments = await _monitoring_payments_stats(since_ts)
    subs = await _monitoring_subscriptions_stats(force_refresh=force_refresh)
    locations = await _monitoring_locations_stats(since_ts)
    trials = await _monitoring_trials_stats(since_ts)
    antiabuse = await _monitoring_antiabuse_stats(since_ts)
    support = await _monitoring_support_stats(since_ts)
    backup = await _monitoring_backup_stats()

    status_ok = (
        int(payments.get("failed") or 0) == 0
        and int(locations.get("error") or 0) == 0
        and int(locations.get("sync_errors") or 0) == 0
        and str(backup.get("root_helper") or "") != "FAILED"
    )
    title = MONITORING_SECTIONS.get(section, "📈 Мониторинг")
    compact_header = [
        f"{title}" if section != "summary" else f"📌 Сводка за {label}",
        "━━━━━━━━━━━━━━",
    ]
    diagnostic_header = [
        f"{title}",
        "━━━━━━━━━━━━━━",
        f"Период: {label}",
        f"Статус: {'✅ OK' if status_ok else '⚠️ есть замечания'}",
        f"Build: {APP_BUILD}",
        f"Обновлено: {datetime.now().strftime('%d.%m.%Y %H:%M:%S')}",
        "",
    ]

    def payments_block():
        return [
            f"💳 Оплаты за {label}",
            f"• всего: {payments['total']} · успешно: {payments['success']} · failed: {payments['failed']}",
            f"• покупки: {payments['buys']} · продления: {payments['renews']}",
            f"• Stars: {payments['stars']} ⭐" + (f" · RUB: {payments['rub']} ₽" if payments['rub'] else ""),
            f"• ожидают оплаты сейчас: {payments['pending_total']} · в обработке сейчас: {payments['processing_total']}",
            f"• apply_failed: {payments['apply_failed']}",
        ]

    def subs_block():
        return [
            "👥 Подписки",
            f"• всего в S-UI: {subs['total']} · активных: {subs['active']}",
            f"• paid active: {subs['paid_active']} · test active: {subs['test_active']} · expired: {subs['expired']}",
            f"• истекают за 24ч: {subs['expiring_24h']} · за 3д: {subs['expiring_3d']}",
            f"• Double VPN доступен у тарифов клиентов: {subs['double_vpn_on']} · недоступен: {subs['double_vpn_off']}",
        ]

    def locations_block():
        lines = [
            f"🌍 Локации за {label}",
            f"• active: {locations['active']}/{locations['enabled']} · всего: {locations['total']}",
            f"• maintenance: {locations['maintenance']} · drain: {locations['drain']} · errors: {locations['error']}",
            f"• последний sync: {locations['last_sync']}",
            f"• sync: {locations['sync_count']} · errors: {locations['sync_errors']} · avg: {locations['sync_avg']:.1f} сек",
            f"• links updated/cleaned/failed: {locations['links_updated']}/{locations['links_cleaned']}/{locations['links_failed']}",
        ]
        if locations["last_error"] != "—":
            lines += ["", "Последняя ошибка:", str(locations["last_error"])[:900]]
        return lines

    def trials_block():
        return [
            f"🎁 Тесты за {label}",
            f"• выдано: {trials['issued']}",
            f"• активных test сейчас: {trials['active']}",
            f"• auto-delete expired test: {trials['auto_deleted']}",
            f"• записей trials всего: {trials['records_total']}",
        ]

    def antiabuse_block():
        return [
            f"🛡 AntiAbuse за {label}",
            f"• кейсов всего: {antiabuse['cases']}",
            f"• warn1: {antiabuse['warn1']} · warn2: {antiabuse['warn2']}",
            f"• активных ограничений: {antiabuse['disabled_active']}",
            f"• событий за период: {antiabuse['events']}",
        ]

    def support_block():
        return [
            f"🎫 Поддержка за {label}",
            f"• открытых сейчас: {support['open']}",
            f"• ждут администратора: {support['waiting_admin']}",
            f"• ждут пользователя: {support['waiting_user']}",
            f"• создано за период: {support['created']}",
            f"• закрытых всего: {support['closed']}",
        ]

    def backup_block():
        return [
            "💾 Backup",
            f"• последний migration backup: {backup['last']}",
            f"• archive readable: {backup['archive']}",
            f"• SQLite integrity: {backup['integrity']}",
            f"• root-helper: {backup['root_helper']}",
        ]

    def errors_block():
        lines = [
            f"⚠️ Ошибки за {label}",
            f"• failed payments: {payments['failed']}",
            f"• apply_failed payments: {payments['apply_failed']}",
            f"• node errors сейчас: {locations['error']}",
            f"• sync errors: {locations['sync_errors']}",
            f"• links_failed: {locations['links_failed']}",
            f"• backup root-helper: {backup['root_helper']}",
        ]
        if locations["last_error"] != "—":
            lines += ["", "Последняя node ошибка:", str(locations["last_error"])[:900]]
        return lines

    blocks = {
        "payments": payments_block,
        "subs": subs_block,
        "locations": locations_block,
        "trials": trials_block,
        "antiabuse": antiabuse_block,
        "support": support_block,
        "backup": backup_block,
        "errors": errors_block,
    }

    if section == "summary":
        parts = compact_header + [
            f"💳 Оплаты: {payments['success']}/{payments['total']} успешно · ⭐ {payments['stars']}",
            f"👥 Подписки: active {subs['active']} · paid {subs['paid_active']} · test {subs['test_active']}",
            f"🌍 Локации: {locations['active']}/{locations['enabled']} active · sync errors {locations['sync_errors']}",
            f"🎁 Тесты: active {trials['active']} · auto-delete {trials['auto_deleted']}",
            f"🛡 AntiAbuse: cases {antiabuse['cases']} · active limits {antiabuse['disabled_active']}",
            f"🎫 Поддержка: open {support['open']} · ждут админа {support['waiting_admin']}",
            f"💾 Backup: {backup['last']} · root-helper {backup['root_helper']}",
        ]
        if not status_ok:
            parts += ["", "Что проверить:"] + errors_block()[1:]
    elif section == "errors":
        parts = diagnostic_header + blocks.get(section, errors_block)()
    else:
        parts = compact_header + blocks.get(section, payments_block)()

    text = "\n".join(parts).strip()
    # Telegram message hard limit is 4096 chars. Unified monitoring should be compact,
    # but node/backup errors can contain long stderr. Keep a hard safety cap.
    if len(text) > 3600:
        text = text[:3500].rstrip() + "\n\n… сообщение сокращено. Откройте подраздел ⚠️ Ошибки или логи сервера для деталей."
    runtime_cache_set(cache_key, text)
    return text


async def build_admin_stats_text() -> str:
    cached_text = runtime_cache_get("admin:stats:text", ADMIN_STATS_CACHE_SECONDS)
    if isinstance(cached_text, str):
        return cached_text

    stats = await get_admin_stats()
    subscriptions_total = 0
    active_subscriptions = 0
    expiring_3d = 0
    expiring_1d = 0
    suspicious_tgids = 0

    try:
        clients = await get_all_clients()
        subscriptions_total = len(clients)
        now_ts = int(time.time())
        groups = await antiabuse_group_by_tgid(clients)
        suspicious_tgids = len(groups)

        for client in clients:
            expiry = int(client.get("expiry") or 0)
            if expiry > now_ts:
                active_subscriptions += 1
                days_left = max(0, int((expiry - now_ts) / 86400))
                if days_left <= 3:
                    expiring_3d += 1
                if days_left <= 1:
                    expiring_1d += 1
    except Exception:
        pass

    text = admin_stats_text(
        users_count=stats["users_count"],
        payments_total=stats["payments_total"],
        payments_success=stats["payments_success"],
        payments_pending=stats["payments_pending"],
        payments_failed=stats["payments_failed"],
        revenue_stars_total=stats["revenue_stars_total"],
        revenue_stars_today=stats["revenue_stars_today"],
        revenue_stars_7d=stats["revenue_stars_7d"],
        revenue_stars_30d=stats["revenue_stars_30d"],
        revenue_rub_total=stats["revenue_rub_total"],
        revenue_rub_today=stats["revenue_rub_today"],
        revenue_rub_7d=stats["revenue_rub_7d"],
        revenue_rub_30d=stats["revenue_rub_30d"],
        buys_total=stats["buys_total"],
        renews_total=stats["renews_total"],
        buys_today=stats["buys_today"],
        renews_today=stats["renews_today"],
        buys_7d=stats["buys_7d"],
        renews_7d=stats["renews_7d"],
        buys_30d=stats["buys_30d"],
        renews_30d=stats["renews_30d"],
        tickets_open=stats["tickets_open"],
        tickets_closed=stats["tickets_closed"],
        subscriptions_total=subscriptions_total,
        active_subscriptions=active_subscriptions,
        expiring_3d=expiring_3d,
        expiring_1d=expiring_1d,
        suspicious_tgids=suspicious_tgids,
        top_tariffs=stats["top_tariffs"],
    )
    runtime_cache_set("admin:stats:text", text)
    return text

