def admin_payment_filter_callback(status_filter: str, page: int = 0) -> str:
    status = str(status_filter or "all")
    if status == "all" and int(page) == 0:
        return "admin:payments"
    return f"admin:payments:list:{status}:{int(page)}"


def admin_payments_keyboard(rows, status_filter: str = "all", *, page: int = 0, total: int | None = None) -> InlineKeyboardMarkup:
    buttons = [
        [
            InlineKeyboardButton(text="Все", callback_data=admin_payment_filter_callback("all", 0)),
            InlineKeyboardButton(text="Успешные", callback_data=admin_payment_filter_callback("success", 0)),
            InlineKeyboardButton(text="Ожидают", callback_data=admin_payment_filter_callback("pending", 0)),
            InlineKeyboardButton(text="Ошибки", callback_data=admin_payment_filter_callback("failed", 0)),
        ],
        [
            InlineKeyboardButton(text="Platega", callback_data=admin_payment_filter_callback("platega", 0)),
            InlineKeyboardButton(text="Stars", callback_data=admin_payment_filter_callback("stars", 0)),
        ],
        [
            InlineKeyboardButton(text="Platega ожидают", callback_data=admin_payment_filter_callback("platega_pending", 0)),
            InlineKeyboardButton(text="Apply failed", callback_data=admin_payment_filter_callback("apply_failed", 0)),
        ],
        [InlineKeyboardButton(text="🔎 Поиск", callback_data="admin:payments:search")],
    ]
    for row in rows[:ADMIN_PAYMENTS_PAGE_SIZE]:
        provider_icon = "💳" if str(row["provider"] or "") == "platega" else "⭐"
        app_suffix = " · apply_failed" if str(row["application_status"] or "") == "apply_failed" else ""
        label = (
            f"{provider_icon} #{row['id']} · {row['user_id']} · "
            f"{payment_kind_label(str(row['kind']))} · "
            f"{payment_amount_text_from_row(row)} · "
            f"{payment_status_label(str(row['status']))}{app_suffix}"
        )
        buttons.append([InlineKeyboardButton(text=label[:64], callback_data=f"admin:payments:view:{row['id']}")])
    if total is not None:
        total_pages = max(1, (int(total) + ADMIN_PAYMENTS_PAGE_SIZE - 1) // ADMIN_PAYMENTS_PAGE_SIZE)
        nav = []
        if int(page) > 0:
            nav.append(InlineKeyboardButton(text="← Назад", callback_data=admin_payment_filter_callback(status_filter, int(page) - 1)))
        if int(page) + 1 < total_pages:
            nav.append(InlineKeyboardButton(text="Вперёд →", callback_data=admin_payment_filter_callback(status_filter, int(page) + 1)))
        if nav:
            buttons.append(nav)
        if total_pages > 1:
            buttons.append([InlineKeyboardButton(text=f"Стр. {int(page) + 1}/{total_pages}", callback_data=admin_payment_filter_callback(status_filter, int(page)))])
    buttons.append([InlineKeyboardButton(text="← К 🛠 Админ", callback_data="admin:panel")])
    return InlineKeyboardMarkup(inline_keyboard=buttons)


async def get_admin_stats() -> dict:
    now = datetime.now()
    start_today = datetime(now.year, now.month, now.day).timestamp()
    start_7d = (now - timedelta(days=7)).timestamp()
    start_30d = (now - timedelta(days=30)).timestamp()

    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT
                COUNT(*) AS total,
                SUM(CASE WHEN status='success' THEN 1 ELSE 0 END) AS success_count,
                SUM(CASE WHEN status='pending' THEN 1 ELSE 0 END) AS pending_count,
                SUM(CASE WHEN status='failed' THEN 1 ELSE 0 END) AS failed_count,
                COUNT(DISTINCT user_id) AS users_count,
                SUM(CASE WHEN status='success' AND currency='XTR' THEN amount ELSE 0 END) AS revenue_stars_total,
                SUM(CASE WHEN status='success' AND currency='XTR' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_stars_today,
                SUM(CASE WHEN status='success' AND currency='XTR' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_stars_7d,
                SUM(CASE WHEN status='success' AND currency='XTR' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_stars_30d,
                SUM(CASE WHEN status='success' AND currency='RUB' THEN amount ELSE 0 END) AS revenue_rub_total,
                SUM(CASE WHEN status='success' AND currency='RUB' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_rub_today,
                SUM(CASE WHEN status='success' AND currency='RUB' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_rub_7d,
                SUM(CASE WHEN status='success' AND currency='RUB' AND paid_at >= ? THEN amount ELSE 0 END) AS revenue_rub_30d,
                SUM(CASE WHEN kind='buy' THEN 1 ELSE 0 END) AS buys_total,
                SUM(CASE WHEN kind='renew' THEN 1 ELSE 0 END) AS renews_total,
                SUM(CASE WHEN kind='buy' AND created_at >= ? THEN 1 ELSE 0 END) AS buys_today,
                SUM(CASE WHEN kind='renew' AND created_at >= ? THEN 1 ELSE 0 END) AS renews_today,
                SUM(CASE WHEN kind='buy' AND created_at >= ? THEN 1 ELSE 0 END) AS buys_7d,
                SUM(CASE WHEN kind='renew' AND created_at >= ? THEN 1 ELSE 0 END) AS renews_7d,
                SUM(CASE WHEN kind='buy' AND created_at >= ? THEN 1 ELSE 0 END) AS buys_30d,
                SUM(CASE WHEN kind='renew' AND created_at >= ? THEN 1 ELSE 0 END) AS renews_30d
            FROM payments
            """,
            (
                start_today, start_7d, start_30d,
                start_today, start_7d, start_30d,
                start_today, start_today, start_7d, start_7d, start_30d, start_30d,
            ),
        ) as cur:
            summary = await cur.fetchone()
        async with conn.execute(
            """
            SELECT tarif_key, COUNT(*) AS cnt
            FROM payments
            WHERE status='success'
            GROUP BY tarif_key
            ORDER BY cnt DESC, tarif_key ASC
            LIMIT 5
            """
        ) as cur:
            top_tariffs_rows = await cur.fetchall()

    async with db_connect(SUPPORT_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute(
            """
            SELECT
                SUM(CASE WHEN status IN ('open', 'answered') THEN 1 ELSE 0 END) AS open_count,
                SUM(CASE WHEN status='closed' THEN 1 ELSE 0 END) AS closed_count
            FROM support_tickets
            """
        ) as cur:
            ticket_summary = await cur.fetchone()

    return {
        "users_count": int(summary["users_count"] or 0),
        "payments_total": int(summary["total"] or 0),
        "payments_success": int(summary["success_count"] or 0),
        "payments_pending": int(summary["pending_count"] or 0),
        "payments_failed": int(summary["failed_count"] or 0),
        "revenue_stars_total": int(summary["revenue_stars_total"] or 0),
        "revenue_stars_today": int(summary["revenue_stars_today"] or 0),
        "revenue_stars_7d": int(summary["revenue_stars_7d"] or 0),
        "revenue_stars_30d": int(summary["revenue_stars_30d"] or 0),
        "revenue_rub_total": int(summary["revenue_rub_total"] or 0),
        "revenue_rub_today": int(summary["revenue_rub_today"] or 0),
        "revenue_rub_7d": int(summary["revenue_rub_7d"] or 0),
        "revenue_rub_30d": int(summary["revenue_rub_30d"] or 0),
        "buys_total": int(summary["buys_total"] or 0),
        "renews_total": int(summary["renews_total"] or 0),
        "buys_today": int(summary["buys_today"] or 0),
        "renews_today": int(summary["renews_today"] or 0),
        "buys_7d": int(summary["buys_7d"] or 0),
        "renews_7d": int(summary["renews_7d"] or 0),
        "buys_30d": int(summary["buys_30d"] or 0),
        "renews_30d": int(summary["renews_30d"] or 0),
        "tickets_open": int(ticket_summary["open_count"] or 0),
        "tickets_closed": int(ticket_summary["closed_count"] or 0),
        "top_tariffs": [(str(row["tarif_key"] or "—"), int(row["cnt"] or 0)) for row in top_tariffs_rows],
    }

async def antiabuse_group_by_tgid(clients: list[dict]) -> list[dict]:
    now_ts = int(time.time())
    groups: dict[int, list[dict]] = {}

    for client in clients:
        desc = str(client.get("desc") or "")
        tgid = parse_tgid_from_desc(desc)
        tg_id_raw = str(client.get("tgId") or "")
        if tgid is None and tg_id_raw.isdigit():
            tgid = int(tg_id_raw)
        if tgid is None:
            continue
        groups.setdefault(int(tgid), []).append(client)

    async with db_connect(PAYMENTS_DB) as conn:
        conn.row_factory = aiosqlite.Row
        result = []
        for tgid, items in groups.items():
            active_count = 0
            expired_count = 0
            names = []
            plan_keys = set()
            expiring_3d = 0

            for c in items:
                expiry = int(c.get("expiry") or 0)
                if expiry > now_ts:
                    active_count += 1
                    days_left = max(0, int((expiry - now_ts) / 86400))
                    if days_left <= 3:
                        expiring_3d += 1
                else:
                    expired_count += 1

                names.append(str(c.get("name") or "unknown"))
                desc = str(c.get("desc") or "")
                plan_key = parse_plan_key_from_desc(desc)
                if plan_key:
                    plan_keys.add(plan_key)

            suspicious_reasons = []
            if len(items) >= 3:
                suspicious_reasons.append("3+ клиентов")
            if active_count >= 2:
                suspicious_reasons.append("2+ активных")
            if expiring_3d >= 2:
                suspicious_reasons.append("несколько скоро истекают")

            async with conn.execute(
                """
                SELECT
                    COUNT(*) AS total,
                    SUM(CASE WHEN status='success' THEN 1 ELSE 0 END) AS success_count,
                    SUM(CASE WHEN kind='renew' THEN 1 ELSE 0 END) AS renew_count,
                    SUM(CASE WHEN kind='buy' THEN 1 ELSE 0 END) AS buy_count,
                    MAX(paid_at) AS last_paid_at
                FROM payments
                WHERE user_id=?
                """,
                (int(tgid),),
            ) as cur:
                row = await cur.fetchone()

            case = await get_antiabuse_case(tgid)
            admin_status = str(case["admin_status"]) if case else "new"
            if admin_status == "review":
                admin_status = "check"
            admin_note = str(case["admin_note"] or "") if case else ""

            payments_total = int(row["total"] or 0)
            success_count = int(row["success_count"] or 0)
            risk_score = len(items) * 2 + active_count * 3 + expiring_3d + success_count

            result.append(
                {
                    "tgid": tgid,
                    "count": len(items),
                    "active_count": active_count,
                    "expired_count": expired_count,
                    "expiring_3d": expiring_3d,
                    "names": names[:10],
                    "plans": sorted(plan_keys),
                    "plan_keys": sorted(plan_keys),
                    "success_count": success_count,
                    "payments_total": payments_total,
                    "payment_count": payments_total,
                    "buy_count": int(row["buy_count"] or 0),
                    "renew_count": int(row["renew_count"] or 0),
                    "last_paid_at": payment_dt_text(row["last_paid_at"]),
                    "suspicious_reasons": suspicious_reasons,
                    "reasons": suspicious_reasons,
                    "suspicious": bool(suspicious_reasons),
                    "risk_score": risk_score,
                    "admin_status": admin_status,
                    "admin_note": admin_note,
                }
            )

    result.sort(
        key=lambda x: (
            0 if x["admin_status"] == "check" else 1,
            0 if x["suspicious_reasons"] else 1,
            -x["risk_score"],
            -x["active_count"],
            -x["count"],
        )
    )
    return result

