@router.message(Command("start"))
async def start_handler(message: types.Message, state: FSMContext) -> None:
    await state.clear()
    await safe_delete_user_command_message(message)
    payload = ""
    try:
        parts = (message.text or "").split(maxsplit=1)
        payload = parts[1].strip() if len(parts) > 1 else ""
    except Exception:
        payload = ""
    registered, reason = await referral_register_from_payload(message.from_user.id, message.from_user.username, payload)
    if registered:
        await message.answer("🤝 Реферальная ссылка применена. Скидка начислится пригласившему после вашей первой успешной оплаты.")
    await message.answer(welcome_text(), reply_markup=await main_menu(message.from_user.id))


