@router.callback_query(F.data.startswith("renew:pick:"))
async def renew_pick_handler(callback: types.CallbackQuery) -> None:
    await callback.answer()
    parts = callback.data.split(":")
    client_id = int(parts[2]) if len(parts) >= 3 and parts[2].isdigit() else 0
    period_key = parts[3] if len(parts) >= 4 else ""

    try:
        items = await get_user_subscriptions(callback.from_user.id)
    except Exception as exc:
        await safe_edit_text(callback.message, "❌ Не удалось получить подписки из S-UI.\n\n" + str(exc)[:700])
        return

    item = next((x for x in items if int(x["id"]) == client_id), None)
    if not item:
        await safe_edit_text(callback.message, "Подписка не найдена.", reply_markup=back_to_menu_keyboard())
        return

    tariff = get_tariff(str(item["plan_key"]))
    if not tariff:
        await safe_edit_text(callback.message, "Для этой подписки продление недоступно.", reply_markup=back_to_menu_keyboard())
        return
    if not renew_menu_enabled_setting() or not is_subscription_renewable_item(item):
        await safe_edit_text(callback.message, no_renewable_subscriptions_text(), reply_markup=back_to_menu_keyboard())
        return

    periods = tariff_available_periods(tariff)
    if not periods:
        await safe_edit_text(callback.message, "Для этого тарифа пока нет доступных сроков продления.", reply_markup=back_to_menu_keyboard())
        return
    if len(periods) > 1:
        await safe_edit_text(callback.message, tariff_periods_select_text(tariff), reply_markup=tariff_periods_select_keyboard(tariff, kind="renew", client_id=client_id))
        return
    discount_pct = await referral_discount_pct_for_user(callback.from_user.id)
    await safe_edit_text(callback.message, renew_preview_text(item, tariff, discount_pct, periods[0]), reply_markup=renew_preview_keyboard(client_id, tariff, periods[0]))


