@router.callback_query(F.data.startswith("renew:invoice:"))
async def renew_invoice_handler(callback: types.CallbackQuery, bot: Bot) -> None:
    await callback.answer()
    parts = callback.data.split(":")
    client_id = int(parts[2]) if len(parts) >= 3 and parts[2].isdigit() else 0
    period_key = parts[3] if len(parts) >= 4 else ""

    try:
        items = await get_user_subscriptions(callback.from_user.id)
    except Exception as exc:
        await callback.message.answer("❌ Не удалось получить подписки из S-UI.\n\n" + str(exc)[:700])
        return

    item = next((x for x in items if int(x["id"]) == client_id), None)
    if not item:
        await callback.message.answer("Подписка не найдена.")
        return

    tariff = get_tariff(str(item["plan_key"]))
    if not tariff:
        await callback.message.answer("Для этой подписки продление недоступно.")
        return
    if not renew_menu_enabled_setting() or not is_subscription_renewable_item(item):
        await callback.message.answer(no_renewable_subscriptions_text(), reply_markup=close_keyboard())
        return
    period = tariff_choose_period(tariff, period_key)
    if not period:
        await callback.message.answer("Для этого тарифа пока нет доступного срока продления.")
        return
    if not tariff.stars_payment_enabled:
        await callback.message.answer("Оплата Stars для этого тарифа сейчас выключена.")
        return
    if int(period.stars_price or 0) <= 0:
        await callback.message.answer("Для выбранного срока не задана цена Stars.")
        return

    existing = await get_pending_payment_for_target(user_id=callback.from_user.id, kind="renew", tarif_key=tariff.key, client_id=client_id)
    if existing:
        await callback.message.answer(f"⚠️ Уже есть счёт к оплате на это продление: #{existing['id']}. Откройте его в разделе «Мои платежи».")
        return

    discount_pct = await referral_discount_pct_for_user(callback.from_user.id)
    final_amount, discount_amount = apply_referral_discount_amount(int(period.stars_price), discount_pct)
    payment_id = await create_payment(
        user_id=callback.from_user.id,
        username=callback.from_user.username,
        tarif_key=tariff.key,
        amount=final_amount,
        kind="renew",
        client_id=client_id,
        period_key=period.period_key,
        period_title=tariff_period_label(period),
        period_days=int(period.days),
        notes="single_file_renew",
        original_amount=int(period.stars_price),
        discount_pct=discount_pct,
        discount_amount=discount_amount,
    )
    payment = await get_payment(payment_id)
    logging.info("payment created renew id=%s user=%s tariff=%s client_id=%s amount=%s discount=%s", payment_id, callback.from_user.id, tariff.key, client_id, final_amount, discount_pct)
    await callback.message.answer(payment_created_text(payment_id, tariff, "renew", amount=final_amount, currency="XTR", provider="stars", original_amount=int(period.stars_price), discount_pct=discount_pct, period=period))
    await send_stars_invoice_for_payment(bot, callback.from_user.id, payment)


