@router.pre_checkout_query()
async def pre_checkout_handler(pre_checkout_query: types.PreCheckoutQuery) -> None:
    payload = str(pre_checkout_query.invoice_payload or "")
    if not payload.startswith("stars:"):
        await pre_checkout_query.answer(ok=False, error_message="Некорректный payload.")
        return

    payment_uid = payload.split(":", 1)[1]
    payment = await get_payment_by_uid(payment_uid)
    if not payment:
        await pre_checkout_query.answer(ok=False, error_message="Счёт не найден.")
        return

    if str(payment["status"]) != "pending":
        await pre_checkout_query.answer(ok=False, error_message="Счёт уже обработан.")
        return
    if str(payment["provider"] or "stars") != "stars":
        await pre_checkout_query.answer(ok=False, error_message="Некорректный провайдер счёта.")
        return
    tariff = get_tariff(str(payment["tarif_key"]))
    if not tariff or not tariff.stars_payment_enabled:
        await pre_checkout_query.answer(ok=False, error_message="Оплата Stars для этого тарифа выключена.")
        return

    await pre_checkout_query.answer(ok=True)


@router.message(F.successful_payment)
async def successful_payment_handler(message: types.Message, bot: Bot) -> None:
    payload = str(message.successful_payment.invoice_payload or "")
    if not payload.startswith("stars:"):
        return

    payment_uid = payload.split(":", 1)[1]
    charge_id = str(message.successful_payment.telegram_payment_charge_id or "")
    payment = await get_payment_by_uid(payment_uid)
    if not payment:
        await message.answer("Платёж получен, но счёт не найден.")
        return

    if str(payment["provider"] or "stars") != "stars":
        await message.answer("Некорректный провайдер платежа.")
        return

    if charge_id:
        existing_by_charge = await get_payment_by_provider_charge_id(charge_id)
        if existing_by_charge and int(existing_by_charge["id"]) != int(payment["id"]):
            existing_payload = payment_result_payload_loads(existing_by_charge["result_payload"] if "result_payload" in existing_by_charge.keys() else None)
            existing_tariff = get_tariff(str(existing_by_charge["tarif_key"]))
            if str(existing_by_charge["status"] or "") == "success" and str(existing_by_charge["application_status"] or "") == "applied" and existing_payload and existing_tariff:
                await message.answer(payment_success_text_from_payload(str(existing_by_charge["kind"] or "buy"), existing_tariff, existing_payload), reply_markup=connect_device_close_keyboard())
                return
            await message.answer("Этот платёж Telegram Stars уже зарегистрирован и обрабатывается. Если подписка не придёт, обратитесь в поддержку.")
            return

    await apply_paid_payment(bot, payment, provider_charge_id=charge_id, payment_method="stars", source="stars_successful_payment")


@router.message(F.text == "💳 Мои платежи")
async def my_payments_handler(message: types.Message, state: FSMContext) -> None:
    await state.clear()
    await safe_delete_user_command_message(message)
    total = await count_user_payments(message.from_user.id)
    page = clamp_page(0, total, USER_PAYMENTS_PAGE_SIZE)
    rows = await list_user_payments(message.from_user.id, limit=USER_PAYMENTS_PAGE_SIZE, offset=page * USER_PAYMENTS_PAGE_SIZE)
