@router.callback_query(F.data.startswith("pay:retry:"))
async def pay_retry_callback(callback: types.CallbackQuery, bot: Bot) -> None:
    await callback.answer()
    payment_id = int(callback.data.split(":")[-1])
    row = await get_payment(payment_id)
    if not row or int(row["user_id"]) != int(callback.from_user.id):
        await callback.message.answer("Платёж не найден.")
        return
    if str(row["status"]) != "failed":
        await callback.message.answer("Повтор доступен только для failed-платежей.")
        return

    existing = await get_pending_payment_for_target(
        user_id=callback.from_user.id,
        kind=str(row["kind"]),
        tarif_key=str(row["tarif_key"]),
        client_id=int(row["client_id"] or 0) if row["client_id"] is not None else None,
    )
    if existing:
        await callback.message.answer(f"⚠️ Уже есть счёт к оплате: #{existing['id']}. Откройте его в разделе «Мои платежи».")
        return

    provider = str(row["provider"] or "stars")
    currency = str(row["currency"] or ("RUB" if provider == "platega" else "XTR"))
    new_payment_id = await create_payment(
        user_id=callback.from_user.id,
        username=callback.from_user.username,
        tarif_key=str(row["tarif_key"]),
        amount=int(row["amount"] or 0),
        provider=provider,
        currency=currency,
        kind=str(row["kind"]),
        client_id=int(row["client_id"] or 0) if row["client_id"] is not None else None,
        period_key=str(row["period_key"] or "") if "period_key" in row.keys() else None,
        period_title=str(row["period_title"] or "") if "period_title" in row.keys() else None,
        period_days=int(row["period_days"] or 0) if "period_days" in row.keys() and row["period_days"] else None,
        notes=f"retry_of:{row['id']}",
        original_amount=int(row["original_amount"] or row["amount"] or 0) if "original_amount" in row.keys() else int(row["amount"] or 0),
        discount_pct=int(row["discount_pct"] or 0) if "discount_pct" in row.keys() else 0,
        discount_amount=int(row["discount_amount"] or 0) if "discount_amount" in row.keys() else 0,
    )
    new_row = await get_payment(new_payment_id)
    await callback.message.answer(f"🔄 Создан новый счёт #{new_payment_id} для повторной оплаты.")
    if provider == "platega":
        tariff = get_tariff(str(row["tarif_key"]))
        if not tariff:
            await callback.message.answer("Тариф не найден для повторной оплаты.")
            return
        try:
            data = await platega_create_transaction(new_row, tariff)
            transaction_id = platega_extract_transaction_id(data)
            payment_url = platega_extract_payment_url(data)
            provider_status = platega_extract_status(data) or "PENDING"
            if not transaction_id or not payment_url:
                raise RuntimeError("Platega вернула неполный ответ")
            await update_payment_provider_data(new_payment_id, provider_charge_id=transaction_id, payment_url=payment_url, provider_status=provider_status, provider_payload=data)
            new_row = await get_payment(new_payment_id)
            await send_platega_payment_link(bot, callback.from_user.id, new_row)
        except Exception as exc:
            await mark_payment_provider_failed(new_payment_id, "CREATE_FAILED", str(exc)[:300])
            await callback.message.answer("❌ Не удалось создать повторный платёж Platega.\n\n" + str(exc)[:700])
        return
    await send_stars_invoice_for_payment(bot, callback.from_user.id, new_row)


