async def remote_admin_check_all_task(bot: Bot, chat_id: int, admin_id: int) -> None:
    try:
        nodes_cfg = remote_load_nodes_config()
        nodes = remote_admin_nodes_all(nodes_cfg) if nodes_cfg else []
        state = await remote_load_node_state()
        if not nodes:
            await send_message_limited(bot, chat_id, "🩺 Проверка локаций\n\nВ nodes.json не найдено ни одной VPS-локации.")
            return
        lines = ["🩺 Проверка всех локации", ""]
        ok_count = 0
        checked_count = 0
        skipped_count = 0
        for node in nodes:
            nid = str(node.get("id") or "?")
            display = str(node.get('display_name') or nid.upper())
            if (not node.get("enabled")) or node.get("maintenance") or node.get("bootstrap"):
                skipped_count += 1
                reasons = []
                if not node.get("enabled"):
                    reasons.append("enabled=false")
                if node.get("maintenance"):
                    reasons.append("maintenance=true")
                if node.get("bootstrap"):
                    reasons.append("bootstrap=true")
                lines.append(f"⚫️ {nid} · {display}")
                lines.append("   • skipped: " + ", ".join(reasons or ["disabled"]) + " · node ожидает ручной bootstrap/sync")
                lines.append("")
                continue
            checked_count += 1
            try:
                check = await asyncio.to_thread(remote_node_check_blocking, nodes_cfg, node)
                ok = bool(check.get("ok"))
                if ok:
                    ok_count += 1
                lines.append(f"{'✅' if ok else '❌'} {nid} · {display}")
                bad = [item for item in (check.get("checks") or []) if not item.get("ok")]
                if bad:
                    for item in bad[:4]:
                        detail = str(item.get("detail") or "").strip()
                        if len(detail) > 120:
                            detail = detail[:119] + "…"
                        lines.append(f"   • {item.get('name')}: {detail or 'ошибка'}")
                st = state.get(nid) or {}
                err = str(st.get("last_error") or "").strip()
                if err and not bad:
                    lines.append(f"   • last_error: {err[:120]}")
            except Exception as exc:
                lines.append(f"❌ {nid}: {str(exc)[:180]}")
            lines.append("")
        lines.append(f"Итог: {ok_count}/{checked_count} checked OK · skipped {skipped_count}/{len(nodes)}")
        await send_message_limited(bot, chat_id, "\n".join(lines).strip())
    except Exception as exc:
        await send_message_limited(bot, chat_id, "❌ Проверка всех nodes failed.\n\n" + str(exc)[:1000])


def remote_backup_export_make_archive() -> Path:
    import tarfile
    import tempfile
    ts = datetime.now().strftime("%Y%m%d-%H%M%S")
    out = Path(tempfile.gettempdir()) / f"bot-sui-backup-{ts}.tar.gz"
    items = [
        (CONFIG_FILE, "config.json"),
        (REMOTE_NODES_FILE, "nodes.json"),
        (DATABASE_DB, "database.sqlite"),
        (BASE_DIR / "bot.py", "bot.py"),
        (BASE_DIR / "requirements.txt", "requirements.txt"),
        (BASE_DIR / "systemd" / "bot-sui.service", "systemd/bot-sui.service"),
    ]
    with tarfile.open(out, "w:gz", format=tarfile.GNU_FORMAT) as tar:
        for src, arc in items:
            try:
                src = Path(src)
                if src.exists():
                    tar.add(src, arcname=arc)
            except Exception:
                continue
    return out


def _migration_should_skip_path(path: Path) -> bool:
    parts = set(path.parts)
    name = path.name
    if name in {"__pycache__", ".pytest_cache", ".mypy_cache"}:
        return True
    if name.endswith(".pyc"):
        return True
    # SQLite WAL/SHM/journal sidecar files are transient and can disappear
    # while copytree is walking /opt/bot-sui. The actual database is copied
    # below through SQLite backup API, so these live sidecars must not be
    # copied as regular files. This prevents harmless races from failing the
    # whole migration backup right after bot start/restart.
    if name.endswith(("-wal", "-shm", "-journal")):
        return True
    try:
        if Path(path).resolve() == DATABASE_DB.resolve():
            return True
    except Exception:
        pass
    # Migration archive should stay portable: logs/backups can be huge and are not required to move service state.
    if "logs" in parts or "backups" in parts:
        return True
    return False


def _migration_copy_path(src: Path, dst: Path) -> None:
    import shutil
    src = Path(src)
    dst = Path(dst)
    if not src.exists():
        return
    if src.is_dir():
        def ignore_func(directory, names):
            ignored = []
            for name in names:
                candidate = Path(directory) / name
                if _migration_should_skip_path(candidate):
                    ignored.append(name)
            return set(ignored)
        if dst.exists():
            shutil.rmtree(dst)
        shutil.copytree(src, dst, symlinks=True, ignore=ignore_func)
    else:
        if _migration_should_skip_path(src):
            return
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)


def _migration_is_root_only_path(path: str | Path) -> bool:
    raw = str(path)
    return raw == "/root" or raw.startswith("/root/")


def _migration_path_readable(path: str | Path) -> bool:
    try:
        p = Path(path)
        if not p.exists():
            return False
        # For dirs we need execute permission too; for files read is enough.
        mode = os.R_OK | (os.X_OK if p.is_dir() else 0)
        return os.access(str(p), mode)
    except Exception:
        return False


def _migration_copy_absolute(src: str | Path, rootfs: Path) -> None:
    src = Path(src)
    try:
        if not src.exists():
            return
        # /root paths are collected by migration_collect_root.sh through sudo.
        # Do not let the non-root bot process recurse into /root, otherwise
        # pathlib/shutil may raise PermissionError before best-effort skips.
        if _migration_is_root_only_path(src) and not _migration_path_readable(src):
            logging.info("migration root-only path delegated to helper: %s", src)
            return
        dst = rootfs / str(src).lstrip("/")
        _migration_copy_path(src, dst)
    except PermissionError as exc:
        logging.warning("migration skip unreadable path=%s: %s", src, exc)
    except Exception as exc:
        logging.warning("migration copy path failed path=%s: %s", src, exc)


def _migration_root_helper_collect(rootfs: Path, manifest: dict) -> None:
    """Collect root-only files through a locked sudo helper when available.

    The bot normally runs as bot-sui and cannot read /root, /etc/nginx,
    some S-UI databases, etc. The installer creates a fixed helper and a
    sudoers rule limited to this helper. If it is not available, migration
    backup continues as best-effort and records a note.
    """
    import shutil
    helper = Path("/usr/local/sbin/bot-sui-migration-collect-root")
    if not helper.exists():
        helper = BASE_DIR / "migration_collect_root.sh"
    sudo_bin = shutil.which("sudo")
    if not helper.exists():
        manifest.setdefault("notes", []).append("root migration helper not installed; root-only paths may be skipped")
        return
    if not sudo_bin:
        manifest.setdefault("notes", []).append("sudo not found; root-only paths may be skipped")
        return
    rc, out = _migration_run_cmd([sudo_bin, "-n", str(helper), str(rootfs)], timeout=240)
    out_text = str(out or "")
    helper_info = {"rc": rc, "output": out_text[-4000:]}
    # Some sudo/systemd environments can report a non-zero subprocess code even
    # after the helper reached its explicit successful finish marker. Treat the
    # marker as successful, while keeping the original rc for diagnostics.
    if rc != 0 and "migration root helper completed" in out_text:
        helper_info["rc_original"] = rc
        helper_info["rc"] = 0
        helper_info["status"] = "completed_with_nonzero_wrapper_rc"
        rc = 0
    elif rc == 0:
        helper_info["status"] = "ok"
    else:
        helper_info["status"] = "failed"
    manifest["root_helper"] = helper_info
    if rc != 0:
        manifest.setdefault("notes", []).append(f"root migration helper failed rc={rc}; root-only paths may be incomplete")


def _migration_run_cmd(args: list[str], timeout: int = 10) -> tuple[int, str]:
    try:
        proc = subprocess.run(args, stdout=subprocess.PIPE, stderr=subprocess.STDOUT, text=True, timeout=timeout)
        return int(proc.returncode), str(proc.stdout or "")
    except Exception as exc:
        return 999, str(exc)


def _migration_sqlite_backup(src: Path, dst: Path) -> bool:
    import shutil
    src = Path(src)
    dst = Path(dst)
    if not src.exists():
        return False
    dst.parent.mkdir(parents=True, exist_ok=True)
    sqlite3_bin = shutil.which("sqlite3")
    if sqlite3_bin:
        rc, out = _migration_run_cmd([sqlite3_bin, str(src), f".backup '{dst}'"], timeout=60)
        if rc == 0 and dst.exists() and dst.stat().st_size > 0:
            return True
        logging.warning("migration sqlite backup failed src=%s rc=%s out=%s", src, rc, out[:300])
    try:
        import shutil as _shutil
        _shutil.copy2(src, dst)
        return True
    except Exception as exc:
        logging.warning("migration sqlite copy fallback failed src=%s: %s", src, exc)
        return False


def _migration_sha256(path: Path) -> str:
    import hashlib
    h = hashlib.sha256()
    with open(path, "rb") as fh:
        for chunk in iter(lambda: fh.read(1024 * 1024), b""):
            h.update(chunk)
    return h.hexdigest()


def _migration_sqlite_integrity_check(path: Path) -> dict:
    """Run PRAGMA integrity_check on a staged SQLite DB copy."""
    import shutil
    path = Path(path)
    rel = str(path)
    if not path.exists() or not path.is_file():
        return {"path": rel, "status": "missing", "detail": "file not found"}
    sqlite3_bin = shutil.which("sqlite3")
    if not sqlite3_bin:
        return {"path": rel, "status": "skipped", "detail": "sqlite3 binary not found"}
    rc, out = _migration_run_cmd([sqlite3_bin, str(path), "PRAGMA integrity_check;"], timeout=60)
    detail = str(out or "").strip().replace("\n", " | ")[:1000]
    if rc == 0 and detail.lower() == "ok":
        return {"path": rel, "status": "ok", "detail": "ok"}
    return {"path": rel, "status": "failed", "detail": detail or f"sqlite3 rc={rc}"}


def _migration_archive_read_check(path: Path) -> dict:
    import tarfile
    path = Path(path)
    try:
        with tarfile.open(path, "r:gz") as tar:
            count = len(tar.getmembers())
        return {"status": "ok", "files": count}
    except Exception as exc:
        return {"status": "failed", "detail": str(exc)[:1000]}


def _migration_collect_integrity_checks(rootfs: Path, manifest: dict) -> dict:
    db_candidates: list[Path] = []
    for pattern in ("*.db", "*.sqlite", "*.sqlite3"):
        db_candidates.extend(rootfs.rglob(pattern))
    db_candidates = sorted({p for p in db_candidates if p.is_file()})
    results = []
    for db_path in db_candidates:
        result = _migration_sqlite_integrity_check(db_path)
        result["path"] = str(db_path.relative_to(rootfs))
        results.append(result)
    ok = sum(1 for r in results if r.get("status") == "ok")
    failed = sum(1 for r in results if r.get("status") == "failed")
    skipped = sum(1 for r in results if r.get("status") == "skipped")
    summary = {"total": len(results), "ok": ok, "failed": failed, "skipped": skipped, "items": results}
    manifest["sqlite_integrity_checks"] = summary
    if failed:
        manifest.setdefault("notes", []).append(f"SQLite integrity check has failed DBs: {failed}")
    return summary


def _migration_integrity_summary_text(manifest: dict) -> str:
    sqlite_summary = manifest.get("sqlite_integrity_checks") or {}
    archive_summary = manifest.get("archive_read_check") or {}
    total = int(sqlite_summary.get("total") or 0)
    ok = int(sqlite_summary.get("ok") or 0)
    failed = int(sqlite_summary.get("failed") or 0)
    skipped = int(sqlite_summary.get("skipped") or 0)
    archive_status = str(archive_summary.get("status") or "unknown")
    lines = [
        "Проверка backup:",
        f"• archive readable: {'OK' if archive_status == 'ok' else archive_status}",
        f"• SQLite integrity: {ok}/{total} OK" + (f", failed {failed}" if failed else "") + (f", skipped {skipped}" if skipped else ""),
    ]
    if failed:
        failed_items = [r for r in (sqlite_summary.get("items") or []) if r.get("status") == "failed"][:5]
        lines.append("• failed DB: " + "; ".join(str(r.get("path")) for r in failed_items))
    return "\n".join(lines)


def _migration_find_sui_paths() -> dict:
    result = {"service_units": [], "directories": [], "databases": [], "notes": []}
    # Static likely locations used by s-ui packages/installers.
    candidate_dirs = [
        Path("/opt/s-ui"),
        Path("/usr/local/s-ui"),
        Path("/etc/s-ui"),
        Path("/var/lib/s-ui"),
        Path("/root/s-ui"),
    ]
    for d in candidate_dirs:
        try:
            if d.exists():
                result["directories"].append(str(d))
                if not _migration_path_readable(d):
                    result["notes"].append(f"directory discovered but not readable by bot process; root helper should collect it: {d}")
        except Exception as exc:
            result["notes"].append(f"candidate dir check failed for {d}: {exc}")
    # Systemd unit discovery catches custom paths without relying on repo defaults.
    for unit in ("s-ui", "sui"):
        rc, out = _migration_run_cmd(["systemctl", "show", unit, "-p", "FragmentPath", "-p", "ExecStart", "--no-pager"], timeout=5)
        if rc == 0 and out:
            for line in out.splitlines():
                if line.startswith("FragmentPath="):
                    p = line.split("=", 1)[1].strip()
                    if p and p != "n/a" and Path(p).exists():
                        result["service_units"].append(p)
                if line.startswith("ExecStart="):
                    # Extract absolute paths from systemd's ExecStart line.
                    for m in re.findall(r"(/[^\s;]+)", line):
                        p = Path(m.strip())
                        if p.exists():
                            if p.is_dir():
                                result["directories"].append(str(p))
                            else:
                                parent = p.parent
                                if parent.exists() and str(parent) not in result["directories"]:
                                    result["directories"].append(str(parent))
    # DB discovery inside discovered dirs, bounded to avoid walking the whole FS.
    dbs = []
    for d_raw in list(dict.fromkeys(result["directories"])):
        d = Path(d_raw)
        if not d.exists() or not d.is_dir():
            continue
        if not _migration_path_readable(d):
            result["notes"].append(f"db discovery skipped unreadable dir in bot process; root helper should collect DBs: {d}")
            continue
        try:
            for pattern in ("*.db", "*.sqlite", "*.sqlite3"):
                for p in d.rglob(pattern):
                    if p.is_file() and not _migration_should_skip_path(p):
                        dbs.append(str(p))
        except Exception as exc:
            result["notes"].append(f"db discovery failed in {d}: {exc}")
    result["directories"] = sorted(set(result["directories"]))
    result["service_units"] = sorted(set(result["service_units"]))
    result["databases"] = sorted(set(dbs))
    return result


def _migration_write_restore_files(staging: Path, manifest: dict) -> None:
    restore_md = staging / "RESTORE_MAIN_VPS.md"
    restore_ru = staging / "RESTORE_MAIN_VPS_RU.md"
    post_ru = staging / "POST_RESTORE_CHECKLIST_RU.md"
    restore_sh = staging / "restore_migration_backup.sh"
    restore_md.write_text(
        "# Restore main VPS from migration backup\n\n"
        "This archive contains secrets: Telegram token, S-UI token, SQLite databases, SSH keys, nodes.json and TLS certs. Keep it private.\n\n"
        "## Typical migration flow\n\n"
        "1. Prepare a fresh Ubuntu VPS.\n"
        "2. Upload and extract this archive as root: `mkdir -p /root/migration && tar --warning=no-unknown-keyword -xzf bot-sui-migration-YYYYMMDD-HHMMSS.tar.gz -C /root/migration`.\n"
        "3. Run: `cd /root/migration && sudo bash restore_migration_backup.sh`.\n"
        "4. Update DNS records for main/panel/sub/apex to the new main VPS IP.\n"
        "5. Verify `/etc/hosts` still points `panel.astramind.dpdns.org` to `127.0.0.1` if the local S-UI API is used through the panel domain.\n"
        "6. Check services: `systemctl status bot-sui s-ui nginx --no-pager`.\n"
        "7. Open Telegram admin panel and run Локации / VPS-node status/sync checks.\n\n"
        "## Russian guide\n\n"
        "See `RESTORE_MAIN_VPS_RU.md` and `POST_RESTORE_CHECKLIST_RU.md`.\n\n"
        "## What is inside\n\n"
        "See `MANIFEST.json`. Files are stored under `rootfs/` using their original absolute paths.\n\n"
        "## Notes\n\n"
        "The script restores files best-effort. It does not change Cloudflare DNS automatically. If S-UI was installed in a non-standard path, check `MANIFEST.json -> sui_discovery`.\n",
        encoding="utf-8",
    )
    restore_ru.write_text(
        "# Восстановление main VPS из migration backup\n\n"
        "Этот архив содержит секреты: Telegram token, S-UI token, базы SQLite, SSH-ключи, `nodes.json` и TLS-сертификаты. Храни его только локально и не пересылай посторонним.\n\n"
        "## Что восстанавливает архив\n\n"
        "Обычно внутри есть:\n"
        "- `/opt/bot-sui` — бот, конфиг, база, ключи, сертификаты для бота;\n"
        "- `/root/cert-CF/astramind.dpdns.org` — wildcard-сертификаты;\n"
        "- systemd units для `bot-sui`, `s-ui`/`sui`, nginx;\n"
        "- найденные файлы S-UI, включая SQLite DB, если они были обнаружены;\n"
        "- nginx configs;\n"
        "- `/etc/hosts`;\n"
        "- `MANIFEST.json` со списком файлов и sha256;\n"
        "- `MIGRATION_BACKUP_REPORT.txt` с проверками integrity.\n\n"
        "## Важная схема переезда\n\n"
        "Если домены остаются прежними (`panel.astramind.dpdns.org`, `sub.astramind.dpdns.org`, `astramind.dpdns.org`), пользователям обычно не нужно менять ссылки. После восстановления надо только переключить DNS на новый main VPS.\n\n"
        "Локации / VPS-node (`nl1`, `pl1`, `de1` и другие) можно оставить прежними. Бот после восстановления продолжит подключаться к ним по SSH-ключу из backup.\n\n"
        "## Порядок восстановления\n\n"
        "1. Подними новый чистый VPS на Ubuntu.\n"
        "2. Скопируй архив migration backup на новый VPS, например в `/root/`.\n"
        "3. Создай директорию для распаковки:\n\n"
        "```bash\n"
        "mkdir -p /root/migration\n"
        "```\n\n"
        "4. Распакуй архив:\n\n"
        "```bash\n"
        "tar --warning=no-unknown-keyword -xzf /root/bot-sui-migration-YYYYMMDD-HHMMSS.tar.gz -C /root/migration\n"
        "```\n\n"
        "5. Запусти restore-скрипт:\n\n"
        "```bash\n"
        "cd /root/migration\n"
        "sudo bash restore_migration_backup.sh\n"
        "```\n\n"
        "6. Скрипт попросит подтверждение. Введи:\n\n"
        "```text\n"
        "RESTORE\n"
        "```\n\n"
        "7. После восстановления проверь `/opt/bot-sui/config.json`:\n\n"
        "```bash\n"
        "sudo jq '.sui, .remote_nodes' /opt/bot-sui/config.json\n"
        "```\n\n"
        "8. Проверь `/etc/hosts`. Для локального обхода Cloudflare строка обычно должна быть такой:\n\n"
        "```text\n"
        "127.0.0.1 panel.astramind.dpdns.org\n"
        "```\n\n"
        "9. В Cloudflare/DNS переключи записи на IP нового main VPS:\n\n"
        "```text\n"
        "main  -> NEW_MAIN_IP\n"
        "panel -> NEW_MAIN_IP\n"
        "sub   -> NEW_MAIN_IP\n"
        "astramind.dpdns.org -> NEW_MAIN_IP\n"
        "```\n\n"
        "10. Перезапусти сервисы:\n\n"
        "```bash\n"
        "sudo systemctl daemon-reload\n"
        "sudo systemctl restart nginx || true\n"
        "sudo systemctl restart s-ui || sudo systemctl restart sui || true\n"
        "sudo systemctl restart bot-sui\n"
        "```\n\n"
        "11. Открой Telegram-бота и проверь:\n"
        "- `🛠 Админ -> 🌍 Локации / VPS-node`;\n"
        "- `🩺 Проверить все nodes`;\n"
        "- `🔄 Запустить sync`;\n"
        "- одну тестовую покупку/продление, если это отдельный тестовый стенд.\n\n"
        "## Если что-то пошло не так\n\n"
        "Сначала смотри логи:\n\n"
        "```bash\n"
        "sudo journalctl -u bot-sui -n 200 --no-pager\n"
        "sudo journalctl -u s-ui -n 200 --no-pager || sudo journalctl -u sui -n 200 --no-pager\n"
        "sudo nginx -t\n"
        "```\n\n"
        "Проверь `MANIFEST.json`: там указано, какие S-UI пути и базы были найдены при создании backup.\n",
        encoding="utf-8",
    )
    post_ru.write_text(
        "# Post-restore checklist для main VPS\n\n"
        "Выполни после восстановления migration backup.\n\n"
        "## 1. Проверка файлов\n\n"
        "```bash\n"
        "sudo test -s /opt/bot-sui/bot.py && echo 'bot.py OK'\n"
        "sudo test -s /opt/bot-sui/config.json && echo 'config.json OK'\n"
        "sudo test -s /opt/bot-sui/nodes.json && echo 'nodes.json OK'\n"
        "sudo test -s /opt/bot-sui/database.sqlite && echo 'database.sqlite OK'\n"
        "sudo test -s /opt/bot-sui/keys/nodes_ed25519 && echo 'nodes SSH key OK'\n"
        "sudo test -s /opt/bot-sui/certs/astramind.dpdns.org/fullchain.pem && echo 'bot cert fullchain OK'\n"
        "sudo test -s /opt/bot-sui/certs/astramind.dpdns.org/privkey.pem && echo 'bot cert privkey OK'\n"
        "```\n\n"
        "## 2. Проверка SQLite\n\n"
        "```bash\n"
        "sudo -u bot-sui sqlite3 /opt/bot-sui/database.sqlite 'PRAGMA integrity_check;'\n"
        "```\n\n"
        "Ожидаемо: `ok`.\n\n"
        "## 3. Проверка config\n\n"
        "```bash\n"
        "sudo jq '.sui.api_url, .sui.sub_url, .remote_nodes' /opt/bot-sui/config.json\n"
        "sudo jq '.nodes[] | {id, enabled, maintenance, drain, host, domain, display_name}' /opt/bot-sui/nodes.json\n"
        "```\n\n"
        "## 4. Проверка systemd\n\n"
        "```bash\n"
        "sudo systemctl status bot-sui --no-pager\n"
        "sudo systemctl status s-ui --no-pager || sudo systemctl status sui --no-pager\n"
        "sudo systemctl status nginx --no-pager\n"
        "```\n\n"
        "## 5. Проверка логов\n\n"
        "```bash\n"
        "sudo journalctl -u bot-sui -n 200 --no-pager\n"
        "sudo journalctl -u s-ui -n 100 --no-pager || sudo journalctl -u sui -n 100 --no-pager\n"
        "```\n\n"
        "## 6. Проверка nginx и доменов\n\n"
        "```bash\n"
        "sudo nginx -t\n"
        "curl -I https://panel.astramind.dpdns.org/ || true\n"
        "curl -I https://sub.astramind.dpdns.org/ || true\n"
        "```\n\n"
        "## 7. Проверка локации из main\n\n"
        "```bash\n"
        "for HOST in $(sudo jq -r '.nodes[] | select(.enabled==true) | .host' /opt/bot-sui/nodes.json); do\n"
        "  echo \"===== $HOST =====\"\n"
        "  sudo -u bot-sui ssh -i /opt/bot-sui/keys/nodes_ed25519 -o BatchMode=yes -o ConnectTimeout=8 root@\"$HOST\" 'systemctl is-active sing-box && sing-box check -c /etc/sing-box/config.json'\n"
        "done\n"
        "```\n\n"
        "## 8. Проверка в Telegram\n\n"
        "Открой:\n"
        "- `🛠 Админ -> 🌍 Локации / VPS-node`;\n"
        "- `🩺 Проверить все nodes`;\n"
        "- `🧾 Журнал sync`;\n"
        "- `🔑 Мои подписки`.\n\n"
        "## 9. Проверка DNS после переключения\n\n"
        "```bash\n"
        "dig +short panel.astramind.dpdns.org\n"
        "dig +short sub.astramind.dpdns.org\n"
        "dig +short astramind.dpdns.org\n"
        "```\n\n"
        "Все нужные записи должны указывать на новый main VPS.\n",
        encoding="utf-8",
    )
    restore_sh.write_text(
        "#!/usr/bin/env bash\n"
        "set -euo pipefail\n\n"
        "ROOT_DIR=\"$(cd \"$(dirname \"$0\")\" && pwd)\"\n"
        "if [ ! -d \"$ROOT_DIR/rootfs\" ]; then\n  echo 'rootfs directory not found. Extract archive first.' >&2\n  exit 1\nfi\n"
        "echo 'This will restore bot-sui/S-UI/nginx files to this VPS.'\n"
        "echo 'Archive contains secrets. Run only on your new main VPS.'\n"
        "echo 'Russian guide: RESTORE_MAIN_VPS_RU.md and POST_RESTORE_CHECKLIST_RU.md'\n"
        "read -r -p 'Type RESTORE to continue: ' CONFIRM\n"
        "[ \"$CONFIRM\" = 'RESTORE' ] || { echo 'Cancelled'; exit 1; }\n\n"
        "apt-get update\n"
        "apt-get install -y python3 python3-venv python3-pip sqlite3 rsync jq curl ca-certificates nginx openssh-client sshpass dnsutils\n\n"
        "if ! id bot-sui >/dev/null 2>&1; then\n  useradd --system --home-dir /opt/bot-sui --shell /usr/sbin/nologin --create-home bot-sui\nfi\n\n"
        "systemctl stop bot-sui 2>/dev/null || true\n"
        "systemctl stop s-ui 2>/dev/null || true\n"
        "systemctl stop sui 2>/dev/null || true\n"
        "systemctl stop nginx 2>/dev/null || true\n\n"
        "rsync -aH --numeric-ids \"$ROOT_DIR/rootfs/\" /\n\n"
        "chown -R bot-sui:bot-sui /opt/bot-sui 2>/dev/null || true\n"
        "chmod 600 /opt/bot-sui/config.json /opt/bot-sui/nodes.json 2>/dev/null || true\n"
        "chmod 600 /opt/bot-sui/keys/nodes_ed25519 2>/dev/null || true\n"
        "chmod 644 /opt/bot-sui/keys/nodes_ed25519.pub 2>/dev/null || true\n"
        "chmod 600 /opt/bot-sui/certs/astramind.dpdns.org/privkey.pem 2>/dev/null || true\n"
        "chmod 644 /opt/bot-sui/certs/astramind.dpdns.org/fullchain.pem 2>/dev/null || true\n\n"
        "cd /opt/bot-sui\n"
        "python3 -m venv venv\n"
        "/opt/bot-sui/venv/bin/pip install -U pip wheel\n"
        "if [ -f requirements.txt ]; then /opt/bot-sui/venv/bin/pip install -r requirements.txt; fi\n\n"
        "systemctl daemon-reload\n"
        "systemctl enable --now bot-sui 2>/dev/null || systemctl start bot-sui\n"
        "systemctl enable --now s-ui 2>/dev/null || systemctl start s-ui 2>/dev/null || true\n"
        "systemctl enable --now nginx 2>/dev/null || systemctl start nginx 2>/dev/null || true\n\n"
        "echo 'Restore finished. Now update DNS to the new main VPS IP and verify services.'\n"
        "echo 'Read RESTORE_MAIN_VPS_RU.md and POST_RESTORE_CHECKLIST_RU.md.'\n"
        "systemctl status bot-sui --no-pager || true\n",
        encoding="utf-8",
    )
    restore_sh.chmod(0o700)

def remote_migration_backup_make_archive() -> tuple[Path, str]:
    import tarfile
    import tempfile
    import shutil
    import hashlib
    ts = datetime.now().strftime("%Y%m%d-%H%M%S")
    out = Path(tempfile.gettempdir()) / f"bot-sui-migration-{ts}.tar.gz"
    staging = Path(tempfile.mkdtemp(prefix=f"bot-sui-migration-{ts}-"))
    rootfs = staging / "rootfs"
    rootfs.mkdir(parents=True, exist_ok=True)
    manifest: dict = {
        "created_at": datetime.now().isoformat(),
        "hostname": os.uname().nodename if hasattr(os, "uname") else "unknown",
        "app_build": APP_BUILD,
        "base_dir": str(BASE_DIR),
        "notes": [],
        "files": [],
    }
    try:
        # Root-assisted collection first: /root certs, nginx/systemd/S-UI files may be unreadable for bot-sui.
        _migration_root_helper_collect(rootfs, manifest)

        # Main bot tree without huge logs/backups; database is backed up safely below.
        if BASE_DIR.exists():
            _migration_copy_path(BASE_DIR, rootfs / str(BASE_DIR).lstrip("/"))
        # Safe bot SQLite snapshot.
        if DATABASE_DB.exists():
            _migration_sqlite_backup(DATABASE_DB, rootfs / str(DATABASE_DB).lstrip("/"))
        # Extra cert location used by current deployment.
        for p in [
            Path("/root/cert-CF/astramind.dpdns.org"),
            Path("/etc/hosts"),
        ]:
            _migration_copy_absolute(p, rootfs)
        # systemd units relevant to this project.
        for pattern in ["/etc/systemd/system/bot-sui*", "/etc/systemd/system/s-ui*", "/etc/systemd/system/sui*", "/etc/systemd/system/nginx.service"]:
            for p in Path("/").glob(pattern.lstrip("/")):
                _migration_copy_absolute(p, rootfs)
        # nginx configs.
        for p in [Path("/etc/nginx/nginx.conf"), Path("/etc/nginx/conf.d"), Path("/etc/nginx/sites-available"), Path("/etc/nginx/sites-enabled")]:
            _migration_copy_absolute(p, rootfs)
        # S-UI discovery and copy.
        sui_info = _migration_find_sui_paths()
        manifest["sui_discovery"] = sui_info
        for unit_path in sui_info.get("service_units") or []:
            _migration_copy_absolute(unit_path, rootfs)
        for d in sui_info.get("directories") or []:
            if _migration_is_root_only_path(d) and not _migration_path_readable(d):
                manifest["notes"].append(f"S-UI directory delegated to root helper: {d}")
                continue
            _migration_copy_absolute(d, rootfs)
        # Safe snapshots for discovered S-UI sqlite DB files. Root-only DBs are handled by helper.
        for db in sui_info.get("databases") or []:
            if _migration_is_root_only_path(db) and not _migration_path_readable(db):
                manifest["notes"].append(f"S-UI database delegated to root helper: {db}")
                continue
            _migration_sqlite_backup(Path(db), rootfs / db.lstrip("/"))
        # Validate staged database snapshots before packaging.
        _migration_collect_integrity_checks(rootfs, manifest)

        # Manifest after staging is populated.
        for file_path in sorted([p for p in rootfs.rglob("*") if p.is_file()]):
            rel = str(file_path.relative_to(staging))
            try:
                manifest["files"].append({
                    "path": rel,
                    "size": int(file_path.stat().st_size),
                    "sha256": _migration_sha256(file_path),
                })
            except Exception as exc:
                manifest["notes"].append(f"manifest failed for {rel}: {exc}")
        _migration_write_restore_files(staging, manifest)
        (staging / "MIGRATION_BACKUP_REPORT.txt").write_text(_migration_integrity_summary_text(manifest) + "\n", encoding="utf-8")
        (staging / "MANIFEST.json").write_text(json.dumps(manifest, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
        with tarfile.open(out, "w:gz", format=tarfile.GNU_FORMAT) as tar:
            for item in ["MANIFEST.json", "MIGRATION_BACKUP_REPORT.txt", "RESTORE_MAIN_VPS.md", "RESTORE_MAIN_VPS_RU.md", "POST_RESTORE_CHECKLIST_RU.md", "restore_migration_backup.sh", "rootfs"]:
                tar.add(staging / item, arcname=item)
        manifest["archive_read_check"] = _migration_archive_read_check(out)
        (staging / "MIGRATION_BACKUP_REPORT.txt").write_text(_migration_integrity_summary_text(manifest) + "\n", encoding="utf-8")
        (staging / "MANIFEST.json").write_text(json.dumps(manifest, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
        with tarfile.open(out, "w:gz", format=tarfile.GNU_FORMAT) as tar:
            for item in ["MANIFEST.json", "MIGRATION_BACKUP_REPORT.txt", "RESTORE_MAIN_VPS.md", "RESTORE_MAIN_VPS_RU.md", "POST_RESTORE_CHECKLIST_RU.md", "restore_migration_backup.sh", "rootfs"]:
                tar.add(staging / item, arcname=item)
        return out, _migration_integrity_summary_text(manifest)
    finally:
        with contextlib.suppress(Exception):
            shutil.rmtree(staging)


@router.callback_query(F.data == "admin:remote")
async def admin_remote_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    try:
        snapshot = await remote_admin_counts()
        await safe_edit_text(callback.message, remote_admin_status_text(snapshot), reply_markup=remote_admin_keyboard())
    except Exception as exc:
        await safe_edit_text(callback.message, "❌ Не удалось получить статус локаций.\n\n" + str(exc)[:1000], reply_markup=admin_subpage_keyboard())


@router.callback_query(F.data.startswith("admin:remote:faq"))
async def admin_remote_faq_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    page = 1
    with contextlib.suppress(Exception):
        parts = str(callback.data or "").split(":")
        if len(parts) >= 4 and str(parts[3]).isdigit():
            page = int(parts[3])
    await safe_edit_text(callback.message, remote_admin_faq_text(page), reply_markup=remote_admin_faq_keyboard(page))


@router.callback_query(F.data == "admin:remote:sync")
async def admin_remote_sync_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    if not is_admin(callback.from_user.id):
        await callback.answer()
        return
    admin_id = int(callback.from_user.id)
    now_ts = time.time()
    last_ts = float(remote_manual_sync_last_ts.get(admin_id) or 0)
    remaining = int((last_ts + REMOTE_NODES_MANUAL_SYNC_COOLDOWN_SECONDS) - now_ts)
    if remaining > 0:
        await callback.answer(f"Sync можно запускать не чаще. Подождите {remaining} сек.", show_alert=True)
        return
    remote_manual_sync_last_ts[admin_id] = now_ts
    await callback.answer("Sync поставлен в очередь")
    await state.clear()
    remote_request_sync(reason=f"admin_sync_now:{callback.from_user.id}")
    snapshot = await remote_admin_counts()
    text = remote_admin_status_text(snapshot) + "\n\n✅ Remote sync поставлен в очередь. Обычно он стартует через 2 секунды и выполнится в фоне."
    await safe_edit_text(callback.message, text, reply_markup=remote_admin_keyboard())


