@router.callback_query(F.data == "admin:remote:migration_backup")
async def admin_remote_migration_backup_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    if not is_admin(callback.from_user.id):
        await callback.answer()
        return
    await state.clear()
    await callback.answer("Готовлю migration backup")
    await callback.message.answer(
        "📦 Migration backup\n\n"
        "Готовлю полный архив для переезда main VPS. Это может занять немного времени.\n\n"
        "Архив будет содержать секреты: Telegram/S-UI токены, SQLite базы, SSH keys, nodes.json и сертификаты. Хранить только локально."
    )
    try:
        archive, check_report = await asyncio.to_thread(remote_migration_backup_make_archive)
        await callback.message.answer_document(
            FSInputFile(str(archive)),
            caption=(
                "📦 Migration backup\n\n"
                "Полный архив для переезда main VPS. Внутри MANIFEST.json, MIGRATION_BACKUP_REPORT.txt, RESTORE_MAIN_VPS_RU.md, POST_RESTORE_CHECKLIST_RU.md и restore_migration_backup.sh.\n\n"
                f"{check_report}\n\n"
                "Содержит секреты. Не пересылайте посторонним."
            ),
        )
    except Exception as exc:
        await callback.message.answer("❌ Migration backup failed.\n\n" + str(exc)[:1200])



def migration_root_console_script_text() -> str:
    return r'''#!/usr/bin/env bash
set -euo pipefail

# ============================================================
# bot-sui ROOT migration package creator
# Run on the CURRENT main VPS as root.
# Output: /root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz
# ============================================================

if [ "${EUID}" -ne 0 ]; then
  echo "ERROR: run this script as root: sudo bash $0" >&2
  exit 1
fi

OUT_DIR="${1:-/root}"
PROJECT_DIR="/opt/bot-sui"
SERVICE_USER="bot-sui"
TS="$(date +%Y%m%d-%H%M%S)"
STAGE="$(mktemp -d /root/bot-sui-root-migration.${TS}.XXXXXX)"
ROOTFS="${STAGE}/rootfs"
ARCHIVE="${OUT_DIR%/}/bot-sui-root-migration-${TS}.tar.gz"
MANIFEST="${STAGE}/MANIFEST.txt"
JSON_MANIFEST="${STAGE}/MANIFEST.json"
REPORT="${STAGE}/MIGRATION_REPORT_RU.txt"
RESTORE_SH="${STAGE}/restore_on_new_vps.sh"
README_RU="${STAGE}/README_RESTORE_RU.md"
CHECKLIST_RU="${STAGE}/POST_RESTORE_CHECKLIST_RU.md"

mkdir -p "$ROOTFS" "$OUT_DIR"
cleanup() { rm -rf "$STAGE"; }
trap cleanup EXIT

echo "== bot-sui root migration package =="
echo "Stage: $STAGE"
echo "Output: $ARCHIVE"

need_cmd() {
  command -v "$1" >/dev/null 2>&1 || return 1
}

if ! need_cmd rsync || ! need_cmd tar || ! need_cmd python3; then
  echo "Installing required tools..."
  apt-get update
  apt-get install -y rsync tar gzip python3 sqlite3 jq curl ca-certificates nginx openssh-client dnsutils
fi

copy_path() {
  local src="$1"
  local dst="$ROOTFS${src}"
  if [ ! -e "$src" ]; then
    return 0
  fi
  mkdir -p "$(dirname "$dst")"
  if [ -d "$src" ]; then
    mkdir -p "$dst"
    rsync -aH --numeric-ids \
      --exclude '/venv/***' \
      --exclude '/.venv/***' \
      --exclude '/__pycache__/***' \
      --exclude '/.pytest_cache/***' \
      --exclude '/.mypy_cache/***' \
      --exclude '/logs/***' --exclude 'logs/***' --exclude '*/logs/***' \
      --exclude '/incident_logs/***' --exclude 'incident_logs/***' --exclude '*/incident_logs/***' \
      --exclude '/backups/***' --exclude 'backups/***' --exclude '*/backups/***' \
      --exclude '/backup/***' --exclude 'backup/***' --exclude '*/backup/***' \
      --exclude '/sui-backups/***' --exclude 'sui-backups/***' --exclude '*/sui-backups/***' \
      --exclude '/releases/***' --exclude 'releases/***' --exclude '*/releases/***' \
      --exclude '/cache/***' --exclude 'cache/***' --exclude '*/cache/***' \
      --exclude '/bot-sui-root-migration-*' \
      --exclude '/bot-sui-migration-*' \
      --exclude '/bot-sui-backup-*' \
      --exclude '*.tar.gz' \
      --exclude '*.tgz' \
      --exclude '*.zip' \
      --exclude '*.7z' \
      --exclude '*.pyc' \
      --exclude '*.tmp' \
      --exclude '*-wal' \
      --exclude '*-shm' \
      --exclude '*-journal' \
      "$src/" "$dst/"
  else
    cp -a "$src" "$dst"
  fi
}

sqlite_backup() {
  local src="$1"
  local dst="$ROOTFS${src}"
  [ -f "$src" ] || return 0
  mkdir -p "$(dirname "$dst")"
  if command -v sqlite3 >/dev/null 2>&1; then
    sqlite3 "$src" ".backup '$dst'" || cp -a "$src" "$dst"
  else
    cp -a "$src" "$dst"
  fi
}

record() {
  echo "$*" >> "$MANIFEST"
}

record "created_at=${TS}"
record "host=$(hostname -f 2>/dev/null || hostname)"
record "project_dir=${PROJECT_DIR}"
record "archive=${ARCHIVE}"

# Main bot files
copy_path "$PROJECT_DIR"
sqlite_backup "$PROJECT_DIR/database.sqlite"

# Certs and root paths used in current deployment
copy_path "/root/cert-CF/astramind.dpdns.org"
copy_path "/etc/hosts"

# systemd units
for p in /etc/systemd/system/bot-sui* /etc/systemd/system/s-ui* /etc/systemd/system/sui* /etc/systemd/system/nginx.service; do
  [ -e "$p" ] && copy_path "$p"
done

# nginx configs
copy_path "/etc/nginx/nginx.conf"
copy_path "/etc/nginx/conf.d"
copy_path "/etc/nginx/sites-available"
copy_path "/etc/nginx/sites-enabled"

# S-UI discovery: common paths + systemd ExecStart paths
SUI_PATHS="/usr/local/s-ui /usr/local/bin/s-ui /usr/local/bin/sui /usr/bin/s-ui /usr/bin/sui /etc/s-ui /etc/sui /var/lib/s-ui /var/lib/sui"
for unit in /etc/systemd/system/s-ui.service /etc/systemd/system/sui.service; do
  if [ -f "$unit" ]; then
    copy_path "$unit"
    while IFS= read -r line; do
      case "$line" in
        ExecStart=*)
          for token in $line; do
            case "$token" in
              /*) SUI_PATHS="$SUI_PATHS ${token#ExecStart=}" ;;
            esac
          done
        ;;
      esac
    done < "$unit"
  fi
done
for pth in $SUI_PATHS; do
  [ -e "$pth" ] && copy_path "$pth"
done

# Known SQLite DB snapshots inside copied app dirs.
# IMPORTANT: prune local backup/log/release trees first; otherwise migration package can accidentally include gigabytes of old hourly snapshots.
for db in $(find "$PROJECT_DIR" /usr/local/s-ui /etc/s-ui /var/lib/s-ui /usr/local/bin /usr/bin -maxdepth 5   \( -path '*/backups' -o -path '*/backups/*' -o -path '*/sui-backups' -o -path '*/sui-backups/*' -o -path '*/logs' -o -path '*/logs/*' -o -path '*/incident_logs' -o -path '*/incident_logs/*' -o -path '*/releases' -o -path '*/releases/*' -o -path '*/cache' -o -path '*/cache/*' -o -path '*/backup' -o -path '*/backup/*' -o -name 'bot-sui-root-migration-*' -o -name 'bot-sui-migration-*' -o -name 'bot-sui-backup-*' \) -prune -o   \( -type f \( -name '*.db' -o -name '*.sqlite' -o -name '*.sqlite3' \) -print \) 2>/dev/null | sort -u); do
  sqlite_backup "$db"
done

# Integrity checks
{
  echo "📦 Root migration package report"
  echo "━━━━━━━━━━━━━━"
  echo "Created: $TS"
  echo "Archive: $ARCHIVE"
  echo "Excluded from rootfs/opt/bot-sui and DB discovery: backups, sui-backups, logs, incident_logs, releases, nested migration archives, venv cache"
  echo ""
  echo "Files copied:"
  find "$ROOTFS" -type f | sed "s#^$ROOTFS##" | sort | head -500
  echo ""
  echo "SQLite integrity checks:"
  for db in $(find "$ROOTFS" -type f \( -name '*.db' -o -name '*.sqlite' -o -name '*.sqlite3' \) 2>/dev/null | sort); do
    if command -v sqlite3 >/dev/null 2>&1; then
      res="$(sqlite3 "$db" 'PRAGMA integrity_check;' 2>&1 || true)"
      echo "$(echo "$db" | sed "s#^$ROOTFS##"): $res"
    else
      echo "$(echo "$db" | sed "s#^$ROOTFS##"): sqlite3 not installed"
    fi
  done
} > "$REPORT"

cat > "$README_RU" <<'README_EOF'
# Восстановление bot-sui на новом main VPS

Это альтернативный root migration package. Он создан root-скриптом на старом main VPS и содержит рабочее состояние: бот, SQLite, config.json, nodes.json, SSH-ключи node, сертификаты, systemd units, nginx configs и обнаруженные файлы S-UI. Старые локальные backup'ы, логи, releases и вложенные архивы намеренно не включаются, чтобы migration package не разрастался до гигабайтов.

Важно: архив содержит секреты. Не отправляй его никому. Храни локально.

## Часть 1. На старом сервере

1. Сохрани скрипт `bot-sui-root-migration-create.sh` на старом main VPS.
2. Запусти от root:

```bash
sudo bash bot-sui-root-migration-create.sh
```

3. В конце скрипт покажет путь к архиву и его размер. Нормальный размер обычно заметно меньше локальной папки `/opt/bot-sui/backups`, потому что backup-история не входит в пакет:

```text
/root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz
```

4. Скачай этот архив на компьютер через SFTP/SCP или панель VPS.

Пример через терминал на своём компьютере:

```bash
scp root@OLD_MAIN_IP:/root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz .
```

## Часть 2. На новом VPS

1. Подними чистый Ubuntu VPS.
2. Залей архив на новый VPS в `/root/`:

```bash
scp bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz root@NEW_MAIN_IP:/root/
```

3. Зайди на новый VPS:

```bash
ssh root@NEW_MAIN_IP
```

4. Распакуй архив:

```bash
mkdir -p /root/migration
cd /root/migration
tar -xzf /root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz
```

5. Запусти restore:

```bash
sudo bash restore_on_new_vps.sh
```

6. Когда скрипт спросит подтверждение, введи:

```text
RESTORE
```

## Часть 3. DNS

После restore переключи DNS-записи на IP нового main VPS:

```text
panel.astramind.dpdns.org -> NEW_MAIN_IP
sub.astramind.dpdns.org   -> NEW_MAIN_IP
astramind.dpdns.org       -> NEW_MAIN_IP
```

Cloudflare:
- panel можно через proxy, если так было раньше;
- sub лучше без challenge/серого облака, как в текущей схеме проекта.

## Часть 4. Проверка после restore

На новом VPS:

```bash
sudo systemctl status bot-sui --no-pager
sudo systemctl status s-ui --no-pager || sudo systemctl status sui --no-pager
sudo nginx -t
sudo journalctl -u bot-sui -n 200 --no-pager
```

В Telegram:
- открой админку;
- запусти `🩺 Проверка production`;
- запусти `🔁 Сверка локаций и ссылок`;
- запусти `🩺 Проверить все локации`;
- при необходимости нажми `🔄 Поставить remote sync` и `🔗 Восстановить links`.

## Часть 5. Если бот не стартует

Проверь:

```bash
sudo /opt/bot-sui/venv/bin/python -m py_compile /opt/bot-sui/bot.py
sudo journalctl -u bot-sui -n 300 --no-pager
sudo ls -lah /opt/bot-sui
sudo cat /opt/bot-sui/config.json | jq '.sui, .remote_nodes'
```

Частая причина: DNS ещё указывает на старый VPS или S-UI service называется не `s-ui`, а `sui`.
README_EOF

cat > "$CHECKLIST_RU" <<'CHECKLIST_EOF'
# Post-restore checklist

Выполни на новом VPS после `restore_on_new_vps.sh`.

## 1. Файлы

```bash
sudo test -s /opt/bot-sui/bot.py && echo bot.py_OK
sudo test -s /opt/bot-sui/config.json && echo config_OK
sudo test -s /opt/bot-sui/nodes.json && echo nodes_OK
sudo test -s /opt/bot-sui/database.sqlite && echo db_OK
sudo test -s /opt/bot-sui/keys/nodes_ed25519 && echo node_ssh_key_OK
```

## 2. Python

```bash
sudo /opt/bot-sui/venv/bin/python -m py_compile /opt/bot-sui/bot.py
```

## 3. SQLite

```bash
sudo -u bot-sui sqlite3 /opt/bot-sui/database.sqlite 'PRAGMA integrity_check;'
```

Ожидаемо: `ok`.

## 4. Сервисы

```bash
sudo systemctl status bot-sui --no-pager
sudo systemctl status s-ui --no-pager || sudo systemctl status sui --no-pager
sudo systemctl status nginx --no-pager
```

## 5. Логи

```bash
sudo journalctl -u bot-sui -n 200 --no-pager
sudo journalctl -u s-ui -n 100 --no-pager || sudo journalctl -u sui -n 100 --no-pager
```

## 6. Node SSH

```bash
for HOST in $(sudo jq -r '.nodes[] | select(.enabled==true) | .host' /opt/bot-sui/nodes.json); do
  echo "===== $HOST ====="
  sudo -u bot-sui ssh -i /opt/bot-sui/keys/nodes_ed25519 -o BatchMode=yes -o ConnectTimeout=8 root@"$HOST" 'systemctl is-active sing-box && sing-box check -c /etc/sing-box/config.json'
done
```

## 7. Telegram admin

Проверь:
- `🩺 Проверка production`;
- `🔁 Сверка локаций и ссылок`;
- `🩺 Проверить все локации`;
- `📋 Все кейсы`;
- тестовую подписку.
CHECKLIST_EOF

cat > "$RESTORE_SH" <<'RESTORE_EOF'
#!/usr/bin/env bash
set -euo pipefail

if [ "${EUID}" -ne 0 ]; then
  echo "ERROR: run as root: sudo bash $0" >&2
  exit 1
fi
ROOT_DIR="$(cd "$(dirname "$0")" && pwd)"
ROOTFS="$ROOT_DIR/rootfs"
if [ ! -d "$ROOTFS" ]; then
  echo "ERROR: rootfs not found. Extract archive first." >&2
  exit 1
fi

echo "This will restore bot-sui/S-UI/nginx files to this VPS."
echo "Archive contains secrets. Run only on the NEW main VPS."
read -r -p "Type RESTORE to continue: " CONFIRM
[ "$CONFIRM" = "RESTORE" ] || { echo "Cancelled"; exit 1; }

apt-get update
apt-get install -y python3 python3-venv python3-pip sqlite3 rsync jq curl ca-certificates nginx openssh-client dnsutils

if ! id bot-sui >/dev/null 2>&1; then
  useradd --system --home-dir /opt/bot-sui --shell /usr/sbin/nologin --create-home bot-sui
fi
if getent group systemd-journal >/dev/null 2>&1; then
  usermod -aG systemd-journal bot-sui || true
fi

systemctl stop bot-sui 2>/dev/null || true
systemctl stop s-ui 2>/dev/null || true
systemctl stop sui 2>/dev/null || true
systemctl stop nginx 2>/dev/null || true

rsync -aH --numeric-ids "$ROOTFS/" /

chown -R bot-sui:bot-sui /opt/bot-sui 2>/dev/null || true
chmod 600 /opt/bot-sui/config.json /opt/bot-sui/nodes.json 2>/dev/null || true
chmod 600 /opt/bot-sui/keys/nodes_ed25519 2>/dev/null || true
chmod 644 /opt/bot-sui/keys/nodes_ed25519.pub 2>/dev/null || true
find /opt/bot-sui/certs -type f -name 'privkey.pem' -exec chmod 600 {} \; 2>/dev/null || true
find /root/cert-CF -type f -name 'privkey.pem' -exec chmod 600 {} \; 2>/dev/null || true

cd /opt/bot-sui
python3 -m venv /opt/bot-sui/venv
/opt/bot-sui/venv/bin/pip install --upgrade pip
if [ -f /opt/bot-sui/requirements.txt ]; then
  /opt/bot-sui/venv/bin/pip install -r /opt/bot-sui/requirements.txt
else
  /opt/bot-sui/venv/bin/pip install aiogram==3.13.1 aiohttp==3.10.5 aiosqlite==0.20.0
fi

/opt/bot-sui/venv/bin/python -m py_compile /opt/bot-sui/bot.py
sqlite3 /opt/bot-sui/database.sqlite 'PRAGMA integrity_check;' || true

systemctl daemon-reload
systemctl enable bot-sui 2>/dev/null || true
systemctl enable nginx 2>/dev/null || true
systemctl restart nginx || true
systemctl restart s-ui 2>/dev/null || systemctl restart sui 2>/dev/null || true
systemctl restart bot-sui

echo ""
echo "Restore finished. Next steps:"
echo "1) Switch DNS to this VPS IP."
echo "2) systemctl status bot-sui s-ui nginx --no-pager"
echo "3) Open Telegram admin -> Проверка production -> Сверка локаций и ссылок."
RESTORE_EOF
chmod 700 "$RESTORE_SH"

# JSON manifest with sha256
python3 - "$STAGE" "$ROOTFS" > "$JSON_MANIFEST" <<'PYEOF'
import hashlib, json, os, sys, time
stage=sys.argv[1]; rootfs=sys.argv[2]
files=[]
for base, _, names in os.walk(rootfs):
    for name in names:
        p=os.path.join(base,name)
        try:
            h=hashlib.sha256()
            with open(p,'rb') as f:
                for chunk in iter(lambda:f.read(1024*1024), b''):
                    h.update(chunk)
            files.append({'path': os.path.relpath(p, stage), 'size': os.path.getsize(p), 'sha256': h.hexdigest()})
        except Exception as e:
            files.append({'path': os.path.relpath(p, stage), 'error': str(e)})
print(json.dumps({'created_at': time.time(), 'files': files}, ensure_ascii=False, indent=2))
PYEOF

tar -C "$STAGE" -czf "$ARCHIVE" MANIFEST.txt MANIFEST.json MIGRATION_REPORT_RU.txt README_RESTORE_RU.md POST_RESTORE_CHECKLIST_RU.md restore_on_new_vps.sh rootfs
sha256sum "$ARCHIVE" > "$ARCHIVE.sha256"
chmod 600 "$ARCHIVE" "$ARCHIVE.sha256"
ARCHIVE_SIZE_HUMAN="$(du -h "$ARCHIVE" | awk '{print $1}')"

echo ""
echo "DONE"
echo "Archive: $ARCHIVE"
echo "Size: $ARCHIVE_SIZE_HUMAN"
echo "SHA256: $(cat "$ARCHIVE.sha256")"
echo ""
echo "Download example from your computer:"
echo "scp root@OLD_MAIN_IP:$ARCHIVE ."
'''


def migration_root_console_guide_text() -> str:
    return '''# Root migration script — инструкция

Этот вариант нужен, когда полноценный restore-drill на отдельном VPS сейчас дорогой/неудобный. Он не заменяет реальный restore-тест на 100%, но делает пакет миграции максимально автономным: архив создаётся root-скриптом, поэтому в него попадают файлы, которые обычный пользователь `bot-sui` может не прочитать.

## 1. На старом main VPS

1. Скачай из Telegram файл `bot-sui-root-migration-create.sh`.
2. Загрузи его на старый main VPS, например в `/root/`.
3. Выполни:

```bash
cd /root
chmod +x bot-sui-root-migration-create.sh
sudo bash ./bot-sui-root-migration-create.sh
```

4. В конце увидишь архив:

```text
/root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz
```

5. Скачай его себе на компьютер:

```bash
scp root@OLD_MAIN_IP:/root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz .
```

## 2. На новом VPS

1. Подними новый чистый Ubuntu VPS.
2. Загрузи архив на новый VPS:

```bash
scp bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz root@NEW_MAIN_IP:/root/
```

3. Зайди на новый VPS:

```bash
ssh root@NEW_MAIN_IP
```

4. Распакуй и запусти restore:

```bash
mkdir -p /root/migration
cd /root/migration
tar -xzf /root/bot-sui-root-migration-YYYYMMDD-HHMMSS.tar.gz
sudo bash restore_on_new_vps.sh
```

5. На вопрос скрипта введи:

```text
RESTORE
```

## 3. После восстановления

1. Переключи DNS на IP нового main VPS.
2. Проверь сервисы:

```bash
sudo systemctl status bot-sui --no-pager
sudo systemctl status s-ui --no-pager || sudo systemctl status sui --no-pager
sudo systemctl status nginx --no-pager
```

3. В Telegram открой:

```text
🛠 Админ → 🩺 Проверка production
🛠 Админ → 🩺 Проверка production → 🔁 Сверка локаций и ссылок
🛠 Админ → 🌍 Локации / VPS-node → 🩺 Проверить все локации
```

4. Если links отличаются — нажми `🔗 Восстановить links`.
5. Если remote sync не прошёл — нажми `🔄 Поставить remote sync` и проверь журнал sync.

## Важно

Архив содержит токены, базы, SSH-ключи и сертификаты. Не отправляй его посторонним и не храни в публичных облаках без шифрования.
'''


@router.callback_query(F.data == "admin:remote:migration_root_script")
async def admin_remote_migration_root_script_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    if not is_admin(callback.from_user.id):
        await callback.answer()
        return
    await state.clear()
    await callback.answer("Готовлю root-скрипт")
    ts = datetime.now().strftime("%Y%m%d-%H%M%S")
    script_path = Path(tempfile.gettempdir()) / f"bot-sui-root-migration-create-{ts}.sh"
    guide_path = Path(tempfile.gettempdir()) / f"ROOT_MIGRATION_GUIDE_RU-{ts}.md"
    script_path.write_text(migration_root_console_script_text(), encoding="utf-8")
    guide_path.write_text(migration_root_console_guide_text(), encoding="utf-8")
    with contextlib.suppress(Exception):
        script_path.chmod(0o700)
    await callback.message.answer_document(
        FSInputFile(str(script_path), filename="bot-sui-root-migration-create.sh"),
        caption=(
            "🧰 Root migration script\n\n"
            "Скачай этот .sh, запусти на текущем main VPS от root. "
            "Он создаст готовый архив `/root/bot-sui-root-migration-*.tar.gz` с restore-скриптом и инструкциями.\n\n"
            "Содержит только код скрипта, секретов внутри отправленного .sh нет. Сам архив после запуска будет содержать секреты."
        ),
    )
    await callback.message.answer_document(
        FSInputFile(str(guide_path), filename="ROOT_MIGRATION_GUIDE_RU.md"),
        caption="📘 Пошаговая инструкция для root migration script.",
    )


@router.callback_query(F.data.startswith("admin:remote:policy:"))
async def admin_remote_policy_toggle_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    global REMOTE_NODES_BLOCK_BITTORRENT, REMOTE_NODES_BLOCK_SMTP, REMOTE_NODES_BLOCK_PRIVATE_IPS
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    key = str(callback.data or "").rsplit(":", 1)[-1]
    if key not in {"block_bittorrent", "block_smtp", "block_private_ips"}:
        await callback.answer("Неизвестная policy", show_alert=True)
        return
    remote_cfg = CONFIG.setdefault("remote_nodes", {})
    current = bool(remote_cfg.get(key, True))
    new_value = not current
    remote_cfg[key] = bool(new_value)
    remote_config_write_current()
    if key == "block_bittorrent":
        REMOTE_NODES_BLOCK_BITTORRENT = bool(new_value)
        label = "BitTorrent drop"
    elif key == "block_smtp":
        REMOTE_NODES_BLOCK_SMTP = bool(new_value)
        label = "SMTP drop"
    else:
        REMOTE_NODES_BLOCK_PRIVATE_IPS = bool(new_value)
        label = "Private IP drop"
    remote_request_sync(reason=f"admin_policy_{key}:{int(callback.from_user.id)}")
    snapshot = await remote_admin_counts()
    text = remote_admin_status_text(snapshot) + f"\n\n✅ Policy обновлена: {label} = {remote_admin_onoff(new_value)}. Remote sync поставлен в очередь."
    await safe_edit_text(callback.message, text, reply_markup=remote_admin_keyboard())


