@router.callback_query(F.data.regexp(r"^admin:remote:clients(:\d+:(all|enabled|disabled))?$"))
async def admin_remote_clients_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    try:
        parts = str(callback.data or "").split(":")
        page = int(parts[3]) if len(parts) >= 4 and parts[3].isdigit() else 0
        filter_mode = parts[4] if len(parts) >= 5 and parts[4] in {"all", "enabled", "disabled"} else "all"
        query = remote_admin_client_search.get(int(callback.from_user.id), "")
        clients = await remote_prepare_clients(await get_all_clients(force_refresh=True))
        all_paid = [c for c in clients if remote_admin_is_paid_like_client(c)]
        filtered = remote_admin_filter_clients(clients, query=query, filter_mode=filter_mode)
        total_pages = max(1, (len(filtered) + REMOTE_ADMIN_CLIENTS_PAGE_SIZE - 1) // REMOTE_ADMIN_CLIENTS_PAGE_SIZE)
        page = min(max(0, page), total_pages - 1)
        await safe_edit_text(
            callback.message,
            remote_admin_clients_text(filtered, all_count=len(all_paid), page=page, filter_mode=filter_mode, query=query),
            reply_markup=remote_admin_clients_keyboard(filtered, page=page, filter_mode=filter_mode, query=query),
        )
    except Exception as exc:
        await safe_edit_text(callback.message, "❌ Не удалось получить remote clients.\n\n" + str(exc)[:1000], reply_markup=remote_admin_keyboard())


