@router.callback_query(F.data.startswith("admin:remote:node_toggle:"))
async def admin_remote_node_toggle_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    if not is_admin(callback.from_user.id):
        await callback.answer()
        return
    await state.clear()
    try:
        parts = str(callback.data or "").split(":")
        node_id = parts[3]
        field = parts[4]
        if field == "include_in_trial":
            await callback.answer("Trial-node режим скрыт: тестовые подписки сейчас main-only.", show_alert=True)
            return
        nodes_cfg = remote_load_nodes_config()
        if not nodes_cfg:
            raise RuntimeError("nodes.json недоступен")
        node = remote_admin_get_node(nodes_cfg, node_id)
        if not node:
            raise RuntimeError("Node не найдена")
        new_value = not bool(node.get(field, False if field in {"enabled", "maintenance", "include_in_trial", "drain"} else True))
        await remote_admin_update_node_field(node_id, field, new_value)
        await callback.answer("Изменено, sync поставлен в очередь")
        nodes_cfg = remote_load_nodes_config()
        node = remote_admin_get_node(nodes_cfg or {}, node_id)
        node_state = (await remote_load_node_state()).get(node_id) or {}
        await safe_edit_text(callback.message, remote_admin_node_detail_text(node, node_state), reply_markup=remote_admin_node_keyboard(node))
    except Exception as exc:
        await callback.answer("Ошибка", show_alert=True)
        await safe_edit_text(callback.message, "❌ Не удалось изменить node.\n\n" + str(exc)[:1000], reply_markup=remote_admin_keyboard())


