@router.callback_query(F.data.startswith("admin:remote:tgproxy_ver:"))
async def admin_remote_tgproxy_version_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    parts = str(callback.data or "").split(":")
