@router.message(AdminStates.waiting_remote_tgproxy_domain)
async def admin_remote_tgproxy_domain_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    node_id = str(data.get("remote_tgproxy_node_id") or "")
    nodes_cfg = remote_load_nodes_config()
    node = remote_admin_get_node(nodes_cfg or {}, node_id)
    if not node:
        await state.clear()
        await message.answer("Node не найдена.", reply_markup=remote_admin_keyboard())
        return
    raw = (message.text or "").strip()
    try:
        if raw in {"-", "—"}:
            default_domain = tgproxy_default_domain_for_node(node)
            if not default_domain:
                raise ValueError("У node нет domain. Отправьте домен/SNI вручную.")
            domain = validate_tgproxy_domain(default_domain)
        else:
            domain = validate_tgproxy_domain(raw)
    except Exception as exc:
        await message.answer("❌ Некорректный домен/SNI.\n\n" + str(exc)[:500], reply_markup=remote_tgproxy_back_keyboard(node_id))
        return
    await state.set_state(AdminStates.waiting_remote_tgproxy_port)
    await state.update_data(remote_tgproxy_node_id=node_id, remote_tgproxy_domain=domain)
    await message.answer(remote_tgproxy_port_prompt_text(node_id, domain), reply_markup=remote_tgproxy_back_keyboard(node_id))


@router.message(AdminStates.waiting_remote_tgproxy_port)
async def admin_remote_tgproxy_port_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    node_id = str(data.get("remote_tgproxy_node_id") or "")
    domain = str(data.get("remote_tgproxy_domain") or "")
    mtg_version = str(data.get("remote_tgproxy_mtg_version") or TELEGRAM_PROXY_MTG_VERSION)
    raw = (message.text or "").strip()
    try:
        port = TELEGRAM_PROXY_DEFAULT_PORT if raw in {"", "-", "—"} else validate_tgproxy_port(raw)
        domain = validate_tgproxy_domain(domain)
    except Exception as exc:
        await message.answer("❌ Некорректный порт.\n\n" + str(exc)[:500], reply_markup=remote_tgproxy_back_keyboard(node_id))
        return
    await state.clear()
    await message.answer(
        f"⏳ Устанавливаю TG PROXY на node {node_id}.\n\nДомен/SNI: {domain}\nПорт: {port}/tcp\nВерсия mtg: {mtg_version_label(mtg_version)}",
        reply_markup=remote_tgproxy_back_keyboard(node_id),
    )
    try:
        result = await remote_tgproxy_install_for_node(node_id, domain=domain, port=port, mtg_version=mtg_version)
        nodes_cfg = remote_load_nodes_config()
        node = remote_admin_get_node(nodes_cfg or {}, node_id)
        row = await get_managed_telegram_proxy_by_node(node_id, include_disabled=True)
        text = (
            "✅ TG PROXY установлен и добавлен в раздел 💎 Telegram proxy.\n\n"
            f"Название: {result['title']}\n"
            f"Домен/SNI: {result['domain']}\n"
            f"Порт: {result['port']}/tcp\n\n"
            + remote_tgproxy_management_text(node, row)
        )
        await message.answer(text, reply_markup=remote_tgproxy_management_keyboard(node_id))
    except Exception as exc:
        await message.answer("❌ Не удалось установить TG PROXY.\n\n" + str(exc)[:1500], reply_markup=remote_tgproxy_back_keyboard(node_id))


