@router.callback_query(F.data.startswith("admin:remote:nodes_export"))
async def admin_remote_nodes_export_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    try:
        page = 0
        parts = str(callback.data or "").split(":")
        if parts and parts[-1].isdigit():
            page = max(0, int(parts[-1]))

        nodes_cfg = remote_load_nodes_config()
        raw = remote_admin_redacted_nodes_json(nodes_cfg)

        chunk_size = 2700
        chunks = [raw[i:i + chunk_size] for i in range(0, len(raw), chunk_size)] or ["{}"]
        total = len(chunks)
        page = min(page, total - 1)
        body = chunks[page]

        text = (
            "📦 nodes.json без паролей\n"
            f"Страница {page + 1}/{total}. Пароли скрыты как ***hidden***.\n\n"
            "```json\n" + body + "\n```"
        )

        rows = []
        nav = []
        if page > 0:
            nav.append(InlineKeyboardButton(text="← Назад", callback_data=f"admin:remote:nodes_export:{page - 1}"))
        if page + 1 < total:
            nav.append(InlineKeyboardButton(text="Вперёд →", callback_data=f"admin:remote:nodes_export:{page + 1}"))
        if nav:
            rows.append(nav)
        rows.append([InlineKeyboardButton(text="← К nodes", callback_data="admin:remote:nodes")])
        await safe_edit_text(callback.message, text, reply_markup=InlineKeyboardMarkup(inline_keyboard=rows))
    except Exception as exc:
        await safe_edit_text(callback.message, "❌ Не удалось показать nodes.json.\n\n" + str(exc)[:1200], reply_markup=remote_admin_keyboard())



