@router.callback_query(F.data.startswith("admin:remote:node_full_cleanup_do:"))
async def admin_remote_node_full_cleanup_do_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    if not is_admin(callback.from_user.id):
        await callback.answer()
        return
    await state.clear()
    node_id = str(callback.data or "").rsplit(":", 1)[-1]
    await callback.answer("Очищаю node")
    try:
        nodes_cfg = remote_load_nodes_config()
        if not nodes_cfg:
            raise RuntimeError("nodes.json недоступен")
        node = remote_admin_get_node(nodes_cfg, node_id)
        if not node:
            raise RuntimeError("Node не найдена")
        await safe_edit_text(callback.message, f"⏳ Очищаю node {node_id}...", reply_markup=remote_admin_node_full_cleanup_keyboard(node_id))
        script = remote_full_cleanup_node_script(node)
        result = await asyncio.to_thread(remote_ssh_run, nodes_cfg, node, "bash -s", input_text=script, timeout=180, check=False)
        if int(getattr(result, "returncode", 1) or 0) != 0:
            raise RuntimeError(f"cleanup ssh rc={result.returncode}\nSTDOUT:\n{result.stdout[-1200:]}\nSTDERR:\n{result.stderr[-1200:]}")
        remote_admin_mark_node_after_full_cleanup(nodes_cfg, node)
        await remote_admin_remove_node_state(node_id)
        node = remote_admin_get_node(nodes_cfg, node_id)
        await remote_admin_mark_node_state_after_full_cleanup(node_id, node)
        await disable_managed_telegram_proxy(node_id, error="node full cleanup")
        remote_request_sync(reason=f"admin_node_full_cleanup:{node_id}")
        node = remote_admin_get_node(nodes_cfg, node_id)
        node_state = (await remote_load_node_state()).get(node_id) or {}
        await safe_edit_text(
            callback.message,
            "✅ VPS очищена. SSH-доступ сохранён. VPS выключена, переведена в обслуживание/drain и требует bootstrap. Теперь можно снова запустить 🚀 Подготовить VPS (bootstrap).\n\n" +
            "Вывод очистки:\n" + str(result.stdout or "")[-1000:] + "\n\n" + remote_admin_node_detail_text(node, node_state),
            reply_markup=remote_admin_node_keyboard(node),
        )
    except Exception as exc:
        await callback.answer("Ошибка", show_alert=True)
        await safe_edit_text(callback.message, "❌ Очистка node не выполнена.\n\n" + str(exc)[:1800], reply_markup=remote_admin_keyboard())

