@router.callback_query(F.data == "admin:cleanup_orphans")
async def admin_cleanup_orphans_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    await state.clear()
    await safe_edit_text(callback.message, "🧹 Очистка хвостов\n\nСобираю preview по S-UI, SQLite и node...", reply_markup=production_tools_keyboard())
    try:
        plan = await production_cleanup_build_plan()
        token = secrets.token_urlsafe(8)
        production_cleanup_runtime_plans[token] = plan
        if len(production_cleanup_runtime_plans) > 20:
            for k in list(production_cleanup_runtime_plans.keys())[:-20]:
                production_cleanup_runtime_plans.pop(k, None)
        data = production_cleanup_plan_data(plan)
        total_rows = int(data.get("total_rows") or 0)
        detail_token, detail_pages = production_store_report(
            title="📄 Списки очистки хвостов",
            summary=data.get("summary", ""),
            sections=data.get("sections") or [],
            back_callback="admin:production_doctor",
        )
        await safe_edit_text(callback.message, data.get("summary", ""), reply_markup=cleanup_preview_keyboard(token, total_rows, detail_token, detail_pages))
    except Exception as exc:
        logging.exception("cleanup preview failed: %s", exc)
        await safe_edit_text(callback.message, "❌ Preview очистки хвостов не выполнен.\n\n" + str(exc)[:1800], reply_markup=production_tools_keyboard())


@router.callback_query(F.data.startswith("admin:cleanup_orphans_apply:"))
async def admin_cleanup_orphans_apply_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    token = callback.data.rsplit(":", 1)[-1]
    plan = production_cleanup_runtime_plans.get(token)
    if not plan:
        await safe_edit_text(callback.message, "❌ План очистки устарел. Открой preview заново.", reply_markup=production_tools_keyboard())
        return
    await safe_edit_text(callback.message, "🧹 Применяю очистку хвостов...", reply_markup=production_tools_keyboard())
    try:
        result = await production_cleanup_apply(plan)
        production_cleanup_runtime_plans.pop(token, None)
        data = production_cleanup_plan_data(plan, applied=True, result=result)
        detail_token, detail_pages = production_store_report(
            title="📄 Списки применённой очистки хвостов",
            summary=data.get("summary", ""),
            sections=data.get("sections") or [],
            back_callback="admin:production_doctor",
        )
        await safe_edit_text(callback.message, data.get("summary", ""), reply_markup=production_tools_keyboard_with_details(detail_token, detail_pages, "📄 Детали очистки"))
    except Exception as exc:
        logging.exception("cleanup apply failed: %s", exc)
        await safe_edit_text(callback.message, "❌ Очистка не применена полностью.\n\n" + str(exc)[:1800], reply_markup=production_tools_keyboard())



@router.callback_query(F.data.startswith("admin:prod_report:"))
async def admin_production_report_page_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    parts = str(callback.data or "").split(":")
    if len(parts) < 4:
        await safe_edit_text(callback.message, "❌ Страница отчёта не найдена.", reply_markup=production_tools_keyboard())
        return
    token = parts[2]
    try:
        page = int(parts[3])
    except Exception:
        page = 0
    report = production_report_runtime_pages.get(token)
    if not report:
        await safe_edit_text(callback.message, "❌ Детали отчёта устарели. Запусти проверку заново.", reply_markup=production_tools_keyboard())
        return
    text, safe_page, total_pages = production_report_page_data(report, page)
    await safe_edit_text(callback.message, text, reply_markup=production_report_page_keyboard(token, safe_page, total_pages, str(report.get("back_callback") or "admin:production_doctor")))


