@router.message(AdminStates.waiting_server_code_migration)
async def admin_server_code_migration_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear(); return
    raw = str(message.text or "").strip()
    if raw in {"-", "отмена", "cancel"}:
        await state.clear(); await message.answer("Отменено.", reply_markup=admin_subpage_keyboard()); return
    parts = raw.split()
    if len(parts) != 2:
        await message.answer("Нужно отправить ровно два значения: OLD NEW. Например: MAIN OriginalVPN"); return
    try:
        plan = await server_code_migration_build_plan(parts[0], parts[1])
        token = secrets.token_urlsafe(8)
        server_code_migration_runtime_plans[token] = plan
        if len(server_code_migration_runtime_plans) > 20:
            for k in list(server_code_migration_runtime_plans.keys())[:-20]:
                server_code_migration_runtime_plans.pop(k, None)
        kb = InlineKeyboardMarkup(inline_keyboard=[[InlineKeyboardButton(text="✅ Применить миграцию", callback_data=f"admin:server_code_migration_apply:{token}")], [InlineKeyboardButton(text="← К проверке production", callback_data="admin:production_doctor")]])
        await state.clear()
        await message.answer(server_code_migration_plan_text(plan), reply_markup=kb)
    except Exception as exc:
        await message.answer("❌ Не удалось подготовить миграцию.\n\n" + str(exc)[:1500])


@router.callback_query(F.data.startswith("admin:server_code_migration_apply:"))
async def admin_server_code_migration_apply_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    token = callback.data.rsplit(":", 1)[-1]
    plan = server_code_migration_runtime_plans.get(token)
    if not plan:
        await safe_edit_text(callback.message, "❌ План миграции устарел. Открой миграцию заново.", reply_markup=production_tools_keyboard()); return
    await safe_edit_text(callback.message, "🧬 Применяю миграцию server_code...", reply_markup=production_tools_keyboard())
    try:
        result = await server_code_migration_apply(plan)
        text = server_code_migration_plan_text(plan, applied=True) + "\n\n" + f"S-UI updated: {result.get('sui_updated')}\nDB renamed: {result.get('renamed')}\nRemote sync: {'queued' if (result.get('remote_sync') or {}).get('queued') else 'not queued'}"
        server_code_migration_runtime_plans.pop(token, None)
        await safe_edit_text(callback.message, text, reply_markup=production_tools_keyboard())
    except Exception as exc:
        logging.exception("server_code migration apply failed: %s", exc)
        await safe_edit_text(callback.message, "❌ Миграция не применена полностью.\n\n" + str(exc)[:1800], reply_markup=production_tools_keyboard())


