@router.message(AdminStates.waiting_block_user)
async def admin_block_user_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    raw = (message.text or "").strip()
    if not raw:
        await message.answer("Отправьте TGID или @username.", reply_markup=admin_subpage_keyboard())
        return

    found = await find_user_for_direct_message(raw)
    if found:
        target_user_id = int(found["user_id"])
        target_username = str(found.get("username") or "")
    elif raw.isdigit():
        target_user_id = int(raw)
        target_username = ""
    else:
        await message.answer("Пользователь не найден. Можно отправить точный TGID.", reply_markup=admin_subpage_keyboard())
        return

    if is_admin(target_user_id):
        await message.answer("Админа нельзя заблокировать через этот раздел.", reply_markup=admin_subpage_keyboard())
        return

    await state.update_data(block_user_id=target_user_id, block_username=target_username)
    await state.set_state(AdminStates.waiting_block_reason)
    await message.answer(admin_block_reason_prompt_text(target_user_id, target_username), reply_markup=admin_subpage_keyboard())


@router.message(AdminStates.waiting_block_reason)
async def admin_block_reason_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    target_user_id = int(data.get("block_user_id") or 0)
    target_username = str(data.get("block_username") or "")
    if not target_user_id:
        await state.clear()
        await message.answer("Цель блокировки потеряна. Начните заново.", reply_markup=admin_subpage_keyboard())
        return
    reason = (message.text or "").strip()
    if reason == "-":
        reason = ""
    try:
        await block_bot_user(target_user_id, target_username, int(message.from_user.id), reason)
    except Exception as exc:
        await state.clear()
        await message.answer("❌ Не удалось заблокировать пользователя.\n\n" + str(exc)[:500], reply_markup=admin_subpage_keyboard())
        return
    await state.clear()
    row = await get_user_block(target_user_id)
    await message.answer(admin_block_detail_text(row), reply_markup=admin_block_detail_keyboard(target_user_id, True))


