@router.callback_query(F.data.startswith("admin:payments:"))
async def admin_payments_sub_callback(callback: types.CallbackQuery, state: FSMContext) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return

    data = callback.data

    if data.startswith("admin:payments:list:"):
        parts = data.split(":")
        status_filter = parts[3] if len(parts) >= 4 else "all"
        page = int(parts[4]) if len(parts) >= 5 and parts[4].isdigit() else 0
        total = await count_admin_payments_filtered(status_filter)
        page = clamp_page(page, total, ADMIN_PAYMENTS_PAGE_SIZE)
        rows = await list_admin_payments_filtered(status_filter, limit=ADMIN_PAYMENTS_PAGE_SIZE, offset=page * ADMIN_PAYMENTS_PAGE_SIZE)
        await safe_edit_text(
            callback.message,
            admin_payments_text(status_filter, page=page, total=total),
            reply_markup=admin_payments_keyboard(rows, status_filter, page=page, total=total),
        )
        return

    if data == "admin:payments:search":
        await state.clear()
        await state.set_state(AdminStates.waiting_payment_search)
        await safe_edit_text(
            callback.message,
            admin_payment_search_prompt_text(),
            reply_markup=admin_payment_search_prompt_keyboard(),
        )
        return

    if data in (
        "admin:payments:success",
        "admin:payments:pending",
        "admin:payments:failed",
        "admin:payments:platega",
        "admin:payments:stars",
        "admin:payments:platega_pending",
        "admin:payments:apply_failed",
    ):
        status_filter = data.split(":")[-1]
        total = await count_admin_payments_filtered(status_filter)
        page = clamp_page(0, total, ADMIN_PAYMENTS_PAGE_SIZE)
        rows = await list_admin_payments_filtered(status_filter, limit=ADMIN_PAYMENTS_PAGE_SIZE, offset=page * ADMIN_PAYMENTS_PAGE_SIZE)
        await safe_edit_text(
            callback.message,
            admin_payments_text(status_filter, page=page, total=total),
            reply_markup=admin_payments_keyboard(rows, status_filter, page=page, total=total),
        )
        return


    if data.startswith("admin:payments:events:"):
        payment_id = int(data.split(":")[-1])
        row = await get_payment(payment_id)
        if not row:
            await safe_edit_text(callback.message, "Платёж не найден.", reply_markup=admin_subpage_keyboard())
            return
        events = await list_payment_events(payment_id, limit=30)
        await safe_edit_text(
            callback.message,
            admin_payment_events_text(row, events),
            reply_markup=InlineKeyboardMarkup(inline_keyboard=[
                [InlineKeyboardButton(text="🔄 Обновить события", callback_data=f"admin:payments:events:{payment_id}")],
                [InlineKeyboardButton(text="← К платежу", callback_data=f"admin:payments:view:{payment_id}")],
            ]),
        )
        return

    if data.startswith("admin:payments:platega_check:"):
        payment_id = int(data.split(":")[-1])
        row = await get_payment(payment_id)
        if not row:
            await safe_edit_text(callback.message, "Платёж не найден.", reply_markup=admin_subpage_keyboard())
            return
        if str(row["provider"] or "") != "platega":
            await safe_edit_text(
                callback.message,
                "Это не Platega-платёж.\n\n" + admin_payment_detail_text(row, tariff_title_or_key(str(row["tarif_key"]))),
                reply_markup=admin_payment_detail_keyboard(row),
            )
            return
        try:
            result, message_text = await platega_check_and_apply_payment(callback.bot, row, source="platega_admin_check")
            updated = await get_payment(payment_id) or row
            prefix = f"Результат проверки Platega: {result}\n{message_text}\n\n"
        except Exception as exc:
            updated = await get_payment(payment_id) or row
            await log_payment_event(
                payment_id,
                "provider_status_error",
                actor_type="admin",
                actor_id=int(callback.from_user.id),
                payment_method="platega",
                details={"source": "platega_admin_check", "error": str(exc)[:700]},
            )
            prefix = "❌ Ошибка проверки Platega:\n" + str(exc)[:700] + "\n\n"
        await safe_edit_text(
            callback.message,
            prefix + admin_payment_detail_text(updated, tariff_title_or_key(str(updated["tarif_key"]))),
            reply_markup=admin_payment_detail_keyboard(updated),
        )
        return

    if data.startswith("admin:payments:view:"):
        payment_id = int(data.split(":")[-1])
        row = await get_payment(payment_id)
        if not row:
            await safe_edit_text(callback.message, "Платёж не найден.", reply_markup=admin_subpage_keyboard())
            return
        await safe_edit_text(
            callback.message,
            admin_payment_detail_text(row, tariff_title_or_key(str(row["tarif_key"]))),
            reply_markup=admin_payment_detail_keyboard(row),
        )
        return

    if data.startswith("admin:payments:approve:"):
        payment_id = int(data.split(":")[-1])
        row = await get_payment(payment_id)
        if not row:
            await safe_edit_text(callback.message, "Платёж не найден.", reply_markup=admin_subpage_keyboard())
            return
        row_status = str(row["status"] or "")
        row_app_status = str(row["application_status"] or "")
        if row_status != "pending" and not (row_status == "processing" and row_app_status == "apply_failed"):
            await safe_edit_text(
                callback.message,
                admin_payment_detail_text(row, tariff_title_or_key(str(row["tarif_key"]))),
                reply_markup=admin_payment_detail_keyboard(row),
            )
            return
        try:
            result_text = await apply_payment_without_payment(callback.bot, row, int(callback.from_user.id))
        except Exception as exc:
            updated = await get_payment(payment_id) or row
            await safe_edit_text(
                callback.message,
                "❌ Не удалось применить платёж без оплаты.\n\n"
                + str(exc)[:700]
                + "\n\n"
                + admin_payment_detail_text(updated, tariff_title_or_key(str(updated["tarif_key"]))),
                reply_markup=admin_payment_detail_keyboard(updated),
            )
            return

        updated = await get_payment(payment_id)
        await safe_edit_text(
            callback.message,
            result_text + "\n\n" + admin_payment_detail_text(updated, tariff_title_or_key(str(updated["tarif_key"]))),
            reply_markup=admin_payment_detail_keyboard(updated),
        )
        return


@router.message(F.text.regexp(r"^(#|№)?\d+$"), AdminStates.waiting_payment_search)
@router.message(AdminStates.waiting_payment_search)
async def admin_payment_search_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return

    query = (message.text or "").strip()
    if not query:
        await message.answer("Введите #payment_id или TGID.", reply_markup=admin_payment_search_prompt_keyboard())
        return

    rows = await search_admin_payments(query)
    await state.clear()
    if not rows:
        await message.answer("Ничего не найдено.", reply_markup=admin_subpage_keyboard())
        return

    await message.answer(
        f"🔎 Результаты поиска платежей\n\nЗапрос: {query}",
        reply_markup=admin_payments_keyboard(rows, "all"),
    )


