@router.callback_query(F.data.startswith("admin:trial:nodes_toggle:"))
async def admin_trial_nodes_toggle_callback(callback: types.CallbackQuery) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    node_id = callback.data.split(":")[-1]
    current = trial_remote_node_scope_ids()
    if current is None:
        try:
            nodes_cfg = remote_load_nodes_config()
            current = {str(n.get("id") or "").strip() for n in remote_admin_nodes_all(nodes_cfg or {}) if str(n.get("id") or "").strip()}
        except Exception:
            current = set()
    else:
        current = set(current)
    if node_id in current:
        current.remove(node_id)
    else:
        current.add(node_id)
    new_scope = normalize_remote_node_scope_value(sorted(current)) if current else "none"
    await set_app_setting("trial_remote_node_scope", new_scope)
    queue_trial_node_scope_sync()
    await safe_edit_text(callback.message, trial_node_scope_menu_text() + "\n\n✅ Сохранено. Remote sync поставлен в очередь.", reply_markup=trial_node_scope_keyboard())


