@router.message(AdminStates.waiting_trial_setting)
async def admin_trial_setting_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    field_name = str(data.get("trial_field") or "")
    raw = (message.text or "").strip()
    try:
        if field_name == "trial_sui_inbounds":
            normalized = normalize_sui_inbounds_input(raw)
            await set_app_setting("trial_sui_inbounds", normalized)
        else:
            value = int(raw)
            if field_name in {"trial_days", "trial_gb"} and value <= 0:
                raise ValueError("Значение должно быть больше 0.")
            if field_name == "trial_cooldown_days" and value < 0:
                raise ValueError("Cooldown не может быть отрицательным.")
            if field_name not in {"trial_days", "trial_gb", "trial_cooldown_days"}:
                raise ValueError("Неизвестное поле настройки.")
            await set_trial_setting_int(field_name, value)
    except Exception as exc:
        await message.answer("❌ Не удалось сохранить настройку.\n\n" + str(exc)[:500], reply_markup=admin_trial_edit_prompt_keyboard())
        return
    await state.clear()
    await message.answer("✅ Настройка сохранена.\n\n" + admin_trial_settings_text(), reply_markup=admin_trial_settings_keyboard())


