@router.message(AdminStates.waiting_welcome_text_template)
async def admin_welcome_text_template_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    raw = str(message.text or "").strip()
    if not raw:
        await message.answer("Отправьте текст сообщением или нажмите «Отменить».", reply_markup=admin_welcome_prompt_keyboard())
        return
    if raw in {"-", "—", "reset", "сброс"}:
        await reset_welcome_text_template()
        await state.clear()
        await message.answer("✅ Приветствие сброшено на стандартный текст.", reply_markup=admin_welcome_settings_keyboard())
        return
    if len(raw) > 3000:
        await message.answer("Слишком длинный текст. Сократите до 3000 символов.", reply_markup=admin_welcome_prompt_keyboard())
        return
    await set_welcome_text_template(raw)
    await state.clear()
    note = ""
    if "{locations}" not in raw:
        note = "\n\n⚠️ В тексте нет {locations}, поэтому список локаций в /start не будет показан."
    await message.answer("✅ Приветствие сохранено." + note + "\n\n" + admin_welcome_settings_text(), reply_markup=admin_welcome_settings_keyboard())


