@router.callback_query(F.data.regexp(r"^admin:monitoring(?::(refresh))?(?::([a-z_]+))?(?::(24h|7d|30d))?$"))
async def admin_monitoring_callback(callback: types.CallbackQuery) -> None:
    raw = str(callback.data or "")
    parts = raw.split(":")
    force_refresh = "refresh" in parts
    section = "summary"
    period = "24h"
    for item in parts[2:]:
        if item in {"24h", "7d", "30d"}:
            period = item
        elif item != "refresh":
            section = item
    section = normalize_monitoring_section(section)
    period, _, _ = monitoring_period_info(period)
    await callback.answer("Обновляю" if force_refresh else "")
    if not is_admin(callback.from_user.id):
        return
    text = await build_admin_monitoring_text(force_refresh=force_refresh, section=section, period=period)
    await safe_edit_text(callback.message, text, reply_markup=admin_monitoring_keyboard(section, period))

