@router.callback_query(F.data.startswith("admin:tariff:nodes_toggle:"))
async def admin_tariff_nodes_toggle_callback(callback: types.CallbackQuery) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    parts = callback.data.split(":")
    if len(parts) < 5:
        return
    tariff_key = parts[3]
    node_id = parts[4]
    tariff = get_tariff(tariff_key)
    if not tariff:
        await safe_edit_text(callback.message, "Тариф не найден.", reply_markup=admin_subpage_keyboard())
        return
    current = tariff_remote_node_scope_ids(tariff)
    if current is None:
        try:
            nodes_cfg = remote_load_nodes_config()
            current = {str(n.get("id") or "").strip() for n in remote_admin_nodes_all(nodes_cfg or {}) if str(n.get("id") or "").strip() and bool(n.get("include_in_paid", True))}
        except Exception:
            current = set()
    else:
        current = set(current)
    if node_id in current:
        current.remove(node_id)
    else:
        current.add(node_id)
    new_scope = normalize_remote_node_scope_value(sorted(current)) if current else "none"
    await upsert_tariff_override(tariff_key, remote_node_scope=new_scope)
    await queue_tariff_node_scope_sync(tariff_key)
    tariff = get_tariff(tariff_key)
    await safe_edit_text(callback.message, tariff_node_scope_menu_text(tariff) + "\n\n✅ Сохранено. Remote sync поставлен в очередь.", reply_markup=tariff_node_scope_keyboard(tariff))


