@router.message(AdminStates.waiting_tariff_create)
async def admin_tariff_create_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    step = str(data.get("tariff_create_step") or "key")
    payload = dict(data.get("tariff_create_data") or {})
    raw = (message.text or "").strip()

    try:
        if step == "key":
            key = normalize_tariff_key_input(raw)
            if get_tariff(key) or get_tariff_override(key):
                raise ValueError("Тариф с таким ключом уже существует.")
            payload["key"] = key
            next_step = "title"

        elif step == "title":
            if not raw:
                raise ValueError("Название не может быть пустым.")
            payload["title"] = raw[:128]
            # Production RC: create only a safe draft tariff from key + title.
            # All commercial settings are edited in the convenient tariff card by buttons.
            await create_custom_tariff(
                key=payload["key"],
                title=payload["title"],
                days=30,
                traffic_gb=30,
                stars_price=0,
                rub_price=0,
                rub_payment_enabled=False,
                is_admin_only=True,
                connection_limit=1,
                sui_group="user",
                sui_inbounds="",
                double_vpn_enabled=True,
                double_vpn_reset_days=0,
                stars_purchase_url=None,
                stars_payment_enabled=False,
                show_stars_official=False,
                show_stars_alt=False,
            )
            await upsert_tariff_override(payload["key"], enabled=0, is_admin_only=1, stars_payment_enabled=0, rub_payment_enabled=0, show_stars_official=0, show_stars_alt=0)
            await state.clear()
            tariff = get_tariff(payload["key"])
            await message.answer(
                "✅ Черновик тарифа создан. Он выключен и доступен только админам. Настройте параметры кнопками ниже, затем включите тариф.\n\n" + tariff_admin_detail_text(tariff),
                reply_markup=tariff_admin_detail_keyboard(tariff),
            )
            return

        elif step == "days":
            value = int(raw)
            if value <= 0:
                raise ValueError("Срок должен быть больше 0.")
            payload["days"] = value
            next_step = "traffic_gb"

        elif step == "traffic_gb":
            if raw in ("∞", "inf", "INF", "unlimited", "UNLIMITED"):
                payload["traffic_gb"] = None
            else:
                value = int(raw)
                if value <= 0:
                    raise ValueError("Трафик должен быть > 0 или ∞.")
                payload["traffic_gb"] = value
            next_step = "payment_mode"

        elif step == "payment_mode":
            norm = raw.lower().replace("-", "_").replace("+", "_").replace(" ", "_")
            aliases = {
                "stars": "stars", "star": "stars", "xtr": "stars", "звезды": "stars", "звёзды": "stars",
                "rub": "rub", "ruble": "rub", "rubles": "rub", "rur": "rub", "руб": "rub", "рубли": "rub",
                "stars_rub": "stars_rub", "rub_stars": "stars_rub", "stars_and_rub": "stars_rub", "оба": "stars_rub", "все": "stars_rub",
            }
            mode = aliases.get(norm)
            if mode not in {"stars", "stars_rub", "rub"}:
                raise ValueError("Введите stars, stars_rub или rub.")
            payload["payment_mode"] = mode
            payload["stars_payment_enabled"] = mode in {"stars", "stars_rub"}
            payload["rub_payment_enabled"] = mode in {"rub", "stars_rub"}
            payload["show_stars_official"] = bool(payload["stars_payment_enabled"])
            payload["show_stars_alt"] = bool(payload["stars_payment_enabled"])
            if payload["stars_payment_enabled"]:
                next_step = "stars_price"
            else:
                payload["stars_price"] = 0
                next_step = "rub_price"

        elif step == "stars_price":
            value = int(raw)
            if value <= 0:
                raise ValueError("Цена Stars должна быть больше 0 для тарифа с оплатой Stars.")
            payload["stars_price"] = value
            if payload.get("rub_payment_enabled"):
                next_step = "rub_price"
            else:
                payload["rub_price"] = 0
                next_step = "is_admin_only"

        elif step == "rub_price":
            value = int(raw)
            if payload.get("rub_payment_enabled") and value <= 0:
                raise ValueError("Цена RUB должна быть больше 0 для тарифа с оплатой RUB.")
            if value < 0:
                raise ValueError("Цена RUB должна быть 0 или больше.")
            payload["rub_price"] = value
            next_step = "is_admin_only"

        elif step == "is_admin_only":
            norm = raw.lower()
            if norm in ("public", "публичный", "pub", "0"):
                payload["is_admin_only"] = False
            elif norm in ("admin", "админ", "admin-only", "1"):
                payload["is_admin_only"] = True
            else:
                raise ValueError("Введите public или admin.")
            next_step = "connection_limit"

        elif step == "connection_limit":
            value = int(raw)
            if value <= 0:
                raise ValueError("Лимит должен быть > 0.")
            payload["connection_limit"] = value
            next_step = "double_vpn_enabled"

        elif step == "double_vpn_enabled":
            payload["double_vpn_enabled"] = parse_admin_bool_input(raw)
            next_step = "sui_group"

        elif step == "sui_group":
            payload["sui_group"] = normalize_sui_group_input(raw)
            if payload.get("double_vpn_enabled", True):
                next_step = "sui_inbounds"
            else:
                payload["sui_inbounds"] = ""
                if payload.get("stars_payment_enabled"):
                    next_step = "stars_purchase_url"
                else:
                    payload["stars_purchase_url"] = None
                    payload["show_stars_official"] = False
                    payload["show_stars_alt"] = False
                    await create_custom_tariff(
                        key=payload["key"], title=payload["title"], days=int(payload["days"]), traffic_gb=payload.get("traffic_gb"),
                        stars_price=int(payload.get("stars_price") or 0), rub_price=int(payload.get("rub_price") or 0),
                        rub_payment_enabled=bool(payload.get("rub_payment_enabled", False)), is_admin_only=bool(payload["is_admin_only"]),
                        connection_limit=int(payload["connection_limit"]), sui_group=payload.get("sui_group") or "user", sui_inbounds="", double_vpn_enabled=bool(payload.get("double_vpn_enabled", True)), stars_purchase_url=None,
                        stars_payment_enabled=bool(payload.get("stars_payment_enabled", False)), show_stars_official=False, show_stars_alt=False,
                    )
                    await state.clear()
                    tariff = get_tariff(payload["key"])
                    await message.answer(tariff_admin_detail_text(tariff), reply_markup=tariff_admin_detail_keyboard(tariff))
                    return

        elif step == "sui_inbounds":
            payload["sui_inbounds"] = normalize_sui_inbounds_input(raw)
            if payload.get("stars_payment_enabled"):
                next_step = "stars_purchase_url"
            else:
                payload["stars_purchase_url"] = None
                payload["show_stars_official"] = False
                payload["show_stars_alt"] = False
                await create_custom_tariff(
                    key=payload["key"], title=payload["title"], days=int(payload["days"]), traffic_gb=payload.get("traffic_gb"),
                    stars_price=int(payload.get("stars_price") or 0), rub_price=int(payload.get("rub_price") or 0),
                    rub_payment_enabled=bool(payload.get("rub_payment_enabled", False)), is_admin_only=bool(payload["is_admin_only"]),
                    connection_limit=int(payload["connection_limit"]), sui_group=payload.get("sui_group") or "user", sui_inbounds=payload.get("sui_inbounds") or "", double_vpn_enabled=bool(payload.get("double_vpn_enabled", True)), stars_purchase_url=None,
                    stars_payment_enabled=bool(payload.get("stars_payment_enabled", False)), show_stars_official=False, show_stars_alt=False,
                )
                await state.clear()
                tariff = get_tariff(payload["key"])
                await message.answer(tariff_admin_detail_text(tariff), reply_markup=tariff_admin_detail_keyboard(tariff))
                return

        elif step == "stars_purchase_url":
            normalized_url = normalize_stars_purchase_url(raw)
            if raw and normalized_url is None and not is_resettable_stars_url_input(raw):
                raise ValueError("Некорректная ссылка. Используйте https://..., t.me/... или @botname, либо - для пропуска.")
            payload["stars_purchase_url"] = normalized_url
            next_step = "show_stars_official"

        elif step == "show_stars_official":
            payload["show_stars_official"] = parse_admin_bool_input(raw)
            next_step = "show_stars_alt"

        elif step == "show_stars_alt":
            payload["show_stars_alt"] = parse_admin_bool_input(raw)
            await create_custom_tariff(
                key=payload["key"], title=payload["title"], days=int(payload["days"]), traffic_gb=payload.get("traffic_gb"),
                stars_price=int(payload.get("stars_price") or 0), rub_price=int(payload.get("rub_price") or 0),
                rub_payment_enabled=bool(payload.get("rub_payment_enabled", False)), is_admin_only=bool(payload["is_admin_only"]),
                connection_limit=int(payload["connection_limit"]), sui_group=payload.get("sui_group") or "user", sui_inbounds=payload.get("sui_inbounds") or "", double_vpn_enabled=bool(payload.get("double_vpn_enabled", True)), stars_purchase_url=payload.get("stars_purchase_url"),
                stars_payment_enabled=bool(payload.get("stars_payment_enabled", True)),
                show_stars_official=bool(payload.get("show_stars_official", True)), show_stars_alt=bool(payload.get("show_stars_alt", True)),
            )
            await state.clear()
            tariff = get_tariff(payload["key"])
            await message.answer(tariff_admin_detail_text(tariff), reply_markup=tariff_admin_detail_keyboard(tariff))
            return

        else:
            raise ValueError("Неизвестный шаг создания тарифа.")
    except Exception as exc:
        await message.answer(f"Ошибка: {exc}", reply_markup=tariff_create_prompt_keyboard())
        return

    await state.update_data(tariff_create_step=next_step, tariff_create_data=payload)
    await message.answer(tariff_create_prompt_text(next_step), reply_markup=tariff_create_prompt_keyboard())


@router.message(AdminStates.waiting_tariff_edit)
async def admin_tariff_edit_message(message: types.Message, state: FSMContext) -> None:
    if not is_admin(message.from_user.id):
        await state.clear()
        return
    data = await state.get_data()
    tariff_key = data.get("tariff_key")
    field_name = data.get("field_name")
    if not tariff_key or not field_name:
        await state.clear()
        await message.answer("Сессия редактирования потеряна.", reply_markup=admin_subpage_keyboard())
        return

    raw = (message.text or "").strip()
    patch = {}
    try:
        if field_name == "title":
            if not raw:
                raise ValueError("Название не может быть пустым.")
            patch["title"] = raw[:128]
        elif field_name == "days":
            value = int(raw)
            if value <= 0:
                raise ValueError("Срок должен быть больше 0.")
            patch["days"] = value
        elif field_name == "traffic_gb":
            if raw in ("∞", "inf", "INF", "unlimited", "UNLIMITED"):
                patch["traffic_gb"] = -1
            else:
                value = int(raw)
                if value <= 0:
                    raise ValueError("Трафик должен быть > 0 или ∞.")
                patch["traffic_gb"] = value
        elif field_name == "stars_price":
            value = int(raw)
            if value < 0:
                raise ValueError("Цена Stars должна быть 0 или больше.")
            patch["stars_price"] = value
        elif field_name == "rub_price":
            value = int(raw)
            if value < 0:
                raise ValueError("Цена RUB должна быть 0 или больше.")
            patch["rub_price"] = value
        elif field_name == "rub_payment_enabled":
            patch["rub_payment_enabled"] = 1 if parse_admin_bool_input(raw) else 0
        elif field_name == "connection_limit":
            value = int(raw)
            if value <= 0:
                raise ValueError("Лимит должен быть > 0.")
            patch["connection_limit"] = value
        elif field_name == "sui_group":
            patch["sui_group"] = normalize_sui_group_input(raw)
        elif field_name == "buy_short_text":
            if raw.strip().lower() in {"-", "none", "null", "нет", "clear", "очистить"}:
                patch["buy_short_text"] = ""
            else:
                patch["buy_short_text"] = normalize_tariff_short_text(raw, limit=240)
        elif field_name == "preview_extra_text":
            if raw.strip().lower() in {"-", "none", "null", "нет", "clear", "очистить"}:
                patch["preview_extra_text"] = ""
            else:
                patch["preview_extra_text"] = normalize_tariff_multiline_text(raw, limit=1000)
        elif field_name == "sui_inbounds":
            patch["sui_inbounds"] = normalize_sui_inbounds_input(raw)
        elif field_name == "double_vpn_reset_days":
            norm = raw.strip().lower()
            if norm in ("-", "save", "no", "нет", "off", "0"):
                patch["double_vpn_reset_days"] = 0
            else:
                value = int(raw)
                if value < 0 or value > 3650:
                    raise ValueError("Введите 0 или число дней 1–3650.")
                patch["double_vpn_reset_days"] = value
        elif field_name == "stars_purchase_url":
            normalized_url = normalize_stars_purchase_url(raw)
            if raw and normalized_url is None and not is_resettable_stars_url_input(raw):
                raise ValueError("Некорректная ссылка. Используйте https://..., t.me/... или @botname, либо - для сброса.")
            patch["stars_purchase_url"] = normalized_url
    except Exception as exc:
        await message.answer(f"Ошибка: {exc}", reply_markup=tariff_edit_prompt_keyboard(tariff_key))
        return

    await upsert_tariff_override(tariff_key, **patch)
    apply_result = None
    prefix = ""
    if field_name == "double_vpn_reset_days":
        try:
            apply_result = await apply_tariff_sui_traffic_reset_to_existing(tariff_key)
            prefix = "✅ Режим сброса трафика основного сервера обновлён." + tariff_reset_apply_result_text(apply_result) + "\n\n"
        except Exception as exc:
            logging.exception("tariff reset apply from manual input failed tariff=%s: %s", tariff_key, exc)
            prefix = f"⚠️ Режим в тарифе сохранён, но применение к существующим подпискам завершилось ошибкой: {html.escape(str(exc))}\n\n"
    await state.clear()
    tariff = get_tariff(tariff_key)
    await message.answer(prefix + tariff_admin_detail_text(tariff), reply_markup=tariff_admin_detail_keyboard(tariff))


@router.message(Command("antiabuse_status"))
async def antiabuse_status_command(message: types.Message) -> None:
    if not is_admin(message.from_user.id):
        return
    cases = await antiabuse_build_cases(force_refresh=True)
    suspicious = [x for x in cases if x["suspicious"]]
    async with db_connect(ANTIABUSE_DB) as conn:
        conn.row_factory = aiosqlite.Row
        async with conn.execute("SELECT COUNT(*) AS c FROM raw_events") as cur:
            raw_row = await cur.fetchone()
        async with conn.execute("SELECT COUNT(*) AS c FROM matches") as cur:
            match_row = await cur.fetchone()
    lines = [
        "🛡 Antiabuse статус",
        "",
        f"Включён: {'да' if ANTIABUSE_ENABLED else 'нет'}",
        f"Базовый лимит за {ANTIABUSE_WINDOW_MINUTES} мин.: {ANTIABUSE_IP_LIMIT}",
        f"Уведомлять пользователя: {'да' if ANTIABUSE_NOTIFY_USER else 'нет'}",
        f"Raw events: {int(raw_row['c'] or 0) if raw_row else 0}",
        f"Matches: {int(match_row['c'] or 0) if match_row else 0}",
    ]
    if suspicious:
        lines += ["", "Подозрительные подписки:"]
        for item in suspicious[:20]:
            lines.append(f"• {item['name']} — {item['unique_window']} уникальных (лимит {item['limit_value']})")
    else:
        lines += ["", "Сейчас подозрительных подписок нет."]
    await message.answer("\n".join(lines))



