@router.callback_query(F.data.startswith("admin:remote:node_ab_diag:"))
async def remote_node_antiabuse_diag_callback(callback: types.CallbackQuery) -> None:
    await callback.answer("Готовлю TXT диагностику…")
    if not is_admin(callback.from_user.id):
        return
    node_id = str(callback.data or "").split(":", 3)[3]
    nodes_cfg = remote_load_nodes_config()
    node = remote_admin_get_node(nodes_cfg or {}, node_id)
    if not nodes_cfg or not node:
        await safe_edit_text(callback.message, "Node не найдена.", reply_markup=remote_admin_nodes_keyboard(nodes_cfg or {}))
        return
    try:
        cmd = "journalctl -u sing-box -o short-iso-precise -n 600 --no-pager"
        p = await asyncio.to_thread(remote_ssh_run, nodes_cfg, node, cmd, timeout=30, check=False)
        log_text = str(p.stdout or "")
        summary, full = remote_antiabuse_parse_diagnostics(log_text)
        with tempfile.NamedTemporaryFile("w", encoding="utf-8", suffix=f"_remote_antiabuse_{node_id}.txt", delete=False) as f:
            f.write(full)
            tmp_name = f.name
        try:
            await callback.message.answer_document(
                FSInputFile(tmp_name, filename=f"remote_antiabuse_diagnostics_{node_id}_{datetime.now().strftime('%Y%m%d_%H%M%S')}.txt"),
                caption=f"🛡 Диагностика antiabuse node {node_id}\n\n" + summary[:800],
            )
        finally:
            with contextlib.suppress(Exception):
                os.unlink(tmp_name)
        await safe_edit_text(callback.message, remote_admin_node_detail_text(node, (await remote_load_node_state()).get(node_id) or {}), reply_markup=remote_admin_node_keyboard(node))
    except Exception as exc:
        await safe_edit_text(callback.message, "❌ Диагностика не выполнена.\n\n" + str(exc)[:1000], reply_markup=remote_admin_node_keyboard(node))


