@router.callback_query(F.data.startswith("antiabuse:profile:"))
async def antiabuse_profile_callback(callback: types.CallbackQuery) -> None:
    await callback.answer()
    if not is_admin(callback.from_user.id):
        return
    parts = str(callback.data or "").split(":")
    try:
        case_id = int(parts[2])
        mode = parts[3] if len(parts) > 3 else "suspicious"
    except Exception:
        await safe_edit_text(callback.message, "Некорректный callback профиля.", reply_markup=admin_subpage_keyboard())
        return
    case = await antiabuse_get_case_by_id(case_id)
    if not case or not case["name"]:
        await safe_edit_text(callback.message, "Кейс antiabuse не найден.", reply_markup=admin_subpage_keyboard())
        return
    meta = await antiabuse_get_client_meta(str(case["name"]))
    tgid = extract_tgid_from_client(meta or {}) if meta else None
    if tgid is None:
        # Try remote meta fallback for node-only cases.
        rmeta = await remote_antiabuse_get_client_meta(str(case["name"]))
        try:
            tgid = int(rmeta.get("tgid") or 0) if rmeta else None
        except Exception:
            tgid = None
    if not tgid:
        await safe_edit_text(
            callback.message,
            "👤 Профиль пользователя недоступен: TGID не найден для этого кейса.",
            reply_markup=antiabuse_detail_keyboard(case_id, mode),
        )
        return
    stats = await get_user_profile_stats(int(tgid))
    try:
        subs = await get_user_subscriptions(int(tgid))
    except Exception:
        subs = []
    active_subscriptions = len([x for x in subs if int(x.get("days_left") or 0) > 0])
    latest_plans = []
    for item in subs[:5]:
        plan = subscription_display_title(item)
        if plan not in latest_plans:
            latest_plans.append(plan)
    text = admin_user_profile_text(
        user_id=int(tgid),
        username=stats.get("username", "—"),
        payments_total=stats["payments_total"],
        payments_success=stats["payments_success"],
        tickets_total=stats["tickets_total"],
        active_subscriptions=active_subscriptions,
        latest_plans=latest_plans,
        referral_stats=await referral_stats_for_user(int(tgid)),
        block_row=await get_user_block(int(tgid)),
    )
    block_row = await get_user_block(int(tgid))
    block_button = InlineKeyboardButton(
        text=("✅ Разблокировать в боте" if block_row and int(block_row["is_active"] or 0) == 1 else "🚫 Заблокировать в боте"),
        callback_data=(f"admin:blocks:unblock:{int(tgid)}" if block_row and int(block_row["is_active"] or 0) == 1 else f"admin:blocks:block:{int(tgid)}"),
    )
    await safe_edit_text(
        callback.message,
        text,
        reply_markup=InlineKeyboardMarkup(inline_keyboard=[[block_button], [InlineKeyboardButton(text="← К antiabuse кейсу", callback_data=f"antiabuse:view:{case_id}:{mode}")]]),
    )


