# =========================
# STORAGE AUTONOMY WATCHDOG
# =========================

def _path_size_bytes_sync(path: Path) -> int:
    try:
        if not path.exists():
            return 0
        if path.is_file():
            return int(path.stat().st_size)
        total = 0
        for root, dirs, files in os.walk(path):
            for filename in files:
                full = Path(root) / filename
                try:
                    total += int(full.stat().st_size)
                except OSError:
                    continue
        return total
    except Exception:
        return 0


def _free_space_mb_sync(path: Path) -> int:
    try:
        target = path if path.exists() else path.parent
        st = os.statvfs(str(target))
        return int((st.f_bavail * st.f_frsize) / (1024 * 1024))
    except Exception:
        return -1


def _human_mb(value: int | float) -> str:
    try:
        mb = float(value)
    except Exception:
        mb = 0.0
    if mb >= 1024:
        return f"{mb / 1024:.2f} ГБ"
    return f"{mb:.0f} МБ"


async def storage_autonomy_metrics() -> dict:
    backups_dir = BASE_DIR / "backups"
    incident_dir = BASE_DIR / "incident_logs"
    db_size, backups_size, logs_size, incident_size, free_mb = await asyncio.gather(
        asyncio.to_thread(_path_size_bytes_sync, DATABASE_DB),
        asyncio.to_thread(_path_size_bytes_sync, backups_dir),
        asyncio.to_thread(_path_size_bytes_sync, LOG_DIR),
        asyncio.to_thread(_path_size_bytes_sync, incident_dir),
        asyncio.to_thread(_free_space_mb_sync, BASE_DIR),
    )
    return {
        "db_mb": round(db_size / (1024 * 1024), 2),
        "backups_mb": round(backups_size / (1024 * 1024), 2),
        "logs_mb": round(logs_size / (1024 * 1024), 2),
        "incident_mb": round(incident_size / (1024 * 1024), 2),
        "free_mb": int(free_mb),
    }


def storage_autonomy_should_alert(key: str) -> bool:
    now_ts = time.time()
    cooldown = AUTONOMY_ALERT_COOLDOWN_HOURS * 3600
    last_ts = float(storage_autonomy_last_alert_ts.get(key) or 0)
    if last_ts > 0 and (now_ts - last_ts) < cooldown:
        return False
    storage_autonomy_last_alert_ts[key] = now_ts
    return True


async def notify_admins_storage_alert(bot: Bot, text: str) -> None:
    for admin_id in ADMIN_IDS:
        try:
            await send_message_limited(bot, int(admin_id), text, bulk=True)
        except Exception as exc:
            logging.warning("storage autonomy admin notify failed for %s: %s", admin_id, exc)


async def storage_autonomy_cleanup_db() -> dict:
    return await cleanup_payment_events_for_autonomy()


async def storage_autonomy_check_once(bot: Bot) -> None:
    if not AUTONOMY_ENABLED:
        return
    metrics = await storage_autonomy_metrics()
    cleanup = await storage_autonomy_cleanup_db()
    logging.info(
        "storage autonomy metrics db=%s backups=%s logs=%s incident=%s free=%s cleanup=%s",
        _human_mb(metrics["db_mb"]),
        _human_mb(metrics["backups_mb"]),
        _human_mb(metrics["logs_mb"]),
        _human_mb(metrics["incident_mb"]),
        _human_mb(metrics["free_mb"]),
        cleanup,
    )

    problems = []
    if int(metrics["free_mb"]) >= 0 and int(metrics["free_mb"]) < AUTONOMY_MIN_FREE_MB:
        problems.append(f"свободного места мало: {_human_mb(metrics['free_mb'])} < {_human_mb(AUTONOMY_MIN_FREE_MB)}")
    if float(metrics["db_mb"]) > AUTONOMY_DB_WARN_MB:
        problems.append(f"database.sqlite большой: {_human_mb(metrics['db_mb'])} > {_human_mb(AUTONOMY_DB_WARN_MB)}")
    if float(metrics["backups_mb"]) > AUTONOMY_BACKUPS_WARN_MB:
        problems.append(f"backups занимают много: {_human_mb(metrics['backups_mb'])} > {_human_mb(AUTONOMY_BACKUPS_WARN_MB)}")
    if float(metrics["logs_mb"]) > AUTONOMY_LOGS_WARN_MB:
        problems.append(f"logs занимают много: {_human_mb(metrics['logs_mb'])} > {_human_mb(AUTONOMY_LOGS_WARN_MB)}")

    if not problems:
        return
    alert_key = "storage:" + ":".join(sorted(p.split(":", 1)[0] for p in problems))
    if not storage_autonomy_should_alert(alert_key):
        return
    text = (
        "⚠️ Автономность сервера\n"
        "━━━━━━━━━━━━━━\n"
        + "\n".join(f"• {p}" for p in problems)
        + "\n━━━━━━━━━━━━━━\n"
        f"DB: {_human_mb(metrics['db_mb'])}\n"
        f"Backups: {_human_mb(metrics['backups_mb'])}\n"
        f"Logs: {_human_mb(metrics['logs_mb'])}\n"
        f"Incident: {_human_mb(metrics['incident_mb'])}\n"
        f"Free: {_human_mb(metrics['free_mb'])}"
    )
    await notify_admins_storage_alert(bot, text)


async def storage_autonomy_loop(bot: Bot) -> None:
    if not AUTONOMY_ENABLED:
        logging.info("Storage autonomy watchdog disabled")
        return
    logging.info("Storage autonomy watchdog started")
    while True:
        try:
            await storage_autonomy_check_once(bot)
        except Exception as exc:
            logging.exception("Storage autonomy watchdog failed: %s", exc)
        await sleep_with_jitter(AUTONOMY_POLL_SECONDS, 60)

# =========================
# MAIN
# =========================

async def main() -> None:
    setup_logging()
    write_health_snapshot(status="starting")
    await log_runtime_audit()
    await init_payments_db()
    await init_trials_db()
    await init_support_db()
    await init_reminders_db()
    await init_antiabuse_db()
    await init_tariffs_db()
    await init_tgproxy_db()
    await init_settings_db()
    await init_referrals_db()
    await init_user_blocks_db()
    await init_remote_nodes_db()
    await init_remote_antiabuse_db()
    await configure_database_pragmas()

    bot = Bot(token=BOT_TOKEN)
    dp = Dispatcher()
    user_block_middleware = UserBlockMiddleware()
    dp.message.outer_middleware(user_block_middleware)
    dp.callback_query.outer_middleware(user_block_middleware)
    dp.include_router(router)

    reminder_task = asyncio.create_task(reminder_loop(bot))
    antiabuse_task = asyncio.create_task(antiabuse_worker(bot))
    health_task = asyncio.create_task(health_loop())
    platega_task = asyncio.create_task(platega_poll_loop(bot))
    platega_callback_task = asyncio.create_task(platega_callback_server_loop(bot))
    payment_watchdog_task = asyncio.create_task(payment_security_watchdog_loop(bot))
    storage_autonomy_task = asyncio.create_task(storage_autonomy_loop(bot))
    remote_nodes_task = asyncio.create_task(remote_sync_loop(bot))
    remote_antiabuse_task = asyncio.create_task(remote_antiabuse_worker(bot))
    trial_cleanup_task = asyncio.create_task(trial_auto_delete_expired_loop(bot))
    old_expiry_task = asyncio.create_task(sui_old_expiry_worker())
    await bot.delete_webhook(drop_pending_updates=False)
    try:
        await dp.start_polling(bot)
    except (KeyboardInterrupt, SystemExit):
        raise
    finally:
        write_health_snapshot(status="stopping")
        reminder_task.cancel()
        antiabuse_task.cancel()
        health_task.cancel()
        platega_task.cancel()
        platega_callback_task.cancel()
        payment_watchdog_task.cancel()
        storage_autonomy_task.cancel()
        remote_nodes_task.cancel()
        remote_antiabuse_task.cancel()
        trial_cleanup_task.cancel()
        old_expiry_task.cancel()
        with contextlib.suppress(asyncio.CancelledError):
            await reminder_task
        with contextlib.suppress(asyncio.CancelledError):
            await antiabuse_task
        with contextlib.suppress(asyncio.CancelledError):
            await health_task
        with contextlib.suppress(asyncio.CancelledError):
            await platega_task
        with contextlib.suppress(asyncio.CancelledError):
            await platega_callback_task
        with contextlib.suppress(asyncio.CancelledError):
            await payment_watchdog_task
        with contextlib.suppress(asyncio.CancelledError):
            await storage_autonomy_task
        with contextlib.suppress(asyncio.CancelledError):
            await remote_nodes_task
        with contextlib.suppress(asyncio.CancelledError):
            await remote_antiabuse_task
        with contextlib.suppress(asyncio.CancelledError):
            await trial_cleanup_task
        with contextlib.suppress(asyncio.CancelledError):
            await old_expiry_task
        await close_http_session()
        await bot.session.close()
        write_health_snapshot(status="stopped")


if __name__ == "__main__":
    asyncio.run(main())

















